// 全局搜索BOM比较
sysGlobalSearchBatchBomCompareAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const selectedData = table.getCheckedNodeList();
  let bomCompareRender = {};

  const bomTemplateParams: any = selectedData.map(item => {
    return {
      guid: item.origin['GUID$'],
      className: item.origin['CLASSNAME$'],
      classGuid: item.origin['CLASSGUID$']
    };
  });

  const isNull = selectedData.length === 0;
  if (isNull) {
    this.dppMessageService.warning('workbench.operationTips.selectMaterialFirst');
    return;
  }

  const is1 = selectedData.every(item => item.origin['OBJECTTYPE$'] && item.origin['OBJECTTYPE$'] === 'Item');
  if (!is1) {
    // OBJECTTYPE$不存在或者不等于Item，提示：存在非物料类对象，无法比较
    this.dppMessageService.warning('workbench.operationTips.nonMaterialObjects');
    return;
  }
  const is2 = selectedData.length <= 2 && selectedData.length !== 0;
  if (!is2) {
    // 如果多选超过两个物料，则提示：最多选择两个对象进行BOM比较！
    this.dppMessageService.warning('workbench.operationTips.onlySelectTwoObject');
    return;
  }
  const is3 = selectedData.every(item => item.origin['UHASBOM$CODE'] && item.origin['UHASBOM$CODE'] === 'Y');
  if (!is3) {
    // 如果选中物料中存在无BOM结构(UHASBOM)的对象，则提示：选中对象无BOM，无法比较！
    this.dppMessageService.warning('workbench.operationTips.notContainBom');
    return;
  }
  this.globalSearchService.getBOMTemplateOrigin(bomTemplateParams).subscribe({
    next: res => {
      if (res.success && res.data.length > 0) {
        if (is1 && is2 && is3) {
          // const render = !selectedData[1]?.origin
          //   ? `bom1Guid=${selectedData[0]?.origin['GUID$']}&bom1ClassName=${selectedData[0]?.origin['CLASSNAME$']}`
          //   : `bom1Guid=${selectedData[0]?.origin['GUID$']}&bom1ClassName=${selectedData[0]?.origin['CLASSNAME$']}&bom2Guid=${selectedData[1].origin['GUID$']}&bom2ClassName=${selectedData[1]?.origin['CLASSNAME$']}`;

          // const property = {
          //   uiType: 'page',
          //   routePath: `/page?name=sysBomComparePage&${render}`
          // };
          // this.as.openBlank(property, this.handleBlankParams(selectedData));

          let bomCompareParams = {}

          if (!selectedData[1]?.origin) {
            bomCompareParams = {
              bom1Guid: selectedData[0]?.origin['GUID$'],
              bom1ClassName: selectedData[0]?.origin['CLASSNAME$'],
            }
          } else {
            bomCompareParams = {
              bom1Guid: selectedData[0]?.origin['GUID$'],
              bom1ClassName: selectedData[0]?.origin['CLASSNAME$'],
              bom2Guid: selectedData[1].origin['GUID$'],
              bom2ClassName: selectedData[1]?.origin['CLASSNAME$'],
            }
          }

          Object.assign(bomCompareParams, { selectedData })
          const button = this.getExeCom<DppButtonComponent>(event);
          const params: RouteUrlKeyParams = {
            model: button.getUiModel().action,
            data: bomCompareParams,
          }
          const routeUi = this.routeService.getRouteUIByKey(button.getUiModel().action['route'])!
          const tranParams = DppTargetRouteUtil.parseUrlKey(params);
          const routePath = DppTargetRouteUtil.getRouteQueryString({ routeUi, tranParams })
          const property = {
            title: routePath,
            routePath
          };

          this.as.openBlank(property);
        }
      } else {
        // 如果选中物料无可比较的BOM模板，则提示：没有可供比较的BOM模板！
        this.dppMessageService.warning('workbench.operationTips.noBOMTemplate');
      }
    }
  });
}

getNextValue(map: any, key: string, direction = 'next'): any {
  const keys = Array.from(map.keys());
  const currentIndex = keys.indexOf(key);

  if (currentIndex === -1) {
    return undefined;
  }

  let nextIndex;

  if (direction === 'next') {
    nextIndex = (currentIndex + 1) % keys.length;
  } else if (direction === 'pre') {
    nextIndex = (currentIndex - 1 + keys.length) % keys.length;
  } else {
    return undefined;
  }

  const nextKey = keys[nextIndex];
  return map.get(nextKey);
}

private getDiffKeys(table: DppTableComponent): string[] {
  // 通过getCols()来动态获取的
  const colKeys = table.beans.columnManage
    .getCols()
    .map((col: any) => col.key)
    .filter(key => key !== 'leftControl');
  const suffix = () => colKeys.map(f => `${f}DIFFERENT`);
  return [...suffix()];
}

private isRowDifferent(origin: any, sort: string | undefined, table: DppTableComponent): boolean {
  if (origin['ALLDIFFERENT'] === 'Y') return true;
  const keys = this.getDiffKeys(table);
  return keys.some(k => origin[k] === true);
}

// 下一个差异
sysNextDifferAciton(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const sort = table.queryCondition.params.get('SORT') as string | undefined;
  const allData = table['dppFlattenNodes'] as RowNode[];

  if (allData.length === 0) {
    this.dppMessageService.warning('workbench.operationTips.refineComparisonConditions');
    return;
  }

  // 获取所有有差异的节点
  const differNodes = allData.filter(n => this.isRowDifferent(n.origin, sort, table));
  if (differNodes.length === 0) {
    return;
  }

  const nodeMap = new Map<string, RowNode>(differNodes.map(n => [n.origin['UNIQUEKEY'], n]));
  const currentSelected = table.getSelectedNodeList(); // 当前高亮选中的行
  let currentId: string;

  if (currentSelected.length > 0) {
    // 有已选中，从当前选中的下一个开始找
    currentId = currentSelected[0].origin['UNIQUEKEY'];
  } else {
    // 首次点击：默认从“第一个差异项的前一个”开始找下一个 → 实际上就是第一个
    currentId = differNodes[differNodes.length - 1].origin['UNIQUEKEY'];
  }

  // 获取下一个要选中的节点
  const nextNode = this.getNextValue(nodeMap, currentId, 'next');
  if (nextNode) {
    table.setNodeSelected(nextNode);
    table.scrollIntoViewIfNeeded(nextNode.rowTop);
  }
}

// 上一个差异
sysPreDifferAciton(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const sort = table.queryCondition.params.get('SORT') as string | undefined;
  let allData = table['dppFlattenNodes'];
  const currenttSelectedData = table.getSelectedNodeList();
  if (allData.length === 0) {
    this.dppMessageService.warning('workbench.operationTips.refineComparisonConditions');
    return;
  }
  const differNodes = (allData as RowNode[]).filter(n => this.isRowDifferent(n.origin, sort, table));
  if (!differNodes.length) {
    return;
  }
  const nodeMap = new Map<string, RowNode>(differNodes.map(n => [n.origin['UNIQUEKEY'], n]));
  let id = differNodes[0].origin['UNIQUEKEY'];
  if (currenttSelectedData.length !== 0) {
    id = currenttSelectedData[0].origin['UNIQUEKEY'];
  }
  const preNode = this.getNextValue(nodeMap, id, 'pre');
  if (preNode) {
    table.setNodeSelected(preNode);
    table.scrollIntoViewIfNeeded(preNode.rowTop);
  }
}

// 仅显示差异项和显示全部（三个方法）
sysBomCompareFilterPresentAction(event: EventInterface): boolean {
  // 仅显示和显示全部
  const table = (event['beans'] as BeanCollections).table;
  return table['onlyDiffer'] ?? true;
}

sysBomCompareFilterPassesAction(event: ExtendFilterEvent): boolean {
  // 仅生效
  const table = (event.node['beans'] as BeanCollections).table;
  if (table['onlyDiffer']) {
    const sort = table.queryCondition.params.get('SORT') as string | undefined;
    const data = event.node.origin;
    return this.isRowDifferent(data, sort, table);
  } else {
    return true;
  }
}

sysOnlyDifferAciton(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const com = this.getExeCom<DppButtonComponent>(event);
  const toolbar = com.toolbarComFn() as DppToolbarComponent;
  const btnList = toolbar['dppButtons']?.toArray();
  const btn = toolbar?.service?.filterBtnsByName('sysOnlyDifferCommand', btnList);

  // 默认仅显示差异项，触发后显示全部
  const onlyDifferent = btn?.model.label.includes('onlyDifferent');
  if (onlyDifferent) {
    if (btn) {
      btn.model.label = 'workbench.command.showAll';
    }
  } else {
    if (btn) {
      btn.model.label = 'workbench.command.onlyDifferent';
    }
  }
  table['onlyDiffer'] = onlyDifferent;
  table.onFilterChanged();
}

// 导出差异
sysExportDifferAciton(event: EventInterface): void {
  this.setLoading(event, true);
  const table = this.getContentCom(event) as DppTableComponent;
  const allData = table.getFlatRootNodes(); // 总
  if (allData.length === 0) {
    this.dppMessageService.warning('workbench.operationTips.noDataToExport');
    this.setLoading(event, false);
    return;
  }
  const { level, ...restParams } = Object.fromEntries(table.rootCondition.params) as any;
  const params = {
    ...restParams,
    LEVEL: -1,
    ONLYDIFFERENCE: table['onlyDiffer'] ? true : false
  };
  this.globalSearchService.exportBomCompareRes(params).subscribe({
    next: res => {
      // console.log(res);
      if (res.success) {
        const label = this.translate.transform('workbench.field.comparisonResult');
        this.setLoading(event, false);
        const downloadUrl = window.URL.createObjectURL(res.data!);
        const link = document.createElement('a');
        link.href = downloadUrl;
        // link.download = 'bom比较结果.xlsx';
        link.download = `${label}.xls`;
        link.click();
        window.URL.revokeObjectURL(downloadUrl);
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

