// 处理打开新页签的params
handleBlankParams(selectedData: RowNode[]): any {
  let currentGuid = '';
  if (!selectedData[1]?.origin['GUID$']) {
    currentGuid = selectedData[0]?.origin['GUID$'];
  } else {
    currentGuid = selectedData[0]?.origin['GUID$'] + selectedData[1]?.origin['GUID$'];
  }
  return {
    dppRender: {
      guid: currentGuid
    }
  };
}

// bom派生表格 点击复选框后的动作
sysBomForkCheckboxAction(event: EventInterface): void {
  const tableCpm = this.getContentCom<DppTableComponent>(event);
  const selectNode = tableCpm.getCheckedNodes();
  const isRoot = selectNode.some(i => i.origin['ISROOT'] === 'Y');
  const isAllow = !selectNode.some(i => i.origin['ISALLOWDERIVE'] === 'N');
  const floatToolbar = tableCpm.beans.floatToolbarCtrl.getToolbarInstance()!;
  floatToolbar.callback({
    params: {
      //@ts-ignore
      ISROOT: isRoot ? 'Y' : 'N',
      ISALLOWDERIVE: isAllow
    }
  });
}

// bom页签 操作列 BOM派生按钮
sysBomForkDerAction(event: EventInterface): void {
  const rowData = this.getRowData(event);
  const guid = rowData[BomForkKey.end2Key];
  const className = rowData[BomForkKey.end2ClassName];
  const classGuid = rowData[BomForkKey.end2Class];
  // const property = {
  //   uiType: 'page',
  //   routePath: `/page`
  // };
  // const params = {
  //   dppRender: {
  //     name: 'sysBomForkPage',
  //     guid,
  //     className,
  //     classGuid,
  //     paramsAddData: true,
  //     title: BomForkRouteTitle.bomFork
  //   }
  // };
  const button = this.getExeCom<DppButtonComponent>(event);
  const routeParams: RouteUrlKeyParams = {
    model: button.getUiModel().action,
    data: rowData,
  }
  const routeUi = this.routeService.getRouteUIByKey(button.getUiModel().action['route'])!
  const tranParams = DppTargetRouteUtil.parseUrlKey(routeParams);
  const routePath = DppTargetRouteUtil.getRouteQueryString({ routeUi, tranParams })
  const property = {
    title: routePath,
    routePath
  };

  this.setLoading(event, true);

  let confirmModal: NzModalRef | undefined = undefined;
  this.bomForkService
    .hasDerivedRecord(guid)
    .pipe(
      switchMap(i => {
        return new Observable<string>(obs => {
          if (!i.data) {
            this.as.openBlank(property);
            this.setLoading(event, false);
            obs.complete();
            return;
          }
          confirmModal = new ModalClass(this.as).confirm(
            i18n_BOM_Fork.WARNING_HAVE_BOM_TITLE,
            {
              title: '',
              dppFooter: [
                {
                  label: this.tranPipe.transform('common.button.confirm'),
                  type: 'primary',
                  onClick: () => {
                    obs.next(i.data!);
                    obs.complete();
                  }
                },
                {
                  label: this.tranPipe.transform('common.button.cancel'),
                  type: 'default',
                  onClick: () => {
                    this.as.openBlank(property);
                    obs.complete();
                    confirmModal?.destroy();
                    this.setLoading(event, false);
                  }
                }
              ]
            },
            true
          );
        });
      }),
      switchMap(i => this.bomForkService.deleteDeriveRecord(guid, i))
    )
    .subscribe({
      next: res => {
        if (res.success && res.data) {
          this.as.openBlank(property);
        }
        confirmModal?.destroy();
        this.setLoading(event, false);
      },
      error: err => {
        confirmModal?.destroy();
        this.setLoading(event, false);
      }
    });
}

