// bom派生表格 操作列 派生按钮
sysBomForkOperaForkAction_old(event: EventInterface): void {
  const rowData = this.getRowData(event);
  const rowNode = this.getNode(event) as RowNode;
  const page = this.getRootPageService(event);
  const tableCpm = this.getContentCom<DppTableComponent>(event);
  const tabFormCpm = page.getComFnMapByName<TabFormComponent>(BomForkCommandConstant.tabFormCommand)!;
  this.setLoading(event, true);
  this.commonService
    .getObject1(rowData[`END2#${SystemClassFieldEnum.CLASSNAME}`], rowData[`END2#${SystemClassFieldEnum.GUID}`])
    .subscribe({
      next: res => {
        if (res.success && res.data) {
          const upDateData = {
            [BomForkKey.bomForkType]: BomForkType.fork,
            [`${BomForkKey.bomForkType}$TITLE`]: BomForkOptionLabel.fork
          };
          tabFormCpm.update(res.data!, rowData);
          tableCpm.refreshNode(rowNode, upDateData);
          BomDerivationUtil.updateParentDerivative(rowNode, tableCpm);
        }
        this.setLoading(event, false);
      },
      error: err => {
        this.setLoading(event, false);
      }
    });
}

