// bom派生表格 操作列 重置按钮
sysBomForkOperaCancelDelAction(event: EventInterface): void {
  const rowData = this.getRowData(event);
  const rowNode = this.getNode(event) as RowNode;
  const page = this.getRootPageService(event);
  const tableCpm = this.getContentCom<DppTableComponent>(event);
  const tabFormCpm = page.getComFnMapByName<TabFormComponent>(BomForkCommandConstant.tabFormCommand)!;
  this.setLoading(event, true);
  const params = BomDerivationUtil.buildBomForkUpdateParams(rowData, BomForkType.none);
  this.bomForkService.resetDeriveRecord(params).subscribe({
    next: res => {
      if (rowData[BomForkKey.bomForkType] === BomForkType.add) {
        tableCpm.deleteNode([rowNode]);
      }
      // 如果是替换，先要删除
      if (rowData[BomForkKey.bomForkType] === BomForkType.replace && rowNode.children.length > 0) {
        tableCpm.deleteNode(rowNode.children);
      }
      const batchEventParams: BomForkBatchParams = {
        tableCpm,
        batchDatas: res.data!,
        message: this.message,
        event,
        option: i18n_BOM_Fork.RESET
      };
      BomDerivationUtil.batchHandle(batchEventParams);
      tabFormCpm.removeForkPage(rowData);
      // 如果是替换(成功后)，先要删除
      if (rowData[BomForkKey.bomForkType] === BomForkType.replace) {
        const find = res.data!.details.find(
          i => i.result === 'SUCCESS' && i.data[BomForkKey.derKey] === rowData[BomForkKey.derKey]
        );
        if (find && rowNode.origin['HASEND2']) {
          tableCpm.refreshData(rowNode);
        }
      }

      if (rowData[BomForkKey.bomForkType] === BomForkType.del) {
        if (rowNode.origin['HASEND2'] && rowNode.isExpanded) {
          tableCpm.refreshData(rowNode);
        }
      }
      // 清空结构类字段
      Object.keys(rowNode.origin).forEach(key => {
        if (key.includes(BomForkKey.structurePre)) {
          rowNode.setDataValue(key, '');
        }
      });
      this.setLoading(event, false);
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

// bom派生表格 浮动toolbar 设置字段值
sysBomForkBatchSetFieldAction(event: EventInterface): void {
  const tableCpm = this.getContentCom<DppTableComponent>(event);
  const selectNodes = tableCpm.getCheckedNodes();
  const classNames = new Array<string>();
  const rowNodeMap = new Map<string, RowNode>();
  selectNodes.forEach(i => {
    const className = i.origin[`END2#${SystemClassFieldEnum.CLASSNAME}`];
    if (!classNames.includes(className)) {
      classNames.push(className);
    }
    rowNodeMap.set(i.origin[SystemClassFieldEnum.GUID], i);
  });

  const reqs$ = new Array<Observable<IFormUiModel>>();
  classNames.forEach(i => {
    reqs$.push(this.uiModelService.getModelConfig<IFormUiModel>(UIModelTypeEnum.FORM, `class_${i}`));
  });

  this.setLoading(event, true);
  let button_: ModalButtonOptions;
  let modal_: DppNzModalRef;
  forkJoin(reqs$)
    .pipe(
      // 处理字段集合
      map(ress => {
        let fields = new Array<DppFieldTypeConfig[]>();
        ress.forEach(i => {
          const iFields = i.fields || [];
          iFields.forEach(iF => {
            fields.push(iF.fieldGroup!);
          });
        });
        return fields;
      }),
      // 处理form入参
      map(res => {
        const commonObjectsWithReduce = res.reduce((acc, currentArray) => {
          return acc.filter(obj => currentArray.some(item => item.key === obj.key));
        });
        const options: DppOption[] = [];
        commonObjectsWithReduce.forEach(f => {
          if (
            f.key === SystemClassFieldEnum.PREVIEWPATH ||
            f.key === SystemClassFieldEnum.CLASSIFICATION ||
            f.key === SystemClassFieldEnum.ID
          ) {
            f.templateOptions.visiableExpression = `$SELECT_FIELD?.value==='${f.key}'`;
            return;
          }
          options.push({
            label: f.templateOptions.label!,
            value: f.key
          });
          f.templateOptions.label = i18n_BOM_Fork.VALUE;
          f.templateOptions.required = true;
          f.templateOptions.visiableExpression = `$SELECT_FIELD?.value==='${f.key}'`;
        });
        commonObjectsWithReduce.unshift({
          key: 'SELECT_FIELD',
          type: FieldTypeEnum.COMBO,
          // @ts-ignore
          templateOptions: {
            label: i18n_BOM_Fork.FIELD,
            required: true,
            options
          }
        });
        const fields: DppFieldTypeConfig[] = [
          {
            type: 'grid',
            // @ts-ignore
            templateOptions: {},
            fieldGroup: commonObjectsWithReduce
          }
        ];

        const render: IFormRender = {
          mParams: {
            isObject: false,
            mode: ModeTypeEnum.EDIT,
            fields
          }
        };
        return render;
      }),
      // 换流 确认
      switchMap(res => {
        return new Observable<{ formCpm: DppFormComponent }>(observer => {
          const bs = event.exeComFn() as DppButtonComponent;
          bs.getUiModel().action!.ui = 'form';
          modal_ = CommonEventUtil.buildDefaultModal<DppFormComponent>(
            event,
            (button, formCpm) => {
              button_ = button;
              if (formCpm.onSubmit()) {
                button.loading = true;
                observer.next({
                  formCpm
                });
              }
            },
            this.message,
            res
          );
        });
      }),
      switchMap(res => {
        // const itemList = new Array<BatchSetValueParams>();
        const formData = { ...res.formCpm.getFormData<object>() };
        const sourceList = selectNodes.map(i => {
          const origin = i.origin;
          const updateData = {};
          // Object.keys(origin).forEach(key => {
          //   if (key.includes('END2#')) {
          //     updateData[key.replace('END2#', '')] = origin[key];
          //   }
          // });
          Object.assign(updateData, formData);
          return BomDerivationUtil.buildBomForkUpdateParams(i.origin, BomForkType.fork, updateData);
        });
        return this.bomForkService.batchEditDeriveInfo(sourceList);
      })
    )
    .subscribe({
      next: res => {
        button_.loading = false;
        this.setLoading(event, false);

        if (!res.success) {
          button_.loading = false;
          this.setLoading(event, false);
          return;
        }

        const batchEventParams: BomForkBatchParams = {
          tableCpm,
          batchDatas: res.data!,
          message: this.message,
          event
        };
        BomDerivationUtil.batchHandle(batchEventParams);
        button_.loading = false;
        this.setLoading(event, false);
        modal_.close();
      },
      error: err => {
        if (button_) {
          button_.loading = false;
        }
        this.setLoading(event, false);
      }
    });
}

