// 顶层右上角 派生按钮
sysBomForkTopForkAction(event: EventInterface): void {
  const page = this.getRootPageService(event);
  const topForm = page.getComFnMapByName<DppFormComponent>(BomForkCommandConstant.sysBomForkTopFormCommand)!;

  if (!topForm.onSubmit()) {
    return;
  }

  const formData = topForm.getFormData<{
    TARGET: string;
    TARGET$CLASSNAME: string;
    TARGET$CLASS: string;
    COMMITFOLDER$: string;
  }>();

  this.setLoading(event, true);
  this.bomForkService
    .batchDeriveBom(formData.TARGET, formData.TARGET$CLASSNAME, formData.TARGET$CLASS, formData.COMMITFOLDER$)
    .subscribe({
      next: res => {
        this.setLoading(event, false);

        if (!res.success) {
          const messages = res.data as unknown as string[];
          let message = '';
          messages.forEach((t, index) => {
            message += `${t}<br>`;
          });
          if (message) {
            this.message.error(message);
          }
          this.setLoading(event, false);
          return;
        }
        const property = {
          uiType: 'instance',
          routePath: `/instance`
        };
        const params = {
          dppRender: {
            guid: res.data?.GUID$,
            className: res.data?.CLASSNAME$,
            paramsAddData: true
          }
        };
        this.as.openBlank(property, params);
        window.close();
        this.setLoading(event, false);
      },
      error: err => {
        this.setLoading(event, false);
      }
    });
}

