  const routeUi = this.routeService.getRouteUIByKey(button.getUiModel().action['route'])!
  const tranParams = DppTargetRouteUtil.parseUrlKey(params);
  const routePath = DppTargetRouteUtil.getRouteQueryString({ routeUi, tranParams })
  const property = {
    title: routePath,
    routePath
  };
  this.as.openBlank(property);
}

