// ECN-> 右侧变更请求表更 添加按钮
sysECMLinkECRAction(event: EventInterface): void {
  const formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.ECNDetailCommand)!;
  const formData = formCom.getNotTranFormData<IFoundaton>();
  const tableCom = this.getContentCom<DppTableComponent>(event);
  const checkOutParams: CheckOutParams = {
    iFound: formCom.getFormData(),
    authUser: this.authUserService,
    messageService: this.message
  };
  const isValidCheckOut = EcmEventUtil.isValidCheckOut(checkOutParams);
  if (!isValidCheckOut) {
    return;
  }
  this.setLoading(event, true);
  // 打开高级搜索
  const modal = CommonEventUtil.buildDefaultModal<DppGlobalSearchComponent>(
    event,
    (okButtonThis, advCom) => {
      okButtonThis.loading = true;
      // const selectDatas = advCom.table.getSelectedItems();
      const selectDatas = advCom.table.getCheckedNodes().map(i => i.origin);
      if (selectDatas.length > 0) {
        const ecn = {
          classGuid: formData[SystemClassFieldEnum.CLASSGUID]!,
          guid: formData[SystemClassFieldEnum.GUID]!,
          procrtGuid: formData['PROCESS'] ? formData['PROCESS']['GUID']! : ''
        };
        // let objects = [formComponent.getFormData<IFoundaton>()];
        // if (formComponent.dppRender.mode === ModeTypeEnum.BATCHCREATE) {
        //   objects = formComponent.getFormData<IFoundaton[]>();
        // }
        const items = new Array<{ GUID$: string; CLASSGUID$: string }>();
        selectDatas.forEach(item => {
          items.push({
            GUID$: item['GUID$'],
            CLASSGUID$: item['CLASSGUID$']
          });
        });
        this.ecm.linkECR(ecn, items).subscribe(
          res => {
            if (res.success && res.data) {
              if (res.data.totalCnt === res.data.successCnt) {
                this.message.success('common.operation.newSuccess');
              } else {
                this.message.createTableMessage('success', 'common.operation.newSuccess', res.data);
              }
              const isExpandedNodes = tableCom.getAllNodes().filter(i => i.isExpanded && i.children.length);
              tableCom
                .refreshData()
                .pipe(
                  tap(i => {
                    i.forEach(node => {
                      if (isExpandedNodes.some(t => t.origin['GUID$'] === node.origin['GUID$'])) {
                        tableCom.refreshData(node);
                        node.setExpanded(true);
                      }
                    });
                  })
                )
                .subscribe();
              modal.close();
            } else {
              this.message.warning(`${res.errorCode}:${res.errorMsg}`);
            }
            okButtonThis.loading = false;
            this.setLoading(event, false);
          },
          err => {
            okButtonThis.loading = false;
            this.setLoading(event, false);
          }
        );
      } else {
        this.message.warning('common.operation.noDataSelect');
        okButtonThis.loading = false;
        this.setLoading(event, false);
      }
    },
    this.message
  );
}

// 悬浮toolbar 生成ECO
sysBuildECOAction(event: EventInterface): void {
  const formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.ECNDetailCommand)!;
  const formData = formCom.getNotTranFormData<IFoundaton>();

  const checkOutParams: CheckOutParams = {
    iFound: formCom.getFormData(),
