    return;
  }
  this.setLoading(event, true);
  const tableCom = this.getContentCom<DppTableComponent>(event);
  const upPage = this.getParentPageService<IPageService>(event, 'sysChangeNoticeRightCommand');
  const nextTable = upPage?.getChildPage<DppTableComponent>(CommandConstant.ECOTableDetailCommand);
  const tableSelectDatas = tableCom.getCheckedNodes().map(i => i.origin);
  if (tableSelectDatas.length > 0) {
    const ecn = {
      classGuid: formData[SystemClassFieldEnum.CLASSGUID]!,
      guid: formData[SystemClassFieldEnum.GUID]!,
      procrtGuid: formData['PROCESS'] ? formData['PROCESS']['GUID']! : ''
    };

    const items = new Array<{ GUID$: string; CLASSGUID$: string }>();
    tableSelectDatas.forEach(item => {
      items.push({
        GUID$: item['END2#GUID$'],
        CLASSGUID$: item['END2#CLASSGUID$']
      });
    });

    if (tableSelectDatas.every(i => i['END2#CLASSNAME$'] == 'ECR')) {
      this.message.warning('common.operation.noDataCanPaste');
      this.setLoading(event, false);
      return;
    }

    this.ecm.ecpToEco(ecn, items).subscribe(
      res => {
        if (res.success && res.data) {
          if (res.data.totalCnt === res.data.successCnt) {
            this.message.success('common.operation.newSuccess');
          } else {
            const bs = this.getExeCom<DppButtonComponent>(event);
            this.message.createTableMessage('warning', bs.getUiModel().label, res.data);
          }
          // this.contentComCallback(
          //   event,
          //   CommonEventUtil.buildCallBack(undefined, undefined, EventCallbacksActionName.TREEREFRESH)
          // );
          if (res.data.successCnt) {
            const isExpandedNodes = tableCom.getAllNodes().filter(i => i.isExpanded && i.children.length);
            tableCom
              .refreshData()
              .pipe(
                tap(i => {
                  i.forEach(node => {
                    if (isExpandedNodes.some(t => t.origin['GUID$'] === node.origin['GUID$'])) {
                      tableCom.refreshData(node);
                      node.setExpanded(true);
                    }
                  });
                })
              )
              .subscribe();
            nextTable?.refreshData();
          }
          // modal.close();
        } else {
          this.message.warning(`${res.errorCode}:${res.errorMsg}`);
        }
        this.setLoading(event, false);
      },
      err => {
        this.setLoading(event, false);
      }
    );
  } else {
    this.message.warning('common.operation.noDataSelect');
    this.setLoading(event, false);
  }
}

