// 变更范围添加
async sysECMAddECIAction(event: EventInterface): Promise<void> {
  const com = this.getContentCom<IBaseContentComponent>(event);

  let formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.BatchECPDetailCommand)!;
  const className = com.dppRender.dParams!.className!;
  if (className.includes('ECO')) {
    formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.BatchECODetailCommand)!;
  }
  let formData = formCom.getFormData<IFoundaton>();
  if (formData[SystemClassFieldEnum.ISEDITABLE] !== 'Y') {
    // guess ? table!.setLoading(false) : this.setLoading(event, false);
    this.message.warning('common.operation.notEditable');
    return;
  }
  // BOMTEMPLATE
  const modifType = formData['MODIFYTYPE'];
  const bomTemplate = formData['BOMTEMPLATE'];
  const bomTemplateName = formData['BOMTEMPLATE$NAME'];
  //变更类型为空
  if (!modifType || !bomTemplate) {
    this.message.warning('ecm.operation.bomOrModifTypeNull');
    return;
  }
  const modifTypeName = formData['MODIFYTYPE$NAME'];

  const isValid = formCom.onSubmit();
  if (!isValid) {
    this.message.warning('common.operation.verificationFailed');
    return;
  }
  // 如果不是批量删除 获取范围预设参数
  const preDefineVal = {};
  if (!modifTypeName.includes('BatchDel')) {
    const changeScopeFields = formCom
      .getFields()
      .filter(f => f.templateOptions['fieldKey'] && f.templateOptions['fieldKey'] === 'BOMTEMPLATE');
    if (isEmpty(changeScopeFields)) {
      this.message.warning('ecm.operation.preDefineValNull');
      return;
    }
    changeScopeFields[0].fieldGroup!.forEach(f => {
      const key = f.key?.toString()!;
      preDefineVal[key] = formData[key];
      DppFormUtil.setRelatedValue(formData, key, undefined, preDefineVal);
    });
  }
  const dppRender = {
    guid: formData['CHANGEITEM'],
    classGuid: formData['CHANGEITEM$CLASS'],
    changeType: modifTypeName,
    bomTemplate: bomTemplateName
  };
  const bs = event.exeComFn() as DppButtonComponent;
  let action = { ...bs.getUiModel().action! };
  // action = { ...action };
  Object.assign(action, dppRender);
  // 批量新增
  if (modifTypeName.includes('BatchAdd')) {
    this.createECIComon(event, formCom, 'BatchAdd', preDefineVal, undefined, action);
  }
  // 批量删除
  else if (modifTypeName.includes('BatchDel')) {
    action.ui = UIModelTypeEnum.TABLE;
    // Object.assign(action, dppRender);
    this.createECIComon(event, formCom, 'BatchDel', undefined, undefined, action);
  }
  // 批量修改
  else if (modifTypeName.includes('BatchMod')) {
    action.ui = UIModelTypeEnum.TABLE;
    // Object.assign(action, dppRender);
    this.createECIComon(event, formCom, 'BatchMod', preDefineVal, undefined, action);
  }
  // 批量取代
  else if (modifTypeName.includes('BatchReplace')) {
    if (formData['CR#TARGETITEM'] === formData['CHANGEITEM']) {
      this.message.warning('ecm.warning.replaceAndChangeNotSame');
      return;
    }

    action.ui = UIModelTypeEnum.TABLE;
    // Object.assign(action, dppRender);
    preDefineVal['CR#REPLACERATE'] = `${preDefineVal['CR#REPLACERATEM']}:${preDefineVal['CR#REPLACERATEN']}`; // 暂时
    this.createECIComon(event, formCom, 'BatchReplace', preDefineVal, undefined, action);
  }
}

private createECIComon(
  event: EventInterface,
  formCom: DppFormComponent,
  type: EciModifyType,
  preDefineVal?: object,
  dppRender?: IRenderParameter | object,
  action?: IUIAction
): void {
  let masterData = formCom.getFormData<IFoundaton>();
  // 打开高级搜索
  const modal = CommonEventUtil.buildDefaultModal<DppGlobalSearchComponent | DppTableComponent>(
    event,
    async (okButtonThis, com) => {
      okButtonThis.loading = true;
      let tableCom: DppTableComponent;
      if (com instanceof DppGlobalSearchComponent) {
        tableCom = com.table;
      } else {
        tableCom = com;
      }
      const selectDatas = tableCom!.getCheckedNodes().map(i => i.origin);
      if (selectDatas.length > 0) {
        // 先保存ECO/ECP
        const formDataChange = formCom.getFormChanceData<IFoundaton>();
        // if (Object.keys(formDataChange).length > 0) {
        const object = {
          CLASSNAME$: masterData.CLASSNAME$,
          GUID$: masterData.GUID$,
          MASTERFK$: masterData.MASTERFK$,
          CLASSIFICATIONGUID$: masterData.CLASSIFICATION$,
          UPDATETIME$: masterData[SystemClassFieldEnum.UPDATETIME]
        };
        Object.assign(object, formDataChange, preDefineVal || {});
        const res = await this.boas
          .saveObject(object)
          .toPromise()
          .catch(erro => {
            return;
          });

        if (!res) {
          okButtonThis.loading = false;
          return;
        }
        if (res?.success && res?.data) {
          masterData = res?.data;
          formCom.callback(CommonEventUtil.buildCallBack(res.data, EventCallbacksActionName.UPDATE));
          const rootPage = this.getRootPageService(event);
          // 更新rootpage数据源
          this.updateInstanceData(rootPage, res.data!);
        } else {
          this.message.warning(`${res?.errorCode}:${res?.errorMsg}`);
          okButtonThis.loading = false;
          return;
        }
        // }

        const master = {
          classGuid: masterData[SystemClassFieldEnum.CLASSGUID]!,
          guid: masterData[SystemClassFieldEnum.GUID]!,
          procrtGuid: masterData['PROCESS'] ? masterData['PROCESS']['GUID']! : ''
        };
        const bomTemplateName = masterData['BOMTEMPLATE$NAME'];
        const items = new Array<{
          GUID$: string;
          CLASSGUID$: string;
          STRUCTURE$GUID$: string;
          STRUCTURE$CLASSNAME$: string;
          STRUCTURE$DATASEQ: string;
        }>();
        selectDatas.forEach(item => {
          items.push({
            GUID$: item['GUID$'],
            CLASSGUID$: item['CLASSGUID$'],
            STRUCTURE$GUID$: item['STRUCTURE$GUID$'],
            STRUCTURE$CLASSNAME$: item['STRUCTURE$CLASSNAME$'],
            STRUCTURE$DATASEQ: item['STRUCTURE$DATASEQ']
          });
        });
        this.ecm
          .createECI(master, bomTemplateName, items, type, preDefineVal)
          .pipe(
            switchMap(i =>
              this.commonService
                .getObject1(formCom!.dppRender.dParams!.className!, formCom!.dppRender.dParams!.guid!)
                .pipe(
                  map(t => {
                    return {
                      createECI: i,
                      get: t
                    };
                  })
                )
            ),
            map(i => {
              const rootPage = this.getRootPageService(event);
              // 更新rootpage数据源
              this.updateInstanceData(rootPage, i.get.data!);
              return i.createECI;
            })
          )
          .subscribe({
            next: res => {
              if (res.success && res.data && res.data.ERROR$) {
                if (res.data.ERROR$.successCnt === res.data.ERROR$.errorCnt) {
                  this.message.success('common.operation.newSuccess');
                } else {
                  res.data.ERROR$.successCnt = selectDatas.length - res.data.ERROR$.errorCnt;
                  this.message.createTableMessage('success', 'common.operation.newSuccess', res.data.ERROR$);
                }
                CommonEventUtil.contentComCallback(
                  event,
                  CommonEventUtil.buildCallBack(undefined, undefined, EventCallbacksActionName.REFRESH)
                );
                // // 每次生成ECI的时候 都去保存ECP或者ECO
                // this.createECIAfter(formCom);
                modal.close();
              } else if (!res.success) {
                this.message.warning(`${res.errorCode}:${res.errorMsg}`);
              }
              okButtonThis.loading = false;
              CommonEventUtil.setLoading(event, false);
            },
            error: err => {
              okButtonThis.loading = false;
              CommonEventUtil.setLoading(event, false);
            }
          });
      } else {
        this.message.warning('common.operation.noDataSelect');
        okButtonThis.loading = false;
        this.setLoading(event, false);
      }
    },
    this.message,
    dppRender,
    true,
    action
  );
}

