// 变更范围删除
sysChangeScopeRemoveAction(event: EventInterface): void {
  this.setLoading(event, true);
  const com = this.getContentCom<IBaseContentComponent>(event);
  const className = com.dppRender.dParams!.className!!;
  const rootPage = this.getRootPageService(event);
  let formCom: DppFormComponent | undefined;
  if (className.includes('ECP')) {
    formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.BatchECPDetailCommand);
  } else {
    formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.BatchECODetailCommand);
  }
  const formData = formCom!.getNotTranFormData<IFoundaton>();
  if (formData[SystemClassFieldEnum.ISEDITABLE] !== 'Y') {
    // guess ? table!.setLoading(false) : this.setLoading(event, false);
    this.message.warning('common.operation.notEditable');
    this.setLoading(event, false);
    return;
  }
  const rowData = this.getRowData(event);
  EcmEventUtil.sysChangeScopeRemoveActionFn(event, formData, [rowData], this.ecm, this.message, undefined, res => {
    this.commonService
      .getObject1(formCom!.dppRender.dParams!.className!, formCom!.dppRender.dParams!.guid!)
      .subscribe(res2 => {
        formCom!.callback({
          action: EventCallbacksActionName.UPDATE,
          params: res2.data!
        });
        // 更新rootpage数据源
        this.updateInstanceData(rootPage, res2.data!);
      });
  });
}

/**
 * 浮动toolbar批量指派
 * @use 变更通知界面 | 场景入口设计变更中的实施计划
 */
sysECMBatchAssignAction(event: EventInterface): void {
  const selectDatas = this.getSelectData(event);
  const choose = (c: SelectiveIntegrationComponent): void => {
    const items = new Array<{ GUID$: string; CLASSGUID$: string; CLASSNAME$: string }>();
    selectDatas.forEach(item => {
      items.push({
        GUID$: item['GUID$'],
        CLASSGUID$: item['CLASSGUID$'],
        CLASSNAME$: item['CLASSNAME$']
      });
    });
    if (!c['getSelectedData']()) {
      this.message.warning('common.operation.noDataSelected');
      return;
    }
    this.ecm.savePerformer(items, c['getSelectedData']().GUID).subscribe(
      (res: any) => {
        console.log(res);

        if (res!.success) {
          // 总数量 成功数量  失败数量
          const { successCnt, totalCnt, errorCnt } = res.data;
          if (successCnt && successCnt === totalCnt) {
            this.message.success('common.operation.operationSuccess');
            this.getContentCom<DppTableComponent>(event).refreshData();
          } else {
            this.errMessage.showMessage(event, res);
            //全部失败， 不需要刷新表格
            if (totalCnt === errorCnt) return;
            this.getContentCom<DppTableComponent>(event).refreshData();
          }
        } else {
          this.message.warning(`${res!.errorCode}:${res!.errorMsg}`);
        }
      },
      err => {
        CommonEventUtil.setLoading(event, false);
      }
    );
    modal.close();
  };
  const wizardCom = WizardEventUtil.getWizardCom(event);
  let instanceData = this.getRootPageService(event)?.getInstanceData?.();
  // wizardCom存在说明是场景入口的
  if (wizardCom) {
    instanceData = wizardCom.getWizardHeadInstance<DppFormComponent>(0).getFormData();
    instanceData[SystemClassFieldEnum.ISEDITABLE] = 'Y';
  }
  const checkOutParams: CheckOutParams = {
    iFound: instanceData,
    authUser: this.authUserService,
    messageService: this.message,
    ecos: selectDatas
  };
  const isValidCheckOut = EcmEventUtil.isValidCheckOut(checkOutParams);
  if (!isValidCheckOut) {
    return;
  }
  const modal = this.as.openModal(
    {
      title: 'ecm.command.sysAssignPerformerCommand',
      bodyStyle: { height: '420px' },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: choose
        }
      ],
      content: UserListComponent
    },
    {
      // GROUPIDS: typeMap.get('GROUP')?.['ids'],
      // GROUPNAMES: typeMap.get('GROUP')?.['names'],
      // ROLEIDS: typeMap.get('RIG')?.['ids'],
      // ROLENAMES: typeMap.get('RIG')?.['names'],
      // USERIDS: typeMap.get('USER')?.['ids'],
      // USERNAMES: typeMap.get('USER')?.['names']
    }
  ) as NzModalRef;
}

// 从结构中选择
sysECMSelectFromStructureAction(event: EventInterface): void {
  const rowData = this.getRowData(event);
  const table = this.getContentCom(event) as DppTableComponent;
  const bs = event.exeComFn() as DppButtonComponent;
  const _action = { ...(bs.getUiModel().action! || {}) };
  const height = _action.height!;
  delete _action.height;
  const beForemodal = this.getTriggerModal(event);
  const that = this;
  const modal = bs.as.openModal(
    {
      title: bs.getUiModel().label,
      width: _action.width ? _action.width : '1200px',
      height,
      closeCallBack: () => {
        this.setLoading(event, false);
      },
      // content: DppFormComponent,
      uiType: _action.ui,
      footer: [
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: function (c: DppTableComponent) {
            this.loading = true;
            const tableCom = that.getContentCom(event) as unknown as DppTableComponent;
            const rootTable = tableCom.dppRender;
            const masterData = rootTable?.['dParams']?.['instanceData'];
            const selectDatas = c.getCheckedNodeList();
            if (selectDatas.length > 0) {
              const master = {
                classGuid: masterData[SystemClassFieldEnum.CLASSGUID]!,
                guid: masterData[SystemClassFieldEnum.GUID]!,
                procrtGuid: masterData['PROCESS'] ? masterData['PROCESS']['GUID']! : '',
                isBatch: rootTable['isBatch']
              };
              const items = new Array<{
                CHANGEITEM: string;
                CHANGEITEM$CLASS: string;
                NAME$: string;
                CHANGEITEM$ID$: string;
                CHANGEITEM$NAME$: string;
              }>();
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
              selectDatas.forEach((selectData: any) => {
                const item = selectData['origin'];
                items.push({
                  CHANGEITEM: item['END2#GUID$'],
                  CHANGEITEM$CLASS: item['END2#CLASSGUID$'],
                  NAME$: masterData[SystemClassFieldEnum.NAME],
                  CHANGEITEM$ID$: item['END2#ID$'],
                  CHANGEITEM$NAME$: item['END2#NAME$']
                });
              });
              that.ecm.createDetailObject(master, items).subscribe(
                res => {
                  this.loading = false;
                  if (res!.success && res!.data) {
                    if (res.data.totalCnt === res.data.successCnt) {
                      that.message.success('common.operation.newSuccess');
                    } else {
                      that.message.createTableMessage('success', 'common.operation.newSuccess', res.data);
                    }
                    const outTable = table.dppRender.innerSend?.triggerInstance!();
                    outTable.refreshData();
                    modal.close();
                    beForemodal?.close();
                  } else {
                    that.message.warning(`${res!.errorCode}:${res!.errorMsg}`);
                  }
                },
                err => {
                  CommonEventUtil.setLoading(event, false);
                }
              );
            } else {
              that.message.warning('common.operation.noDataSelect');
              CommonEventUtil.setLoading(event, false);
              this.loading = false;
            }
          }
        }
      ]
    },
    { dppRender: { ..._action, GUID$: rowData['GUID$'], CLASSNAME$: rowData['CLASSNAME$'] } }
  );
}

