// 实施计划批量移除变更指令 / 批量删除变更建议
async sysECMBatchRemoveAction(event: EventInterface): Promise<void> {
  const contentCpm = this.getContentCom<IBaseContentComponent>(event);
  if (contentCpm.dppRender.name?.toLowerCase().includes(UIModelTypeEnum.WIZARD)) {
    this.wizardEventService.sysECMWizardDeleteDetailAction(event, true);
    return;
  }
  let formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.ECNDetailCommand)!;

  const className = contentCpm.dppRender.dParams!.className!;
  if (className.includes('ECR')) {
    formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.ECRDetailCommand)!;
  }
  const formData = formCom.getNotTranFormData<IFoundaton>();
  const rowData = this.getSelectData(event);
  const checkOutParams: CheckOutParams = {
    iFound: formData,
    authUser: this.authUserService,
    messageService: this.message,
    ecos: rowData
  };
