// 影响分析 批量
sysECMBatchImpactAnalysisAction(event: EventInterface): void {
  if (!this.sysECMHasCheckout(event)) {
    return;
  }

  const data = this.getSelectData(event) || [];

  const batchDatas = data.filter(item => item['CLASSNAME$'] === 'ECO_Batch' || item['CLASSNAME$'] === 'ECP_Batch');
  const normalDatas = data.filter(item => item['CLASSNAME$'] !== 'ECO_Batch' && item['CLASSNAME$'] !== 'ECP_Batch');

  const firstItem = data[0];
  const className = firstItem?.['CLASSNAME$'] || '';
  const judgeEcp = className.indexOf('ECP') !== -1;
  const type = judgeEcp ? 'ecp' : 'eco';

  const notStopDatas = type === 'eco' ? normalDatas.filter(item => item['STATUS$'] !== 'OBS') : [...normalDatas];

  if (batchDatas.length && normalDatas.length && !notStopDatas.length) {
    this.message.warning(`ecm.operation.batchECOIsIgnoreOBS`);
    return;
  }

  // 没有普通变更数据
  if (!normalDatas.length) {
    const batchIsIgnore = `ecm.operation.${type === 'eco' ? 'batchECOIsIgnoreYXFX' : 'batchECPIsIgnoreYXFX'}`;
    this.message.warning(batchIsIgnore);
    return;
  }

  // 没有非停用数据(停用状态变更指令被忽略)
  if (!notStopDatas.length) {
    this.message.warning(`ecm.operation.OBSECOIsIgnore`);
    return;
  }

  // 有批量数据、有普通变更数据且没有停用数据
  if (batchDatas.length && normalDatas.length == notStopDatas.length) {
    const onlyNormal = `ecm.operation.${type === 'eco' ? 'onlyNormalECOCanBeYXFX' : 'onlyNormalECPCanBeYXFX'}`;
    this.message.warning(onlyNormal);
  }

  // 有批量数据、有普通变更数据且有停用数据(只有普通变更指令且不是停用状态指令可以进行影响分析)
  if (batchDatas.length && normalDatas.length > notStopDatas.length) {
    this.message.warning(`ecm.operation.batchECONormalOBSCanBeYXFX`);
  }

  // 没批量数据、有普通变更数据且有停用数据(只有非停用状态指令可以进行影响分析)
  if (!batchDatas.length && normalDatas.length > notStopDatas.length) {
    this.message.warning(`ecm.operation.batchECOOBSCanBeYXFX`);
  }

  this.eCMImpactAnalysisAction(event, deepCopy(notStopDatas));
}

