// 影响分析添加实现
ecImpactAnalysisAddAction(event: EventInterface, addArr: DppSafeAny[]): void {
  // 变量准备
  const table = this.getContentCom<DppTableComponent>(event);

  const pageService = this.getRootPageService(event);
  const menu = pageService.getComFnMapByName(MenuNameEnum.ECIMPACTANALYSISMENU) as DppMenuComponent;
  const menuChocie = menu.getSelectedData()?.data;
  const handleMenuArr: DppSafeAny[] = [];
  const itemList: Array<{ GUID$: string; CLASSGUID$: string; CLASSNAME$: string }> = [];
  // 组装参数
  addArr.forEach(item => {
    if (item) {
      itemList.push({
        GUID$: item['GUID$'],
        CLASSGUID$: item['CLASSGUID$'],
        CLASSNAME$: item['CLASSNAME$']
      });
    }
  });
  const obj = {
    GUID$: menuChocie['GUID$'] as string,
    CLASSGUID$: menuChocie['CLASSGUID$'] as string,
    CLASSNAME$: menuChocie['CLASSNAME$'] as string,
    ITEMLIST: itemList
  };
  // 修改menu实现
  const sendToMenu: (changeMess: IBaseData[]) => void = (changeMess: IBaseData[]) => {
    if (changeMess && changeMess.length) {
      changeMess.forEach(success => {
        if (success && success['CHANGEITEM']) {
          handleMenuArr.push({
            ...success,
            name: success['CHANGEITEM$FULLNAME'],
            title: success['CHANGEITEM$FULLNAME'],
            key: success['CHANGEITEM'],
            isLeaf: true,
            icon: success['CHANGEITEM$ICON$']
          });
        }
      });
    }
    menu.setLoading(true);
    // 数据交给menu
    if (changeMess.length > 0) {
      menu.modifyMenuNode(handleMenuArr);
    }
    menu.setLoading(false);
  };
  this.setLoading(event, true);
  // 创建普通变更指令
  this.ecm.createCommonECO(obj).subscribe({
    next: res => {
      if (res && res.data) {
        const ExceptionData = res.data['ExceptionData'] as IBatchData;
        if (ExceptionData && ExceptionData.successCnt !== ExceptionData.totalCnt) {
          this.message.createTableMessage('success', 'common.operation.newSuccess', ExceptionData);
        }
        // debugger
        sendToMenu(res.data['ECO'] || res.data['ECP']);

        const innerSend = table.modelManager.innerSend;
        if (innerSend?.triggerInstance && typeof innerSend?.triggerInstance === 'function') {
          const triggerInstance = innerSend?.triggerInstance() as DppTableComponent;
          triggerInstance.refreshData();
        }
      }
      this.setLoading(event, false);
    },
    error: err => {
      if (err && err.errorCode && err.errorMsg) {
        this.message.error(`${err.errorCode}:${err.errorMsg}`);
      }
      this.setLoading(event, false);
    }
  });
}

