// ECO 基础信息上的保存
sysECOSaveAction(event: EventInterface): void {
  const componet = this.getContentCom<DppFormComponent>(event);
  const obj = componet.getFormData<IFoundaton>();
  const objChanged = componet.getFormChanceData<IFoundaton>();

  const rootPage = this.getRootPageService(event);
  const baseForm = rootPage.getComFnMapByName<DppFormComponent>(CommandConstant.DefaultNewBaseCommand)!;

  this.setLoading(event, true);

  // componet.refreshLoading(true);
  if (obj[SystemClassFieldEnum.ISEDITABLE] !== 'Y' && obj.GUID) {
    this.message.warning('common.operation.notEditable');
    // this.contentComCallback(event, {});
    this.setLoading(event, false);
    return;
  }
  if (!componet.onSubmit()) {
    this.message.create('warning', 'common.operation.verificationFailed');
    this.setLoading(event, false);
    return;
  }
  const isChanged = componet.isChangedByData();
  // 判断对象是否变化
  if (!isChanged) {
    this.message.create('warning', 'common.operation.unchanged');
    this.setLoading(event, false);
    return;
  }
  const object = {
    CLASSNAME$: obj.CLASSNAME$,
    GUID$: obj.GUID$,
    MASTERFK$: obj.MASTERFK$,
    CLASSIFICATIONGUID$: obj.CLASSIFICATION$
    // UPDATETIME$: obj[SystemClassFieldEnum.UPDATETIME]
  };
  objChanged[SystemClassFieldEnum.UPDATETIME] = obj[SystemClassFieldEnum.UPDATETIME];
  // Object.assign(object, objChanged);
  object['props'] = objChanged;
  // 范围预设传全部
  const preDefineVal = {};
  const changeScopeFields = componet
    .getFields()
    .filter(f => f.templateOptions['fieldKey'] && f.templateOptions['fieldKey'] === 'BOMTEMPLATE');
  if (!isEmpty(changeScopeFields)) {
    changeScopeFields[0].fieldGroup!.forEach(f => {
      const key = f.key?.toString()!;
      preDefineVal[key] = obj[key];
      DppFormUtil.setRelatedValue(obj, key, undefined, preDefineVal);
    });
    const modifTypeName = obj['MODIFYTYPE$NAME'];
    if (modifTypeName.includes('BatchReplace')) {
      preDefineVal['CR#REPLACERATE'] = `${preDefineVal['CR#REPLACERATEM']}:${preDefineVal['CR#REPLACERATEN']}`;
      if (obj['CR#TARGETITEM'] === obj['CHANGEITEM']) {
        this.message.warning('ecm.warning.replaceAndChangeNotSame');
        this.setLoading(event, false);
        return;
      }
    }
    Object.assign(object['props'], preDefineVal);
  }

  // Object.assign(object, objChanged);

  this.boas.saveObject(object, false, DppUrlConfig.itemManagement.saveObject).subscribe({
    next: res => {
      if (res.success && res.data) {
        const callback = CommonEventUtil.buildCallBack(res.data, EventCallbacksActionName.UPDATE);
        // 刷新当前页面
        this.contentComCallback(event, callback);
        // 右边base(普通ECP，批量ECP不存在baseForm)
        baseForm?.callback(callback);
        const newData = { ...preDefineVal, ...res.data! };
        // 更新rootpage数据源
        this.updateInstanceData(rootPage, newData);
        this.setLoading(event, false);
        this.message.create('success', 'basic.common.notice.successfullySaved');
      } else {
        this.message.error(`${res.errorCode}:${res.errorMsg}`);
        this.setLoading(event, false);
      }
    },
    error: res => {
      this.setLoading(event, false);
    }
  });
}

// 单元格更新指派人
sysCellSavePerformerAction(event: CellSaveEvent): Observable<DppResponse<IBatchData>> {
  const data = event.data;
  const changedProps = event.editChancedRowData;
  const rootPage = this.getRootPageService(event);
  const instanceData = rootPage.getInstanceData();
  const checkOutParams: CheckOutParams = {
    iFound: instanceData,
    authUser: this.authUserService,
    messageService: this.message
  };
  const isValidCheckOut = EcmEventUtil.isValidCheckOut(checkOutParams);
  if (!isValidCheckOut) {
    return of(data);
  }

  const { key, classIDKey, classNameKey } = useKey();
  const performerKey = 'PERFORMER';

  const rowToUpdate = {
    [key]: data[key],
    [classIDKey]: data[classIDKey],
    [classNameKey]: data[classNameKey]
  };

  const performer = changedProps[performerKey];

  return this.ecm.savePerformer([rowToUpdate], performer);
}

