// 普通变更指令 其他表格 删除
sysECODeleteECIAction(event: EventInterface): void {
  const formCom = this.formRootFindChild<DppFormComponent>(event, CommandConstant.ECODetailCommand);

  const formData = formCom!.getNotTranFormData<IFoundaton>();
  if (formData[SystemClassFieldEnum.ISEDITABLE] !== 'Y') {
    this.message.warning('common.operation.notEditable');
    return;
  }
  const params = this.getRowData(event) as IFoundaton;
  const details = [params];
  const items = new Array<{ GUID$: string; CLASSGUID$: string }>();
  const master = {
    classGuid: formData.CLASSGUID$!,
    guid: formData.GUID$!,
    procrtGuid: formData['PROCESS'] ? formData['PROCESS']['GUID']! : ''
  };
  details.forEach(item => {
    items.push({
      GUID$: item['STRUCTUREOBJECT']['GUID$']!,
      CLASSGUID$: item['STRUCTUREOBJECT']['CLASSGUID$']!
    });
  });

  this.ecm.deleteECI(master, items).subscribe(
    res => {
      if (res!.success && res!.data) {
        if (res!.data.totalCnt === res!.data.successCnt) {
          this.message.success('common.operation.deleteSuccess');
        } else {
          this.message.createTableMessage('success', 'basic.common.button.delete', res!.data);
        }
        this.getContentCom<DppTableComponent>(event).refreshData();
      } else {
        this.message.warning(`${res!.errorCode}:${res!.errorMsg}`);
      }
      CommonEventUtil.setLoading(event, false);
    },
    err => {
      CommonEventUtil.setLoading(event, false);
    }
  );
}

