// ECR 创建ECN
sysECRCreateECNAction(event: EventInterface): void {
  const page = this.getRootPageService(event);
  const formCpm = page.getComFnMapByName<DppFormComponent>(CommandConstant.ECNDetailCommand)!;
  const ecr = page.getInstanceData() as IFoundaton;
  const newECN = {
    CLASSNAME$: 'ECN_new',
    NAME$: ecr.NAME$,
    REASON: ecr['REASON']
  };
  generateFieldMapping({
    mappingType: 'folder',
    fieldKey: 'COMMITFOLDER$',
    sourceData: ecr,
    onValueUpdate: (key, value) => {
      newECN![key] = value;
    }
  });

  this.setLoading(event, true);
  this.ecm
    .createMasterObject(newECN)
    .pipe(
      map(i => i.data!),
      switchMap(i => {
        const createdECNParams = {
          classGuid: i.CLASSGUID$!,
          guid: i.GUID$!
        };
        const ECRParams = {
          GUID$: ecr.GUID$!,
          CLASSGUID$: ecr.CLASSGUID$!
        };
        return this.ecm
          .linkECR(createdECNParams, [ECRParams], {
            interceptor: 'false'
          })
          .pipe(
            map(i2 => {
              if (!i2.data) {
                throw {
                  type: 'linkMessage',
                  message: 'ECN link ECR err',
                  ECN: i
                };
              }
              return i;
            }),
            catchError(err => {
              throw {
                type: 'link',
                res: err,
                ECN: i
              };
            })
          );
      })
    )
    .subscribe({
      next: res => {
        // 打开ECN详情页改为使用新页签打开
        this.as.openBlank({
          routePath: `instance?className=${res.CLASSNAME$}&guid=${res.GUID$}`
        });
        this.setLoading(event, false);
      },
      error: errRes => {
        if (errRes.type && (errRes.type === 'linkMessage' || errRes.type === 'link')) {
          const errMsg1 = this.tranPipe.transform('common.title.created');
          const errMsg2 = this.tranPipe.transform(
            errRes.type === 'link' ? errRes.res.error.errorMessage : errRes.message
          );
          this.message.error(`${errMsg1},${errMsg2}`);
        }
        this.setLoading(event, false);
      }
    });
}

