// ECO 编辑变更内容 单元格保存
sysChangeContentRowAction(event: TableCellEvent): Observable<DppResponse<IFoundaton>> {
  const node = event.node;
  const nodeData = node.origin as unknown as ChangeContent;
  const tableCpm = this.getContentCom<DppTableComponent>(event);
  let newData = {};
  if (event.column.key === ChangeContentKey.AFTER_OBJECT) {
    const obj = event['newValue'] as IFoundaton;
    newData = EcmEventUtil.objectHandle(nodeData, obj, 'after');
  }
  if (event.column.key === ChangeContentKey.BEFORE_OBJECT) {
    const obj = event['newValue'] as IFoundaton;
    newData = EcmEventUtil.objectHandle(nodeData, obj, 'before');
  }
  let options$ = of(true);
  if (event.column.key === ChangeContentKey.CHANGE_TYPE) {
    newData = EcmEventUtil.parseModifyType(nodeData, event.editChancedRowData as object);
    if (event.data[`${ChangeContentKey.CHANGE_TYPE}$NAME`] === 'BatchReplace') {
      const option_ = this.commonListService.getList('code', {
        codeName: 'Replacepolicy'
      }) as Observable<DppResponse<CodeType[]>>;
      options$ = option_.pipe(
        map(i => {
          const options = i.data!;
          const find = options.find(i => i.code === 'MandatoryReplace');
          if (find) {
            newData[ChangeContentKey.REPLACE_POLICY] = find.value;
            newData[`${ChangeContentKey.REPLACE_POLICY}$NAME`] = find.itemName;
            newData[`${ChangeContentKey.REPLACE_POLICY}$CODE`] = find.code;
            newData[`${ChangeContentKey.REPLACE_POLICY}$TITLE`] = find.label;
          }
          return true;
        })
      );
    }

    // node.origin = {} as any;
  }
  // if (event.column.key === ChangeContentKey.REPLACE_RATE) {
  //   const vaild = /^(?!0:0)([1-9][0-9]*):([1-9][0-9]*)$/.test(nodeData[ChangeContentKey.REPLACE_RATE]);
  //   if (!vaild) {
  //     newData[ChangeContentKey.REPLACE_RATE] = '1:1';
  //   }
  // }

  if (event.column.key === ChangeContentKey.REPLACE_POLICY) {
    newData[ChangeContentKey.EFFECTIVE_DATE] = '';
    newData[ChangeContentKey.INVALID_DATE] = '';
  }
  return options$.pipe(
    tap(() => {
      node.updateData({ ...nodeData, ...newData });
    }),
    switchMap(() => {
      const data: DppResponse<IFoundaton> = {
