// ECO 编辑变更内容 检查
sysChangeContentCheckAciton(event: EventInterface): void {
  const ecoTableCpm = this.getTrigger<DppTableComponent>(event);
  const drawerModal = this.getTriggerDrawer(event);
  const tableCpm = this.getContentCom<DppTableComponent>(event);
  const tableToolbarCpm = tableCpm.topToolbar;
  const tableDatas = tableCpm.getFlatRootNodes().map(i => i.origin) as unknown as ChangeContent[];
  tableDatas.pop();
  const ecoList = tableCpm.dppRender.dParams!['ecoList'] as IFoundaton[];
  const showNewBtn = tableToolbarCpm.service.filterBtnsByName(
    CommandConstant.ECOChangeBomSelectCommand,
    tableToolbarCpm.dppButtons.toArray()
  )!;
  const render = {
    ecoList: ecoList.map(i => {
      return {
        GUID$: i['GUID$'],
        CLASSGUID$: i['CLASSGUID$'],
        ID$: i['ID$']
      };
    }),
    bomTemplate: showNewBtn.value,
    changeContents: tableDatas.map((i, index) => EcmEventUtil.toChangeContentParams(i, index))
  };
  const buttonFn: CheckButtonFn = {
    okFn: (button, cpm, modal) => {},
    cancelFn: (button, cpm, modal) => {
      button.loading = true;
      cpm.cancelCheck().subscribe(() => {
        button.loading = false;
        modal.close();
      });
    },
    executeFn: (button, cpm, modal) => {
      button.loading = true;
      cpm.executeEc().subscribe(res => {
        button.loading = false;
        if (res.errCount === 0) {
          this.message.success(i18n_ECM.EXECUTE_FINSH);
          modal.close();
          drawerModal?.close();
        }
        ecoTableCpm.refreshData();
      });
    },
    terminationFn: (button, cpm, modal) => {
      modal.close();
    },
    exportFn: (button, cpm, modal) => {
      cpm.exportFn();
    },
    exportBomTableFn: (button, cpm, modal) => {
      button.loading = true;
      this.sysChangeContentExportAciton(event).subscribe(() => {
        button.loading = false;
      });
    },
    saveResultFn: (button, cpm, modal) => {
      cpm.exportFn();
      modal.close();
    }
  };
  EcmEventUtil.buildCheckCpmModal(event, buttonFn, this.message, render);
}

// ECO 编辑变更内容 导入并检查
sysChangeContentImportAciton(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  // table.deleteNode(table.getFlatRootNodes());
  // datas.forEach(i => {
  //   table.addData(i);
  // });
  // return;
  this.setLoading(event, true);
  const fileInput = document.createElement('input');
  fileInput.type = 'file';
  fileInput.accept = '.csv,.xlsx,.xls';
  fileInput.style.display = 'none';

  const tableToolbarCpm = table.topToolbar;
  const showNewBtn = tableToolbarCpm.service.filterBtnsByName(
    CommandConstant.ECOChangeBomSelectCommand,
    tableToolbarCpm.dppButtons.toArray()
  )!;

  fileInput.addEventListener('change', fileEvent => {
    const files = (fileEvent.target as HTMLInputElement).files!;
    this.ecm
      .importBatchChange(files[0])
      .pipe(
        map(i => i.data!)
        // catchError(i => of(dataParams))
      )
      .subscribe({
        next: res => {
          table.deleteNode(table.getFlatRootNodes());
          showNewBtn.refreshSelf(
            () => {
              showNewBtn.value = res.bomTemplate;
            },
            { update: true }
          );
          const tableDatas = new Array<ChangeContent>();
          res.scopes.forEach(i => {
            const item = EcmEventUtil.toChangeContent(i as ChangeContentParams);
            table.addData(item);
            tableDatas.push(item);
          });
          EcmEventUtil.delAndEditAction(table, tableDatas);
          this.sysChangeContentCheckAciton(event);
          this.setLoading(event, false);
        },
        error: err => {
          this.setLoading(event, false);
        }
      });
    fileInput.remove();
  });
  fileInput.addEventListener('cancel', fileEvent => {
    fileInput.remove();
    this.setLoading(event, false);
  });
  fileInput.click();
}

// ECO 编辑变更内容 导出编辑表
sysChangeContentExportAciton(event: EventInterface): Subject<void> {
  const table = this.getContentCom<DppTableComponent>(event);
  const nodes = table.getFlatRootNodes();
  const lastData = nodes[nodes.length - 1].origin;
  const obs = new Subject<void>();
  const datas = table
    .getFlatRootNodes()
    .map((i, index) => EcmEventUtil.toChangeContentParams(i.origin as any, index));
  if (Object.keys(lastData).length === 0) {
    datas.pop();
  }
  const tableToolbarCpm = table.topToolbar;
  const showNewBtn = tableToolbarCpm.service.filterBtnsByName(
    CommandConstant.ECOChangeBomSelectCommand,
    tableToolbarCpm.dppButtons.toArray()
  )!;
  const ecn = table.dppRender.dParams!['ecn'] as IFoundaton;
  this.setLoading(event, true);
  const bs = this.getExeCom<DppButtonComponent>(event);
  this.ecm.exportBatchChange(datas, showNewBtn.value).subscribe({
    next: res => {
      this.setLoading(event, false);
      if (!res.success) {
        obs.next();
        obs.complete();
        return;
      }
      this.downloadBlob(res.data!, `${ecn.ID$!}-${this.datePipe.transform(new Date(), 'yyyyMMddHHmmssSSS')}.xlsx`);
      obs.next();
      obs.complete();
      // this.setLoading(event, false);
    },
    error: err => {
      this.setLoading(event, false);
      obs.next();
      obs.complete();
    }
  });
  return obs;
}

// ECO 编辑变更内容 导出模板
sysChangeContentExportTemplateAciton(event: EventInterface): void {
