    }
  });
}

private downloadBlob(data: Blob, fileName: string): void {
  const downloadUrl = window.URL.createObjectURL(data);
  const link = document.createElement('a');
  link.href = downloadUrl;
  link.download = fileName;
  link.click();
  window.URL.revokeObjectURL(downloadUrl);
}

/**
 * 编辑变更内容 - 生效日期单元格保存事件处理器
 *
 * 业务规则：
 * 1. 生效日期不能晚于失效日期
 * 2. 当生效日期变更后，如果已有失效日期，需要验证日期逻辑
 * 3. 如果生效日期晚于失效日期，则自动清空失效日期
 *
 * @param event - 单元格保存事件对象
 * @param event.newValue - 新的生效日期值
 * @param event.data - 当前行的完整数据
 * @returns Observable<Record<string, any>> - 返回更新后的日期数据
 *
 * @example
 * // 正常情况：生效日期早于失效日期
 * event.newValue = '2024-01-01'
 * event.data[INVALID_DATE] = '2024-12-31'
 * // 结果：两个日期都保留
 *
 * @example
 * // 异常情况：生效日期晚于失效日期
 * event.newValue = '2024-12-31'
 * event.data[INVALID_DATE] = '2024-01-01'
 * // 结果：失效日期被清空
 */
public sysEffectDateCellSaveEvent(event: CellSaveEvent): Observable<Record<string, any>> {
  /**
   * 解析并验证日期字符串
   * @param dateString - 日期字符串
   * @returns Date | null - 有效的日期对象或null
   */
  const parseAndValidateDate = (dateString: string): Date | null => {
    try {
      if (!dateString || dateString.trim() === '') {
        return null;
      }

      const dateObj = new Date(dateString);

      // 检查是否为有效日期
      if (isNaN(dateObj.getTime())) {
        console.warn(`无效的日期格式: ${dateString}`);
        return null;
      }

      return dateObj;
    } catch (error) {
      console.warn(`日期解析失败: ${dateString}`, error);
      return null;
    }
  };

  /**
   * 判断是否需要清空失效日期
   * @param effectiveDate - 生效日期字符串
   * @param invalidDate - 失效日期字符串
   * @returns boolean - 是否需要清空失效日期
   */
  const shouldClearInvalidDate = (effectiveDate: string, invalidDate: string): boolean => {
    // 基础验证：两个日期都必须存在
    if (!effectiveDate || !invalidDate) {
      return false;
    }

    // 日期格式验证和转换
    const effectiveDateObj = parseAndValidateDate(effectiveDate);
    const invalidDateObj = parseAndValidateDate(invalidDate);

    // 如果任一日期无效，不执行清空操作
    if (!effectiveDateObj || !invalidDateObj) {
      return false;
    }

    // 比较日期：生效日期晚于失效日期时需要清空
    return effectiveDateObj > invalidDateObj;
  };

  return new Observable<Record<string, any>>(observer => {
    try {
      // 1. 提取并验证输入参数
      const effectiveDateInput = event.newValue as string;
      const currentInvalidDate = event.data?.[ChangeContentKey.INVALID_DATE] as string;

      // 2. 构建基础返回数据结构
      const updateResult: Record<string, any> = {
        [ChangeContentKey.EFFECTIVE_DATE]: effectiveDateInput,
        [ChangeContentKey.INVALID_DATE]: currentInvalidDate || ''
      };

      // 3. 执行日期逻辑验证和处理
      if (shouldClearInvalidDate(effectiveDateInput, currentInvalidDate)) {
        // 清空失效日期并记录清空原因
        updateResult[ChangeContentKey.INVALID_DATE] = '';
      }

      // 4. 返回处理结果
      observer.next({
        success: true,
        data: updateResult
      });
      observer.complete();
    } catch (error) {
      // 5. 错误处理
      console.error('处理生效日期单元格保存事件时发生错误:', error);
      observer.error(error);
    }
  });
}

// 抛转ERP
InsERPAction(event: EventInterface): void {
  this.setLoading(event, true);
  const page = this.getRootPageService(event);
  const rowData = page.getInstanceData();
