ecoReplaceChangeAction: ObjectCanDeactivate = (value, fieldCpm, formCpm) => {
  const removeFields = [
    'CR#REPLACEPOLICY',
    'CR#REPLACERATEM',
    'CR#REPLACERATEN',
    'CR#EFFECTIVEDATE',
    'CR#EXPIRATIONDATE',
    'CR#BASE',
    'CR#LAYER',
    'CR#DESIGNATORS',
    'CR#REMARK'
  ];
  const fields = (formCpm.getUiModel() as IFormUiModel).fields;
  fields.forEach(g => {
    g.fieldGroup?.forEach(f => {
      const key = f.key!.toString();
      if (removeFields.includes(key)) {
        const value = f.templateOptions.defaultValue || '';
        if (f.type === 'code') {
          const key$ = key.endsWith('$') ? key : `${key}$`!;
          fieldCpm.setValueOfDefault(`${key$}NAME`, '');
          fieldCpm.setValueOfDefault(`${key$}CODE`, '');
          fieldCpm.setValueOfDefault(`${key$}TITLE`, '');
          fieldCpm.setValueOfDefault(`${key$}DESCRIPTION`, '');
        }
        if (value) {
          fieldCpm.setValueOfDefault(key, value, { markAsTouched: true });
        } else {
          fieldCpm.setValueOfDefault(key, '', { markAsTouched: true });
          f.formControl.setErrors(null);
        }
      }
    });
  });
  return of(true);
};

