/**
 * 高级搜索批量导出
 * @param event
 * @returns
 */
sysGlobalSearchExportAction(event: EventInterface): void {
  this.setLoading(event, true);
  const table = this.getContentCom(event) as DppTableComponent;
  const params = table.queryCondition.getRawValue() as any;
  const selectedData = table.getCheckedNodeList();
  if (!selectedData) {
    this.dppMessageService.warning('common.operation.noDataSelected');
    this.setLoading(event, false);
    return;
  }
  // 1. 批量导出，根据选中的数据导出，走浏览器
  let exportCondition = new QueryCondition(DppQueryConditionOperator.OR);
  let guids: string[] = [];
  selectedData.forEach(item => {
    if (item.origin['HASAUTH'] !== false) {
      guids.push(item.origin['GUID$']);
    }
  });
  if (!guids.length) {
    // 无导出权限
    this.dppMessageService.error('common.operation.exportPermission');
    this.setLoading(event, false);
    return;
  }
  // let guids = selectedData.map(item => item.origin['GUID$']);
  exportCondition.addCondition(new QueryConditionInfo('GUID$', guids, DppQueryConditionOperator.IN));
  params['condition'].items.push(exportCondition);

  this.globalSearchService.exportPart(params).subscribe({
    next: res => {
      if (res.success) {
        const fileGuid = res.data['FILE_GUID'];
        if (fileGuid) {
          this.userWorkPlatformService.downloadFile(fileGuid!, false).subscribe({
            next: ress => {
              this.setLoading(event, false);
              table.beans.floatToolbarCtrl.updateToolbarVisible(false); // 隐藏浮动工具栏
              table.setAllChecked(false); // 取消选中
              this.dppMessageService.success('common.operation.operationSuccess');
              const now = new Date();
              const year = now.getFullYear();
              const month = String(now.getMonth() + 1).padStart(2, '0');
              const day = String(now.getDate()).padStart(2, '0');
              const dateStr = `${year}${month}${day}`;
              const timestamp = String(Date.now()).slice(0, 9);

              const downloadUrl = window.URL.createObjectURL(ress.data!);
              const link = document.createElement('a');
              link.href = downloadUrl;
              link.download = `${dateStr}${timestamp}.xls`;
              link.click();
              window.URL.revokeObjectURL(downloadUrl);
            },
            error: err => {
              this.setLoading(event, false);
            }
          });
        }
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

