  const saveAsObj = componet.getService().saveAsObj;
  const obj = componet.getFormData<IFoundaton>();
  const objChanged = componet.getFormChanceData<IFoundaton>();

  this.setLoading(event, true);

  // componet.refreshLoading(true);
  if (obj.ISCHECKOUT$ !== 'Y' && obj.GUID) {
    this.dppMessageService.create('warning', 'backend.business.dppMessageService.notCheckout');
    // this.contentComCallback(event, {});
    this.setLoading(event, false);
    return;
  }
  if (!componet.onSubmit()) {
    this.dppMessageService.create('warning', 'common.operation.verificationFailed');
    this.contentComCallback(event, {});
    this.setLoading(event, false);
    return;
  }
  if (isEmpty(obj[FormFieldFileEnum.FILEPROPS])) {
    delete objChanged[FormFieldFileEnum.FILEPROPS];
    delete objChanged[FormFieldFileEnum.FILES];
    delete obj[FormFieldFileEnum.FILEPROPS];
    delete obj[FormFieldFileEnum.FILES];
  }

  // 判断对象是否变化
  if (!saveAsObj && Object.keys(objChanged).length === 0) {
    this.dppMessageService.create('warning', 'common.operation.unchanged');
    this.contentComCallback(event, {});
    this.setLoading(event, false);
    return;
  }
  const object = {
    CLASSNAME$: obj.CLASSNAME$,
    GUID$: obj.GUID$,
    MASTERFK$: obj.MASTERFK$,
    CLASSIFICATIONGUID$: obj.CLASSIFICATION$
  };
  if (obj[SystemClassFieldEnum.UPDATETIME]) {
    object[SystemClassFieldEnum.UPDATETIME] = obj[SystemClassFieldEnum.UPDATETIME];
  }
  Object.assign(object, objChanged);

  this.formSaveObjBefore(event, object, false);
}

