// form保存前处理动作
formSaveObjBefore(event: EventInterface, object: NzSafeAny, isCheckIn: boolean): void {
  const saveAsObj = this.getContentCom<DppFormComponent>(event).getService().saveAsObj;
  // let url=DppUrlConfig.itemManagement.saveObjectSimple;
  if (!isEmpty(saveAsObj)) {
    if (saveAsObj!.hasBom) {
      const modal = this.getExeCom<DppButtonComponent>(event).as.confirm(
        'common.operation.confirm.saveAsBOM.question',
        {
          // title: deleteTitle,
          footer: {
            nzOkText: 'basic.system.boolean.Y',
            nzCancelText: 'basic.system.boolean.N',
            nzOnOk: () => {
              object['isContainBom'] = 'Y';
              this.saveAsObjectHandle(event, object, isCheckIn);
            },
            nzOnCancel: () => {
              object['isContainBom'] = 'N';
              this.saveAsObjectHandle(event, object, isCheckIn);
            }
          },
          title: ''
        }
      );
    } else {
      this.saveAsObjectHandle(event, object, isCheckIn);
    }
  } else {
    this.formSaveObj(event, object, isCheckIn);
  }
}

// form另存对象处理
saveAsObjectHandle(event: EventInterface, object: NzSafeAny, isCheckIn: boolean): void {
  const formCom = this.getContentCom<DppFormComponent>(event);
  const saveAsObj = formCom.getService().saveAsObj;
  const CFField = formCom.getService().CFField;

  const CLASSIFICATIONGUID$ = object[SystemClassFieldEnum.CLASSIFICATION];
  const isContainBom = object['isContainBom'];
  delete object['CLASSNAME$'];
  delete object[SystemClassFieldEnum.CLASSIFICATION];

  const props = {};
  const cprops = {};
  if (CFField?.templateOptions.typeValue) {
    Object.keys(object).forEach(key => {
      const cfKey = `${CFField?.templateOptions.typeValue.toUpperCase()}#`;
      if (CFField && key.includes(cfKey)) {
        // cprops[key.replace(cfKey, 'CF#')] = object[key];
        cprops[key] = object[key];
      } else {
        props[key] = object[key];
      }
    });
  }
  object = {
    props,
    cprops
  };
  object[SystemClassFieldEnum.GUID] = saveAsObj!.guid;
  object['CLASSNAME$'] = saveAsObj!.className;
  object['isContainPartReplace'] = 'N';
  object['CLASSIFICATIONGUID$'] = CLASSIFICATIONGUID$;
  object['isContainBom'] = isContainBom;

  this.formSaveObj(event, object, isCheckIn, true);
}

/**
 * form保存对象
 * @param {EventInterface} event
 * @param {*} object
 * @param {boolean} [isCheckIn=false]
 * @param {boolean} [isSaveAs=false]
 * @param {(data: IBaseData) => void} [fn] 保存的回调 仅当isCheckIn为false时起作用,(不管成功与否都会回调，返回为空时，可能请求异常、也可能请求回来的数据就是空的)
 * @memberof ModifyInstanceEventService
 */
formSaveObj(
  event: EventInterface,
  object: NzSafeAny,
  isCheckIn: boolean = false,
  isSaveAs: boolean = false,
  fn?: (data?: IBaseData, isErr?: boolean) => void
): void {
  const bs = this.getExeCom<DppButtonComponent>(event);
  this.boas.saveObject(object, isSaveAs).subscribe({
    next: res => {
      // 不成功
      if (!res.success) {
        this.dppMessageService.error(`${res.errorCode}:${res.errorMsg}`);
        this.setLoading(event, false);
        return;
      }
      // 检入
      if (isCheckIn) {
        res.data![SystemClassFieldEnum.UPDATETIME] = new Date(res.data![SystemClassFieldEnum.UPDATETIME]!)
          .getTime()
          .toString();
        this.formCheckInHandle(event, res.data);
        return;
      }
      // 回调
      if (fn) {
        fn(res.data);
        return;
      }
      this.getRootPageService(event)?.setInstanceData({
        data: res.data!
      });
      // 提示
      this.dppTranslateService.get('basic.common.notice.successfullySaved').subscribe(res => {
        this.dppMessageService.success(res);
      });
      if (res.data!['FILERESULT']) {
        const fileresult = res.data!['FILERESULT'] as IBatchData;
        if (fileresult.errorCnt !== 0) {
          this.dppMessageService.createTableMessage('warning', bs.getUiModel().label, fileresult);
        }
      }

      // 查看模态框是否存在
      const modal = CommonEventUtil.getModal(event);
      // 存在 打开新页签
      if (modal) {
        const property = {
          title: `【${this.translation.transform(res?.data?.BOTITLE$!)}】${res?.data?.['FULLNAME$']}`,
          uiType: 'instance',
          routePath: '/instance'
        };
        const params = {
          dppRender: {
            className: res?.data?.CLASSNAME$,
            guid: res?.data?.GUID$
          }
        };
        modal?.close();
        this.as.openBlank(property, params);
      }
      // 不存在 打开新页签
      else {
        const callback = CommonEventUtil.buildCallBack(
          res.data,
          isSaveAs ? EventCallbacksActionName.SAVEAS : EventCallbacksActionName.UPDATE,
          EventCallbacksActionName.UPDATE
        );
        const instance = this.getRootPageService(event);
        this.updateTitle({
          router: this.router,
          modal,
          title: `【${this.translation.transform(res.data!.BOTITLE$!)}】${res.data!['FULLNAME$']}`,
          page: instance
        });
        // 刷新当前页面
        this.contentComCallback(event, callback);
      }
      this.setLoading(event, false);
    },
    error: res => {
      this.setLoading(event, false);
      if (!fn) {
        return;
      }
      fn(undefined, true);
    }
  });
}

