// form检入
formCheckIn(event: EventInterface): void {
  this.setLoading(event, true);
  const formCom = this.getContentCom<DppFormComponent>(event);
  const service = this.getContentCom<DppFormComponent>(event).getService();
  if (!formCom.onSubmit()) {
    this.dppMessageService.warning('common.operation.verificationFailed');
    this.setLoading(event, false);
    return;
  }
  const obj = service.getFormData<IFoundaton>();
  const objChanged = service.getFormChanceData<IFoundaton>();
  const object = {
    CLASSNAME$: obj.CLASSNAME$,
    GUID$: obj.GUID$,
    MASTERFK$: obj.MASTERFK$,
    CLASSIFICATIONGUID$: obj.CLASSIFICATION$ ? obj.CLASSIFICATION$ : '',
    UPDATETIME$: obj.UPDATETIME$! // 必传的参数
  };
  if (isEmpty(obj[FormFieldFileEnum.FILEPROPS])) {
    delete objChanged[FormFieldFileEnum.FILEPROPS];
    delete objChanged[FormFieldFileEnum.FILES];
    delete obj[FormFieldFileEnum.FILEPROPS];
    delete obj[FormFieldFileEnum.FILES];
  }
  // 判断对象是否变化
  if (!(Object.keys(objChanged).length === 0)) {
    Object.assign(object, objChanged);
    this.formSaveObjBefore(event, object, true);
  } else {
    this.formCheckInHandle(event, object);
  }
}

