/**
 * @description 项目所有的检入
 * @param event
 */
CheckIn(event: EventInterface): void {
  const contentComponent: IBaseContentComponent = this.getContentCom<IBaseContentComponent>(event);
  const type = contentComponent.type;

  if (type === 'form') {
    this.formCheckIn(event);
    return;
  }

  const data: IFoundaton = this.getRowData(event);

  const checkKey = 'ISCHECKOUT$';
  const classNameKey = 'CLASSNAME$';
  const key = 'GUID$';
  const updateTimeKey = 'UPDATETIME$';
  const checkInValue = 'Y';

  if (data[checkKey] !== checkInValue) {
    console.warn('检出数据的状态不对');
    return;
  }

  this.setLoading(event, true);

  const res$ = this.boas.checkObject(
    data[classNameKey]!,
    data[key]!,
    new Date(data[updateTimeKey] as string).getTime().toString(),
    CheckActiveEnum.CHECKIN
  );

  res$.subscribe({
    next: res => {
      if (res.success) {
        this.dppMessageService.success('basic.modalTip.checkInSucceed');
        (contentComponent as unknown as DppTableComponent).refreshData();
        this.setLoading(event, false);
      } else {
        this.dppMessageService.error(`${res.errorCode}:${res.errorMsg}`);
        this.setLoading(event, false);
      }
    },
    error: res => {
      this.setLoading(event, false);
    }
  });
}

