/**
 *
 * @param event
 * @use 项目全部检出
 * @constructor
 */
CheckOut(event: EventInterface): void {
  const contentComponent: IBaseContentComponent = this.getContentCom<IBaseContentComponent>(event);
  const type = contentComponent.type;
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  let data: IFoundaton = getData();

  const checkKey = 'ISCHECKOUT$';
  const key = 'GUID$';
  const checkValue = 'Y';
  const updateKey = 'UPDATETIME$';
  const classNameKey = 'CLASSNAME$';

  if (data[checkKey] === checkValue) {
    this.dppMessageService.warning('backend.business.dppMessageService.notCheckOut');
    return;
  }

  this.setLoading(event, true);
  const page = this.getRootPageService(event);
  const instanceData = page?.getInstanceData() || {};
  const res$ = this.boas.checkObject(data[classNameKey]!, data[key]!, data[updateKey]!, CheckActiveEnum.CHECKOUT);

  res$.subscribe({
    next: res => {
      if (!res.success) {
        this.dppMessageService.error(`${res.errorCode}:${res.errorMsg}`);
        return;
      }
      this.dppMessageService.success('basic.modalTip.checkOutSucceed');
      res.data = res.data || {};
      const data = { ...instanceData, ...res.data! };
      if (type === 'form') {
        page?.setInstanceData({
          data
        });
        formCheckOutHandle(data);
        // 更新rootpage数据源
        this.updateInstanceData(page, data);
      } else if (type === 'table') {
        tableFn(data);
      } else if (type === 'card') {
        cardFn(data);
      }
      this.setLoading(event, false);
    },
    error: res => {
      this.setLoading(event, false);
    }
  });

  function formCheckOutHandle(resData: IFoundaton): void {
    // 猜你想
    const instance = _this.getRootPageService(event);
    const bs = _this.getExeCom<DppButtonComponent>(event);
    const obj = { data: { ...data, ...resData }, bs: bs?.contentComFn, modal: bs?.dppRender?.model };
    if (bs.dppRender.isTextFlag) obj.modal.guess = 'GUESS';
    instance?.['handelGuessSendNotify']?.(obj, _this.commonService);

    // modal刷新
    const modal = CommonEventUtil.getModal(event);
    _this.updateTitle({
      router: _this.router,
      modal,
      title: `【${_this.translation.transform(resData!.BOTITLE$!)}】${resData!['FULLNAME$']}`,
      page: instance
    });

    // form刷新
    const callBackData = CommonEventUtil.buildCallBack(
      resData,
      EventCallbacksActionName.UPDATE,
      EventCallbacksActionName.UPDATE
    );
    _this.contentComCallback(event, callBackData);
  }
  function tableFn(res: NzSafeAny): void {
    (contentComponent as unknown as DppTableComponent).refreshData();
  }
  function cardFn(res: NzSafeAny): void {
    (contentComponent as unknown as DppCardComponent).refreshData();
  }
  function getData(): IFoundaton {
    if (type === 'form') {
      return (contentComponent as DppFormComponent).getFormData();
    } else {
      return _this.getRowData(event);
    }
  }
}

// 取消檢出
CancekCheckOut(event: EventInterface): void {
  const bs = this.getExeCom<DppButtonComponent>(event);
  let data = this.getRowData(event);
  const type = this.getContentCom<IBaseContentComponent>(event).type;

  const checkKey = 'ISCHECKOUT$';
  const classNameKey = 'CLASSNAME$';
  const key = 'GUID$';
  const updateTimeKey = 'UPDATETIME$';

  if (data[checkKey] !== 'Y') {
    this.dppMessageService.warning('backend.business.message.statusErr', {
      args: data[SystemClassFieldEnum.FULLNAME]
    });
    return;
  }

  this.setLoading(event, true);

  const res$ = this.boas.checkObject(
    data[classNameKey],
    data[key],
    new Date(data[updateTimeKey]).getTime().toString(),
    CheckActiveEnum.CANCELCHECKOUT
  );

  res$.subscribe({
    next: res => {
      if (res.success) {
        this.dppMessageService.success(`common.operation.operationSuccess`);

        if (type === 'form') {
          const callBackData = CommonEventUtil.buildCallBack(
            res.data,
            EventCallbacksActionName.UPDATE,
            EventCallbacksActionName.UPDATE
          );
          const modal = CommonEventUtil.getModal(event);
          if (modal) {
            modal!.updateModalTitle!(
              `【${this.translation.transform(res.data!.BOTITLE$!)}】${res.data!['FULLNAME$']}`
            );
          }
          this.contentComCallback(event, callBackData);
          this.setLoading(event, false);
          this.getRootPageService(event)?.setInstanceData({
            data: res.data!
          });
          // 更新rootpage数据源
          this.updateInstanceData(this.getRootPageService(event), res.data!);
          return;
        }
        const table = this.getContentCom(event) as unknown as DppTableComponent;
        table.refreshData();
      }
      this.setLoading(event, false);
    },
    error: res => {
      this.setLoading(event, false);
    }
  });
}

