public workflowReleasedFn(getDataValue: workflowReleasedData, event: EventInterface): void {
  const page = this.getRootPageService(event);
  const rowData = page.getInstanceData() as any;
  const openPageModal = (formData: {
    CLASSGUID$: string;
    CLASSNAME$: string;
    GUID$: string;
    TEMPLATE: string;
    TEMPLATE$TITLE: string;
    DESCRIPTION: string;
    CREATEUSERNAME: string;
  }): void => {
    const button = this.getExeCom<DppButtonComponent>(event);
    const params: RouteUrlKeyParams = {
      model: button.getUiModel().action,
      data: formData,
    }
    const routeUi = this.routeService.getRouteUIByKey(button.getUiModel().action['route'])!
    const tranParams = DppTargetRouteUtil.parseUrlKey(params);
    const routePath = DppTargetRouteUtil.getRouteQueryString({ routeUi, tranParams })
    const property = {
      title: routePath,
      routePath
    };

    this.as.openBlank(property);
  };
  of(true)
    .pipe(
      // 打开启动流程弹框
      switchMap(i => {
        const params: IFormRender = {
          name: FormConfigModelEnum.STARTWFACTION,
          mParams: {
            mode: ModeTypeEnum.EDIT,
            isObject: false
          },
          data: {
            type: 'workFlowTemplate',
            classGuid: getDataValue.CLASSGUID$,
            className: getDataValue.CLASSNAME$,
            guid: getDataValue.GUID$,
            // NAME: rowData.FULLNAME$,
            DESCRIPTION: rowData.FULLNAME$
            // CREATEUSERNAME: getDataValue['CREATEUSER$NAME']
          }
        };
        return new Observable<{ button: ModalButtonOptions; formCpm: DppFormComponent; modal: DppNzModalRef }>(
          obser => {
            const startWorkflowParam: BuildModalParams<DppFormComponent> = {
              event,
              message: this.dppMessageService,
              cpmParams: {
                dppRender: params
              },
              footers: [
                {
                  label: 'common.button.cancel',
                  type: 'default',
                  onClick: (button, formCpm, model): void => {
                    model.close();
                    obser.complete();
                  }
                },
                {
                  label: 'common.button.confirm',
                  type: 'primary',
                  onClick: (button, formCpm, modal): void => {
                    if (formCpm.onSubmit()) {
                      obser.next({
                        button,
                        formCpm,
                        modal
                      });
                      // obser.complete();
                    }
                  }
                }
              ],
              content: DppFormComponent
            };
            CommonEventUtil.buildModal(startWorkflowParam);
          }
        );
      }),
      // 查询对象是否有未完成的流程
      switchMap(i => {
        const formData = i.formCpm.getFormData<{ TEMPLATE: string }>();
        i.button.loading = true;
        return this.workFlowService
          .getNotFinishedProcess(rowData.GUID$!, rowData.CLASSGUID$!, rowData.CLASSNAME$!, formData.TEMPLATE)
          .pipe(
            switchMap(t => {
              return new Observable<{ button: ModalButtonOptions; formCpm: DppFormComponent; modal: DppNzModalRef }>(
                observe => {
                  if (!t.data) {
                    observe.next(i);
                    // observe.complete();
                    return;
                  }
                  let contents = this.translation.transform('workflow.operation.existWoringWf');
                  const existWoringParam: BuildModalParams<string> = {
                    event,
                    message: this.dppMessageService,
                    cpmParams: {},
                    footers: [
                      {
                        label: 'common.button.cancel',
                        type: 'default',
                        onClick: (button, content, modal): void => {
                          i.modal.close();
                          modal.close();
                        }
                      },
                      {
                        label: 'common.button.confirm',
                        type: 'primary',
                        onClick: (button, content, modal): void => {
                          const fromInstance = t.data['FROMINSTANCE'];
                          const items = fromInstance?.split('$');
                          const params = {
                            CLASSGUID$: items?.[1],
                            CLASSNAME$: '',
                            GUID$: t.data['GUID'],
                            TEMPLATE: t.data['WFTEMPLATEGUID'],
                            TEMPLATE$TITLE: t.data['TEMPLATENAME'],
                            DESCRIPTION: t.data['DESCRIPTION'],
                            CREATEUSERNAME: rowData['CREATEUSER$NAME']
                          };
                          openPageModal.call(this, params);
                          i.modal.close();
                          modal.close();
                        }
                      }
                    ],
                    content: contents
                  };
                  CommonEventUtil.buildModal(existWoringParam).afterClose.subscribe(res => {
                    i.button.loading = false;
                  });
                  observe.complete();
                }
              );
            })
          );
      }),
      // 创建流程
      switchMap(i => {
        const formData = i.formCpm.getFormData<{ TEMPLATE: string; DESCRIPTION: string; TEMPLATE$TITLE: string }>();
        return this.workFlowService
          .createWorkflow(formData['TEMPLATE'], '', '', formData.DESCRIPTION, rowData.GUID$, rowData.CLASSGUID$)
          .pipe(
            tap(t => {
              if (!t.success) {
                i.button.loading = false;
                return;
              }
              i.modal.close();
              this.setLoading(event, false);
              this.dppMessageService.success('workflow.operation.createWfSuccess');

              const params = {
                CLASSGUID$: rowData.CLASSGUID$,
                CLASSNAME$: rowData.CLASSNAME$,
                GUID$: t.data['GUID'],
                TEMPLATE: formData['TEMPLATE'],
                TEMPLATE$TITLE: formData['TEMPLATE$TITLE'],
                DESCRIPTION: formData['DESCRIPTION'],
                CREATEUSERNAME: rowData['CREATEUSER$NAME']
              };
              openPageModal.call(this, params);
            }),
            catchError(err => {
              i.button.loading = false;
              return of();
            })
          );
      })
    )
    .subscribe();
}

// 批量检入 - 批量检出
batchCheckActiveObject(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const selectNodes = table.getCheckedNodes();

  if (selectNodes.length === 0) {
    this.dppMessageService.warning('basic.modalTip.SelectFiles');
    return;
  }
  const { key, classIDKey, updateTimeKey, typeKey } = useKey();

  // 批量检入检出
  const params = selectNodes.map((item): IBatchCheckParamter => {
    const origin = item.origin;
    return {
      CLASSGUID$: origin[classIDKey],
      GUID$: origin[key]!,
      DATATYPE: origin[typeKey],
      props: {
        UPDATETIME$: new Date(origin[updateTimeKey] as string).getTime().toString()
      }
    };
  });
  const action = this.getExeModel(event)['action'];
  const batchType = action['batchType'];

  this.setLoading(event, true);

  const res$ = this.boas.batchCheckActiveObject(params as IBatchCheckParamter[], batchType);
  res$.subscribe({
    next: res => {
      if (res.success) {
        if (res.data) {
          // 总数量 成功数量  失败数量
          const { successCnt, totalCnt, errorCnt } = res.data;
          if (successCnt === totalCnt) {
            this.dppMessageService.success('common.operation.operationSuccess');
          } else {
            this.errMessageService.showMessage(event, res);
          }
          //全部检入失败， 不需要刷新表格
          if (totalCnt !== errorCnt) {
            table.refreshData();
          }
        }
      }
      this.setLoading(event, false);
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

/**
 * @description 批量删除
 * @use 产品设计一级页面｜产品设计二级页面｜公共空间一级页面｜公共空间二级页面
 * @param event
 */
async sysBatchDeleteAction(event: EventInterface): Promise<void> {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const selectNodes = table.getCheckedNodes();
  const pageService = this.getRootPageService(event);
  const menu =
    CommonEventUtil.getPublicAndProductMenu(pageService) ||
    (pageService.getComFnMapByName(MenuNameEnum.PROCESS) as DppMenuComponent);
  if (selectNodes.length === 0) {
    this.dppMessageService.warning('basic.modalTip.SelectFiles');
    return;
  }

  this.setLoading(event, true);
  // 有dataType的是二级页面，且选项中有文件，需要调用menu的刷新方法
  const folderKey = 'DATATYPE';
  const folderValue = 'Folder';
  const idKey = 'GUID$';
  const classNameKey = 'CLASSGUID$';

  // 是否是一级页面
  const isTopPage = !(
    table.dppRender.mParams?.['name'] == 'sysProductDesignDetailTable' ||
    table.dppRender.mParams?.['name'] == 'sysPublicSpaceItemTable' ||
    table.dppRender.mParams?.['name'] == 'sysProcessManagementDetailTable'
  );
  // 选择的节点中是否有文件类型 针对二级页面
  let hasFolder = false;
  // 一级页面和二级页面的入参不同
  let handleFn: (item: RowNode) => NzSafeAny = isTopPage
    ? (item: RowNode) => {
      return {
        GUID: item.origin[idKey]
      };
    }
    : (item: RowNode) => {
      const { [idKey]: GUID$, [classNameKey]: CLASSGUID$, [folderKey]: DATATYPE } = item.origin;
      if (DATATYPE === folderValue) {
        hasFolder = true;
      }
      return { GUID$, CLASSGUID$, DATATYPE };
    };

  let params = selectNodes.map(handleFn);
  let res$ = isTopPage
    ? this.commonSpaceService.asyncBatchDeleteFolder(params)
    : this.commonSpaceService.asyncBatchDeleteObject(params);

  res$.subscribe(res => {
    if (res.success && res.data) {
      if (res.data?.successCnt && res.data?.successCnt === res.data?.totalCnt) {
        this.dppMessageService.success('common.operation.deleteSuccess');
      } else {
        this.errMessageService.showMessage(event, res);
      }
      if (res.data?.successCnt) {
        if (hasFolder) {
          menu.refresh();
        } else {
          table.refreshData();
        }
      }
      this.setLoading(event, false);
    }
  });
}

/**
 * @use 产品设计二级页面操作栏
 * @param event
 */
deleteObject(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const data = this.getRowData(event);

  const pageService = this.getRootPageService(event);
  const menu =
    CommonEventUtil.getPublicAndProductMenu(pageService) ||
    (pageService.getComFnMapByName(MenuNameEnum.PROCESS) as DppMenuComponent);
  const { typeKey, key, classIDKey } = useKey();

  const folderValue = 'Folder';

  // 文件夹与对象入参、接口、刷新方式均不同
  const isFolder = data[typeKey] === folderValue;

  const params = isFolder ? data[key] : { GUID$: data[key], CLASSGUID$: data[classIDKey] };
  const res$ = isFolder ? this.commonSpaceService.deleteFolder(params) : this.boas.deleteObject(params as ObjectGuid);

  this.setLoading(event, true);
  // @ts-ignore
  res$.subscribe(
    (res: { success: NzSafeAny }) => {
      if (res && res.success) {
        // 如果 res 不为空且成功
        if (isFolder) {
          // 处理文件夹
          menu.refresh();
        } else {
          table.refreshData(); // 刷新数据表
        }
        this.setLoading(event, false);
        this.dppMessageService.success('common.operation.deleteSuccess');
      }
    },
    () => {
      this.setLoading(event, false);
    }
  );
}

