/**
 * @description 批量移交检出
 * @use 产品设计二级页面操悬浮|公共空间二级页面悬浮
 * @param event
 */
batchMaterialTransferCheckOut(event: EventInterface): void {
  const datePipe = new DatePipe('zh-CN');
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const data = table.getCheckedNodes();

  const { checkOutUserKey, updateTimeKey, key, classIDKey, classNameKey, typeKey, ownerKey } = useKey();

  const params = {
    objects: data.map((item): ITransferParameter => {
      const origin = item.origin;
      return {
        CLASSGUID$: origin[classIDKey],
        CLASSNAME$: origin[classNameKey],
        title: item[classNameKey],
        GUID$: origin[key],
        DATATYPE: origin[typeKey],
        DEALBOM: 'Y',
        TOUSERGUID: origin[ownerKey],
        UPDATETIME$: /^-+$/.test(origin[updateTimeKey])
          ? origin[updateTimeKey]
          : datePipe.transform(origin[updateTimeKey], 'yyyy-MM-dd HH:mm:ss', 'GMT+8')!
      };
    })
  };

  const checkoutUserGUID = data[0]?.[checkOutUserKey] ? data[0][checkOutUserKey] : 'data[0]?.CHECKOUTUSER$';
  this.setLoading(event, true);

  // @ts-ignore
  const that = this;

  const [modalRef, afterClose] = this.as.createDialog(DialogTypeEnum.USER, checkoutUserGUID, {
    title: 'basic.common.command.checkOutTransferCommand',
    width: '600px',
    bodyStyle: { height: '350px' },
    closable: false,
    footer: [
      {
        label: 'common.button.cancel',
        type: 'default',
        onClick(userListComponent: UserListComponent) {
          that.setLoading(event, false);
          modalRef.close();
        }
      },
      {
        label: 'common.button.confirm',
        type: 'primary',
        onClick(userListComponent: UserListComponent) {
          const selectedData = userListComponent.getSelectedData() as ListNode;
          if (!selectedData) {
            that.dppMessageService.warning('common.modalTip.selectUser');
            return;
          }
          this.loading = true;

          params['objects'].forEach(obj => (obj.TOUSERGUID = selectedData.GUID!));
          that.boas.batchTransferCheckout(params['objects']).subscribe({
            next: res => {
              if (res.success && res.data) {
                // 总数量 成功数量  失败数量
                const { successCnt, totalCnt, errorCnt } = res.data;
                if (totalCnt === successCnt) {
                  that.dppMessageService.success('common.operation.operationSuccess');
                  modalRef.close();
                } else {
                  that.errMessageService.showMessage(event, res);
                }
                if (totalCnt !== errorCnt) {
                  table.refreshData();
                }
              }
              that.setLoading(event, false);
              this.loading = false;
            },
            error: err => {
              // 外面悬浮toolbar的状态
              that.setLoading(event, false);
              // 弹窗底部按钮的状态
              this.loading = false;
            }
          });
        }
      }
    ]
  });
  afterClose.subscribe(() => {
    this.setLoading(event, false);
  });
}

