// 移交检出
sysCheckOutTransferAction(event: EventInterface): void {
  const datas = this.getContentCom<IBaseContentComponent>(event);
  const getDataValue = this.getRowData(event);
  const bs = this.getExeCom(event) as DppButtonComponent;

  const chechkoutUserID = getDataValue['CHECKOUTUSER$'];
  const updateTime = getDataValue['UPDATETIME$'];
  const chechkoutUserName = getDataValue['CHECKOUTUSER$NAME'];

  this.as.createDialog(DialogTypeEnum.USER, chechkoutUserID, {
    title: 'basic.common.command.checkOutTransferCommand',
    width: '600px',
    bodyStyle: { height: '350px' },
    // defaultType: DialogTypeEnum.USER,
    onOk: (userListComponent: UserListComponent): void => {
      const datePipe = new DatePipe('zh-CN');
      const selectedData = userListComponent.getSelectedData() as ListNode;
      const formattedDate = datePipe.transform(updateTime, 'yyyy-MM-dd HH:mm:ss', 'GMT+8');

      // 如果用户没有修改所有者提示：检出者XXX未修改!
      if (chechkoutUserID === selectedData.GUID) {
        this.dppTranslateService
          .get('common.operation.checkoutUserNotChanged', { checkoutuser: chechkoutUserName })
          .subscribe(res => {
            this.dppMessageService.warning(res);
          });
        return;
      }
      this.boas
        .transferCheckout({
          GUID$: getDataValue['GUID$'],
          CLASSNAME$: getDataValue['CLASSNAME$'],
          CLASSGUID$: getDataValue['CLASSGUID$'],
          DATATYPE: getDataValue['DATATYPE'],
          TOUSERGUID: userListComponent ? selectedData.GUID : chechkoutUserID,
          UPDATETIME$: formattedDate!,
          DEALBOM: 'Y'
        })
        .subscribe({
          next: res => {
            if (res.success) {
              this.dppMessageService.success('common.operation.operationSuccess');
              if (datas.dppRender?.name === ModeNameEnum.SYSWORKBENCHMYTASKTABLE) {
                this.contentComCallback(event, {
                  operate: EventCallbacksActionName.REFRESH,
                  guidList: bs.dppRender.index,
                  params: res.data
                });
              } else {
                // 刷新当前form的数据
                const callBackData = CommonEventUtil.buildCallBack(
                  res.data,
                  EventCallbacksActionName.UPDATE,
                  EventCallbacksActionName.UPDATE
                );
                this.contentComCallback(event, callBackData);

                // 刷新当前界面data
                this.getRootPageService(event)?.setInstanceData({
                  data: res.data!
                });
              }
              this.setLoading(event, false);
            }
          }
        });
    }
  });
}

// 修改所有者
sysModOwnerAction(event: EventInterface): void {
  const bs = this.getExeCom<DppButtonComponent>(event);
  const data = this.getRowData(event);

  const ownerIDKey = 'OWNERUSER$';
  const ownerNameKey = 'OWNERUSER$NAME';
  const classNameKey = 'CLASSNAME$';
  const classIDKey = 'CLASSGUID$';
  const key = 'GUID$';
  const guidKey = 'GUID';

  const ownerID = data[ownerIDKey];
  const ownerName = data[ownerNameKey];
  const that = this;
  const modal = this.as.openModal(
    {
      title: 'basic.common.command.ModifyOwnerCommand',
      width: '600px',
      bodyStyle: { height: '350px' },
      uiType: 'userList',
      footer: [
        {
          label: '确定',
          type: 'primary',
          onClick(userListComponent: UserListComponent) {
            const datePipe = new DatePipe('zh-CN');
            const currentDate = datePipe.transform(new Date(), 'yyyy-MM-dd HH:mm:ss', 'GMT+8');

            const selectedNode = userListComponent.getSelectedData() as ListNode;
            // 如果用户没有修改所有者提示：所有者XXX未修改!
            if (ownerID === selectedNode[guidKey]) {
              that.dppTranslateService
                .get('common.operation.owneruserNotChanged', { owneruser: ownerName })
                .subscribe(res => {
                  that.dppMessageService.warning(res);
                });
              return;
            }

            const res$ = that.boas.changeOwner({
              GUID$: data[key],
              CLASSNAME$: data[classNameKey],
              CLASSGUID$: data[classIDKey],
              OWNERUSERGUID$: userListComponent ? selectedNode[guidKey] : ownerID,
              UPDATETIME$: currentDate!,
              DEALBOM: 'N'
            });
            this.loading = true;
            res$.subscribe({
              next: res => {
                if (res.success) {
                  that.dppMessageService.success('common.operation.operationSuccess');

                  const contentComponent = that.getContentCom<IBaseContentComponent>(event);
                  const type = contentComponent.type;

                  if (type === 'table' || type === 'card') {
                    contentComponent['refreshData']?.();
                    this.loading = false;
                    modal.close();
                    return;
                  }

                  // form刷新
                  const callBackData = CommonEventUtil.buildCallBack(
                    res.data,
                    EventCallbacksActionName.UPDATE,
                    EventCallbacksActionName.UPDATE
                  );
                  // 刷新当前form的数据
                  that.contentComCallback(event, callBackData);

                  // 刷新当前界面data
                  that.getRootPageService(event)?.setInstanceData({
                    data: res.data!
                  });
                }
                this.loading = false;
                modal.close();
              },
              error: err => {
                this.loading = false;
              }
            });
          }
        }
      ]
    },
    { key: ownerID }
  );
}

// 批量删除END2 维护产品结构
sysBatchRemoveEnd2Action(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const btn = this.getExeCom(event) as DppButtonComponent;
  const isRelation = btn.dppRender.model.action.isRelation;
  const templateName = table.queryCondition.params.get('templateName') as string;
  const selectNodes = table.getCheckedNodes();

  if (selectNodes.length === 0) {
    this.dppMessageService.warning('common.operation.noDataSelect');
    return;
  }
  const guid = table.dppRender['guid'];
  const className = table.dppRender['className'];
  const filterSelectNodes = selectNodes.filter(item => item.origin['ROWKEY']);
  if (!filterSelectNodes.length) {
    this.dppMessageService.warning('common.message.warning.notAllowRootNode');
    return;
  }

  // 只有同阶才能进行移除操作
  const isSameLevel =
    selectNodes.length > 0 && selectNodes.every(item => item['uiLevel'] === selectNodes[0]['uiLevel']);
  if (!isSameLevel) {
    this.dppMessageService.warning('common.operation.selectSameGrade');
    return;
  }

  this.setLoading(event, true);
  const relation = {
    end1: { guid, className },
    templateName,
    isBOM: templateName === 'BOM',
    structures: RelationUtil.buildStructures(
      ModifyEnum.DEL,
      filterSelectNodes.map(item => item.origin) as IFoundaton[]
    )
  };
  this.relationService.deleteRelation(relation, isRelation).subscribe({
    next: res => {
      if (res.success) {
        if (filterSelectNodes.length < selectNodes.length) {
          this.dppMessageService.success('common.message.success.filterRootNode');
        } else {
          this.dppMessageService.success('common.operation.removeSucceed');
        }
        table.deleteNode(filterSelectNodes);
        this.setLoading(event, false);
      }
    },
    error: e => {
      this.setLoading(event, false);
    }
  });
}

// 批量删除END2 相关对象
sysInstanceRelatedBatchDeleteAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const btn = this.getExeCom(event) as DppButtonComponent;
  const isRelation = btn.dppRender.model.action.isRelation;
  const templateName = table.queryCondition.params.get('templateName') as string;
  const selectNodes = table.getCheckedNodes();
  if (selectNodes.length === 0) {
    this.dppMessageService.warning('common.operation.noDataSelect');
    return;
  }
  const guid = table.dppRender['guid'];
  const className = table.dppRender['className'];

  const filterSelectNodes = selectNodes.filter(item => item.origin['ROWKEY']);
  if (!filterSelectNodes.length) {
    this.dppMessageService.warning('common.message.warning.notAllowRootNode');
    return;
  }
  this.setLoading(event, true);
  const relation = {
    end1: { guid, className },
    templateName,
    isBOM: templateName === 'BOM',
    structures: filterSelectNodes.map(item => {
      return {
        objectGuid: {
          guid: item.origin['ROWKEY']['GUID'],
          className: item.origin['ROWKEY']['CLASSNAME'],
          classGuid: item.origin['ROWKEY']['CLASSGUID']
        },
        end2: {
          guid: item.origin['GUID$'],
          className: item.origin['CLASSNAME$']
        }
      };
    })
  };
  const isBeUsed = table.dppRender.dParams?.['isBeUsed'];
  const isDeleteChild = isBeUsed && isBeUsed === 'N';
  let fromProcess: any = !!table.dppRender.dParams?.['fromProcess'];
  fromProcess = isDeleteChild ? fromProcess : undefined;
  this.relationService
    .deleteRelation(relation, String(isDeleteChild), fromProcess)
    .pipe(
      tap(res => {
        if (res.success && res.data) {
          const { successCnt, totalCnt } = res.data as any;
          if (successCnt === totalCnt) {
            this.dppMessageService.success('common.operation.removeSucceed');
          } else {
            this.errMessageService.showMessage(event, res as any);
          }
          this.contentComCallback(event, {
            operate: EventCallbacksActionName.REFRESH
          });
        }
      }),
      finalize(() => this.setLoading(event, false))
    )
    .subscribe();
}

/**
 * @description 树形结构表格删除关联关系
 * @use 工艺管理
 * @param event
 */
sysRemoveEnd2Action(event: EventInterface): void {
  let node = this.getNode(event) as RowNode;
  let table = this.getContentCom<DppTableComponent>(event);

  const className = table.modelManager.initParams['className'];
  const guid = table.modelManager.initParams['guid'];
  const templateName = table.queryCondition.params.get('templateName') as string;
  const isBOM = templateName === 'BOM';

  const params = createParams();
  if (!params) {
    return;
  }
  this.setLoading(event, true);
  this.relationService
    .deleteRelation(params as NzSafeAny)
    .pipe(finalize(() => this.setLoading(event, false)))
    .subscribe({
      next: res => {
        if (!res.data) return;
        if (res.success && res.data['successCnt'] === res.data['totalCnt']) {
          this.dppMessageService.success('common.operation.removeSucceed');
          table.deleteNode([node]);
          table.refreshData();
        } else {
          const errorMessage = res.data['details'][0]['message'];
          this.dppMessageService.error(errorMessage);
        }
      }
    });

  function createParams(): false | Record<string, unknown> {
    let end1 = {};
    let structures: Structure[] = [];
    const { classNameKey, treeKey, key, treeClassNameKey, classIDKey, treeFullNameKey, fullNameKey } = useKey();
    if (isBOM) {
      let parent = node.parentNode;
      if (!parent) return false;
      end1 = {
        guid: parent.origin[treeKey],
        className: parent.origin[treeClassNameKey]
      };
      structures = [
        {
          objectGuid: {
            guid: node.origin['ROWKEY']['GUID'],
            className: node.origin['ROWKEY']['CLASSNAME'],
            classGuid: node.origin['ROWKEY']['CLASSGUID']
          },
          end2: {
            guid: node.origin['END2$'],
            className: node.origin['END2$CLASSNAME']
          }
        }
      ];
    } else {
      end1 = {
        guid,
        className
      };
      structures = [
        {
          objectGuid: {
            guid: node.origin['ROWKEY']['GUID'],
            className: node.origin['ROWKEY']['CLASSNAME'],
            classGuid: node.origin['ROWKEY']['CLASSGUID']
          },
          end2: {
            guid: node.origin[key],
            className: node.origin[classNameKey]
          }
        }
      ];
    }
    return {
      end1,
      templateName,
      isBOM,
      structures
    };
  }
}

