// BOM编辑
sysBOMEditAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const node = this.getNode(event) as RowNode;
  const data = node.origin;
  const fromProcess = table.dppRender.dParams!['fromProcess'] === 'true' ? true : undefined;

  const param = {
    fromProcess,
    end1: [
      {
        guid: data['END2#GUID$'],
        className: data['END2#CLASSNAME$']
      }
    ]
  };
  this.setLoading(event, true);
  this.relationService
    .editBom(param)
    .pipe(finalize(() => this.setLoading(event, false)))
    .subscribe({
      next: res => {
        if (res.data!.errorCnt !== 0) {
          this.dppMessageService.error(res.data!.details[0].message);
          this.setLoading(event, false);
          return;
        }

        this.dppMessageService.success('common.operation.operationSuccess');
        this.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            details: res.data!.details.map(item => {
              return {
                result: item.result,
                data: {
                  PARENT: {
                    ...item.data,
                    GUID$: item.data['END2#GUID$']
                  }
                }
              };
            })
          })
          .subscribe();
      }
    });
}

// BOM编辑 =》 切换到instance BOM编辑tab页
sysEditBOMAction(event: EventInterface): void {
  const contentCom = this.getContentCom<IBaseContentComponent>(event);
  const itemValue = this.getRowData(event);
  // 未打开料时
  if (contentCom?.type === 'table' || contentCom?.type === 'card') {
    // eslint-disable-next-line @typescript-eslint/no-this-alias
    const _that = this;
    // 打开对象
    this.openObjectFn(event, itemValue, (modal: DppNzModalRef) => {
      // 通知刷新instance 到bom编辑页面
      const pageService = _that.getModalInnerPageService(modal);
      if (pageService?.['subjextPageObj']) {
        const panelName = Object.keys(pageService?.['subjextPageObj'])?.[0];
        _that.changePanel(event, {
          panelName,
          pageService,
          panelOpt: {
            optionType: 'jump',
            jumpTabName: 'sysInstanceBOMCommand'
          }
        });
      }
    });
  } else if (contentCom?.type === 'form') {
    const pageService = this.getUpPage(event);
    if (pageService?.['subjextPageObj']) {
      const panelName = Object.keys(pageService?.['subjextPageObj'])?.[0];
      this.changePanel(event, {
        panelName,
        panelOpt: {
          optionType: 'jump',
          jumpTabName: 'sysInstanceBOMCommand'
        }
      });
    }
  }
}

