// BOM取消编辑
sysBOMEditCancelAction(event: EventInterface): void {
  const node = this.getNode(event) as RowNode;
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const fromProcess = table.dppRender.dParams!['fromProcess'] === 'true' ? true : undefined;

  const data = node.origin;
  // listroot接口不带END2#   listBom接口带END2#
  const viewIdKey = data['END2#VIEWFK$'] ?? data['VIEWFK$'];
  const viewClassGuidKey = data['END2#VIEWFK$CLASSGUID'] ?? data['VIEWFK$CLASSGUID'];
  const param = {
    fromProcess,
    view: [
      {
        classGuid: viewClassGuidKey,
        guid: viewIdKey
      }
    ]
  };

  this.setLoading(event, true);
  this.relationService
    .cancelCheckBOMView(param)
    .pipe(finalize(() => this.setLoading(event, false)))
    .subscribe({
      next: res => {
        if (res.data!.errorCnt !== 0) {
          this.dppMessageService.error(res.data!.details[0].message);
          this.setLoading(event, false);
          return;
        }
        this.dppMessageService.success('common.operation.operationSuccess');
        this.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            details: res.data!.details.map(item => {
              return {
                result: item.result,
                data: {
                  PARENT: {
                    ...item.data,
                    GUID$: item.data['END2#GUID$'],
                    // 因为无值的字段后端不返回，所以这里还是需要加一些重置字段
                    'VIEW#CHECKOUTUSER$': undefined,
                    'VIEW#CHECKOUTUSER$FULLNAME$': undefined
                  }
                }
              };
            })
          })
          .subscribe();
        this.setLoading(event, false);
      }
    });
}

