/**
 * @description 黏贴
 * @use 产品设计二级页面
 * @param event
 */
sysPasteFolderAction(event: EventInterface): void {
  const pageService = this.getRootPageService(event);
  const menu = CommonEventUtil.getDesignLibraryMenuCom(pageService) as DppMenuComponent;
  const rowData = this.getRowData(event);
  const folders: string[] = [];
  let libraryFolderGuid = '';
  let isMultiple: boolean;
  let params: {
    libraryFolderGuid?: string;
    folders?: string[];
    targetFoldersGuid: string;
  };
  const copySet = this.authService.getClipBoardSet(clipBoardTypeEnum.FOLDER_TYPE); // FOLDER_TYPE
  const forderData = Array.from(copySet) as IBaseData[];
  if (forderData.length > 1) {
    forderData.forEach(item => {
      folders.push(item.GUID!);
    });
    isMultiple = true;
    params = {
      folders,
      targetFoldersGuid: rowData['GUID$']
    };
  } else {
    libraryFolderGuid = forderData[0]?.GUID!;
    isMultiple = false;
    params = {
      libraryFolderGuid,
      targetFoldersGuid: rowData['GUID$']
    };
  }
  if (!params.libraryFolderGuid && folders.length === 0) {
    this.dppMessageService.warning('common.operation.noDataCanPaste');
    return;
  }
  this.setLoading(event, true);
  this.productDesignService.stickupMenuItems(params, isMultiple).subscribe({
    next: res => {
      this.setLoading(event, false);
      if (isMultiple) {
        const response = res as DppResponse<IBatchData>;
        const { successCnt, totalCnt, errorCnt } = response.data!;
        if (successCnt && successCnt === totalCnt) {
          this.dppMessageService.success('common.operation.operationSuccess');
          menu?.refresh();
        } else {
          this.errMessageService.showMessage(event, response);
          if (totalCnt === errorCnt) return;
          menu?.refresh();
        }
      } else {
        if (res.success) {
          this.dppMessageService.success('common.operation.operationSuccess');
          menu?.refresh();
        }
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

// 新建关联关系
async sysNewRelatedAction(event: EventInterface): Promise<void> {
  const bs = this.getExeCom(event) as DppButtonComponent;
  const table = this.getContentCom<DppTableComponent>(event);
  const { className, guid, templateName } = CommonEventUtil.getTableMess(table);
  const action = bs.getUiModel().action!;
  if (isEmpty(templateName)) {
    return;
  }

  const page = this.getRootPageService(event);
  const end1 = page.getInstanceData();
  const template = table.dppRender['templateName'];
  const readyData = {
    className,
    guid,
    templateName,
    ...template
  };
  generateFieldMapping({
    mappingType: 'folder',
    fieldKey: 'COMMITFOLDER$',
    sourceData: end1,
    onValueUpdate: (key, value) => {
      readyData[key] = value;
    }
  });
  let data = readyData;
  let expression = '';
  this.setLoading(event, true);
  this.boas.getCadConfig().subscribe({
    next: res => {
      const configData = res.data! as CadConfig;

      // cad特殊处理
      if (template.TEMPLATENAME === TemplateNameEnum.ITEMRELATECAD) {
        const cadConfigHandleRes = this.publicEvent.cadConfigHandle({
          configData,
          formData: { NAME$: end1['NAME$'], ID$: end1['ID$'] },
          data: readyData
        });
        data = cadConfigHandleRes.data;
        expression = cadConfigHandleRes.expression;
      }

      const params: WizardRender = {
        name: action.name!,
        mParams: {
          mode: action.mode,
          isObject: action.isObject,
          expression,
          footerbar: action['footerbar']
        },
        dParams: configData,
        data,
        innerSend: {
          instanceData: end1 as Record<string, unknown>
        }
      };
      params['innerSend']!['configData'] = configData;
      const modal: DppNzModalRef = this.as.openModal(
        {
          title: bs.getUiModel().label,
          width: action.width,
          bodyStyle: { height: action.height! },
          closable: true,
          // bodyStyle: { height: '40vh' },
          // content: DppWizardComponent,
          uiType: UIModelTypeEnum.WIZARD,
          footer: 'noFooter',
          isInteractive: false,
          modalSelf: () => modal,
          triggerInstance: () => table
        },
        { dppRender: params }
      );
      this.setLoading(event, false);
    },
    error: err => this.setLoading(event, false)
  });
}

sysNewRelatedCompleteAction(event: EventInterface): void {
  const wizardCom = this.getContentCom<DppWizardComponent>(event);
  const table = wizardCom?.triggerInstance?.() as unknown as DppTableComponent;
  const { className, guid, templateName } = CommonEventUtil.getTableMess(table);

  if (isEmpty(templateName)) {
    return;
  }

  // const modal = wizardCom.modalSelf?.() as DppNzModalRef;
  // const newItemEvent = wizardCom.dppRender.mParams['newItemEvent'] as EventInterface;
  // const rowData = this.getRowData(newItemEvent);
  // const instance = this.getRootPageService(newItemEvent).getInstanceData();

  const saveObject$ = this.publicEvent.sysNewItemCompleteEcoAction(event, {
    openObject: false,
    refreshTable: false,
    isRepeat: false
  });

  saveObject$
    .pipe(
      catchError(err => {
        if (err.type === 'check') {
          return of(err.iFound);
        }
        return throwError(err);
      }),
      switchMap(iFound => {
        const relation = {
          end1: {
            className,
            guid
          },
          templateName,
          isBOM: false,
          structures: [
            {
              end2: {
                guid: iFound!['GUID$'],
                classGuid: iFound!['CLASSGUID$'],
                className: iFound!['CLASSNAME$']
              },
              props: {},
              modifyType: ModifyEnum.ADD
