          ]
        };
        const isAddChild = table.dppRender.dParams?.['isBeUsed'] === 'N';
        let fromProcess: boolean | undefined = !!(table.dppRender.dParams?.['fromProcess'] === 'true');
        fromProcess = isAddChild ? fromProcess : undefined;

        return this.relationService.batchOperateActive(relation, ModifyEnum.ADD, isAddChild, fromProcess);
