/**
 * 新建对象后的操作
 * @param {EventInterface} event
 * @param {IFormRender} render form入参
 * @param {(data?: IBaseData) => void} [callBack] 保存的回调 (不管成功与否都会回调，返回为空时，可能请求异常、也可能请求回来的数据就是空的)
 * @param {boolean} [isOpenAfterbuild] 新建后是否打开
 * @memberof ModifyInstanceEventService
 */
newObjectActionHandle(
  event: EventInterface,
  render: IFormRender,
  callBack?: (data?: IBaseData) => void,
  isOpenAfterbuilt?: boolean
): void {
  const bs = this.getExeCom(event) as DppButtonComponent;
  const action = bs.getUiModel().action!;
  const content = this.getContentCom<DppTableComponent>(event);
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  const modal = bs.as.openModal(
    {
      title: bs.getUiModel().label,
      width: action.width,
      bodyStyle: { height: action.height! },
      closeCallBack: () => { },
      content: DppFormComponent,
      footer: [
        {
          label: 'basic.common.command.previousStep',
          size: 'default',
          show: (formComponent: DppFormComponent) => {
            return formComponent.plugins?.get(FormPluginEnum.STEP)!?.stepTitles.length > 1;
          },
          disabled: (formComponent: DppFormComponent) => {
            return formComponent.plugins?.get(FormPluginEnum.STEP)!?.currentStepIndex === 0;
          },
          onClick: (formComponent: DppFormComponent) => {
            formComponent.plugins
              .get(FormPluginEnum.STEP)!
              .changeContent(formComponent.plugins?.get(FormPluginEnum.STEP)!?.currentStepIndex - 1);
          }
        },
        {
          label: 'basic.common.command.nextStep',
          size: 'default',
          show: (formComponent: DppFormComponent) => {
            return formComponent.plugins?.get(FormPluginEnum.STEP)!?.stepTitles.length > 1;
          },
          disabled: (formComponent: DppFormComponent) => {
            return (
              formComponent.plugins?.get(FormPluginEnum.STEP)!?.currentStepIndex + 1 >
              formComponent.plugins?.get(FormPluginEnum.STEP)!?.stepTitles.length - 1
            );
          },
          onClick: (formComponent: DppFormComponent) => {
            const index = formComponent.plugins?.get(FormPluginEnum.STEP)!?.currentStepIndex;
            formComponent.plugins
              .get(FormPluginEnum.STEP)!
              .changeContent(formComponent.plugins?.get(FormPluginEnum.STEP)!?.currentStepIndex + 1);
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          disabled: (formComponent: DppFormComponent) => {
            const stepFprmCpm = formComponent.plugins?.get(FormPluginEnum.STEP)!;
            const baseFields = stepFprmCpm?.stepUIMap?.get(stepFprmCpm.stepTitles[0])?.fields! || [];
            return baseFields.length === 1;
          },
          async onClick(formComponent: DppFormComponent) {
            this.loading = true;
            const isValid = formComponent.onSubmit();
            if (isValid) {
              const data = formComponent.getFormData<IFoundaton>();
              const repeatCheckFlag = await that.publicEvent.hasClassRepeatCheck(data, data => {
                const needsDelKeys = ['className', 'guid', 'templateName'];
                needsDelKeys.forEach(key => {
                  if (data[key]) {
                    delete data[key];
                  }
                });
              });
              if (!repeatCheckFlag) {
                return;
              }

              // publiSaveData.setData('publicSpaceNewObjec', modal);
              that.formSaveObj(event, formComponent.getFormData(), false, false, (data, isErr) => {
                this.loading = false;
                if (isErr) {
                  return;
                }
                if (isOpenAfterbuilt === true || isOpenAfterbuilt === undefined) {
                  that.openObjectFn(event, data, () => { }, { triggerInstance: render['triggerInstance'] });
                }
                if (callBack) {
                  callBack(data);
                } else {
                  // that.contentComCallback(event, {
                  //   action: EventCallbacksActionName.UPDATE,
                  //   operate: EventCallbacksActionName.ADDPARAMANDSEARCH,
                  //   guidList: [bs.dppRender.index],
                  //   params: data
                  // });
                  // const callBackData = CommonEventUtil.buildCallBack(
                  //   data,
                  //   undefined,
                  //   EventCallbacksActionName.REFRESH
                  // );
                  // // 刷新表格
                  // that.contentComCallback(event, callBackData);

                  if (content?.type === 'table') {
                    // 刷新表格
                    content.refreshData();
                  }
                }
                // 关闭当前弹窗(callBack关闭)
                modal?.close();
                if (content?.type === 'table') {
                  const pageService = that.getRootPageService(event);
                  const menu = CommonEventUtil.getPublicAndProductMenu(pageService);
                  menu?.refresh();
                }
              });
            } else {
              this.loading = false;
              that.dppTranslateService.get('basic.common.notice.verificationFailed').subscribe(res => {
                that.dppMessageService.info(res);
              });
            }
          }
        }
      ],
      triggerInstance: () => content
    },
    { dppRender: render }
  );
  // console.log(modal.componentInstance);
  // debugger;
}

// 相关附件添加
AddRelatedAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event) as DppTableComponent;
  const tableName = table.dppRender.name;
  const button = this.getExeCom(event) as unknown as DppButtonComponent;
  const isBeUsed = table.dppRender.dParams?.['isBeUsed'];
  const fromProcess = !!table.dppRender.dParams?.['fromProcess'];
  const { className, guid, templateName } = CommonEventUtil.getTableMess(table);
  let menuDataSourceUrl;
  let dataSourceUrl;
  if (isBeUsed === 'N') {
    menuDataSourceUrl = `/Common/IAdvSearchService/listMenuItemsForRelationChildAdd?END1$CLASSNAME$=${className}&END1$=${guid}`;
    dataSourceUrl = `/Common/IAdvSearchService/listItemsForRelationChildAdd?END1$CLASSNAME$=${className}&END1$=${guid}`;
  } else if (isBeUsed === 'Y') {
    menuDataSourceUrl = `/Common/IAdvSearchService/listMenuItemsForRelationParentAdd?END2$CLASSNAME$=${className}&END2$=${guid}`;
    dataSourceUrl = `/Common/IAdvSearchService/listItemsForRelationParentAdd?END2$CLASSNAME$=${className}&END2$=${guid}`;
  }
  let content: any;
  let name;
  content = DppGlobalSearchComponent;
  name = table.dppRender.name;
  // content = DppGlobalSearchComponent;
  // name = table.dppRender.name;
  const buttonModel: IButtonUiModel = this.getExeModel(event) as IButtonUiModel; // 不能从按钮里拿哦
  // const tableData = event.contentComFn()['data']; // 点击添加那一层的表格数据
  const tableData = table.getTreeNodes(); // 点击添加那一层的表格数据
  const that = this;
  const modal = this.as.openModal(
    {
      title: buttonModel.label,
      // width: '80vw',
      // height: '60vh',
      full: true,
      content,
      footer: [
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(ContentCom: DppGlobalSearchComponent) {
            this.loading = true;
            let selectData = ContentCom.table.getCheckedNodes()?.map(item => {
              return item.origin;
            }) as unknown as IFoundaton[];

            if (!selectData || selectData.length === 0) {
              that.dppMessageService.warning('common.operation.noDataSelected');
              this.loading = false;
              return;
            }

            const params = buildParams(selectData, isBeUsed === 'Y', fromProcess);

            addRelation(
              params,
              () => {
                this.loading = false;
              },
              () => {
                modal.close();
              }
            ).subscribe();
          }
        }
      ]
    },
    {
      dppRender: {
        name,
        dParams: {
          templateName,
          className,
          guid,
          isSearch: true
        },
        mParams: {
          name,
          // toolbar: 'searchToolbar',
          property: {
            submit: 'true',
            type: 'ui'
          },
          description: 'ItemManagerCommand',
          initShow: 'false',
          ui: 'search',
          type: 'ui',
          menuDataSource: `${menuDataSourceUrl}&relationTemplateNames=${templateName}`,
          dataSource: `${dataSourceUrl}&relationTemplateNames=${templateName}&isBeUsed=${table.dppRender.dParams?.['isBeUsed']}`,
          label: 'basic.common.command.ItemManagerCommand',
          modelType$: 'command',
          isRowCheckable: '$origin["HASAUTH"] === true || $origin["HASAUTH"] === undefined',
          initQuery: 'false'
        }
      }
    }
  );

  const buildParams = (
    selectData: IFoundaton[],
    beUsed: boolean,
    fromProcess?: boolean
  ): {
    params: any;
    fromProcess?: boolean;
    isAddChild?: boolean;
  } => {
    const param: Structure[] = [];

    selectData.forEach(selectedData => {
      const end2 = {
        guid: selectedData.GUID$,
        classGuid: selectedData.CLASSGUID$,
        className: selectedData.CLASSNAME$
      };
      param.push({
        end2: end2,
        props: {},
        modifyType: ModifyEnum.ADD
      });
    });
    const relation = {
      end1: {
        className,
        guid
      },
      templateName,
      isBOM: false,
      structures: param
    };
    const isBeUsed = table.dppRender.dParams?.['isBeUsed'];
    const isAddChild = isBeUsed && isBeUsed === 'N';
    return {
      params: relation,
      fromProcess: isBeUsed === 'N' ? fromProcess : undefined,
      isAddChild
    };
  };

  const addRelation = (
    params: { params: any; fromProcess?: boolean; isAddChild?: boolean },
    closeBtnLoading: () => void,
    closeModal: () => void
  ): Observable<any> => {
    const { params: relation, fromProcess, isAddChild } = params;
    return this.relationService.batchOperatebatchLinkActive(relation, isAddChild, fromProcess).pipe(
      tap(res => {
        if (res.success && res.data) {
          const { successCnt, totalCnt, errorCnt } = res.data;
          if (successCnt === totalCnt) {
            this.dppMessageService.success('common.operation.addRelatedSuccess');
            closeModal();
          } else {
            this.errMessageService.showMessage(event, res);
          }
          this.contentComCallback(event, {
            operate: EventCallbacksActionName.UPDATE
          });
        }
      }),
      finalize(() => {
        closeBtnLoading();
      })
    );
  };
}

