ProcessAddRelatedAction(event: EventInterface): void {
  const bs = this.getExeCom<DppButtonComponent>(event);
  const table = this.getContentCom<DppTableComponent>(event) as DppTableComponent;
  const tableName = table.dppRender.name!.replace(/(\w+)(Table)/g, '$1Search$2');
  const { className, guid, templateName } = CommonEventUtil.getTableMess(table);
  const buttonModel: IButtonUiModel = this.getExeModel(event) as IButtonUiModel; // 不能从按钮里拿哦
  const tableData = table.getTreeNodes(); // 点击添加那一层的表格数据
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  const modal = this.as.openModal(
    {
      title: buttonModel.label,
      uiType: 'search',
      full: true,
      // content: DppTableComponent,
      footer: [
        {
          label: 'basic.common.button.confirm',
          type: 'primary',
          onClick(globalSearch: DppGlobalSearchComponent) {
            this.loading = true;
            const checkNodes = globalSearch.table.getCheckedNodes();
