              that.dppMessageService.warning('common.operation.noDataSelected');
              this.loading = false;
              return;
            }
            this.loading = false;
            modal.close();
            addRelation(data);
          }
        }
      ]
    },
    {
      dppRender: {
        name: tableName,
        dParams: {
          templateName,
          className,
          guid
        },
        mParams: {
          name: tableName,
          // toolbar: 'searchToolbar',
