// 相关附件 粘贴
sysRelationPasteChildNodeAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const { className, guid, templateName } = CommonEventUtil.getTableMess(table);
  const tableData = table.getTreeNodes();
  // const tableData = event.contentComFn()['data']; // 点击添加那一层的表格数据
  const buttonModel: IButtonUiModel = this.getExeModel(event) as IButtonUiModel; // 不能从按钮里拿哦
  const bs = this.getExeCom(event) as DppButtonComponent;
  const toolbarDynamicParams = bs.dppRender.config?.toolbarDynamicParams;
  const isBeUsed = toolbarDynamicParams ? toolbarDynamicParams.isBeUsed || 'N' : 'N';
  const copySet = this.authUserService.getClipBoardSet(clipBoardTypeEnum.OBJECT_TYPE);

  if (!copySet || copySet.size === 0) {
    this.dppMessageService.warning('common.operation.noDataCanPaste');
    return;
  }

  this.setLoading(event, true);

  const param: Structure[] = [];

  copySet.forEach((selectedData: NzSafeAny) => {
    const end2 = {
      guid: selectedData.GUID,
      classGuid: selectedData.CLASSGUID
      // className: selectedData.CLASSNAME$
    };
    param.push({
      end2,
      props: {},
      modifyType: ModifyEnum.ADD
    });
  });
  const relation = {
    end1: {
      className,
      guid
    },
    templateName,
    isBOM: false,
    isBeUsed: isBeUsed === 'Y',
    structures: param
  };
  const isAddChild = table.dppRender.dParams?.['isBeUsed'] === 'N';
  let fromProcess: boolean | undefined = !!table.dppRender.dParams?.['fromProcess'];
  fromProcess = isAddChild ? fromProcess : undefined;
  this.relationService
    .batchOperateActive(relation, ModifyEnum.ADD, isAddChild, fromProcess)
    .pipe(
      tap(res => {
        if (res.success && res.data) {
          const { successCnt, totalCnt, errorCnt } = res.data;
          if (successCnt === totalCnt) {
            this.dppMessageService.success('common.operation.addRelatedSuccess');
          } else {
            this.errMessageService.showMessage(event, res);
          }
          this.contentComCallback(event, {
            operate: EventCallbacksActionName.UPDATE
          });
        }
      }),
      finalize(() => {
        this.setLoading(event, false);
      })
    )
    .subscribe();
}

/**关联图纸和 文档公共逻辑
 * @param {EventInterface} event
 * @param {string} title
 * @param {string} templateName
 * @memberof ModifyInstanceEventService
 */
private handelRelated(event: EventInterface, title: string, templateName: string, interfaceNames: string): void {
  const contentCom = this.getContentCom<IBaseContentComponent>(event);
  const rowData = this.getRowData(event);
  const className = rowData?.['CLASSNAME$'];
  const guid = rowData?.['GUID$'];

  const render: IRenderParameterNew<IUiModel> = {
    name: 'ItemManageSearchTable',
    mParams: {
      // toolbar: 'searchToolbar',
      dataSource: `/ItemManagement/IItemManagementService/listItems?relationTemplateNames=${templateName}&end1ClassName=${className}&end1Guid=${guid}`,
      menuDataSource: `/Common/IAdvSearchService/listMenuItemsForObjectSearch?interfaceNames=${interfaceNames}`,
      initShow: 'false'
    },
    dParams: {}
  };

  const modal = this.as.openModal(
    {
      title,
      width: '80vw',
      full: true,
      openModalCloseDrawer: false,
      uiType: 'search',
      onOk: (globalSearchComponent: DppGlobalSearchComponent) => {
        const nodes = globalSearchComponent.table.getCheckedNodes();
        if (!nodes?.length) {
          return;
        }
        const data = nodes.map(item => item?.origin) as IFoundaton[];
        const param: Structure[] = [];
        data.forEach(selectedData => {
          const end2 = {
            guid: selectedData.GUID$,
            classGuid: selectedData.CLASSGUID$,
            className: selectedData.CLASSNAME$
          };
          param.push({
            end2: end2,
            props: {},
            modifyType: ModifyEnum.ADD
          });
        });
        const relation = {
          end1: {
            className: rowData?.['CLASSNAME$'],
            classGuid: rowData?.['CLASSGUID$'],
            guid: rowData?.['GUID$']
          },
          templateName,
          isBOM: false,
          structures: param
        };
        this.relationService.batchOperateActive(relation, ModifyEnum.ADD).subscribe({
          next: res => {
            if (res.success) {
              this.dppMessageService.success('basic.modalTip.AddedAssociation');
              const pageService = this.getUpPage(event);
              let panelNameArr;
              if (contentCom.type === 'modal') {
                panelNameArr = pageService?.['subjextPageObj'];
              } else if (contentCom.type === 'form') {
                panelNameArr = pageService?.parentPageService?.['subjextPageObj'];
              }
              if (panelNameArr) {
                console.log(Object.keys(panelNameArr)?.[0]);
                this.changePanel(event, {
                  panelName: Object.keys(panelNameArr)?.[0],
                  panelOpt: {
                    optionType: 'jump',
                    jumpTabName: 'sysInstanceRelatedCommand'
                  }
                });
              }
            }
          }
        });
      },
      onCancel: () => {
        modal?.close();
      }
    },
    {
      dppRender: render
    }
  );
}

// 关联图纸
sysAddRelatedCadAction(event: EventInterface): void {
  const rowData = this.getRowData(event);
  let templateName = TemplateNameEnum.CADRELATECAD;
  if (rowData?.['OBJECTTYPE$'] === '3DCad') {
    templateName = TemplateNameEnum.CADRELATECAD;
  } else if (rowData?.['OBJECTTYPE$'] === 'Item') {
    templateName = TemplateNameEnum.ITEMRELATECAD;
  }
  this.relationService
    .listRelationTemName({ className: rowData?.['CLASSNAME$'], guid: rowData?.['GUID$'] })
    .pipe(
      map(response => {
        if (!response.success) {
          throw new Error('Failed to fetch relation template names');
        }
        const arrTempName = templateName.split(':');
        const filteredTemp = arrTempName.filter(item => response.data?.includes(item))?.join(':');
        if (!filteredTemp) {
          this.dppMessageService.warning('common.modalTip.NoTemplateFound');
          return null;
        }
        return filteredTemp;
      }),
      switchMap(filteredTemp => {
        if (!filteredTemp) {
          return of(null);
        }
        this.handelRelated(event, 'basic.common.command.AssociatedCAD', filteredTemp, ModelInterfaceEnum.ICAD);
        return of(null);
      }),
      catchError(err => {
        console.error(err);
        return of(null);
      })
    )
    .subscribe();
}

