// 生成BOM/CADToBOM[猜你想]
sysCreateBOMAction(event: EventInterface): void {
  let rowData = this.getRowData(event);
  const content = this.getContentCom(event) as DppFormComponent;
  const bs = this.getExeCom(event) as DppButtonComponent;
  const createBom = (): void => {
    this.relationService
      .cadToBOM(
        {
          // guid: rowData?.['GUID$'],
          // className: rowData?.['CLASSNAME$']
        },
        'BOM',
        true,
        rowData?.['CLASSNAME$'],
        rowData?.['GUID$']
      )
      .subscribe({
        next: res => {
          if (res.success && res.data) {
            this.dppMessageService.success(`common.operation.operationSuccess`);
            // 打开BOM关联的料
            if (res.data?.['GUID$']) {
              this.setLoading(event, false);
              const obj = {
                name: ' ',
                description: '生成BOM',
                action: {
                  route: '/instance',
                  ui: 'instance',
                  refresh: 'true',
                  titleExpression: 'item',
                  name: `class_${res.data?.CLASSNAME$}`,
                  type: ButtonFixedActionType.OPEN,
                  className: res.data?.['CLASSNAME$'],
                  classGuid: res.data?.['CLASSGUID$'],
                  guid: res.data?.['GUID$'],
                  mode: 'edit'
                },
                // label: 'basic.common.command.CreateBOM',
                modelType$: 'command'
              };
              this.as.invoke(res.data, obj);
            }
          }
          this.setLoading(event, false);
          loadingModal?.close();
        },
        error: err => {
          this.setLoading(event, false);
          loadingModal?.close();
        }
      });
  };

  this.setLoading(event, true);
  // 创建全局laoding
  const loadingModal = this.modal.create({
    nzContent: GlobalSpinComponent,
    nzWrapClassName: 'sysCreateBOMAction-modal',
    nzFooter: null,
    nzClosable: false,
    nzKeyboard: false,
    nzMask: false,
    nzCentered: true,
    nzMaskClosable: false,
    nzWidth: '100vw',
    nzBodyStyle: { height: 'calc(100vh)' }
  });
  this.relationService.getCadToBomPermission(rowData?.['CLASSNAME$'], rowData?.['GUID$']).subscribe({
    next: res => {
      if (res.data && res.success) {
        if (res.data?.CADTOBOM && (!res.data.CADTOBOM?.ENABLE || !res.data?.CADTOBOM?.VISIBLE)) {
          this.dppMessageService.warning('common.operation.noPermission');
          this.setLoading(event, false);
          loadingModal?.close();
          return;
        }
        if (res.data?.CADTOBOM && res.data?.CADTOBOM?.CONFIRM) {
          this.as.confirm('common.operation.confirm.cadToBOM.question', {
            title: '',
            footer: {
              nzOnOk: () => {
                createBom();
              },
              nzOnCancel: () => {
                this.setLoading(event, false);
                loadingModal?.close();
              }
            }
          });
        } else {
          createBom();
        }
      }
      // this.setLoading(event, false);
    },
    error: err => {
      this.setLoading(event, false);
      loadingModal?.close();
    }
  });
  return;
}

