/**初始化预览主文件
 * @memberof ModifyInstanceEventService
 */
initFilePreview(event: EventInterface, tableData: IFoundaton | string): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const { className, guid, templateName } = CommonEventUtil.getTableMess(table);
  const emptyTable = table.type === 'table' && table.getTreeNodes()?.length === 0;
  if (emptyTable || typeof tableData === 'string') {
    const fileGuid = emptyTable ? tableData['GUID'] : tableData;
    const upPage = this.getUpPage(event);
    const file = upPage.getChildPage<DppIframeComponent>('sysKKfilePreviewCommand');
    file?.browse({
      dParams: {
        className,
        guid,
        fileGuid
      }
    });
  }
}

