  if (guess) {
    table['modelManager'] = {
      modelProperty: { ...bs?.dppRender?.['model'] },
      initParams: { ...bs?.dppRender?.['config']?.data }
    } as DppTableModel;
  }
  const { className, guid, templateName } = CommonEventUtil.getTableMess(table);
  // 空表格 初始化预览主文件
  // function reFreshTable(tableData: IFoundaton): void {
  //   if (table.type === 'table' && table.getTreeNodes()?.length === 0) {
  //     const upPage = that.getUpPage(event);
  //     const file = upPage.getChildPage<DppIframeComponent>('sysKKfilePreviewCommand');
  //     file?.browse({
  //       dParams: {
  //         className,
  //         guid,
  //         fileGuid: tableData['GUID']
  //       }
  //     });
  //   }
  // }
  if (guess) {
    formData = this.getRowData(event);
  } else {
    let commandName = 'sysNewOutLeftInstanceDetailCommand';
    const objectType = rootInstance['OBJECTTYPE$'];
    if (objectType === 'ecr') {
      commandName = CommandConstant.ECRDetailCommand;
    } else if (objectType === 'ecn') {
      commandName = CommandConstant.ECNDetailCommand;
    }
    let formCom = this.formRootFindChild<DppFormComponent>(event, commandName);
    formData = formCom?.getFormData<IBaseData>() || {};
    if (bs?.model?.name == 'sysObjectFileUploadCommand' || bs?.model?.name == 'sysTaskObjectFileUploadCommand') {
      formData = bs.data;
    }
  }

  // if (formData['STATUS$'] === 'RLS' && !workAuth?.procRtGuid) {
  //   this.dppMessageService.warning('common.operation.rlsObjectNotOperation');
  //   this.setLoading(event, false);
  //   return;
  // }
  // // 未检出
  // if (
  //   formData[SystemClassFieldEnum.ISCHECKOUT] !== 'Y' &&
  //   bs?.model?.name !== 'sysObjectFileUploadCommand' &&
  //   bs?.model?.name !== 'sysTaskObjectFileUploadCommand' &&
  //   !workAuth?.procRtGuid
  // ) {
  //   this.dppMessageService.warning('backend.business.message.notCheckout');
  //   return;
  // }
  const action = bs.getUiModel().action!;
  const model = {};
  model[SystemClassFieldEnum.GUID] = formData[SystemClassFieldEnum.GUID];
  model[SystemClassFieldEnum.CLASSNAME] = formData[SystemClassFieldEnum.CLASSNAME];
  model[SystemClassFieldEnum.UPDATETIME] = DppFormUtil.convertToDate(formData[SystemClassFieldEnum.UPDATETIME])
    .getTime()
    .toString();
  // 传文件数据给form 方便form判断
  if (!guess) model[Form_Constant.INPUT_FILES_KEY] = table.getTreeNodes().map(i => i.origin);
  const params: IFormRender = {
    name: action.name, //'UploadFileForm',
    mParams: {
      mode: action.mode, //ModeTypeEnum.EDIT,
      isObject: action.isObject!
    },
    data: model
  };
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _that = this;
  const modal = bs.as.openModal(
    {
      title: bs.getUiModel().label,
      width: action.width,
      bodyStyle: { height: action.height! },
      closeCallBack: () => { },
      content: DppFormComponent,
      footer: [
        // {
        //   label: 'common.button.cancel',
        //   type: 'default',
        //   onClick: () => {
        //     modal.close();
        //   }
        // },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(data: DppFormComponent) {
            const object = data.getFormData<IBaseData>(); /* 获取form 上传文件列表数据 */
            this.loading = true;
            if (object['FILEPROPS$']?.length > 0) {
              if (modal) {
                modal.updateConfig({ nzClosable: false });
              }
              const formData = new FormData();
              const tranObj = object as IFoundaton & DppSafeAny;
              let isSingleFile = false;
              // 文件类型处理
              if (!isEmpty(tranObj.FILEPROPS$)) {
                if (!isEmpty(tranObj.DWFILES)) {
                  isSingleFile = tranObj.DWFILES.length === 1 ? true : false;
                  if (tranObj.DWFILES.length > 0) {
                    tranObj.DWFILES.forEach((file: any) => {
                      delete file.url;
                      formData.append(isSingleFile ? 'file' : 'files', file, file.name);
                    });
                  }
                } else {
                  formData.append('files', JSON.stringify([]));
                }

                // object处理
                formData.append('item', JSON.stringify({ CLASSNAME$: tranObj.CLASSNAME$, GUID$: tranObj.GUID$ }));

                const url = isSingleFile
                  ? DppUrlConfig.itemManagement.attachSingleFileToObject
                  : DppUrlConfig.itemManagement.attachFilesToObject;

                // const workAuth = page.getPageData() as WorkflowAuthority;
                // this.boas.saveObject(object, false, '', table.dppRender.dParams?.['fromProcess'], workAuth?.procRtGuid)
                _that.boas.attachFilesToObject(formData, url).subscribe({
                  next: res => {
                    if (res.success && res.data) {
                      this.loading = false;
                      if (modal) {
                        modal.updateConfig({ nzClosable: true });
                      }
                      const EventCallbacks = {
                        operate: EventCallbacksActionName.REFRESH
                      };
                      // 上传文件集合
                      if (res.data['FILERESULT']) {
                        const fileresult = res.data['FILERESULT'] as IBatchData;
                        if (fileresult.errorCnt !== 0) {
                          _that.dppMessageService.createTableMessage('warning', bs.getUiModel().label, fileresult);
                          if (fileresult.successCnt) _that.initFilePreview(event, res.data);
                        } else {
                          _that.dppMessageService.success('basic.modalTip.UploadSuccessful');
                          _that.initFilePreview(event, res.data);
                          rootPageService.refreshInstanceData();
                        }
                      } else {
                        _that.dppMessageService.success('basic.modalTip.UploadSuccessful');
                        _that.initFilePreview(event, res.data);
                        rootPageService.refreshInstanceData();
                      }
                      if (!guess) {
                        _that.contentComCallback(event, EventCallbacks);
                        _that.updateInstanceData(rootPageService, res.data);
                      }
                      const pageService = _that.getUpPage(event);
                      const content = pageService.getComFnMapByName('sysNewOutFileTableCommand') as DppTableComponent;
                      content?.refreshData();
                      modal?.close();
                    }
                    this.loading = false;
                  },
                  error: err => {
                    this.loading = false;
                    modal?.updateConfig({ nzClosable: true });
                  }
                });
              }
            } else {
              this.loading = false;
              _that.dppMessageService.warning('basic.modalTip.SelectFiles');
            }
          }
        }
      ]
    },
    { dppRender: params } // param  传给ui的form组件
  );
}

