/**
 * 版本回滚
 * @param event
 */
sysRollBackIterationAction(event: EventInterface): void {
  const form = this.getTrigger<DppFormComponent>(event);
  const triggerPageService = form.pageService;
  const drawer = this.getTriggerDrawer(event);
  this.setLoading(event, true);
  // const params = this.getSelectData(event) as IFoundaton[];
  let modal: DppNzModalRef | undefined = undefined;
  if (!judgeInstanceRoute(this.router)) {
    modal = form.dppRender['modalSelf']() as DppNzModalRef;
  }
  let rowData = this.getRowData(event);
  const object = {
    CLASSNAME$: rowData['CLASSNAME$'],
    GUID$: rowData['GUID$'],
    CLASSGUID$: rowData['CLASSGUID'],
    iterationId: rowData['ITERATIONID$'],
    autoCheckout: 'Y'
  };
  this.boas.rollBackIteration(object).subscribe({
    next: res => {
      if (res.success) {
        this.dppMessageService.success('common.operation.rollbackSuccess');
        // 抽屉关闭
        drawer?.close();
        const rootPage = triggerPageService?.getRootPageService();
        rootPage.refreshInstanceData({ isRefreshSelf: true });
        this.setLoading(event, false);
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

