/**
 * 批量重启队列
 * @param event
 */
batchRestartQueueAction(event: EventInterface): void {
  const tableComponent = this.getContentCom(event) as unknown as DppTableComponent;
  // let rowData = this.getSelectData(event) as IFoundaton[];
  const params = this.getSelectData(event) as IFoundaton[];
  let jobids: string[] = [];
  if (params) {
    params.forEach(item => {
      jobids.push(item?.['GUID'] as string);
    });
  }
  const object = {
    jobs: jobids
  };
  this.setLoading(event, true);
  this.queueService.reStartQueue(object, QueueTypeEnum.INTEGRATE).subscribe({
    next: res => {
      if (res.success) {
        this.setLoading(event, false);
        const { successCnt, totalCnt, errorCnt } = res.data!;
        if (successCnt && successCnt === totalCnt) {
          this.dppMessageService.success('common.operation.operationSuccess');
          tableComponent.refreshData();
        } else {
          this.errMessageService.showMessage(event, res);
          //全部失败， 不需要刷新表格
          if (totalCnt === errorCnt) return;
          tableComponent.refreshData();
        }
      }
    },
    error: error => {
      this.setLoading(event, false);
    }
  });
}

