 * @param event
 */
fileTransfer(event: EventInterface, title: string): void {
  const data = this.getRowData(event);
  const resData = this.getExeCom<DppButtonComponent>(event).remoteMoreData as { [key: string]: string[] };
  let guid: string[] = [];
  Object.keys(resData).forEach(key => {
    if (key === title) {
      const data = resData[key];
      if (data.length !== 0) {
        guid = data;
      }
    }
  });
  this.addTransfIntoQueue({
    GUID$: data['GUID$'],
    CLASSGUID$: data['CLASSGUID$'],
    transConfigGuids: guid
  });
}

