/**
 * 对象详情打开ECR/ECN
 * @param event
 */
sysOpenECRAction(event: EventInterface): void {
  const bs = this.getExeCom<DppButtonComponent>(event);
  const changeItem = this.getContentCom<DppFormComponent>(event).getFormData<IFoundaton>();
  // const changeItemModal = this.getContentCom<DppFormComponent>(event).dppRender[ActionKeyEnum.MODALSELF]();
  const action = { ...bs.getUiModel().action! };
  action['model'] = {};
  generateFieldMapping({
    mappingType: 'folder',
    fieldKey: 'COMMITFOLDER$',
    sourceData: changeItem,
    onValueUpdate: (key, value) => {
      action['model'][key] = value;
    }
  });

  // action[ActionKeyEnum.TRIGGERINSTANCE] = () => this.getContentCom(event);
  const ecrNewFormModal = CommonEventUtil.buildDefaultModal<DppFormComponent>(
    event,
    async (okButton, formCom) => {
      okButton.loading = true;
      const isValid = formCom.onSubmit();
      let ECR: IFoundaton;
      const formData = formCom.getFormData<IBaseData>();
      if (isValid) {
        /**
         * 1.创建ECR/ECN
         */
        {
          // if (formData['WFTEMPLATEGUID']) {
          //   formData['autoCreateProcess'] = 'Y';
          // }
          let isError = false;
          const res = await this.ecm
            .createMasterObject(formData)
            .toPromise()
            .catch(error => {
              isError = true;
            });
          if (isError) {
            okButton.loading = false;
            return;
          }
          // @ts-ignore
          if (res?.success && res?.data) {
            ECR = res?.data;
          } else {
            // @ts-ignore
            this.dppMessageService.warning(`${res?.errorCode}:${res?.errorMsg}`);
            return;
          }
        }
        /**
         * 2.关联对象到ECP/ECO
         */
        {
          const master = {
            classGuid: ECR[SystemClassFieldEnum.CLASSGUID]!,
            guid: ECR[SystemClassFieldEnum.GUID]!,
            procrtGuid: ECR['PROCESS'] ? ECR['PROCESS']['GUID']! : '',
            isBatch: formData['ISBATCH']
          };
          const itemList = [
            {
              CHANGEITEM: changeItem[SystemClassFieldEnum.GUID]!,
              CHANGEITEM$CLASS: changeItem[SystemClassFieldEnum.CLASSGUID]!,
              NAME$: ECR[SystemClassFieldEnum.NAME]!,
              CHANGEITEM$ID$: changeItem[SystemClassFieldEnum.ID]!,
              CHANGEITEM$NAME$: changeItem[SystemClassFieldEnum.NAME]!
            }
          ];
          this.ecm.createDetailObject(master, itemList).subscribe({
            next: res => {
              if (res.data?.totalCnt === res.data?.successCnt) {
                //关闭ECR的modal
                ecrNewFormModal.close();
                //关闭打开对象的modal
                // changeItemModal?.close();
                console.log('d', ECR);
                // 打开ECR详情页改为使用新页签打开
                this.as.openBlank({
                  routePath: `instance?className=${ECR.CLASSNAME$}&guid=${ECR.GUID$}`
                });
              } else {
                // 删除前面创建的ECR（包括ECR的流程）
                EcmEventUtil.deleteMaster(
                  event,
                  ECR,
                  this.ecm,
                  this.dppMessageService,
                  this.workFlowService,
                  this.boas,
                  false
                );
                okButton.loading = false;
                this.dppMessageService.createTableMessage('success', 'common.operation.newSuccess', res.data!);
              }
            },
            error: async err => {
              // 删除前面创建的ECR（包括ECR的流程）
              EcmEventUtil.deleteMaster(
                event,
                ECR,
                this.ecm,
                this.dppMessageService,
                this.workFlowService,
                this.boas,
                false
              );
              okButton.loading = false;
              // this.setLoading(event, false);
            }
          });
        }
      } else {
        okButton.loading = false;
      }
    },
    this.dppMessageService,
    undefined,
    true,
    action
  );
}

