/**
 * 保存对象
 * @param event
 * @returns Observable
 */
saveObjectOfObs(event: EventInterface): Observable<DppResponse<IFoundaton>> {
  const componet = this.getContentCom<DppFormComponent>(event);
  const obj = componet.getFormData<IFoundaton>();
  const objChanged = componet.getFormChanceData<IFoundaton>();
  const saveAsObj = componet.getService().saveAsObj;
  // this.setLoading(event, true);

  // componet.refreshLoading(true);
  if (obj[SystemClassFieldEnum.ISEDITABLE] !== 'Y' && obj.GUID) {
    this.dppMessageService.warning('common.operation.notEditable');
    // this.contentComCallback(event, {});
    this.setLoading(event, false);
    return of();
  }
  if (!componet.onSubmit()) {
    this.dppMessageService.create('warning', 'common.operation.verificationFailed');
    this.setLoading(event, false);
    return of();
  }

  const isChanged = componet.isChangedByData();
  // 判断对象是否变化
  if (!saveAsObj && !isChanged) {
    this.dppMessageService.create('warning', 'common.operation.unchanged');
    this.setLoading(event, false);
    return of();
  }
  const object = {
    CLASSNAME$: obj.CLASSNAME$,
    GUID$: obj.GUID$,
    MASTERFK$: obj.MASTERFK$,
    CLASSIFICATIONGUID$: obj.CLASSIFICATION$
    // UPDATETIME$: obj[SystemClassFieldEnum.UPDATETIME]
  };
  objChanged[SystemClassFieldEnum.UPDATETIME] = obj[SystemClassFieldEnum.UPDATETIME];
  // object['props'] = objChanged;
  // const isECOECP = object.CLASSNAME$?.includes('ECO') || object.CLASSNAME$?.includes('ECP') ? true : false;
  // if (isECOECP) {
  //   object['props'] = objChanged;
  //   return this.boas.saveObject(object, false, DppUrlConfig.itemManagement.saveObject);
  // } else {
  //   Object.assign(object, objChanged);
  //   return this.boas.saveObject(object, false, DppUrlConfig.itemManagement.saveObject);
  // }
  Object.assign(object, objChanged);
  return this.boas.saveObject(object);
}

async checkInObjectOfObs(event: EventInterface): Promise<Observable<DppResponse<IFoundaton>>> {
  const componet = this.getContentCom<DppFormComponent>(event);
  const obj = componet.getFormData<IFoundaton>();
  const objChanged = componet.getFormChanceData<IFoundaton>();
  // this.setLoading(event, true);

  // componet.refreshLoading(true);
  // if (obj[SystemClassFieldEnum.ISEDITABLE] !== 'Y' && obj.GUID) {
  //   this.dppMessageService.warning('common.operation.notEditable');
  //   // this.contentComCallback(event, {});
  //   this.setLoading(event, false);
  //   return of();
  // }
  if (!componet.onSubmit()) {
    this.dppMessageService.create('warning', 'common.operation.verificationFailed');
    this.setLoading(event, false);
    return of();
  }
  const isChanged = componet.isChangedByData();
  const object = {
    CLASSNAME$: obj.CLASSNAME$!,
    GUID$: obj.GUID$!,
    MASTERFK$: obj.MASTERFK$,
    CLASSIFICATIONGUID$: obj.CLASSIFICATION$,
    UPDATETIME$: obj[SystemClassFieldEnum.UPDATETIME]!
  };
  // 判断对象是否变化
  if (isChanged) {
    objChanged[SystemClassFieldEnum.UPDATETIME] = obj[SystemClassFieldEnum.UPDATETIME];
    Object.assign(object, objChanged);
    let isErr = false;
    const res = await this.boas
      .saveObject(object)
      .toPromise()
      .catch(err => {
        isErr = true;
      });
    if (isErr) {
      return of();
    }
    // @ts-ignore
    if (res?.success) {
      object.UPDATETIME$ = res.data?.UPDATETIME$!;
    }
  }
  return this.boas.checkObject(object.CLASSNAME$, object.GUID$, object.UPDATETIME$, CheckActiveEnum.CHECKIN);
}

