  const data = this.getRowData(event);

  const folderKey = 'DATATYPE';
  const folderValue = 'Folder';

  const isFileType = data[folderKey] === folderValue;
  if (isFileType) {
    this.commonPreview(event, data);
    return;
  }

  const guid = data['END2#GUID$'] || data['GUID$'];
  const className = data['END2#CLASSNAME$'] || data['CLASSNAME$'];
  this.commonService.getDefaultPreviewFile(className, guid).subscribe(
    res => {
      if (res.success && res.data) {
        if (
          res.data['FILETYPE'] === 'NEW_DI_3D' ||
          res.data['FILETYPE'] === 'NEW_DI_2D' ||
          res.data['FILETYPE'] === 'KK_FILE'
        ) {
          const modal = this.as.openModal(
