              dppRender: {
                dParams: {
                  className: className,
                  guid: guid,
                  classGuid: data['CLASSGUID$'],
                  ziqianHideBtn: 'remarkPanelPC',
                  hidebtnCfg: '#ico-Tagging',
                  autoOpenStruct: true
                }
              }
            }
          );
        } else {
          const preUrl = this.configService.getConfig().apiUrl;
          let imgUrl = '';
          if (data['PREVIEWPATH$']) {
            imgUrl = preUrl + data['PREVIEWPATH$'];
          } else {
            imgUrl = preUrl + data['THUMBNAIL$'];
          }
          this.nzImageService.preview([
            {
              src: imgUrl,
              alt: '',
              width: '300px',
              height: '300px'
            }
          ]);
        }
      }
    },
    err => { }
  );
}

