InsERPBatchGlobalSearchOptionAction(event: EventInterface): void {
  this.setLoading(event, true);
  // const page = this.getRootPageService(event);
  const table = this.getContentCom<DppTableComponent>(event);
  const condition = table.queryCondition.getRawValue();
  const batchRows = table.getCheckedNodes();
  let rowCheckedDatas = batchRows?.map(item => item?.['origin']);
  const itemList = rowCheckedDatas?.filter(item => item?.['OBJECTTYPE$'] != 'Item');
  if (itemList && itemList.length > 0) {
    // this.dppMessageService.error('common.operation.erpTempInfoTip');
    // this.setLoading(event, false);
    // return;
  }
  let classList: string[] = [];
  rowCheckedDatas?.forEach(ele => {
    if (ele['CLASSNAME$'] && !classList.includes(ele['CLASSNAME$'])) {
      classList.push(ele['CLASSNAME$']);
    }
  });
  this.erpIntegrationService.batchListERPTemplate({ classNameList: classList }).subscribe({
    next: res => {
      this.setLoading(event, false);
      if (res.success && res.data) {
        if (res.data?.length > 0) {
          openERPIntegrationModal(rowCheckedDatas, classList, condition, event);
