sysGlobalSearchBatchDeleteAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const checkedNodes = table.getCheckedNodeList();

  let params: IBatchCheckParamter[] = [];
  if (checkedNodes.length) {
    checkedNodes.forEach(item => {
      params.push({
        CLASSGUID$: item.origin['CLASSGUID$'],
        GUID$: item.origin['GUID$'],
        DATATYPE: item.origin['DATATYPE'],
        props: {
          UPDATETIME$: item.origin['UPDATETIME$']
        }
      });
    });
    this.boas.batchCheckActiveObject(params, CheckActiveEnum.DELETE).subscribe({
      next: res => {
        if (res.data && res.success) {
          // 总数量 成功数量  失败数量
          const { successCnt, totalCnt, errorCnt } = res.data;
          if (successCnt && successCnt === totalCnt) {
            this.dppMessageService.success('common.operation.deleteSuccess');
            table.refreshData();
          } else {
            this.errMessageService.showMessage(event, res);
            //全部失败， 不需要刷新表格
            if (totalCnt === errorCnt) return;
            table.refreshData();
          }
        }
      }
    });
  }
}

