        width: '480px',
        content: DppFormComponent,
        bodyStyle: { height: '430px', padding: '0 10px 0 0' },
        footer: [
          {
            label: 'common.button.cancel',
            type: 'default',
            onClick: (): void => {
              modal?.close();
            }
          },
          {
            label: 'common.button.confirm',
            type: 'primary',
            onClick(data: DppFormComponent) {
              // 内容组件
              const isValid = data.onSubmit();
              const formData = data.getFormData() as DppSafeAny;
              if (isValid) {
                data.setLoading(true);
                this.loading = true;
                const companiys = formData?.['COMPANIES'];
                let companiyList: string[] = [];
                companiys?.forEach((element: NzSafeAny) => {
                  if (element) {
                    companiyList.push(element?.['value']);
                  }
                });
                let rowDatas: Array<{
                  guid?: string;
                  className?: string;
                }> = [];
                rowCheckedDatas?.forEach(rowData => {
                  rowDatas.push({ guid: rowData?.['GUID$'], className: rowData?.['CLASSNAME$'] });
                });
                const params: {
                  templateGuid?: string;
                  queuePolicy?: string;
                  BOMTemplateName?: string;
                  objectGuidList: Array<{
                    guid?: string;
                    className?: string;
                  }>;
                  companyList?: string[];
                } = {
                  templateGuid: formData?.['INTEGRATIONTEMPLATE'],
                  queuePolicy: formData?.['QUEUEPOLICY'],
                  objectGuidList: rowDatas,
                  companyList: companiyList
                };
                that.erpIntegrationService
                  .checkRealTime({ templateGuid: formData?.['INTEGRATIONTEMPLATE'] })
                  .subscribe({
                    next: res => {
                      if (res.success) {
                        if (res.data) {
                          ERPIntegratedInfo.call(this, rowDatas, formData);
                        } else {
                          that.erpIntegrationService.createERPJob(params).subscribe({
                            next: res => {
                              if (res.success) {
                                modal.close();
                                that.dppMessageService.success('common.operation.operationSuccess');
                              }
                            },
                            error: () => {
                              data.setLoading(false);
                              this.loading = false;
                            }
                          });
                        }
                      }
                    }
                  });
              }
            }
          }
        ],
        canDrag: true
      },
      { dppRender: params }
    );
  };
  const ERPIntegratedInfo = (
    rowDatas: Array<{
      guid?: string;
      className?: string;
    }>,
    formData: NzSafeAny
  ): void => {
    this.erpIntegrationService
      .getERPTitle({
        templateGuid: formData?.['INTEGRATIONTEMPLATE']
      })
      .subscribe({
        next: res => {
          if (res.success) {
            const companiys = formData?.['COMPANIES'];
            let companiyList: string[] = [];
            companiys?.forEach((element: NzSafeAny) => {
              if (element) {
                companiyList.push(element?.['value']);
              }
            });
            const render: {
              templateGuid?: string;
              objectGuidList: Array<{
                guid?: string;
                className?: string;
              }>;
              companyList?: string[];
            } = {
              templateGuid: formData?.['INTEGRATIONTEMPLATE'],
              objectGuidList: rowDatas,
              companyList: companiyList
            };
            const params: NzSafeAny = {
              // name: 'sysERPIntegratedInfoTable',
              mParams: {
                dataSource: `${DppUrlConfig.ErpIntegration.listERPFoundationObject}?templateGuid=$templateGuid&objectGuidList=$objectGuidList&companyList=$companyList`
