// 主料辅料单元格保存事件
sysProcessCellSaveAction(event: CellSaveEvent): any {
  // @notice!!! 使用模型名称来判断哪里使用是否可以改为对应数据的某个参数更合理
  const table = event.beans.table;
  const modelName = table.modelManager.modelName;
  // 主料表格模型名称
  const mainModelName = 'sysProcessMainItemTable';
  // 辅料表格模型名称
  const secondaryModelName = 'sysSecondaryItemTable';

  const isMainTable = modelName === mainModelName;

  const data = event.data;
  const changedProps = event.editChancedRowData;
  const column = event.column;
  if (column.type === 'number') {
    const value = changedProps[column.key];
    changedProps[column.key] = value ? Number(value) : null;
  }
  let templateName = isMainTable ? 'AsmProcess-ZL' : 'AsmProcess-FL';

  const end1 = {
    guid: data['END1#GUID$'],
    className: data['END1#CLASSNAME$'],
    classGuid: data['END1#CLASSGUID$']
  };
  const end2 = {
    guid: data['END2#GUID$'],
    className: data['END2#CLASSNAME$'],
    classGuid: data['END2#CLASSGUID$']
  };
  const objectGuid = {
    guid: data['ROWKEY']['GUID'],
    className: data['ROWKEY']['CLASSNAME'],
    classGuid: data['ROWKEY']['CLASSGUID']
  };
  const relation = {
    end1,
    templateName,
    isBOM: false,
    structures: [
      {
        end2,
        objectGuid,
        props: {
          ...changedProps
        }
      }
    ]
  };
  return this.relationService.batchSaveRelation(relation);
}

