/**
 * bom导入
 * @param event
 */
sysBOMImportAction(event: EventInterface): void {
  const bs = this.getExeCom<DppButtonComponent>(event);
  const fileName = bs.getUiModel().action!['fileName'];
  const table = this.getContentCom<DppTableComponent>(event);
  const rootPageService = this.getRootPageService(event);
  let instanceData: IFoundaton = {};

  if (rootPageService) {
    instanceData = rootPageService.getInstanceData();
  } else {
    instanceData = table.dppRender!.dParams!['objectData'] || {};
  }

  const openModal = (): void => {
    const params: IRenderParameterNew<IUiModel> = {
      name: 'BomImportComponent',
      data: {
        fileName: fileName,
        instanceData
      }
    };
    const modal = this.as.openModal(
      {
        title: 'basic.common.command.sysBOMImportCommand',
        width: '50vw',
        centered: true,
        bodyStyle: { height: '380px', overflow: 'hidden' },
        modalSelf: () => modal,
        content: BomImportComponent,
        footer: []
      },
      { dppRender: params }
    ) as DppNzModalRef;
    modal.afterOpen.subscribe(res => {
      (modal.getContentComponent() as BomImportComponent).drawer = modal;
      (modal.getContentComponent() as BomImportComponent).tableCom = table;
    });
  };
  this.setLoading(event, true);
  const object$ = this.commonService.getObject1(instanceData.CLASSNAME$!, instanceData.GUID$!);
  object$
    .pipe(
      filter(res => {
        this.setLoading(event, false);
        const iFound = res.data!;
        const user = this.authUserService.getUser()!;
        if (iFound.ISCHECKOUT$ === 'Y' && user.guid !== iFound.CHECKOUTUSER$) {
          this.dppMessageService.warning('backend.business.message.isCheckedOut');
          return false;
        }
        return true;
      }),
      tap(() => {
        const uhasbom = instanceData?.['UHASBOM$NAME'];
        if (uhasbom && uhasbom == 'Y') {
          this.notificationService.PromptDialogNotification(
            'warning',
            'instance.operation.overlayBOMOrNot',
            '',
            (eventType, componentRef, notificationRef) => {
              if (eventType != 'close') {
                const messageId = notificationRef?.messageId;
                this.notificationService.remove(messageId);
                if (eventType == 'confirm') {
                  openModal.call(this);
                }
              }
            },
            true,
            {
              nzStyle: {
                marginTop: 'calc(50vh - 89px)'
              },
              nzDuration: 0,
              nzPlacement: 'top'
            }
          );
        } else {
          openModal.call(this);
        }
      })
    )
    .subscribe();
}

