downloadFile(file: any, fileName: string, isAll: boolean): void {
  const getFile$ = this.userWorkPlatformService.downloadAllFile;
  const param = `false/${file.fileGuid}`;
  file.loading = true;
  getFile$.call(this.userWorkPlatformService, param, isAll).subscribe({
    next: res => {
      if (window.navigator && window.navigator['msSaveOrOpenBlob']) {
        window.navigator['msSaveOrOpenBlob'](res.data!, fileName);
      } else {
        const url = window.URL.createObjectURL(res.data!);
        const a = document.createElement('a');
        a.href = url;
        a.download = fileName;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        window.URL.revokeObjectURL(url);
      }
      file.loading = false;
    },
    error: err => {
      file.loading = false;
    }
  });
}

