// 批量剪切
sysBomBatchCutAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const selectNodes = table.getCheckedNodes();

  // 批量剪切前，将单个剪切可能存在的情况清除
  const previousNode = Array.from(this.authService.getClipBoardSet(clipBoardTypeEnum.OBJECT_TYPE));
  localStorage.removeItem('isCut');
  previousNode.forEach(item => {
    let data = {
      parent: item['PARENTGUID'],
      child: item['OLDRELATION']
    };
    this.bomTableRefreshService
      .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
        table,
        details: [
          {
            result: 'SUCCESS',
            data: {
              PARENT: { GUID$: data.parent },
              CHILD: { cutStatus: '', isRefresh: false, GUID$: data.child }
            }
          }
        ]
      })
      .subscribe();
  });

  // 根节点不能进行剪切操作
  const isRootY = selectNodes.some(item => item.origin['ISROOT'] === 'Y');
  if (isRootY) {
    this.dppMessageService.warning('common.message.warning.notCutRootNode');
    return;
  }
  // 只有同父节点才能进行剪切操作
  const checkSameParent = (): boolean => {
    if (selectNodes.length === 0) return false;

    const firstParentId = selectNodes[0].parentNode?.id || null;

    for (let i = 1; i < selectNodes.length; i++) {
      const currentParentId = selectNodes[i].parentNode?.id || null;
      if (firstParentId !== currentParentId) {
        return false; // 立即返回，不继续检查
      }
    }

    return true;
  };

  if (!checkSameParent()) {
    this.dppMessageService.warning('common.operation.selectSameGrade');
    return;
  }
  // 画线
  selectNodes.map(node => {
    // node.setData({ ...node.origin, cutStatus: 'cutting', isRefresh: true });
    this.bomTableRefreshService
      .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
        table,
        details: [
          {
            result: 'SUCCESS',
            data: {
              PARENT: { GUID$: node.parentNode!.origin['END2#GUID$'] },
              CHILD: { cutStatus: 'cutting', isRefresh: true, GUID$: node.origin['GUID$'] }
            }
          }
        ]
      })
      .subscribe();
  });

  const params: Array<{
    PARENTGUID: string;
    GUID: string;
    CLASSGUID: string;
    CLASSNAME: string;
    FULLNAME: string;
    OLDRELATION: string;
    OLDRELATION$CLASSNAME: string;
  }> = [];
  selectNodes.forEach(item => {
    const data = item.origin;
    params.push({
      PARENTGUID: item.parentNode!.origin['END2#GUID$'],
      GUID: data['END2#GUID$'],
      CLASSGUID: data['END2#CLASSGUID$'],
      CLASSNAME: data['END2#CLASSNAME$'],
      FULLNAME: data['END2#FULLNAME$'],
      OLDRELATION: data['GUID$'],
      OLDRELATION$CLASSNAME: data['CLASSNAME$']
    });
  });
  localStorage.setItem(clipBoardTypeEnum.OBJECT_TYPE, JSON.stringify(params));
  localStorage.setItem('isCut', JSON.stringify(true));
  this.dppMessageService.success('common.operation.operationSuccess');
}

