sysBomCellSaveAction(event: CellSaveEvent): any {
  const table = event.contentComFn() as unknown as DppTableComponent;
  const data = event.data;
  const dParams = table.dppRender.dParams;
  const fromProcess = dParams!['fromProcess'] === 'true' ? true : undefined;
  const rowKey = data['ROWKEY'];
  const props = event.editChancedRowData;
  const object = {
    props,
    rowKey
  };
  return this.relationService.cellSave(object, fromProcess).pipe(
    map(res => {
      if (!res.success) {
        return {
          success: false
        };
      }
      if (res.data) {
        const child = res.data['CHILD'];
        const parent = res.data['PARENT'];

        this.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            shouldUpdateParent: true,
            details: [
              {
                result: 'SUCCESS',
                data: {
                  PARENT: parent,
                  // 更新是使用对象id进行匹配的
                  CHILD: { ...child }
                }
              }
            ]
          })
          .subscribe();
      }
      return {
        success: true
      };
    }),
    catchError(err => {
      return of({
        success: false
      });
    })
  );
}

