refreshChildTable(table: DppTableComponent, event: EventInterface): void {
  table.refreshData().subscribe({
    next: res => {
      // 如果是父表格的操作，选中父表格第一条，同步刷子表格；子表格操作不需要
      const tableName = table.dppRender?.name;
      const isParentOperate = tableName === 'sysIntegrateParentTable';
      if (res.length > 0 && isParentOperate) {
        table.setNodeSelected(0);
        const parentId = res[0].origin['JOBID'];
        // 找到子表格，调用refreshParams方法
        const page = this.getRootPageService(event);
        const childTable = page.getComFnMapByName<DppTableComponent>('sysIntegrateChildCommand');
        childTable?.refreshByParams({ parentId });
      }
    }
  });
}

