// 检入（外侧）
async OutCheckIn(event: EventInterface, config?: OutFormConfig): Promise<void> {
  const page = this.getRootPageService(event);
  const { baseForm, detailForm } = this.instanceTool.getInstanceDefaultBaseFormInfo(event, config);
  if (detailForm) {
    if (!detailForm.onSubmit()) {
      this.dppMessageService.warning('common.operation.verificationFailed');
      this.setLoading(event, false);
      return undefined;
    }
  }
  const data = await this.instanceTool.optionBeforeSave({
    event,
    baseForm,
    detailForm,
    dppMessageService: this.dppMessageService,
    publicEvent: this.publicEvent,
    boas: this.boas
  });
  if (!data) {
    return;
  }
  this.setLoading(event, true);
  // 再检入
  if (data.ISCHECKOUT$ === 'Y') {
    this.boas.checkObject(data.CLASSNAME$!, data.GUID$!, data.UPDATETIME$!, CheckActiveEnum.CHECKIN).subscribe({
      next: res => {
        if (res.success) {
          this.dppMessageService.success('basic.modalTip.checkInSucceed');
          this.instanceTool.refreshInstance(event, { ...config, rootPage: page });
          // 判断当前页签是否存在文件表格，存在就刷新
          const innerSend = detailForm!.dppRender.innerSend;
          if (innerSend && innerSend.getPageThis) {
            const currentPage = innerSend.getPageThis();
            const tableCpm = currentPage.getChildPage(CommandConstant.sysNewOutFileTableCommand) as DppTableComponent;
            //检出检出的时候需要更新文件表格top的toolbar和操作列的toolbar
            const newData = { ...(tableCpm?.dppRender.data || {}), ...res.data };
            tableCpm?.topToolbar.callback({ params: newData });
            if (tableCpm && tableCpm?.dppRender.innerSend) {
              tableCpm.dppRender.innerSend.instanceData = res.data as Record<string, unknown>;
            }
            tableCpm?.refreshData();
          }
          this.setLoading(event, false);

          config?.actionAfterFn?.();
        } else {
          this.setLoading(event, false);
        }
      },
      error: res => {
        // this.errorShow(bs, res);
        // this.outgoingCallback(bs, {});
        this.setLoading(event, false);
      }
    });
  }
}

