// 检出（外侧）
OutCheckOut(event: EventInterface, config?: OutFormConfig): void {
  const page = this.getRootPageService(event);
  const rowData = page.getInstanceData() as IFoundaton;
  let toolbar = page.toolbarRef() as DppToolbarComponent;
  const formCpm = this.getContentCom<DppFormComponent>(event);

  this.setLoading(event, true);
  // 检出
  if (rowData.ISCHECKOUT$ === 'N') {
    this.boas
      .checkObject(rowData.CLASSNAME$!, rowData.GUID$!, rowData.UPDATETIME$!, CheckActiveEnum.CHECKOUT)
      .subscribe({
        next: res => {
          if (res.success) {
            this.dppMessageService.success('common.operation.operationSuccess');
            if (res.data) {
              this.instanceTool.refreshInstance(event, { ...config, rootPage: page });
            }
            // 判断当前页签是否存在文件表格，存在就刷新
            const innerSend = formCpm.dppRender.innerSend;
            if (innerSend && innerSend.getPageThis) {
              const currentPage = innerSend.getPageThis();
              const tableCpm = currentPage.getChildPage(
                CommandConstant.sysNewOutFileTableCommand
              ) as DppTableComponent;
              //检出检出的时候需要更新文件表格top的toolbar和操作列的toolbar
              const newData = { ...(tableCpm?.dppRender.data || {}), ...res.data };
              tableCpm?.topToolbar.callback({ params: newData });
              if (tableCpm && tableCpm?.dppRender.innerSend) {
                tableCpm.dppRender.innerSend.instanceData = res.data as Record<string, unknown>;
              }
              tableCpm?.refreshData();
            }
          } else {
            this.dppMessageService.success(`${res.errorCode}:${res.errorMsg}`);
          }
          this.setLoading(event, false);
          toolbar.callback.call(toolbar, { params: res.data! });

          config?.actionAfterFn?.();
        },
        error: res => {
          this.setLoading(event, false);
        }
      });
  }
}

