// 保存（外侧）
async OutInstanceSaveAction(event: EventInterface, config?: OutFormConfig): Promise<void> {
  const page = this.getRootPageService(event);
  const defaultBaseFormName = config?.baseFormName || CommandConstant.DefaultNewBaseCommand;
  const defaultDetailFormName = config?.detailFormName || CommandConstant.DefaultNewDetailCommand;
  let baseForm = page?.getComFnMapByName<DppFormComponent>(defaultBaseFormName);
  let detailForm =
    page?.getComFnMapByName<DppFormComponent>(defaultDetailFormName) || this.getContentCom<DppFormComponent>(event);
  let data: IFoundaton = {};
  let dataIsChange = false;
  let obj: IFoundaton = {};
  if (baseForm) {
    const objChanged = baseForm.getFormChanceData<IFoundaton>();

    const isChanged = Object.keys(objChanged).length === 0 ? false : true;
    if (!dataIsChange && isChanged) {
      dataIsChange = isChanged;
    }

    if (dataIsChange) {
      // const file = {};
      // file[FormFieldFileEnum.FILEPROPS] = objChanged[FormFieldFileEnum.FILEPROPS];
      // file[FormFieldFileEnum.FILES] = objChanged[FormFieldFileEnum.FILES];
      // Object.assign(data, file);
    }
  }
  if (detailForm) {
    const saveAsObj = detailForm.getService().saveAsObj;
    // 验证失败
    if (!detailForm.onSubmit()) {
      this.dppMessageService.warning('common.operation.verificationFailed');
      this.setLoading(event, false);
      return;
    }

    const objChanged = detailForm.getFormChanceData<IFoundaton>();
    const isChanged = Object.keys(objChanged).length === 0 ? false : true;
    // 未发生改变
    if (!saveAsObj && !isChanged) {
      // this.dppMessageService.create('warning', 'common.operation.unchanged');
      this.contentComCallback(event, {});
      this.setLoading(event, false);
      return;
    }

    obj = detailForm.getFormData<IFoundaton>();
    const object = {
      CLASSNAME$: obj.CLASSNAME$,
      GUID$: obj.GUID$,
      MASTERFK$: obj.MASTERFK$,
      CLASSIFICATIONGUID$: obj.CLASSIFICATION$ ? obj.CLASSIFICATION$ : '',
      ISCHECKOUT$: obj.ISCHECKOUT$,
      UPDATETIME$: obj.UPDATETIME$! // 必传的参数
    };
    Object.assign(data, object);
    // 流程信息添加
    data['PROCRTGUID'] = obj['PROCRTGUID'];
    if (!dataIsChange && isChanged) {
      dataIsChange = isChanged;
    }
    if (saveAsObj) {
      Object.assign(data, obj);
    }
    if (dataIsChange) {
      Object.assign(data, objChanged);
      const file = {};
      file[FormFieldFileEnum.FILEPROPS] = objChanged[FormFieldFileEnum.FILEPROPS];
      file[FormFieldFileEnum.FILES] = objChanged[FormFieldFileEnum.FILES];
      Object.assign(data, file);
    }
  }
  if (!baseForm && !detailForm) {
    return;
  }
  const saveAsObj = detailForm!.getService().saveAsObj;
  // 未发生改变, 另存不判断是否变化
  if (!dataIsChange && !saveAsObj) {
    this.dppMessageService.create('warning', 'common.operation.unchanged');
    return;
  }

  let obs: Observable<DppResponse<IFoundaton>>;
  // 正常保存接口请求后处理
  const saveAfterHandle = (data: IFoundaton): void => {
    this.updateTitle({
      router: this.router,
      page,
      modal: CommonEventUtil.getModalByCom(detailForm!),
      title: `【${this.translation.transform(data!.BOTITLE$!)}】${data!['FULLNAME$']}`
    });
    const operateJudge = EventCallbacksActionName.UPDATE;
    const callBackData = {
      // operate: operateJudge,
      action: operateJudge,
      // guidList: [rowData.GUID$ as string],
      params: data
    };
    const upPage = this.getUpPage(event);
    // 刷新form
    baseForm?.callback(callBackData);
    this.updateInstanceData(page, data!);

    // 如果是流程打开的，刷新当前页
    if (detailForm?.dppRender.dParams?.fromProcess) {
      page.refreshInstanceData({
        isRefreshSelf: true
      });
    } else {
      detailForm?.callback(callBackData);
    }
    // 文件上传异常接口
    if (data!['FILERESULT']) {
      const fileresult = data!['FILERESULT'] as IBatchData;
      if (fileresult.errorCnt !== 0) {
        this.dppMessageService.createTableMessage('warning', 'common.command.sysFileUploadCommand', fileresult);
      } else {
        this.dppMessageService.success('basic.common.notice.successfullySaved');
      }
    } else {
      // debugger
      this.dppMessageService.success('basic.common.notice.successfullySaved');
    }
  };
  // 另存为-保存接口请求后处理
  const saveAsAfterHandle = (data: IFoundaton): void => {
    const modal = this.getTriggerModal(event);
    modal?.close();
    this.as?.openBlank(
      { routePath: '/instance' },
      {
        dppRender: {
          className: data?.CLASSNAME$,
          guid: data?.GUID$
        }
      }
    );
  };
  const obsFn = (saveAfterHandle: (data: IFoundaton) => void): void => {
    this.setLoading(event, true);
    obs
      .pipe(
        map(i => i.data!),
        switchMap(obj => {
          const bs = this.getExeCom<DppButtonComponent>(event);
          const action = bs.getUiModel().action;
          // 模型上控制自动检出
          if (action['IS_AUTO_CHECKOUT'] !== 'Y') {
            return of(obj);
          }
          const { CLASSNAME$, GUID$, UPDATETIME$ } = obj;
          return this.boas
            .checkObject(CLASSNAME$!, GUID$!, UPDATETIME$!, CheckActiveEnum.CHECKOUT, undefined, {
              interceptor: 'false'
            })
            .pipe(
              map(i => Object.assign(obj, i.data!)),
              catchError(error => {
                const errMsg = [
                  this.translation.transform('common.title.created'),
                  this.translation.transform(error.error.errorMessage)
                ].join(',');
                this.dppMessageService.error(errMsg);
                return of(obj);
              })
            );
        }),
        tap(obj => {
          saveAfterHandle.call(this, obj);
          this.setLoading(event, false);
        }),
        catchError(err => {
          this.setLoading(event, false);
          return throwError(err);
        })
      )
      .subscribe();
  };

  //另存的保存
  if (!isEmpty(saveAsObj) && !page) {
    if (saveAsObj!.hasBom) {
      // const modal = this.as.confirm('common.operation.confirm.saveAsBOM.question', {
      //   // title: deleteTitle,
      //   footer: {
      //     nzOnOk: () => {
      //       data['isContainBom'] = 'Y';
      //       data = FormEventUtil.saveAsObjectHandle(data, saveAsObj!, detailForm!);
      //       obs = this.boas.saveObject(data, true);
      //       obsFn(saveAsAfterHandle);
      //     },
      //     nzOnCancel: () => {
      //       data['isContainBom'] = 'N';
      //       data = FormEventUtil.saveAsObjectHandle(data, saveAsObj!, detailForm!);
      //       obs = this.boas.saveObject(data, true);
      //       obsFn(saveAsAfterHandle);
      //     }
      //   },
      //   title: ''
      // });
      const property: Property = {
        uiType: 'saveAsConfirm',
        width: '400px',
        height: '100px',
        closable: false,
        style: { top: '40%' }
      };
      const modal = this.as.openModal(
        {
          ...property,
          footer: [
            {
              label: 'common.button.cancel',
              type: 'default',
              onClick: (): void => {
                // data['isContainBom'] = 'N';
                // data['isContainPartReplace'] = 'N';
                // data = FormEventUtil.saveAsObjectHandle(data, saveAsObj!, detailForm!);
                // obs = this.boas.saveObject(data, true);
                // obsFn(saveAsAfterHandle);
                modal.close();
              }
            },
            {
              label: 'common.button.confirm',
              type: 'primary',
              onClick: async (Cpn: saveAsConfirmComponent) => {
                data['isContainBom'] = Cpn.isContainBom ? 'Y' : 'N';
                data['isContainPartReplace'] = Cpn.isContainPartReplace ? 'Y' : 'N';
                data = FormEventUtil.saveAsObjectHandle(data, saveAsObj!, detailForm!);

                const repeatCheckFlag = await this.publicEvent.hasClassRepeatCheck(obj);
                if (!repeatCheckFlag) {
                  return;
                }
                obs = this.boas.saveObject(data, true);
                obsFn(saveAsAfterHandle);
                modal.close();
              }
            }
          ]
        },
        { dppRender: { data } }
      );
      return;
    } else {
      data['isContainBom'] = 'N';
      data = FormEventUtil.saveAsObjectHandle(data, saveAsObj!, detailForm!);
      const repeatCheckFlag = await this.publicEvent.hasClassRepeatCheck(obj);
      if (!repeatCheckFlag) {
        return;
      }

      obs = this.boas.saveObject(data, true);
      obsFn(saveAsAfterHandle);
    }
  } else {
    const repeatCheckFlag = await this.publicEvent.hasClassRepeatCheck(obj);
    if (!repeatCheckFlag) {
      return;
    }

    obs = this.boas.saveObject(data);
    obsFn(saveAfterHandle);
  }
}

