// 取消检出（外侧）
OutCancekCheckOut(event: EventInterface, config?: OutFormConfig): void {
  const page = this.getRootPageService(event);
  let obj = page.getInstanceData();
  const formCpm = this.getContentCom<DppFormComponent>(event);

  const checkoutFn = () => {
    if (obj['ISCHECKOUT$'] === 'N') {
      this.dppMessageService.warning('backend.business.message.statusErr', {
        args: obj[SystemClassFieldEnum.FULLNAME]
      });
      return;
    }
    if (obj['ISCHECKOUT$'] === 'Y') {
      this.setLoading(event, true);
      this.boas
        .checkObject(
          obj['CLASSNAME$'],
          obj['GUID$'],
          new Date(obj['UPDATETIME$']).getTime().toString(),
          CheckActiveEnum.CANCELCHECKOUT
        )
        .subscribe({
          next: res => {
            if (res.success && res.data) {
              this.dppMessageService.success(`common.operation.operationSuccess`);
              // 由于接口针对无数据字段不返回;而form组件更新数据需要字段信息；为了避免这种刷新不起作用
              // 进沟通；取消检出修改为；直接刷新页面
              // window.location.reload();
              this.instanceTool.refreshInstance(event, { ...config, rootPage: page });
              // 判断当前页签是否存在文件表格，存在就刷新
              const innerSend = formCpm.dppRender.innerSend;
              if (innerSend && innerSend.getPageThis) {
                const currentPage = innerSend.getPageThis();
                const tableCpm = currentPage.getChildPage(
                  CommandConstant.sysNewOutFileTableCommand
                ) as DppTableComponent;
                tableCpm?.refreshData();
              }
              this.setLoading(event, false);
              config?.actionAfterFn?.();
            } else {
              this.setLoading(event, false);
            }
          },
          error: res => {
            this.setLoading(event, false);
          }
        });
    }
  };
  const objChanged = formCpm.getFormChanceData<IFoundaton>();
  const isChanged = Object.keys(objChanged).length;
  if (isChanged) {
    this.as.confirm('instance.operation.confirmCancelCheckOut', {
      title: 'instance.title.prompt',
      footer: {
        nzOnOk: () => {
          checkoutFn.call(this);
        },
        nzOnCancel: () => {
          this.setLoading(event, false);
        }
      }
    });
  } else {
    checkoutFn();
  }
}

