/** 文件转换
 * @param event
 */
private _fileTransfer(event: EventInterface): void {
  const page = this.getRootPageService(event);

  let data = page.getInstanceData();
  const exeCom = this.getExeCom<DppButtonComponent>(event);
  const resData = exeCom.remoteMoreData;
  let guid = '';
  Object.keys(resData).some(key => {
    const data = resData[key];
    if (data.length !== 0) {
      guid = data[0];
      return true;
    }
    return false;
  });
  this._addTransfIntoQueue({
    GUID$: data['GUID$'],
    CLASSGUID$: data['CLASSGUID$'],
    transConfigGuid: guid
  });
}

private _addTransfIntoQueue(params: { GUID$: string; CLASSGUID$: string; transConfigGuid: string }): void {
  this.boas.createTransformQueue(params).subscribe(res => {
    if (res.success) {
      this.dppMessageService.success('转换任务创建成功!');
    }
  });
}

