// 变更请求/变更通知（外侧）
OutSysOpenECRAction(event: EventInterface): void {
  const page = this.getRootPageService(event);
  const changeItem: IFoundaton = page.getInstanceData();
  const bs = this.getExeCom<DppButtonComponent>(event);
  const action = { ...bs.getUiModel().action! };
  const render = assembParams({ action });
  render.data = render.data || {};
  generateFieldMapping({
    mappingType: 'folder',
    fieldKey: 'COMMITFOLDER$',
    sourceData: changeItem,
    onValueUpdate: (key, value) => {
      render.data![key] = value;
    }
  });
  this.commonService
    .newObject(render.dParams!['CLASSNAME$'])
    .pipe(
      tap(res => {
        if (res.success) {
          render.data = { ...res.data, ...render.data };
          const ecrNewFormModal = CommonEventUtil.buildDefaultModal<DppFormComponent>(
            event,
            async (okButton, formCom) => {
              okButton.loading = true;
              const isValid = formCom.onSubmit();
              let ECR: IFoundaton;
              const formData = formCom.getFormData<IBaseData>();
              if (isValid) {
                /**
                 * 1.创建ECR/ECN
                 */
                {
                  // if (formData['WFTEMPLATEGUID']) {
                  //   formData['autoCreateProcess'] = 'Y';
                  // }
                  let isError = false;
                  const res = await this.ecm
                    .createMasterObject(formData)
                    .toPromise()
                    .catch(error => {
                      isError = true;
                    });
                  if (isError) {
                    okButton.loading = false;
                    return;
                  }
                  // @ts-ignore
                  if (res?.success && res?.data) {
                    ECR = res?.data;
                  } else {
                    // @ts-ignore
                    this.dppMessageService.warning(`${res?.errorCode}:${res?.errorMsg}`);
                    return;
                  }
                }
                /**
                 * 2.关联对象到ECP/ECO
                 */
                {
                  const master = {
