// 修订（外侧）
OutSysNewRevisionAction(event: EventInterface): void {
  const page = this.getRootPageService(event);

  let obj = page.getInstanceData();
  this.setLoading(event, true);
  this.boas
    .creaeRevision({
      CLASSNAME$: obj['CLASSNAME$']!,
      CLASSGUID$: obj['CLASSGUID$']!,
      GUID$: obj['GUID$']!,
      ISAUTOCHECKOUT$: 'Y'
    })
    .subscribe({
      next: res => {
        if (res.success && res.data) {
          if (res.data['ERROR']) {
            const error = res.data?.['ERROR'];
            this.dppMessageService.warning(`${error.code}:${error.dppMessageService}`);
          } else {
            this.dppMessageService.success('common.operation.reviseSuccess');
            // page.setInstanceData({ data: res.data });
            // this.instanceTool.refreshFormAndTool(event, res.data);
            // this.closeAction({ router: this.router, closeNow: true });
            //关闭页签
            // 浏览器兼容性问题:
            // 如果不使用延时,在执行 window.close() 后立即执行 openBlank() 打开新页签时,
            // 不同浏览器的行为会不一致:
            // - Chrome: 能够正常关闭当前页签,并在新页签中打开实例详情
            // - Firefox: 关闭当前页签,但新内容会在新窗口而非新页签中打开
            // 因此添加 setTimeout 延时,确保先完成关闭操作,再执行打开新页签的操作
            setTimeout(() => {
              window.close();
            });
            //打开新页签
            const dppRender = { className: res.data.CLASSNAME$, guid: res.data.GUID$ };
            this.as.openBlank({ routePath: '/instance' }, { dppRender });
          }
        } else {
          this.dppMessageService.warning(`${res.errorCode}:${res.errorMsg}`);
        }
        this.setLoading(event, false);
      },
      error: err => this.setLoading(event, false)
    });
}

