// 从iframe操作触发，操作table的选中
sysSelectList(event: EventInterface): void {
  if (this.flag) {
    return;
  }
  this.flag = true;

  const iframe = this.getExeCom(event) as DppIframeComponent;
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const type = iframe.dppRender.dParams?.className;
  let data: any = this.getRowData(event);
  let treeNode = table.getAllNodes();
  if (iframe['ZI_QI_AN']) {
    // 忽略大小写进行选中匹配
    treeNode = treeNode?.map(node => {
      node.origin['END2#FILENAME$'] = node.origin['END2#FILENAME$']?.toLowerCase();
      return node;
    });
    if (data) {
      const dataArr = data[0]?.split('/');
      data = [dataArr?.[dataArr.length - 1]];
      data[0] = this.cleanString(data[0], type);
    }
  }

  // 先全部取消选中
  table.setAllChecked(false);
  // table.setNodeExpandByLevel()
  const modifiedArray = !iframe['ZI_QI_AN'] ? this.removeHyphenAndAfterFromAll(data as string[]) : data;

  const foundNodes = this.findNodesByOriginInTreeArray(treeNode, modifiedArray);
  table.setNodeChecked(foundNodes);

  setTimeout(() => {
    this.flag = false;
  }, 100);
}

cleanString(str: string, type?: string): string {
  if (!type) return str; // 如果没有指定类型，直接返回原字符串

  const patterns = {
    InventorModel: /:\d+$/, // 匹配末尾的冒号和数字
    SolidWorksModel: /-\d+$/, // 匹配末尾的减号和数字
    CATIAModel: /\([^)]+\)$/, // 匹配末尾的括号及其内容
    SolidEdgeModel: /\.\w+:\d+$/, // 匹配末尾的点号、英文、冒号和数字
    UGNXModel: /; refset part$|; refset entire part$|\.\w+:\d+$/
  };

  const pattern = patterns[type];
  if (pattern && pattern.test(str)) {
    return str.replace(pattern, ''); // 去掉匹配的部分
  }

  return str; // 如果不匹配任何条件，返回原字符串
}

// 从table操作触发，操作iframe的选中
sysSelectChart(event: EventInterface): void {
  if (this.flag) {
    return;
  }
  this.flag = true;

  const table = this.getExeCom(event) as DppTableComponent;
  const iframe = this.getContentCom(event) as DppIframeComponent;
  const type = iframe.dppRender.dParams?.className;
  const data = this.getRowData(event) as any;

  let changeNodes: RowNode[] = data;

  let checked = changeNodes.length === 0 ? false : true;
  if (window['nd_viewCtrl']) {
    const treeIdBase = (window as any).nd_viewCtrl.getSelectList();
    window['nd_viewCtrl'].setSelectState(treeIdBase, false);

    if (!checked) {
      window['nd_viewCtrl'].setSelectState(treeIdBase, checked);
      setTimeout(() => {
        this.flag = false;
      }, 100);
      return;
    }
  }

  if (iframe['ZI_QI_AN']) {
    changeNodes = changeNodes?.map(node => {
      node.origin['END2#FILENAME$'] = node.origin['END2#FILENAME$']?.toLowerCase();
      return node;
    });
    const modelTree = iframe['ZI_QI_AN']['modelTree'];
    let selectNodes: any = [];
    changeNodes.forEach(node => {
      selectNodes.push(this.findSelectFullNames(node));
    });
    console.log(selectNodes);

    let finalArr: string[] = [];
    selectNodes = selectNodes.map((str: any) => {
      const replacedPath = this.replacePath(str, modelTree);
      const selectSplitParts = replacedPath.split('/');
      selectSplitParts.pop();
      const path = selectSplitParts.join('/');

      const splitParts = str.split('/');
      const previewPath = splitParts[splitParts.length - 2].toLowerCase();
      const fileNamePath = splitParts[splitParts.length - 1].toLowerCase();
      modelTree.map((item: any) => {
        let transPreviewPath = this.cleanString(item.name, type);
        if (transPreviewPath === previewPath) {
          item.children.map((child: any) => {
            let transChild = this.cleanString(child, type);
            if (transChild === fileNamePath) {
              // finalArr.push(child);
              finalArr.push(`${path}/${child}`);
            }
          });
        }
      });
      return replacedPath;
    });
    const finalResult = Array.from(new Set(finalArr));

    const viewerZQIframe = iframe['ZI_QI_AN']['viewerZQIframe']?.nativeElement as HTMLIFrameElement;
    const DATA = {
      type: 'viewer.outside.selection.select',
      data: {
        objects: finalResult
      }
    };
    viewerZQIframe?.contentWindow?.postMessage(DATA, iframe['ZI_QI_AN']?.['URL']);
    setTimeout(() => {
      this.flag = false;
    }, 100);
    return;
  }

  // ------新迪相关选中处理
  const extractedIDs = changeNodes.map(item => item.origin['END2#FILENAME$']);
  // 删掉.及之后的字符
  const operatedIDs = extractedIDs.map(item => {
    const index = item.indexOf('.');
    return index !== -1 ? item.substring(0, index) : item;
  });

  if ((window as any).nd_viewCtrl) {
    const getModelTreeBase = (window as any).nd_viewCtrl.getModelTreeBase();
    const finalArr: string[] = [];
    this.findIdsByNames(operatedIDs, getModelTreeBase, finalArr, type);
    window['nd_viewCtrl'].setSelectState(finalArr, checked);
    setTimeout(() => {
      this.flag = false;
    }, 100);
  }
}

//找到匹配的选中
private findNodesByOriginInTreeArray(treeArray: RowNode[], valuesToCheck: string[]): RowNode[] {
  const foundNodes: RowNode[] = [];

  // 遍历树数组
  for (const tree of treeArray) {
    const treeFoundNodes = this.findNodesByOrigin(tree, valuesToCheck);
    foundNodes.push(...treeFoundNodes); // 将当前树的匹配结果合并到主结果数组中
  }

  return foundNodes;
}

private findNodesByOrigin(tree: RowNode, valuesToCheck: string[]): RowNode[] {
  const foundNodes: RowNode[] = [];

  // 检查当前节点
  for (const value of valuesToCheck) {
    // const finalnode = tree.origin['END2#FILENAME$'].split('.')[0];
    const finalnode = tree.origin['END2#FILENAME$'].replace(/\.[^\.]+$/, '');

    // let lastIndex = finalnode.lastIndexOf('-');
    // let nodetrans = lastIndex !== -1 ? finalnode.substring(0, lastIndex) : finalnode;
    if (finalnode === value || (/\.[a-zA-Z]+$/.test(value) && tree.origin['END2#FILENAME$'] === value)) {
      foundNodes.push(tree);
      // 如果找到了一个匹配的节点，继续搜索，因为可能有多个匹配
    }
  }

  // 检查子节点
  if (tree.children) {
    for (const child of tree.children) {
      const childFoundNodes = this.findNodesByOrigin(child, valuesToCheck);
      foundNodes.push(...childFoundNodes); // 将子节点的匹配结果合并到主结果数组中
    }
  }

  return foundNodes;
}

private findIdsByNames(ids: string[], node: LightWrightChartTreeNode, result: string[] = [], type?: string): void {
  for (const id of ids) {
    // let lastIndex = node.name.lastIndexOf('-');
    // let nodetrans = lastIndex !== -1 ? node.name.substring(0, lastIndex) : node.name;
    // const finalnode = nodetrans.split('.')[0];
    const finalnode = this.cleanString(node.name, type);

    if (finalnode === id && !result.includes(node.objectid)) {
      result.push(node.objectid);
    }
    if (node.children) {
      for (const child of node.children) {
        this.findIdsByNames(ids, child, result, type);
      }
    }
  }
}

// 删掉最后一个-及之后的字符
private removeHyphenAndAfterFromAll(arr: string[]): any[] {
  for (let i = 0; i < arr.length; i++) {
    let str = arr[i];
    const index = str.lastIndexOf('-');
    if (index !== -1) {
      arr[i] = str.substring(0, index);
    }
  }
  return arr;
}

// -----------子虔获取选中数据的完整路径----------
findSelectFullNames(node: RowNode): string {
  if (!node?.origin?.['END2#FILENAME$']) {
    return '';
  }
  let findFullName = node.origin['END2#FILENAME$'].replace(/\.[^/.]+$/, '');

  if (!node?.parentNode?.origin?.['END2#FILENAME$']) {
    // findFullName = node.origin['END2#FILENAME$'];
    return `${node.origin['END2#FILENAME$']}/${findFullName}`;
  }

  const parentValue = this.findSelectFullNames(node.parentNode);
  return `${parentValue}/${findFullName}`;
}

findFullName(name: string, tree: any): string {
  for (const node of tree.slice(1)) {
    // 从下标 1 开始遍历
    // if (node.name.includes(name)) {
    //   return node.name; // 返回完整路径名称
    // }
    if (node.name.toLowerCase().includes(name.toLowerCase())) {
      return node.name; // 返回完整路径名称
    }
  }
  return name;
}

replacePath(path: string, tree: any): string {
  // 按照 `/` 分割路径
  const parts = path.split('/');

  // 替换路径中的每一部分
  const replacedParts = parts.map((part: string, inx: number) => {
    if (inx) {
      return this.findFullName(part, tree);
    } else {
      return tree[0]?.name;
    }
  });

  // 返回替换后的路径
  return replacedParts.join('/');
}

