  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const menu = this.getExeCom(event) as DppMenuComponent;
  const selectNode = menu.getSelectedData()?.data;
  const params = {};
  paramsKeysArr.forEach(key => {
    if (key) {
      if (key.includes(':')) {
        const keyArr = key.split(':');
        params[keyArr[0]] = selectNode[keyArr[1]];
      } else {
        params[key] = selectNode[key];
      }
    }
  });
  table.refreshByParams(params);
}

