/**
 * @description 新建
 * @use 工艺管理二级页面
 * @param event
 */
sysProcessManageNewObjectAction(event: EventInterface): void {
  const exeModel = this.getExeModel(event);
  const rootPage = this.getRootPageService(event);
  const menuCom = CommonEventUtil.getDesignLibraryMenuCom(rootPage) as DppMenuComponent;
  const action = exeModel?.['action'];
  const choiceMenuObj = menuCom?.getSelectedData()?.data;

  const params: IFormRender = {
    name: action.name,
    mParams: {
      mode: action.mode,
      initValue: `withMainFile=Y`,
      isObject: action.isObject,
      dynaControl: `CLASSNAME$:editable=${action['className'] ? false : true}`
    },
    data: {
      CLASSNAME$: action['className'],
      // folderDataSoure: url,
      libraryType: 'PROCESS'
    }
  };

  generateFieldMapping({
    mappingType: 'folder',
    fieldKey: 'COMMITFOLDER$',
    sourceData: choiceMenuObj['origin'],
    onValueUpdate: (key, value) => {
      params.data![key] = value;
    },
    isMapToObject: false
  });
  if (action['dynaControl']) {
    params.mParams!.dynaControl += `;${action['dynaControl']}`;
  }
  PubSpaceEventUtil.stepFormHandle(event, params, {
    okFn: (button, formCpm, modal) => {
      const isValid = formCpm.onSubmit();
      if (!isValid) {
        return;
      }
      const data = formCpm.getFormData<IFoundaton>();
      let obss: Observable<
        Array<{
          type: string;
          res: DppResponse<IFoundaton>;
        }>
      >;
      const request1 = this.boas.saveObject(data).pipe(
        map(i => {
          return {
            type: 'save',
            res: i
          };
        })
      );
      if (data.ISAUTOCHECKOUT$ === 'Y') {
        const request2 = request1.pipe(
          switchMap(saveResult => {
            const { CLASSNAME$, GUID$, UPDATETIME$ } = saveResult.res.data!;
            return this.boas
              .checkObject(CLASSNAME$!, GUID$!, UPDATETIME$!, CheckActiveEnum.CHECKOUT, undefined, {
                interceptor: 'false'
              })
              .pipe(
                map(checkResult => ({
                  type: 'check',
                  res: checkResult
                })),
                catchError(i => {
                  return throwError({
                    type: 'check',
                    res: i
                  });
                })
              );
          })
        );
        data.ISAUTOCHECKOUT$ = 'N';
        obss = forkJoin([request2]);
      } else {
        obss = forkJoin([request1]);
      }
      button.loading = true;
      obss.subscribe({
        next: resp => {
          this.getContentCom<DppTableComponent>(event).refreshData();
          modal.close();
          this.modify.openObjectFn(event, resp[0].res.data, () => {}, {});
        },
        error: errRes => {
          button.loading = false;
          if (errRes.type && errRes.type === 'check') {
            const errMsg1 = this.tranPipe.transform('common.title.created');
            const errMsg2 = this.tranPipe.transform(errRes.res?.error?.errorMessage);
            this.dppMessageService.error(`${errMsg1},${errMsg2}`);
            // this.getContentCom<DppTableComponent>(event)?.refreshData();
            // modal?.close();
          }
        }
      });
    }
  });
}

