  const instanceData = toolbar.dppRender.innerSend?.instanceData;
  const operatingStation = pageService.getComFnMapByName('sysOperatingStationCommand') as FlowChartComponent;
  const render = {
    name: 'sysOperatingStationAddTable',
    mParams: {
      isRowCheckable: `$origin['HASAUTH'] == false ? false : true`,
      toolbar: 'sysOperatingStationAddToolBar',
      dataSource: '/Common/ICommonService/listObject?className=$className&isIndexQuery=$isIndexQuery'
    },
    dParams: {
      className: 'OperationStation',
      isIndexQuery: 'N'
    }
  };
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  const modal = this.as.openModal(
    {
      title: 'process.operation.selectOperatingStation',
      width: '80vw',
      height: '600px',
      content: DppTableComponent,
      footer: [
        {
          label: 'common.button.cancel',
