          type: 'primary',
          onClick(data) {
            // 内容组件
            this.loading = true;
            const table = data as DppTableComponent;
            const checkedNodes = table.getCheckedNodes();

            if (!checkedNodes.length) {
              that.dppMessageService.warning('common.operation.noDataSelected');
              this.loading = false;
              return;
