/**
 * 装配大纲工艺流程组成移动事件
 * 根据被拖拽节点拖拽后的位置对比，来决定传的参数，上移传目标位置的下一位   下移传目标位置的上一位
 * @param event
 */
sysAssemblyOutlineDragAction(event: RowDragEvent): Observable<boolean> {
  const table = event.beans.table;
  const instanceData = table.dppRender?.innerSend?.instanceData!;
  const dragNode = event.dragNode;
  const dragNodeData = dragNode.origin;
  const dropNode = event.dropNode;
  const dropNodeData = dropNode.origin;
  const currentDataRowKey = dragNodeData?.['ROWKEY'];
  const allNodes = table.getAllNodes();
  let end1: { guid: string; className: string } = {
    className: instanceData?.['CLASSNAME$']!?.toString(),
    guid: instanceData?.['GUID$']!?.toString()
  };
  const dragIndex = dragNode.rowIndex!;
  const dropIndex = dropNode.rowIndex!;

  // 上拖传下 下拖传上
  let finallyIndex: number;
  if (dropIndex < dragIndex) {
    // 上托
    finallyIndex = event.pos === 1 ? dropIndex : dropIndex + 1;
  } else {
    // 下托
    finallyIndex = event.pos === 1 ? dropIndex - 1 : dropIndex;
  }
  const finallyNode = allNodes[finallyIndex];

  // 如果相差是0 就是自己本身 直接返回false
  if (Math.abs(dragIndex - finallyIndex) === 0) {
    return of(false);
  }

  const STRUCTURES = [
    {
      end2: {
        className: finallyNode.origin['CLASSNAME$']!,
        id: finallyNode.origin['ID$']
        // guid: rowData?.['GUID$']!
      },
      objectGuid: {
        guid: finallyNode.origin['ROWKEY']['GUID']!,
        className: finallyNode.origin['ROWKEY']['CLASSNAME']!
      },
      props: {
        DATASEQ: dragNodeData?.['DATASEQ']
      }
    },
    {
      end2: {
        className: dragNodeData?.['CLASSNAME$']!,
        id: dragNodeData['ID$']
        // guid: rowData?.['GUID$']!
      },
      objectGuid: {
        guid: currentDataRowKey?.['GUID']!,
        className: currentDataRowKey?.['CLASSNAME']!
      },
      props: {
        DATASEQ: finallyNode.origin['DATASEQ']
      }
    }
  ];
  const relation = {
    end1: end1,
    structures: STRUCTURES,
    type: 'drag'
  };
  return this.processManagementService.batchSaveAsmProcessRelation(relation).pipe(
    tap(res => {
      if (res.success) {
        this.dppMessageService.success('common.operation.operationSuccess');
        table.refreshData();
      }
    }),
    map(() => false),
    catchError(err => {
      return of(false);
    })
  );
}

/**
 * 装配大纲工艺流程组成table新建
 * @param event
 */
sysAssemblyOutlineProcessFlowConstituteTableNewAction(event: EventInterface): void {
  const pageService = this.getRootPageService(event);
  const operatingStation = pageService.getComFnMapByName('sysOperatingStationCommand') as FlowChartComponent;
  const table = this.getContentCom<DppTableComponent>(event);
  const end1Iinstance = table?.['dppRender']?.['innerSend']?.['instanceData'];
  if (!operatingStation.selectNode) {
    this.dppMessageService.warning('process.operation.pleaseSelectOperatingStationNode');
    return;
  }
  const guid = operatingStation.selectNode?.['STATION_GUID']?.toString()!;
  const params: IFormRender = {
    name: 'sysNewProcessManagementForm',
    mParams: {
      mode: ModeTypeEnum.STEP,
      initValue: `withMainFile=Y`,
      isObject: false,
      expression: 'CLASSNAME$:editable=false'
    },
    data: {
      CLASSNAME$: 'AssemblyProcess'
    }
  };
  generateFieldMapping({
    mappingType: 'folder',
    fieldKey: 'COMMITFOLDER$',
    sourceData: end1Iinstance,
    onValueUpdate: (key, value) => {
      params.data![key] = value;
    },
    isMapToObject: false
  });

  PubSpaceEventUtil.stepFormHandle(event, params, {
    okFn: (button, formCpm, modal) => {
      const isValid = formCpm.onSubmit();
      if (!isValid) {
        return;
      }
      const data = formCpm.getFormData<IFoundaton>();
      let obss: Observable<
        Array<{
          type: string;
          res: DppResponse<IFoundaton>;
        }>
      >;
      const request1 = this.boas.saveObject(data).pipe(
        map(i => {
          return {
            type: 'save',
            res: i
          };
        })
      );
      if (data.ISAUTOCHECKOUT$ === 'Y') {
        const request2 = request1.pipe(
          switchMap(saveResult => {
            const { CLASSNAME$, GUID$, UPDATETIME$ } = saveResult.res.data!;
            return this.boas
              .checkObject(CLASSNAME$!, GUID$!, UPDATETIME$!, CheckActiveEnum.CHECKOUT, undefined, {
                interceptor: 'false'
              })
              .pipe(
                map(checkResult => ({
                  type: 'check',
                  res: checkResult
                }))
              );
          }),
          catchError(i => {
            return throwError({
              type: 'check',
              res: i
            });
          })
        );
        data.ISAUTOCHECKOUT$ = 'N';
        obss = forkJoin([request2]);
      } else {
        obss = forkJoin([request1]);
      }
      button.loading = true;
      obss.subscribe({
        next: resp => {
          const end2Iinstance = resp[0].res.data;
          const END1 = {
            className: end1Iinstance?.['CLASSNAME$']!?.toString(),
            guid: end1Iinstance?.['GUID$']!?.toString()
          };
          const STRUCTURES = [
            {
              end2: {
                className: end2Iinstance?.['CLASSNAME$']!,
                guid: end2Iinstance?.['GUID$']!
              },
              props: {
                WORKSTATION: guid
              },
              modifyType: 'ADD'
            }
          ];
          const relation = {
            end1: END1,
            structures: STRUCTURES
          };
          this.processManagementService.batchLinkAsmProcess(relation).subscribe({
            next: res => {
              if (res.success) {
                this.dppMessageService.success('common.operation.operationSuccess');
                table.refreshData();
              }
            }
          });
          modal.close();
          // this.modify.openObjectFn(event, resp[0].res.data, () => { }, {});
        },
        error: errRes => {
          button.loading = false;
          if (errRes.type && errRes.type === 'check') {
            const errMsg1 = this.tranPipe.transform('common.title.created');
            const errMsg2 = this.tranPipe.transform(errRes.res.error.errorMessage);
            this.dppMessageService.error(`${errMsg1},${errMsg2}`);
            // this.getContentCom<DppTableComponent>(event).refreshData();
            modal.close();
          }
        }
      });
    }
  });
}

/**
 * 装配大纲工艺流程组成table添加
 * @param event
 */
sysAssemblyOutlineProcessFlowConstituteTableAddAction(event: EventInterface): void {
  const pageService = this.getRootPageService(event);
  const operatingStation = pageService.getComFnMapByName('sysOperatingStationCommand') as FlowChartComponent;
  const guid = operatingStation.selectNode?.['STATION_GUID']?.toString()!;
  if (!operatingStation.selectNode) {
    this.dppMessageService.warning('process.operation.pleaseSelectOperatingStationNode');
    return;
  }
  const render = {
    name: 'sysAssemblyOutlineProcessFlowConstituteAddTable',
    mParams: {
      toolbar: 'sysAssemblyOutlineProcessFlowConstituteProcessAddToolBar',
      // dataSource: '/Common/ICommonService/listObject?interfaceNames=$interfaceNames'
      dataSource: '/Common/IAdvSearchService/listItemsForInterfaceSearch?interfaceNames=$interfaceNames'
    },
    dParams: {
      interfaceNames: 'IAssemblyProcess'
    }
  };
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  const modal = this.as.openModal(
    {
      title: 'process.operation.assemblyOutlineSelect',
      width: '80vw',
      height: '600px',
      content: DppTableComponent,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(data) {
            this.loading = true;
            const addTable = data as DppTableComponent;
            const table = that.getContentCom<DppTableComponent>(event);
            const end1Iinstance = table?.['dppRender']?.['innerSend']?.['instanceData'];
            const checkedNodesInfo = addTable.getCheckedNodes();
            if (checkedNodesInfo && checkedNodesInfo.length > 0) {
              let end1: { guid: string; className: string } = {
                className: end1Iinstance?.['CLASSNAME$']!?.toString(),
                guid: end1Iinstance?.['GUID$']!?.toString()
              };
              let STRUCTURES: Array<{
                end2: { guid: string; className: string };
                props: Record<string, unknown>;
                modifyType: string;
              }> = [];
              checkedNodesInfo?.forEach(item => {
                STRUCTURES.push({
                  end2: { className: item?.['origin']?.['CLASSNAME$']!, guid: item?.['origin']?.['GUID$']! },
                  props: {
                    WORKSTATION: guid
                  },
                  modifyType: 'ADD'
                });
              });
              const relation = {
                end1: end1,
                structures: STRUCTURES
              };
              that.processManagementService.batchLinkAsmProcess(relation).subscribe({
                next: res => {
                  if (res.success) {
                    that.dppMessageService.success('common.operation.operationSuccess');
                    table.refreshData();
                  }
                  this.loading = false;
                  modal.close();
                },
                error: err => {
                  this.loading = false;
                }
              });
            } else {
              this.loading = false;
              that.dppMessageService.warning('common.operation.noDataSelected');
            }
          }
        }
      ]
    },
    { dppRender: render }
  );
}

/**
 * 装配工序添加弹窗搜索
 * @param event
 */
sysAssemblyOutlineProcessFlowConstituteProcessAddSearchAction(event: EventInterface): void {
  const keys = ['ID$', 'NAME$'];
  const button: DppButtonComponent = this.getExeCom<DppButtonComponent>(event);
  const table = this.getContentCom(event) as DppTableComponent;
  const inputvalue: string = button.value;
  if (!inputvalue) {
    table.refreshByCondition([]);
    return;
  }
  const searchCondition = new QueryCondition(DppQueryConditionOperator.OR);
  keys.forEach(itey => {
    searchCondition.addCondition(new QueryConditionInfo(itey, [inputvalue], DppQueryConditionOperator.LIKE));
  });
  table.refreshByCondition(searchCondition);
}

