  /**
   * 上传文件（基于表格
   * @param {EventInterface} event
   * @memberof QueryInstanceEventService
   */
  sysProcessUploadFileAction(event: EventInterface): void {
    const bs = this.getExeCom(event) as DppButtonComponent;
    const guess = bs?.dppRender?.['model'].guess;
    let formData: IBaseData = {};
    const table = this.getContentCom<DppTableComponent>(event);
    if (guess) {
      formData = this.getRowData(event);
    } else {
      let formCom = this.formRootFindChild<DppFormComponent>(event, 'sysNewOutLeftInstanceDetailCommand');
      formData = formCom?.getFormData<IBaseData>() || {};
    }

    // 未检出
    if (formData[SystemClassFieldEnum.ISCHECKOUT] !== 'Y') {
      this.dppMessageService.warning('backend.business.message.notCheckout');
      return;
    }
    const action = bs.getUiModel().action!;
    const model = {};
    model[SystemClassFieldEnum.GUID] = formData[SystemClassFieldEnum.GUID];
    model[SystemClassFieldEnum.CLASSNAME] = formData[SystemClassFieldEnum.CLASSNAME];
    model[SystemClassFieldEnum.UPDATETIME] = DppFormUtil.convertToDate(formData[SystemClassFieldEnum.UPDATETIME])
      .getTime()
      .toString();
    // 传文件数据给form 方便form判断
    if (!guess) model[Form_Constant.INPUT_FILES_KEY] = table.getTreeNodes().map(i => i.origin);
    const params: IFormRender = {
      name: action.name, //'UploadFileForm',
      mParams: {
        mode: action.mode, //ModeTypeEnum.EDIT,
        isObject: action.isObject!
      },
      data: model
    };
    const that = this;
    const modal = bs.as.openModal(
      {
        title: bs.getUiModel().label,
        width: action.width,
        bodyStyle: { height: action.height! },
        closeCallBack: () => {},
        content: DppFormComponent,
        footer: [
          {
            label: 'common.button.confirm',
            type: 'primary',
            onClick(data: DppFormComponent) {
              const object = data.getFormData<IBaseData>(); /* 获取form 上传文件列表数据 */
              if (object['FILEPROPS$']?.length > 0) {
                that.setLoading(event, true);
                modal?.updateConfig({ nzClosable: false });
                this.loading = true;
                that.boas.saveObject(object, false).subscribe({
                  next: res => {
                    if (res.success && res.data) {
                      const EventCallbacks = {
                        operate: EventCallbacksActionName.REFRESH
                      };
                      // 上传文件集合
                      if (res.data['FILERESULT']) {
                        const fileresult = res.data['FILERESULT'] as IBatchData;
                        if (fileresult.errorCnt !== 0) {
                          that.dppMessageService.createTableMessage('warning', bs.getUiModel().label, fileresult);
                          if (fileresult.successCnt) that.initFilePreview(event, res.data);
                        } else {
                          that.dppMessageService.success('basic.modalTip.UploadSuccessful');
                          that.initFilePreview(event, res.data);
                        }
                      } else {
                        that.dppMessageService.success('basic.modalTip.UploadSuccessful');
                        that.initFilePreview(event, res.data);
                      }
                      if (!guess) {
                        that.contentComCallback(event, EventCallbacks);
                      }
                      const pageService = that.getUpPage(event);
                      if (pageService?.['subjextPageObj']) {
                        const panelName = Object.keys(pageService?.['subjextPageObj'])?.[0];
                        that.changePanel(event, {
                          panelName,
                          panelOpt: {
                            optionType: 'jump',
                            jumpTabName: 'sysFileCommand'
                          }
                        });
                      }
                      modal?.close();
                      modal?.updateConfig({ nzClosable: true });
                      this.loading = false;
                    }
                    that.setLoading(event, false);
                  },
                  error: err => {
                    that.setLoading(event, false);
                    modal?.updateConfig({ nzClosable: true });
                    this.loading = false;
                  }
                });
              } else {
                that.dppMessageService.warning('basic.modalTip.SelectFiles');
              }
            }
          }
        ]
      },
      { dppRender: params } // param  传给ui的form组件
    );
  }
