  /**
   * 工序批量删除事件
   * @param event
   * @returns
   */
  sysProcessBatchRemoveEnd2Action(event: EventInterface): void {
    const table = this.getContentCom(event) as unknown as DppTableComponent;
    const instanceData = table.dppRender.innerSend?.instanceData;
    const btn = this.getExeCom(event) as DppButtonComponent;
    const isRelation = btn.dppRender.model.action.isRelation;
    const templateName = table.queryCondition.params.get('templateName') as string;
    const selectNodes = table.getCheckedNodes();

    if (selectNodes.length === 0) {
      this.dppMessageService.warning('common.operation.noDataSelect');
      return;
    }
    // const guid = table.dppRender['guid'];
    // const className = table.dppRender['className'];
    const guid = instanceData?.['GUID$']?.toString();
    const className = instanceData?.['CLASSNAME$']?.toString();
    const filterSelectNodes = selectNodes.filter(item => item.origin['ROWKEY']);
    if (!filterSelectNodes.length) {
      this.dppMessageService.warning('common.message.warning.notAllowRootNode');
      return;
    }
    this.setLoading(event, true);
    const relation = {
      end1: { guid, className },
      templateName,
      isBOM: templateName === 'BOM',
      structures: RelationUtil.buildStructures(
        ModifyEnum.DEL,
        filterSelectNodes.map(item => item.origin) as IFoundaton[]
      )
    };
    this.relationService.deleteRelation(relation, isRelation).subscribe({
      next: res => {
        if (res.success) {
          if (filterSelectNodes.length < selectNodes.length) {
            this.dppMessageService.success('common.message.success.filterRootNode');
          } else {
            this.dppMessageService.success('common.operation.removeSucceed');
          }

          table.deleteNode(filterSelectNodes);
          this.setLoading(event, false);
          table.refreshData();
        }
      },
      error: e => {
        this.setLoading(event, false);
      }
    });
  }

  private getRoute(node: RowNode): string[] {
    const route: string[] = [];
    let parent: RowNode | null = node;
    while (parent) {
      route.push(parent.id!);
      parent = parent.parentNode;
    }
    return route.reverse();
  }
