/**
 * 作业站流程图节点点击事件
 * @param event
 */
sysAssemblyOutlineProcessFlowFlowChartNodeClick(event: EventInterface): void {
  const rowData = event.rowData;
  const table = this.getContentCom(event) as DppTableComponent;
  const instanceData = table.dppRender?.innerSend?.instanceData!;
  if (instanceData?.['STATUS$'] == 'RLS') {
    if (rowData) {
      const searchCondition = new QueryCondition(DppQueryConditionOperator.AND);
      searchCondition['items']?.push({
        name: 'WORKSTATION',
        operator: 'Equals',
        values: [rowData?.['STATION_GUID']!]
      });
      table.refreshByCondition(searchCondition);
    } else {
      const queryCondition = table.queryCondition;
      queryCondition.reset();
      table.refreshData();
    }
    return;
  }
  const toolbar = table.topToolbar as DppToolbarComponent;
  const showNewBtn = toolbar?.service?.filterBtnsByName(
    'sysAssemblyOutlineProcessFlowConstituteTableNewCommand',
    toolbar.dppButtons.toArray()
  )!;
  const showAddBtn = toolbar?.service?.filterBtnsByName(
    'sysAssemblyOutlineProcessFlowConstituteTableAddCommand',
    toolbar.dppButtons.toArray()
  )!;
  const showRefreshBtn = toolbar?.service?.filterBtnsByName(
    'sysAssemblyOutlineProcessFlowConstituteSerialNumberRefreshCommand',
    toolbar.dppButtons.toArray()
  )!;
  if (rowData) {
    showNewBtn.setDisabled(false);
    showAddBtn.setDisabled(false);
    showRefreshBtn.setDisabled(false);
    const searchCondition = new QueryCondition(DppQueryConditionOperator.AND);
    searchCondition['items']?.push({
      name: 'WORKSTATION',
      operator: 'Equals',
      values: [rowData?.['STATION_GUID']!]
    });
    table.refreshByCondition(searchCondition);
  } else {
    showNewBtn.setDisabled(true);
    showAddBtn.setDisabled(true);
    showRefreshBtn.setDisabled(true);
    const queryCondition = table.queryCondition;
    queryCondition.reset();
    table.refreshData();
  }
}

/**
 * 装配大纲工序顺序号事件
 * @param event
 */
sysAssemblyOutlineProcessFlowConstituteSerialNumberAction(event: CellSaveEvent): Observable<DppResponse<NzSafeAny>> {
  const table = event.beans.table;
  const instanceData = table.dppRender?.innerSend?.instanceData!;
  const rowData = event.data;
  const rowKey = rowData?.['ROWKEY'];

  const pageService = this.getRootPageService(event);
  const operatingStation = pageService.getComFnMapByName('sysOperatingStationCommand') as FlowChartComponent;
  if (!operatingStation.selectNode) {
    this.dppMessageService.warning('process.operation.pleaseSelectOperatingStationNode');
    const res: DppResponse<NzSafeAny> = {
      errorCode: '',
      errorMsg: '',
      success: true,
      data: { ...event.data, ...{ DATASEQ: event.oldValue } }
    };
    return of(res);
  }

  let newValue = this.padSequenceNumber(event.newValue);

  let end1: { guid: string; className: string } = {
    className: instanceData?.['CLASSNAME$']!?.toString(),
    guid: instanceData?.['GUID$']!?.toString()
  };
  const STRUCTURES = [
    {
      end2: {
        className: rowData?.['CLASSNAME$']!
        // guid: rowData?.['GUID$']!
      },
      objectGuid: {
        guid: rowKey?.['GUID']!,
        className: rowKey?.['CLASSNAME']!
      },
      props: {
        DATASEQ: newValue
      }
    }
  ];
  const relation = {
    end1: end1,
    structures: STRUCTURES
  };
  return this.processManagementService.batchSaveAsmProcessRelation(relation).pipe(
    map(res => {
      this.dppMessageService.success('common.operation.operationSuccess');
      res.data = undefined;
      event.node.setDataValue(event.column.key, newValue);
      return res;
    })
  );
}

