sysFabricationOutlineProcessFlowConstituteNewBrotherNodeAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const end1Instance = table.dppRender?.innerSend?.instanceData;

  const params: IFormRender = {
    name: 'sysNewProcessManagementForm',
    mParams: {
      mode: ModeTypeEnum.STEP,
      initValue: `withMainFile=Y`,
      isObject: false,
      expression: 'CLASSNAME$:editable=false'
    },
    data: {
      CLASSNAME$: 'FabricationProcess'
    }
  };
  generateFieldMapping({
    mappingType: 'folder',
    fieldKey: 'COMMITFOLDER$',
    sourceData: end1Instance,
    onValueUpdate: (key, value) => {
      params.data![key] = value;
    }
  });

  PubSpaceEventUtil.stepFormHandle(event, params, {
    okFn: (button, formCpm, modal) => {
      const isValid = formCpm.onSubmit();
      if (!isValid) {
        return;
      }
      const data = formCpm.getFormData<IFoundaton>();
      let obss: Observable<
        Array<{
          type: string;
          res: DppResponse<IFoundaton>;
        }>
      >;
      const request1 = this.boas.saveObject(data).pipe(
        map(i => {
          return {
            type: 'save',
            res: i
          };
        })
      );
      if (data.ISAUTOCHECKOUT$ === 'Y') {
        const request2 = request1.pipe(
          switchMap(saveResult => {
            const { CLASSNAME$, GUID$, UPDATETIME$ } = saveResult.res.data!;
            return this.boas
              .checkObject(CLASSNAME$!, GUID$!, UPDATETIME$!, CheckActiveEnum.CHECKOUT, undefined, {
                interceptor: 'false'
              })
              .pipe(
                map(checkResult => ({
                  type: 'check',
                  res: checkResult
                }))
              );
          }),
          catchError(i => {
            return throwError({
              type: 'check',
              res: i
            });
          })
        );
        data.ISAUTOCHECKOUT$ = 'N';
        obss = forkJoin([request2]);
      } else {
        obss = forkJoin([request1]);
      }
      button.loading = true;
      obss.subscribe({
        next: resp => {
          const table = this.getContentCom(event) as DppTableComponent;
          const instanceData = table.dppRender?.innerSend?.instanceData!;
          const rowData = this.getRowData(event);
          const end2Iinstance = resp[0].res.data;
          // console.log('end1Iinstance ',end1Iinstance);
          // console.log('end2Iinstance ',end2Iinstance);
          const END1 = {
            className: instanceData?.['CLASSNAME$']!?.toString(),
            guid: instanceData?.['GUID$']!?.toString()
          };
          const STRUCTURES = [
            {
              end2: {
                className: end2Iinstance?.['CLASSNAME$']!,
                guid: end2Iinstance?.['GUID$']!
              },
              props: {},
              modifyType: 'ADD'
            }
          ];
          const param = {
            sequence: rowData?.['DATASEQ'],
            relation: {
              end1: END1,
              structures: STRUCTURES
            }
          };
          this.processManagementService.batchInsertFabProcess(param).subscribe({
            next: res => {
              if (res.success) {
                table.refreshData();
              }
            }
          });
          modal.close();
          // this.modify.openObjectFn(event, resp[0].res.data, () => {}, {});
        },
        error: errRes => {
          button.loading = false;
          if (errRes.type && errRes.type === 'check') {
            const errMsg1 = this.tranPipe.transform('common.title.created');
            const errMsg2 = this.tranPipe.transform(errRes.res.error.errorMessage);
            this.dppMessageService.error(`${errMsg1},${errMsg2}`);
            this.getContentCom<DppTableComponent>(event).refreshData();
            modal.close();
          }
        }
      });
    }
  });
}

/**
 * 上传文件（基于表格
 * @param {EventInterface} event
 * @memberof QueryInstanceEventService
 */
sysProcessUploadFileAction(event: EventInterface): void {
  const bs = this.getExeCom(event) as DppButtonComponent;
  const guess = bs?.dppRender?.['model'].guess;
  let formData: IBaseData = {};
  const table = this.getContentCom<DppTableComponent>(event);
  if (guess) {
    formData = this.getRowData(event);
  } else {
    let formCom = this.formRootFindChild<DppFormComponent>(event, 'sysNewOutLeftInstanceDetailCommand');
    formData = formCom?.getFormData<IBaseData>() || {};
  }

  // 未检出
  if (formData[SystemClassFieldEnum.ISCHECKOUT] !== 'Y') {
    this.dppMessageService.warning('backend.business.message.notCheckout');
    return;
  }
  const action = bs.getUiModel().action!;
  const model = {};
  model[SystemClassFieldEnum.GUID] = formData[SystemClassFieldEnum.GUID];
  model[SystemClassFieldEnum.CLASSNAME] = formData[SystemClassFieldEnum.CLASSNAME];
  model[SystemClassFieldEnum.UPDATETIME] = DppFormUtil.convertToDate(formData[SystemClassFieldEnum.UPDATETIME])
    .getTime()
    .toString();
  // 传文件数据给form 方便form判断
  if (!guess) model[Form_Constant.INPUT_FILES_KEY] = table.getTreeNodes().map(i => i.origin);
  const params: IFormRender = {
    name: action.name, //'UploadFileForm',
    mParams: {
      mode: action.mode, //ModeTypeEnum.EDIT,
      isObject: action.isObject!
    },
    data: model
  };
  const that = this;
  const modal = bs.as.openModal(
    {
      title: bs.getUiModel().label,
      width: action.width,
      bodyStyle: { height: action.height! },
      closeCallBack: () => {},
      content: DppFormComponent,
      footer: [
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(data: DppFormComponent) {
            const object = data.getFormData<IBaseData>(); /* 获取form 上传文件列表数据 */
            if (object['FILEPROPS$']?.length > 0) {
              that.setLoading(event, true);
              modal?.updateConfig({ nzClosable: false });
              this.loading = true;
              that.boas.saveObject(object, false).subscribe({
                next: res => {
                  if (res.success && res.data) {
                    const EventCallbacks = {
                      operate: EventCallbacksActionName.REFRESH
                    };
                    // 上传文件集合
                    if (res.data['FILERESULT']) {
                      const fileresult = res.data['FILERESULT'] as IBatchData;
                      if (fileresult.errorCnt !== 0) {
                        that.dppMessageService.createTableMessage('warning', bs.getUiModel().label, fileresult);
                        if (fileresult.successCnt) that.initFilePreview(event, res.data);
                      } else {
                        that.dppMessageService.success('basic.modalTip.UploadSuccessful');
                        that.initFilePreview(event, res.data);
                      }
                    } else {
                      that.dppMessageService.success('basic.modalTip.UploadSuccessful');
                      that.initFilePreview(event, res.data);
                    }
                    if (!guess) {
                      that.contentComCallback(event, EventCallbacks);
                    }
                    const pageService = that.getUpPage(event);
                    if (pageService?.['subjextPageObj']) {
                      const panelName = Object.keys(pageService?.['subjextPageObj'])?.[0];
                      that.changePanel(event, {
                        panelName,
                        panelOpt: {
                          optionType: 'jump',
                          jumpTabName: 'sysFileCommand'
                        }
                      });
                    }
                    modal?.close();
                    modal?.updateConfig({ nzClosable: true });
                    this.loading = false;
                  }
                  that.setLoading(event, false);
                },
                error: err => {
                  that.setLoading(event, false);
                  modal?.updateConfig({ nzClosable: true });
                  this.loading = false;
                }
              });
            } else {
              that.dppMessageService.warning('basic.modalTip.SelectFiles');
            }
          }
        }
      ]
    },
    { dppRender: params } // param  传给ui的form组件
  );
}

