/**
 * 新建交付物事件
 * @param event
 */
sysProcessTaskNewDeliverablesAction(event: EventInterface): void {
  const exeCom = this.getExeCom(event) as DppButtonComponent;
  const instance = exeCom.dppRender?.['config']?.['innerSend']?.['instanceData'];
  const table = this.getContentCom<DppTableComponent>(event);
  const rootNodes = table.getFlatRootNodes();
  const alldata = rootNodes?.map(item => item.origin);
  const foundItem = alldata?.find(item => item?.['ISROOT'] == 'Y');
  const className = foundItem?.['CLASSNAME'];
  const params: IFormRender = {
    name: 'sysNewProcessDeliveryStepForm',
    mParams: {
      mode: ModeTypeEnum.STEP,
      initValue: `withMainFile=Y`,
      isObject: false,
      expression: 'CLASSNAME$:editable=false'
    },
    data: {
      CLASSNAME$: className
    }
  };
  PubSpaceEventUtil.stepFormHandle(event, params, {
    okFn: (button, formCpm, modal) => {
      const isValid = formCpm.onSubmit();
      if (!isValid) {
        return;
      }
      const data = formCpm.getFormData<IFoundaton>();
      let obss: Observable<
        Array<{
          type: string;
          res: DppResponse<IFoundaton>;
        }>
      >;
      const request1 = this.boas.saveObject(data).pipe(
        map(i => {
          return {
            type: 'save',
            res: i
          };
        })
      );
      if (data.ISAUTOCHECKOUT$ === 'Y') {
        const request2 = request1.pipe(
          switchMap(saveResult => {
            const { CLASSNAME$, GUID$, UPDATETIME$ } = saveResult.res.data!;
            return this.boas
              .checkObject(CLASSNAME$!, GUID$!, UPDATETIME$!, CheckActiveEnum.CHECKOUT, undefined, {
                interceptor: 'false'
              })
              .pipe(
                map(checkResult => ({
                  type: 'check',
                  res: checkResult
                }))
              );
          }),
          catchError(i => {
            return throwError({
              type: 'check',
              res: i
            });
          })
        );
        data.ISAUTOCHECKOUT$ = 'N';
        obss = forkJoin([request2]);
      } else {
        obss = forkJoin([request1]);
      }
      button.loading = true;
      obss.subscribe({
        next: resp => {
          const end2Iinstance = resp[0].res.data;
          const param = {
            DELIVERABLEITEMGUID: foundItem?.['GUID'],
            INSTANCEGUID: end2Iinstance?.['GUID$']?.toString()!,
            INSTANCECLASSGUID: end2Iinstance?.['CLASSGUID$']?.toString()!,
            TASK: instance?.['GUID$'],
            TASK$CLASS: instance?.['CLASSGUID$']
          };
          this.processManagementService.saveDeliverable(param).subscribe({
            next: res => {
              if (res.success) {
                this.dppMessageService.success('common.operation.operationSuccess');
                modal.close();
                const firstRootNode = table.beans.rowModel.getRootNode().children[0];
                const route = this.getRoute(firstRootNode);
                table.applyTransaction({
                  route,
                  add: [res.data]
                });
              }
            }
          });
          modal.close();
          // this.modify.openObjectFn(event, resp[0].res.data, () => {}, {});
        },
        error: errRes => {
          button.loading = false;
          if (errRes.type && errRes.type === 'check') {
            const errMsg1 = this.tranPipe.transform('common.title.created');
            const errMsg2 = this.tranPipe.transform(errRes.res.error.errorMessage);
            this.dppMessageService.error(`${errMsg1},${errMsg2}`);
            this.getContentCom<DppTableComponent>(event).refreshData();
            modal.close();
          }
        }
      });
    }
  });
}

