      RELATIONPRODUCT$CLASS: formData['RELATIONPRODUCT$CLASS'],
      RELATIONPRODUCT$FULLNAME: formData['RELATIONPRODUCT$FULLNAME'],
      RELATIONPRODUCT$CLASSNAME: formData['RELATIONPRODUCT$CLASSNAME'],
      RELATIONITEM: formData['RELATIONITEM'],
      RELATIONITEM$CLASS: formData['RELATIONITEM$CLASS'],
      RELATIONITEM$FULLNAME: formData['RELATIONITEM$FULLNAME'],
      RELATIONITEM$CLASSNAME: formData['RELATIONITEM$CLASSNAME'],
      NAME$: formData['NAME$'],
      PLANFINISHTIME: new Date(formData['PLANFINISHTIME']).getTime().toString(),
      PLANSTARTTIME: new Date(formData['PLANSTARTTIME']).getTime().toString(),
      RESPONSIBLE: formData['EXECUTOR']?.value,
      RESPONSIBLE$TITLE: formData['EXECUTOR']?.label,
      EXECUTOR: formData['EXECUTOR']?.value || '',
      EXECUTOR$TITLE: formData['EXECUTOR']?.label || '',
      deliveryItems
    };
    if (type == 'sysTaskWizardAssignCommand') {
      if (!formData['EXECUTOR']?.value) {
        this.dppMessageService.warning('task.assign.assignFailedNoResponsiblePerson');
        this.setLoading(event, false);
        return;
      }
      object['autoAssign'] = 'Y';
      object['RESPONSIBLE'] = formData['EXECUTOR']?.value;
      object['RESPONSIBLE$TITLE'] = formData['EXECUTOR']?.label;
    }
    this.productDesignService.createTask(object).subscribe({
      next: res => {
