/**
 * @description 产品设计 新增交付项
 * @use 产品设计/产品管理/任务管理-新建任务-交付物-新增交付物(前端)｜工作台任务派发（前端）｜工作台直接打开新页签（接口）
 * @modify chenglong 2025-01-07 修改新增成功后的刷新
 */
sysNewTaskAddDeliverablesAction(event: EventInterface): void {
  // 任务信息
  const rowData = this.getRowData(event) as any;
  const table = this.getContentCom(event) as DppTableComponent;
  const render: IRenderParameterNew<IUiModel> = {
    name: 'sysBatchAddDeliverablesForm',
    mParams: {
      mode: ModeTypeEnum.BATCHCREATE
    },
    dParams: {
      exceptItfNameList: ['IPM', 'IProjectType', 'IBOMView', '', 'IECM', 'INonQueryable']
    }
  };

  // 这里区分一下是前端添加还是接口添加
  const isFrontAdd = !rowData.GUID$;

  const onConfirm = (
    forCom: DppFormComponent,
    modal: DppNzModalRef,
    setBtnLoading: (loading: boolean) => void
  ): void => {
    setBtnLoading(true);
    const isValid = forCom.onSubmit();
    if (!isValid) {
      setBtnLoading(false);
      return;
    }
    const data = forCom.getNotTranFormData() as DppSafeAny[];
    const arrayOfData = Object.values(data);
    const formData = forCom.getFormData() as DppSafeAny[];
    if (isFrontAdd) {
      const needAddData = this.buildAddData(arrayOfData);
      // 暂时处理，等form适配级联后可去掉
      // const newNeedAddData = needAddData.filter(item => item.TYPE);
      table.applyTransaction({
        add: needAddData,
        addIndex: 0
      });
      setBtnLoading(false);
      modal.close();
    } else {
      const addParams = this.buildAddParams(rowData, formData, arrayOfData);
      this.productDesignService.batchSaveDeliveryItem(addParams).subscribe({
        next: res => {
          if (res.success && res.data) {
            const { successCnt, totalCnt, errorCnt, details } = res.data;
            if (successCnt && successCnt === totalCnt) {
              this.dppMessageService.success('common.operation.operationSuccess');
            } else {
              this.errorMessageService.showMessage(event, res);
            }
            // 获取添加成功的数据
            const successAddData = details
              .filter((item: any) => item.result === 'SUCCESS')
              .map((item: any) => item.data);
            if (successAddData.length > 0) {
              table.applyTransaction({
                add: successAddData
              });
            }
            setBtnLoading(false);
            //全部失败， 不需要刷新表格
            if (totalCnt === errorCnt) return;
            modal.close();
          }
        },
        error: _err => {
          setBtnLoading(false);
        }
      });
    }
  };
  const modal: DppNzModalRef = this.as.openModal(
    {
      title: 'task.operation.NewDeliverables',
      width: '80vw',
      bodyStyle: { height: '400px', overflowY: 'scroll', overflowX: 'scroll' },
      closable: true,
      uiType: UIModelTypeEnum.FORM,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal?.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(forCom: DppFormComponent) {
            const setBtnLoading = (loading: boolean): void => {
              this.loading = loading;
            };
            onConfirm(forCom, modal, setBtnLoading);
          }
        }
      ],
      isInteractive: false,
      modalSelf: () => modal
    },
    { dppRender: render }
  );
}

private buildAddData(arrayOfData: DppSafeAny): DppSafeAny[] {
  return arrayOfData.map((item: DppSafeAny) => {
    return {
      TYPE: typeof item?.TYPE === 'string' ? item?.TYPE$NODES?.[0]?.title : item?.TYPE?.title,
      TYPEValue: typeof item?.TYPE === 'string' ? item?.TYPE : item?.TYPE?.key,
      CLASSIFICATION: item?.['CLASSIFICATION']?.title || '',
      CLASSIFICATIONValue: item?.['CLASSIFICATION']?.key || '',
      ISMAST: item?.['ISMAST'],
      ISRELEASE: item?.['ISRELEASE'],
      REMARK: item?.['REMARK']
    };
  });
}

private buildAddParams(rowData: any, formData: any, arrayOfData: any): any[] {
  return Object.values(formData).map((item: any) => {
    return {
      TASK: rowData['GUID$'],
      TASK$CLASS: rowData?.['CLASSGUID$'],
      CLASSGUID: item?.TYPE,
      CLASSIFICATION: item?.['CLASSIFICATION'] || '',
      ISNEED: item?.['ISMAST'] || '',
      ISRELEASE: item?.['ISRELEASE'] || '',
      REMARK: item?.['REMARK'],
      NAME$: this.tranPipe.transform(arrayOfData.find((itey: any) => item?.TYPE === itey.TYPE.key)?.TYPE.title)
    };
  });
}

