/**
 * 批量删除交付物和交付物类型
 *
 * 业务规则:
 * 1. 交付物类型只能在未指派(NTA)状态下删除
 * 2. 交付物对象只能在进行中(RUN)状态下删除
 *
 * 任务状态说明:
 * - INI: 未启动
 * - NTA: 未指派
 * - RUN: 进行中
 * - APP: 审批中
 * - PUS: 已暂停
 * - COP: 已完成
 * - SSP: 已取消
 *
 * @param event 事件对象
 * @author cl
 * @modifyDate 2025-01-08
 * @modifyContent
 * 1. 增加任务状态校验
 * 2. 优化删除后的表格更新逻辑
 * 3. 完善错误处理
 */
sysTaskDeliverablesBatchDeleteAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const btnComp = this.getExeCom(event) as DppButtonComponent;
  const instance = btnComp.dppRender?.['config']?.['innerSend']?.['instanceData'];
  const taskStatus = instance['EXECUTESTATUS$NAME'];

  // 获取选中的非根节点
  const selectedNodes = table.getCheckedNodeList();

  // 检查任务状态和删除权限
  const hasDeliverableType = selectedNodes.some(node => node.origin['ISROOT'] === 'Y');
  if (hasDeliverableType && taskStatus !== 'NTA') {
    this.dppMessageService.warning('task.assign.DeleteTaskTypeErrorWarning');
    return;
  }

  const hasDeliverable = selectedNodes.some(node => node.origin['ISROOT'] === 'N');
  if (hasDeliverable && taskStatus !== 'RUN') {
    this.dppMessageService.warning('task.assign.DeleteTaskObjectErrorWarning');
    return;
  }

  const needRemoveNodeMap = new Map<string, RowNode>();
  const taskId = instance?.['GUID$']?.toString()!;
  const taskClassId = instance?.['CLASSGUID$']?.toString()!;

  // 构建删除参数
  const deleteParams = selectedNodes.map(item => {
    needRemoveNodeMap.set(item.origin['GUID'], item);
    return {
      GUID: item.origin['GUID'],
      TASK: taskId,
      TASK$CLASS: taskClassId
    };
  });

  // 执行删除操作
  this.setLoading(event, true);
  const del$ = hasDeliverableType
    ? this.productDesignService.batchDeleteDeliveryItem(deleteParams)
    : this.productDesignService.batchDeleteDeliverable(deleteParams);
  del$.subscribe({
    next: res => {
      if (res.success && res.data) {
        const { successCnt, errorCnt, totalCnt, details } = res.data;

        // 处理部分成功部分失败的情况
        if (successCnt === totalCnt) {
          this.dppMessageService.success('common.operation.operationSuccess');
        } else {
          this.errorMessageService.showMessage(event, res);
        }
        // 获取删除成功的数据
        const successData = details.filter(item => item.result === 'SUCCESS').map(item => item.data);
        if (successData.length > 0) {
          const needRemoveNode = successData
            .filter(item => !!item['GUID'])
            .map(item => needRemoveNodeMap.get(item['GUID']!));

          table.deleteNode(needRemoveNode);
        }

        this.setLoading(event, false);
      }
    },
    error: () => {
      this.setLoading(event, false);
    },
    complete: () => {
      this.setLoading(event, false);
    }
  });
}

