        formData['COMPLETIONRATE'],
        datePipe.transform(formData['PLANFINISHTIME'], 'yyyy-MM-dd HH:mm:ss', 'GMT+8')!,
        datePipe.transform(formData['PLANSTARTTIME'], 'yyyy-MM-dd HH:mm:ss', 'GMT+8')!,
        formData['RESPONSIBLE'],
        formData['SENDER']?.value ? formData['SENDER']?.value : loginUser?.guid,
        formData['SENDTIME'] || '',
        formData['IMPORTANCELEVEL']?.value || formData['IMPORTANCELEVEL'] || ''
      )
      .subscribe({
        next: res => {
          if (res.success) {
            this.dppMessageService.success('common.modalTip.saveSucceed');
            this.instanceTool.refreshInstance(event);
            form.callback({
              action: EventCallbacksActionName.UPDATE,
              params: { ...formData, ...res.data }
            });
          }
          this.setLoading(event, false);
        },
        error: _err => {
          this.setLoading(event, false);
        }
      });
  } else {
    this.dppMessageService.warning('common.operation.verificationFailed');
    this.setLoading(event, false);
  }
}

// 指派任务给其他人
assignAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  // const linkDataSource = table.dppRender['data'] as IFoundaton;
  const getDataValue = this.getRowData(event); // 表格行數據
  const guid = getDataValue['GUID$'];
  const params: DppSafeAny = {
    name: 'sysInstanceDetailObjectAssignForm',
    mode: ModeTypeEnum.EDIT,
    mParams: {
      mode: 'edit',
      expression:
        'RELATIONPRODUCT:editable=false;RELATIONITEM:editable=false;NAME$:editable=false;REMARK:editable=true;PLANFINISHTIME:required=true:editable=true;RESPONSIBLEPEOPLE:required=true;EXECUTOR:required=true'
    },
    className: getDataValue['CLASSNAME$'],
    guid,
    isObject: false,
    data: {
      EXECUTOR: getDataValue?.['EXECUTOR'],
      EXECUTOR$NAME: getDataValue?.['EXECUTOR$NAME'],
      REMARK: getDataValue?.['REMARK'],
      PLANSTARTTIME: getDataValue?.['PLANSTARTTIME'],
      PLANFINISHTIME: getDataValue?.['PLANFINISHTIME'],
      IMPORTANCELEVEL: getDataValue?.['IMPORTANCELEVEL'],
      IMPORTANCELEVEL$TITLE: getDataValue?.['IMPORTANCELEVEL$TITLE']
    }
  };
  // guid不存在的时候 就是bom的字段
  if (!guid) {
    delete params.className;
    delete params.guid;
    Object.assign(params.model, {
      NAME$: getDataValue['NAME$'],
      RELATIONITEM: getDataValue['RELATIONITEM'],
      RELATIONITEM$CLASS: getDataValue['RELATIONITEM$CLASS'],
      RELATIONITEM$FULLNAME: getDataValue['RELATIONITEM$FULLNAME'],
      RELATIONITEM$CLASSNAME: getDataValue['RELATIONITEM$CLASSNAME']
    });
    params.mParams.expression =
      'PLANFINISHTIME:required=true;RESPONSIBLEPEOPLE:required=true;RELATIONPRODUCT:editable=false;RELATIONITEM:editable=false;EXECUTOR:required=true';
  }
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  const modal = this.as.openModal(
    {
      title: 'basic.common.toolbar.assignmentTaskToolbar',
      width: '480px',
      content: DppFormComponent,
      bodyStyle: { height: '430px', padding: '0 10px 0 0' },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal?.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(data) {
            // 内容组件
            const isValid = data.onSubmit();
            const formData = data.getFormData();
            if (isValid) {
              this.loading = true;
              data.setLoading(true);
              let obs: Observable<DppResponse<DppTaskData>>;
              if (!guid) {
                obs = _this.productDesignService.createTask(formData);
              } else {
                obs = _this.productDesignService.assignOtherPerformer(
                  true,
                  formData['EXECUTOR'],
                  undefined,
                  getDataValue['GUID$'],
                  getDataValue['CLASSGUID$'],
                  getDataValue['CLASSNAME$'],
                  formData['REMARK'],
                  formData['UPDATECONTENT'],
                  formData['PLANFINISHTIME'] || '',
                  formData['PLANSTARTTIME'] || '',
                  formData['IMPORTANCELEVEL']?.value || formData['IMPORTANCELEVEL'] || ''
                );
              }
              obs.subscribe({
                next: res => {
                  modal?.close();
                  if (res.success) {
                    if (res.data) {
                      _this.dppMessageService.success('basic.modalTip.SuccessfullyAssignedtask');
                      table.refreshData();
                      _this.instanceTool.refreshFormAndTool(event, { ...getDataValue, ...res.data });
                      _this.menuService.updateNav({
                        type: NAV_ENUM.NOTICE,
                        opt: NAV_OPTION.REFRESH
                      });
                    }
                  } else {
                    _this.msg.create('error', `${res.errorCode}:${res['errorMessage']}`);
                  }
                  data.setLoading(false);
                  this.loading = false;
                },
                error: _res => {
                  modal.close();
                  data.setLoading(false);
                  this.loading = false;
                }
              });
            }
          }
        }
      ],
      canDrag: true
    },
    { dppRender: params }
  );
}

// 任务对象界面  指派任务
sysObjectAssignAction(event: EventInterface): void {
  const page = this.getRootPageService(event) as DppInstanceService;
  const content = this.getContentCom(event);
  let flag = true;
  const rowData = (content as DppFormComponent).getFormData?.() as IBaseData;
  const loginUser = this.autoUserService.getUser();
  let saveAsObj: { className: string; guid: string; hasBom: boolean } | undefined;
  let instanceData = this.getRowData(event);
  let objChanged: IFoundaton = {};
  if (content!['type'] == 'form') {
    instanceData = (content as DppFormComponent)?.getFormData?.() as IFoundaton;
    saveAsObj = (content as DppFormComponent).getService()?.saveAsObj;
    objChanged = (content as DppFormComponent).getFormChanceData<IFoundaton>();
  }
  const datePipe = new DatePipe('zh-CN');
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  const params: DppSafeAny = {
    name: 'sysInstanceDetailObjectAssignForm',
    mode: ModeTypeEnum.EDIT,
    isObject: false,
    data: {
      EXECUTOR: rowData?.['EXECUTOR'],
      EXECUTOR$NAME: rowData?.['EXECUTOR$NAME'],
      REMARK: rowData?.['REMARK'],
      UPDATECONTENT: rowData?.['UPDATECONTENT'],
      PLANSTARTTIME: datePipe.transform(rowData?.['PLANSTARTTIME'], 'yyyy-MM-dd HH:mm:ss', 'GMT+8'),
      PLANFINISHTIME: datePipe.transform(rowData?.['PLANFINISHTIME'], 'yyyy-MM-dd HH:mm:ss', 'GMT+8'),
      IMPORTANCELEVEL: rowData?.['IMPORTANCELEVEL'],
      IMPORTANCELEVEL$TITLE: rowData?.['IMPORTANCELEVEL$TITLE']
    }
  };
  const modal = _this.as.openModal(
    {
      title: 'basic.common.toolbar.assignmentTaskToolbar',
      width: '480px',
      content: DppFormComponent,
      bodyStyle: { height: '430px', padding: '0 10px 0 0' },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal?.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(data: DppFormComponent) {
            const isValid = data.onSubmit();
            const formData = data.getFormData() as IBaseData;
            const obs = _this.productDesignService.assignOtherPerformer(
              true,
              formData['EXECUTOR'],
              undefined,
              rowData['GUID$'],
              rowData['CLASSGUID$'],
              rowData['CLASSNAME$'],
              formData['REMARK'],
              formData['UPDATECONTENT'],
              formData['PLANFINISHTIME'] || '',
              formData['PLANSTARTTIME'] || '',
              formData['IMPORTANCELEVEL']?.value || formData['IMPORTANCELEVEL'] || ''
            );
            if (isValid) {
              this.loading = true;
              data.setLoading(true);
              if (!flag) {
                this.loading = false;
                return;
              } else {
                flag = false;
              }
              if (!saveAsObj && (Object.keys(objChanged)?.length === 0 || content!['type'] == 'table')) {
                // 未修改form界面 直接指派
                obs.subscribe({
                  next: res => {
                    if (res.success) {
                      data.setLoading(false);
                      this.loading = false;
                      if (res.data) {
                        modal?.close();
                        _this.dppMessageService.success('basic.modalTip.SuccessfullyAssignedtask');
                        if (content!['type'] === 'table') {
                          (content as DppTableComponent).refreshData();
                        } else {
                          page.refreshInstanceData({
                            isRefreshSelf: true,
                            callback: () => {
                              // @ts-ignore
                              const table = page.getComFnMapByName<DppTableComponent>(
                                CommandConstant.sysNewOutFileTaskTableCommand
                              );
                              const topToolbar = table?.topToolbar;
                              topToolbar?.refresh({ params: res.data as IFoundaton, refreshRemote: true });
                              _this.instanceTool.refreshFormAndTool(
                                event,
                                { ...rowData, ...res.data },
                                { detailFormName: CommandConstant.newOutLeftInstanceTaskDetailCommand }
                              );

                              const latest = page?.getComFnMapByName(
                                'sysTaskNewOutLatestCommand'
                              ) as InstanceLatestComponent;
                              latest?.refresh();
                            }
                          });
                        }
                      }
                    }
                  },
                  error: err => {
                    flag = true;
                    data.setLoading(false);
                    this.loading = false;
                  }
                });
                return;
              }
              _this.productDesignService
                .saveTask(
                  instanceData['GUID$']!,
                  instanceData['CLASSNAME$']!,
                  instanceData['RELATIONPRODUCT'] || '',
                  instanceData['RELATIONPRODUCT$CLASS'] || '',
                  instanceData['RELATIONITEM'],
                  instanceData['RELATIONITEM$CLASS'],
                  instanceData['NAME$']!,
                  instanceData['EXECUTOR'] || '',
                  instanceData['REMARK'] || '',
                  instanceData['COMPLETIONRATE'],
                  instanceData['PLANFINISHTIME'] || '',
                  instanceData['PLANSTARTTIME'] || '',
                  instanceData['RESPONSIBLE'],
                  instanceData['SENDER'] ? instanceData['SENDER'] : loginUser?.guid,
                  instanceData['SENDTIME'] || '',
                  instanceData['IMPORTANCELEVEL']?.value || instanceData['IMPORTANCELEVEL'] || ''
                )
                .subscribe({
                  next: res => {
                    if (res.success) {
                      obs.subscribe({
                        next: res2 => {
                          if (res2.success) {
                            this.loading = false;
                            if (res2.data) {
                              modal?.close();
                              _this.dppMessageService.success('basic.modalTip.SuccessfullyAssignedtask');
                              if (content!['type'] === 'table') {
                                (content as DppTableComponent).refreshData();
                              } else {
                                _this.instanceTool.refreshFormAndTool(
                                  event,
                                  { ...rowData, ...res2.data },
                                  { detailFormName: CommandConstant.newOutLeftInstanceTaskDetailCommand }
                                );
                                _this.instanceTool.refreshFormAndTool(
                                  event,
                                  { ...rowData, ...res2.data },
                                  { detailFormName: 'sysTaskNewOutLatestCommand' }
                                );
                              }
                            }
                          }
                          data.setLoading(false);
                          this.loading = false;
                        },
                        error: err => {
                          flag = true;
                          data.setLoading(false);
                          this.loading = false;
                        }
                      });
                    }
                    _this.setLoading(event, false);
                    this.loading = false;
                  },
                  error: _err => {
                    flag = true;
                    _this.setLoading(event, false);
                    this.loading = false;
                  }
                });
              data.setLoading(true);
              // 指派责任人
            } else {
              flag = true;
              this.loading = false;
            }
          }
        }
      ],
      canDrag: true
    },
    { dppRender: params }
  );
}

