/**
 * @description 启动  取消 提交 删除 暂停(仅工作台待办/分配任务)
 * @use 任务对象实例界面 工艺任务实例界面（启动  取消 删除）
 */
sysObjectTaskAction(event: EventInterface): void {
  const type = this.getExeCom<DppButtonComponent>(event)?.getUiModel()?.['name'];
  this.setLoading(event, true);
  const content = this.getContentCom(event);
  const rowData = this.getRowData(event);
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  let isSubmit = type == 'sysInstanceDetailObjectSubmitLinkCommand' || type == 'sysInstanceDetailObjectSubmitCommand';
  function fn(data?: DppFormComponent, modal?: any, setBtnLoading?: (loading: boolean) => void): void {
    setBtnLoading?.(true);
    const obs = _this.productDesignService.pauseAuditTask(
      rowData['GUID$'],
      rowData['CLASSGUID$'],
      rowData['CLASSNAME$'],
      '',
      type
    );
    obs.subscribe({
      next: res => {
        if (res.success) {
          if (type == 'sysInstanceDetailObjectStartLinkCommand' || type == 'sysInstanceDetailObjectStartCommand') {
            setBtnLoading?.(false);
            _this.dppMessageService.success('workbench.operationTips.SuccessfullyInitiated');
          } else {
            // 提交上传文件
            if (isSubmit) {
              const page = _this.getRootPageService(event);
              const object = data?.getFormData<IBaseData>(); /* 获取form 上传文件列表数据 */
              modal?.close();
              if (object?.['FILEPROPS$']?.length > 0) {
                _this.setLoading(event, true);
                _this.boas.saveObject(object!, false).subscribe({
                  next: res => {
                    if (res.success && res.data) {
                      setBtnLoading?.(false);
                      // 上传文件集合
                      if (res.data['FILERESULT']) {
                        const fileresult = res.data['FILERESULT'] as IBatchData;
                        if (fileresult.errorCnt !== 0) {
                          _this.dppMessageService.createTableMessage(
                            'warning',
                            'workbench.sysAssignTaskManagementTable.SubmitTask', // 提交任务
                            fileresult
                          );
                          // return;
                        } else {
                          _this.dppMessageService.success('common.operation.operationSuccess');
                        }
                      } else {
                        _this.dppMessageService.success('common.operation.operationSuccess');
                      }
                      const table = page.getComFnMapByName<DppTableComponent>(
                        CommandConstant.sysNewOutFileTaskTableCommand
                      );
                      table?.refreshData();
                      _this.instanceTool.refreshFormAndTool(
                        event,
                        { ...rowData, ...res.data },
                        { detailFormName: CommandConstant.newOutLeftInstanceTaskDetailCommand }
                      );
                      _this.getRootPageService(event)?.getComFnMapByName('sysTaskNewOutLatestCommand')?.['refresh']();
                    }
                    _this.setLoading(event, false);
                    setBtnLoading?.(false);
                  },
                  error: err => {
                    _this.setLoading(event, false);
                    setBtnLoading?.(false);
                  }
                });
              } else {
                // 刷新需要
                isSubmit = false;
              }
            } else {
              setBtnLoading?.(false);
              _this.dppMessageService.success('common.operation.operationSuccess');
            }
          }
          if (content!['type'] === 'table') {
            (content as DppTableComponent).refreshData();
          } else {
            if (type == 'sysInstanceDetailObjectDeleteCommand') {
              // 关闭页签
              _this.closeAction({ router: _this.router, closeNow: true });
              return;
            }

            if (!isSubmit) {
              const page = _this.getRootPageService(event);
              const table = page.getComFnMapByName<DppTableComponent>(CommandConstant.sysNewOutFileTaskTableCommand);
              table?.refreshData();

              page.refreshInstanceData({
                isRefreshSelf: true,
                callback: () => {
                  const table = page.getComFnMapByName<DppTableComponent>(
                    CommandConstant.sysNewOutFileTaskTableCommand
                  );
                  const topToolbar = table?.topToolbar;
                  topToolbar?.refresh({ params: res.data as IFoundaton, refreshRemote: true });
                  _this.refreshInstanceForm(page);
                  _this.getRootPageService(event)?.getComFnMapByName('sysTaskNewOutLatestCommand')?.['refresh']();
                }
              });
            }
          }
        } else {
          _this.msg.create('error', `${res.errorCode}:${res['errorMessage']}`);
        }
        _this.setLoading(event, false);
        setBtnLoading?.(false);
      },
      error: _err => {
        // 保存启动任务时的 400后端做的提醒
        setBtnLoading?.(false);
        _this.setLoading(event, false);
      }
    });
  }

  if (type == 'sysInstanceDetailObjectCancelCommand') {
    this.as.confirm('workbench.sysAssignTaskManagementTable.cancelTask', {
      title: '',
      footer: {
        nzOnOk: () => {
          fn();
        },
        nzOnCancel: () => {
          this.setLoading(event, false);
        }
      }
    });
    return;
  }
  if (isSubmit) {
    const model: any = {};
    model[SystemClassFieldEnum.GUID] = rowData[SystemClassFieldEnum.GUID];
    model[SystemClassFieldEnum.CLASSNAME] = rowData[SystemClassFieldEnum.CLASSNAME];
    model[SystemClassFieldEnum.UPDATETIME] = DppFormUtil.convertToDate(rowData[SystemClassFieldEnum.UPDATETIME])
      .getTime()
      .toString();
    const modal = this.as.openModal(
      {
        title: `${rowData['COMPLETIONRATE'] != '100'
          ? 'workbench.sysAssignTaskManagementTable.SubmitTaskDescription'
          : 'workbench.sysAssignTaskManagementTable.SubmitTask'
          }`,
        width: '600px',
        content: DppFormComponent,
        bodyStyle: { height: '200px', padding: '0 10px 0 0' },
        footer: [
          {
            label: 'common.button.cancel',
            type: 'default',
            onClick: (): void => {
              modal?.close();
              this.setLoading(event, false);
            }
          },
          {
            label: 'common.button.confirm',
            type: 'primary',
            onClick(data: DppFormComponent) {
              // 如果有附件
              const setBtnLoading = (loading: boolean): void => {
                this.loading = loading;
              };
              fn(data, modal, setBtnLoading);
            }
          }
        ],
        canDrag: true
      },
      {
        dppRender: {
          mParams: {
            name: 'UploadFileForm',
            isObject: false,
            mode: ModeTypeEnum.EDIT
          },
          name: 'UploadFileForm',
          data: model
        }
      }
    );
    modal.afterClose.subscribe(() => {
      this.setLoading(event, false);
    });
    return;
  }

