// 撤回事件
sysObjectWithDrawAction(event: EventInterface): void {
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const that = this;
  const type = this.getExeCom<DppButtonComponent>(event)?.getUiModel()?.['name'];
  const content = this.getContentCom(event);
  const rowData = this.getRowData(event);
  const params: DppSafeAny = {
    name: 'sysObjectWithDrawForm',
    mode: ModeTypeEnum.EDIT,
    isObject: false
  };
  const modal = this.as.openModal(
    {
      title: 'workbench.sysAssignTaskManagementTable.WithdrawTask', // 暂停任务
      width: '600px',
      content: DppFormComponent,
      bodyStyle: { height: '200px', padding: '0 10px 0 0' },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal?.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(data: DppFormComponent) {
            const formData = data.getFormData() as DppSafeAny;
            const isValid = data.onSubmit();
            if (isValid) {
              data.setLoading(true);
              this.loading = true;
              let obs: Observable<DppResponse<DppTaskData>>;
              obs = that.productDesignService.pauseAuditTask(
                rowData['GUID$'],
                rowData['CLASSGUID$'],
                rowData['CLASSNAME$'],
                formData['WITHDRAW'],
                type
              );
              obs.subscribe({
                next: res => {
                  modal?.close();
                  if (res.success) {
                    that.dppMessageService.success('common.operation.operationSuccess');
                    if (content!['type'] === 'table') {
                      (content as DppTableComponent).refreshData();
                    } else {
                      const page = that.getRootPageService(event);
                      const table = page.getComFnMapByName<DppTableComponent>(
                        CommandConstant.sysNewOutFileTaskTableCommand
                      );
                      table?.refreshData();
                      page.refreshInstanceData({
                        isRefreshSelf: true,
                        callback: () => {
                          const table = page.getComFnMapByName<DppTableComponent>(
                            CommandConstant.sysNewOutFileTaskTableCommand
                          );
                          const topToolbar = table?.topToolbar;
                          topToolbar?.refresh({ params: res.data as IFoundaton, refreshRemote: true });
                          that.refreshInstanceForm(page);
                          that
                            .getRootPageService(event)
                            ?.getComFnMapByName('sysTaskNewOutLatestCommand')
                            ?.['refresh']();
                        }
                      });
                    }
                  } else {
                    that.msg.create('error', `${res.errorCode}:${res['errorMessage']}`);
                  }
                  data.setLoading(false);
                  this.loading = false;
                },
                error: _res => {
                  modal.close();
                  data.setLoading(false);
                  this.loading = false;
                }
              });
            }
          }
        }
      ],
      canDrag: true
    },
    { dppRender: params }
  );
}

/**
 * @description 审核
 * @use 任务对象实例界面
 */
sysObjectAuditAction(event: EventInterface): void {
  const content = this.getContentCom(event);
  const rowData = this.getRowData(event);
  const params: DppSafeAny = {
    name: 'sysObjectAuditForm',
    mode: ModeTypeEnum.EDIT,
    isObject: false
  };
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const this_ = this;
  function auditFn(data: DppFormComponent, type?: string, setBtnLoading?: (loading: boolean) => void): void {
    data.setLoading(true);
    setBtnLoading?.(true);
    let obs: Observable<DppResponse<DppTaskData>>;
    obs = this_.productDesignService.pauseAuditTask(
      rowData['GUID$'],
      rowData['CLASSGUID$'],
      rowData['CLASSNAME$'],
      data.getFormData()?.['ANNOTATIONS'],
      type
    );
    obs.subscribe({
      next: res => {
        modal?.close();
        if (res.success) {
          this_.dppMessageService.success('common.operation.operationSuccess');
          if (res.data) {
            if (content!['type'] === 'table') {
              (content as DppTableComponent).refreshData();
            } else {
              this_.instanceTool.refreshFormAndTool(
                event,
                { ...rowData, ...res.data },
                { detailFormName: CommandConstant.newOutLeftInstanceTaskDetailCommand }
              );
              this_.getRootPageService(event)?.getComFnMapByName('sysTaskNewOutLatestCommand')?.['refresh']();
            }
          }
        } else {
          this_.msg.create('error', `${res.errorCode}:${res['errorMessage']}`);
        }
        data.setLoading(false);
        setBtnLoading?.(false);
      },
      error: _res => {
        modal.close();
        data.setLoading(false);
        setBtnLoading?.(false);
      }
    });
  }
  const modal = this.as.openModal(
    {
      title: 'common.field.Audittask',
      width: '600px',
      content: DppFormComponent,
      bodyStyle: { height: '300px', padding: '0 10px 0 0' },
      footer: [
        {
          label: 'basic.common.command.sysApprovalRejectCommand',
          type: 'default',
          onClick(data: DppFormComponent) {
            const isValid = data.onSubmit();
            if (isValid) {
              const setBtnLoading = (loading: boolean): void => {
                this.loading = loading;
              };
              auditFn(data, 'reject', setBtnLoading);
            }
          }
        },
        {
          label: 'basic.common.command.sysApprovalAcceptCommand',
          type: 'primary',
          onClick(data: DppFormComponent) {
            const isValid = data.onSubmit();
            if (isValid) {
              const setBtnLoading = (loading: boolean): void => {
                this.loading = loading;
              };
              auditFn(data, 'complete', setBtnLoading);
            }
          }
        }
      ],
      canDrag: true
    },
    { dppRender: params }
  );
}

/**
 * @description 新增子任务=》分配任务确认按钮 和 指派按钮
 * @use 任务对象实例界面
 */
sysBatchAddAdmeaConfirmAction(event: EventInterface): void {
  this.setLoading(event, true);
  const loginUser = this.autoUserService.getUser();
  const type = this.getExeCom<DppButtonComponent>(event)?.getUiModel()?.name;
  const page = this.getRootPageService(event);
  const content = this.getContentCom(event) as DppToolbarComponent;
  const drawer = content?.['dppRender']?.['innerSend']?.['drawerSelf']?.() as DppNzDrawerRef;
  const form = page.getComFnMapByName('sysBatchAddAdmeaFormCommand') as DppFormComponent;
  const table = content?.['dppRender']?.['innerSend']?.['triggerInstance']?.() as DppTableComponent;
  const parentData = table?.dppRender?.dParams?.['linkDataSource'] as IFoundaton;
  const isValid = form.onSubmit();
  const formData = form.getFormData() as any[];
  if (isValid) {
    form.setLoading(true);
    const object = formData.map(item => {
      return {
        ParentTask: parentData.GUID$,
        SENDER: loginUser?.guid,
        EXECUTOR: item?.['EXECUTOR'],
        ParentTask$CLASS: parentData.CLASSGUID$,
        RelationItem: item?.['RELATIONITEM'],
        RelationItem$CLASS: item?.['RELATIONITEM$CLASS'],
        PLANFINISHTIME: item['PLANFINISHTIME'],
        PLANSTARTTIME: item['PLANSTARTTIME'],
        NAME$: item['NAME$'],
        // PLANFINISHTIME: item['PLANFINISHTIME'] ? new Date(item['PLANFINISHTIME']).getTime().toString() : '',
        // PLANSTARTTIME: item['PLANSTARTTIME'] ? new Date(item['PLANSTARTTIME']).getTime().toString() : '',
        REMARK: item['REMARK'],
        IMPORTANCELEVEL: item['IMPORTANCELEVEL']
      };
    });
    let autoAssign = 'N';
    if (type == 'sysBatchAddAdmeaAssignCommand') {
      autoAssign = 'Y';
    }
    // return;
    this.productDesignService
      .batchCreateTask(parentData['RELATIONPRODUCT']!, parentData['RELATIONPRODUCT$CLASS']!, object, autoAssign)
      .subscribe({
        next: res => {
          if (res.success && res.data) {
          }
          if (res.data?.successCnt && res.data?.successCnt === res.data?.totalCnt) {
            this.dppMessageService.success('common.operation.newSuccess');
          } else {
            this.errorMessageService.showMessage(event, res);
          }
          this.setLoading(event, false);
          form.setLoading(false);
          drawer?.close();
          table?.refreshData();
        },
        error: _err => {
          drawer?.close();
          this.setLoading(event, false);
          form.setLoading(false);
          table?.refreshData();
        }
      });
  } else {
    this.setLoading(event, false);
  }
}

