/**
 * @description 产品设计批量指派任务
 * @use 产品设计/产品管理/任务管理-批量指派任务
 */
batchAssignmentAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const bs = this.getExeCom(event) as DppButtonComponent;
  const model = bs.getUiModel() as ButtonIUiModel;
  let modal: DppNzModalRef | null = null;

  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;

  //上一级页面的行数据
  const parentData = table.modelManager.initParams['linkDataSource']?.['origin'] as any;

  const { key, classIDKey, classNameKey, fullNameKey } = useKey();

  const params: IFormRender = {
    name: FormBatchConfigModelEnum.SYSBATCHNEWASSIGNMENTTASKFORM,
    mParams: {
      mode: ModeTypeEnum.BATCHCREATE
    },
    dParams: {
      className: model.action!['className']
    },
    data: {
      RELATIONPRODUCT: parentData[key],
      RELATIONPRODUCT$CLASS: parentData[classIDKey],
      RELATIONPRODUCT$FULLNAME: parentData[fullNameKey],
      RELATIONPRODUCT$CLASSNAME: parentData[classNameKey]
    }
  };

  modal = openDialog(params, onClickFn);

  function onClickFn(contentComponent: DppFormComponent): void {
    const isValid = contentComponent.onSubmit();
    if (!isValid) {
      return;
    }
    contentComponent.setLoading(true);
    _this.setLoading(event, true);
    const taskList = contentComponent.getFormData() as [];

    _this.productDesignService.batchCreateTask(parentData[key], parentData[classIDKey], taskList).subscribe({
      next: (res: DppResponse<IBatchData>) => {
        if (res.success && res.data) {
          if (res.data.successCnt && res.data.successCnt === res.data?.totalCnt) {
            _this.dppMessageService.success('common.operation.newSuccess');
          } else {
            _this.errorMessageService.showMessage(event, res);
          }
        }
        contentComponent.setLoading(false);
        _this.setLoading(event, false);
        modal?.close();
        table.refreshData();
      },
      error: _res => {
        _this.setLoading(event, false);
        modal?.close();
        contentComponent.setLoading(false);
      }
    });
  }

  function openDialog(params: any, onClickFn: any): DppNzModalRef {
    return _this.as.openModal(
      {
        title: 'productdesign.toolbar.sysNewAssignmentTaskToolbar',
        content: DppFormComponent,
        width: '75vw',
        bodyStyle: { height: '420px', padding: '0' },
        footer: [
          {
            label: 'common.button.cancel',
            type: 'default',
            onClick: (): void => {
              modal?.close();
            }
          },
          {
            label: 'common.button.confirm',
            type: 'primary',
            onClick: onClickFn
          }
        ]
      },
      { dppRender: params }
    );
  }
}

// 删除产品(操作栏删除和 批量删除)
sysMaintenanceProductDeleteAction(event: EventInterface): void {
  const getDataValue = this.getRowData(event) as IFoundaton;
  const objectGuid = {
    classGuid: '',
    guid: ''
  };
  this.setLoading(event, true);
  if (getDataValue?.GUID$) {
    // 单个删除操作
    objectGuid.classGuid = getDataValue['CLASSGUID$']!;
    objectGuid.guid = getDataValue['GUID$'];
    if (getDataValue['level'] === 1) {
      objectGuid.classGuid = getDataValue['END2#CLASSGUID$'];
      objectGuid.guid = getDataValue['END2#GUID$'];
    }
    // 发送请求
    this.productDesignService.productActive(objectGuid, 'delete').subscribe({
      next: res => {
        if (res.success) {
          if (res.data) {
            this.dppMessageService.success('common.operation.deleteSuccess');
            this.contentComCallback(event, {
              action: EventCallbacksActionName.ADDPARAMANDSEARCH
            });
          }
        }
        this.setLoading(event, false);
      },
      error: _res => {
        this.setLoading(event, false);
      }
    });
  } else {
    // 批量删除操作
    const objects = [];
    for (const item of this.getSelectData(event)) {
      if (item['level'] === 1) {
        objects.push({
          CLASSNAME$: item['END2#CLASSNAME$'],
          GUID$: item['END2#GUID$']
        });
      } else {
        objects.push({
          GUID$: item['GUID$'],
          CLASSNAME$: item['CLASSNAME$']
        });
      }
    }
    // 发送请求
    this.productDesignService.batchDeleteObj(objects).subscribe({
      next: res => {
        if (res.success) {
          if (res.data) {
            if (res.data.successCnt && res.data.successCnt === res.data.totalCnt) {
              this.dppMessageService.success('common.operation.deleteSuccess');
            } else {
              this.errorMessageService.showMessage(event, res);
            }
            if (res.data.successCnt) {
              this.contentComCallback(event, {
                action: EventCallbacksActionName.ADDPARAMANDSEARCH
              });
            }
          }
        }
        this.setLoading(event, false);
      },
      error: _res => {
        this.setLoading(event, false);
      }
    });
  }
}

