/**
 * @description 转派任务
 * @use 设计任务 工艺任务 详情界面
 */
transferAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const rowData = this.getRowData(event);
  let flag = true;
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  const dataValue = this.getRowData(event);
  const formRender: IFormRender = {
    name: 'sysInstanceDetailObjectTransferForm',
    mParams: {
      mode: dataValue['EXECUTESTATUS$NAME'] === 'COP' ? ModeTypeEnum.VIEW : ModeTypeEnum.EDIT,
      isObject: false,
      expression: 'EXECUTOR:required=true'
    },
    dParams: {
      className: dataValue['CLASSNAME$'],
      guid: dataValue['GUID$'],
      REMARK: dataValue?.['REMARK'],
      RELATIONITEM: dataValue['RELATIONITEM'],
      UPDATECONTENT: dataValue?.['UPDATECONTENT']
    }
  };
  const modal = this.as.openModal(
    {
      title: 'common.button.changeTask',
      width: '600px',
      closable: true,
      bodyStyle: {
        height: '400px',
        padding: '0'
      },
      content: DppFormComponent,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          show: dataValue['EXECUTESTATUS$NAME'] !== 'completed',
          onClick(data) {
            const isValid = data.onSubmit();
            const formData = data.getFormData();
            const isChange = data.isChanged();
            if (isValid) {
              data.setLoading(true);
              this.loading = true;
              if (!flag) {
                this.loading = false;
                return;
              } else {
                flag = false;
              }
              if (!isChange && !formData?.['FILEPROPS$']?.length) {
                _this.dppMessageService.warning('workbench.operationTips.NoActualChanges');
                flag = true;
                data.setLoading(false);
                this.loading = false;
                return;
              }

              let obs;
              obs = _this.productDesignService.assignOtherPerformer(
                false,
                formData.EXECUTOR,
                formData.NAME$,
                dataValue['GUID$'],
                dataValue['CLASSGUID$'],
                dataValue['CLASSNAME$'],
                formData.REMARK,
                formData.UPDATECONTENT,
                formData['PLANFINISHTIME'] || '',
                undefined,
                undefined,
                formData.RELATIONITEM,
                formData.RELATIONITEM$CLASS,
                formData
              );
              obs.subscribe({
                next: res => {
                  if (res.success) {
                    const page = _this.getRootPageService(event);
                    const refreshFn = (): void => {
                      modal.close();
                      _this.setLoading(event, false);
                      _this.dppMessageService.success('common.modalTip.assignTasksSucceed');

                      if (table.type === 'form') {
                        const table = page.getComFnMapByName<DppTableComponent>(
                          CommandConstant.sysNewOutFileTaskTableCommand
                        );
                        table?.refreshData();
                        page.refreshInstanceData({
                          isRefreshSelf: true,
                          callback: () => {
                            const table = page.getComFnMapByName<DppTableComponent>(
                              CommandConstant.sysNewOutFileTaskTableCommand
                            );
                            const topToolbar = table?.topToolbar;
                            topToolbar?.refresh({ params: res.data as IFoundaton, refreshRemote: true });
                            _this.refreshInstanceForm(page);
                            _this
                              .getRootPageService(event)
