/**
 * @description 关注/取消关注
 * @use 产品设计/产品管理｜工作台
 * @param event
 */
sysChangeAttentionAction(event: EventInterface): void {
  const data = this.getRowData(event);
  const node = this.getNode(event) as RowNode;
  const table = this.getContentCom(event) as unknown as DppTableComponent;

  const { myAttentionKey, modaNameKey, classNameKey, key } = useKey();

  const value = data[myAttentionKey];
  // 是否是工作台
  const isWorkPlat = !!data[modaNameKey];
  const type = value === 'Y' ? 'unSubscribe' : 'subscribe';

  const params = {
    className: data[classNameKey],
    guid: isWorkPlat ? data['INSTANCEGUID'] : data[key]
  };
  this.setLoading(event, true);

  this.productDesignService.productActive(params, type).subscribe(
    _res => {
      if (_res.success) {
        sendDataObj.sendNotify('MYATTENTION_CHANGE_NOTICES', data);
        const updateData = {
          ISMYATTENTION$: value === 'Y' ? 'N' : 'Y'
        };
        table?.refreshNode?.(node, updateData);
      }
      this.setLoading(event, false);
    },
    _err => {
      this.setLoading(event, false);
    }
  );
}

