// 新建产品库
sysNewProductLibraryAction(event: EventInterface): void {
  let title = 'productdesign.command.sysNewProductLibraryCommand';
  const formParams: IFormRender = {
    name: FormConfigModelEnum.NEWPRODUCTFORM,
    mParams: {
      mode: ModeTypeEnum.EDIT
    }
  };

  const table = this.getContentCom<DppTableComponent>(event);

  const onConfirm = (render: {
    formCpn: DppFormComponent;
    modal: DppNzModalRef;
    table: DppTableComponent;
    setBtnLoading: (loading: boolean) => void;
  }): void => {
    const { formCpn, modal, table, setBtnLoading } = render;
    const isValid = formCpn.onSubmit();
    const tranObj = formCpn.getFormData() as any;

    let request = new Observable<DppResponse<IFoundaton>>();

    if (isValid) {
      const formData = new FormData();
      formCpn.setLoading(true);
      setBtnLoading(true);
      if (!isEmpty(tranObj.FILEPROPS$) && !isEmpty(tranObj.DWFILES)) {
        if (tranObj.DWFILES.length > 0) {
          tranObj.DWFILES.forEach((file: any) => {
            delete file.url;
            const clonedFile = new File([file], file.uid, {
              type: file.type
            });
            formData.append('dwFile', clonedFile);
          });
        }
        formData.append('object', JSON.stringify(tranObj));
        request = this.productDesignService.saveLibrary(formData as unknown as Record<string, string>, true);
      } else {
        request = this.productDesignService.saveLibrary(tranObj, false);
      }
      request.subscribe({
        next: res => {
          modal.close();
          if (res.success) {
            this.dppMessageService.success('productdesign.operation.createProductLibSuccess');
            table.refreshData();
            // 打开团队界面
            this.openTeam(res.data as Record<string, string>, table);
          }
          formCpn.setLoading(false);
          setBtnLoading(false);
        },
        error: _err => {
          // modal.close();
          formCpn.setLoading(false);
          setBtnLoading(false);
        }
      });
    }
  };

  const modal = this.as.openModal(
    {
      title: title,
      width: '650px',
      height: 'auto',
      bodyStyle: { maxHeight: '400px' },
      content: DppFormComponent,
      footer: [
        {
          label: 'common.button.cancel', // 按钮文本
          type: 'default',
          onClick: () => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm', // 按钮文本
          type: 'primary',
          isEnter: true,
          onClick(formCpn: DppFormComponent) {
            const setBtnLoading = (loading: boolean): void => {
              this.loading = loading;
            };
            onConfirm({ formCpn, modal, table, setBtnLoading });
          }
        }
      ]
    },
    {
      dppRender: formParams
    }
  );
}

