// 产品库模板/批量启用、禁用
sysTMBatchEnableDisableAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const selectNodes = table.getCheckedNodes();
  const action = this.getExeModel(event)['action'];
  let isValid = 'Y';
  switch (action['batchType']) {
    case 'enable':
      isValid = 'Y';
      break;
    case 'disable':
      isValid = 'N';
      break;
  }

  if (selectNodes.length > 0) {
    let params: { TEMPLATEGUID: string[]; ISVALID: string } = {
      TEMPLATEGUID: [],
      ISVALID: isValid
    };
    selectNodes.forEach(item => {
      params['TEMPLATEGUID'].push(item.origin['GUID$']);
    });
    this.productDesignService.TMBatchEnableDisable(params).subscribe({
      next: res => {
        if (res.data && res.success) {
          // 总数量 成功数量  失败数量
          const { successCnt, totalCnt, errorCnt } = res.data;
          if (successCnt && successCnt === totalCnt) {
            this.dppMessageService.success('common.operation.operationSuccess');
            table.refreshData();
          } else {
            this.errorMessageService.showMessage(event, res);
            //全部失败， 不需要刷新表格
            if (totalCnt === errorCnt) return;
            table.refreshData();
          }
        }
      }
    });
  }
}

