sysProductModOwnerAction(event: EventInterface): void {
  const rowData = this.getRowData(event);
  const table = this.getContentCom(event) as DppTableComponent;

  const ownerID = rowData['OWNERUSER$'];
  const ownerName = rowData['OWNERUSER$NAME'];

  this.as.createDialog(DialogTypeEnum.USER, ownerID, {
    title: 'basic.common.command.ModifyOwnerCommand',
    width: '600px',
    bodyStyle: { height: '350px' },
    onOk: (userListComponent: UserListComponent): void => {
      const datePipe = new DatePipe('zh-CN');
      const currentDate = datePipe.transform(new Date(), 'yyyy-MM-dd HH:mm:ss', 'GMT+8');

      const selectedNode = userListComponent.getSelectedData() as ListNode;
      if (ownerID === selectedNode['GUID']) {
        this.dppTranslateService
          .get('common.operation.owneruserNotChanged', { owneruser: ownerName })
          .subscribe(res => {
            this.dppMessageService.warning(res);
          });
        return;
      }

      const params = {
        LIBRARYGUID: rowData['LIBRARYGUID$'],
        GUID$: rowData['GUID$'],
        CLASSNAME$: rowData['CLASSNAME$'],
        CLASSGUID$: rowData['CLASSGUID$'],
        OWNERUSERGUID$: userListComponent ? selectedNode['GUID'] : ownerID,
        UPDATETIME$: currentDate!,
        DEALBOM: 'N'
      };

      this.productDesignService.productManageModifyOwner(params).subscribe({
        next: res => {
          if (res.data && res.success) {
            this.dppMessageService.success('common.operation.operationSuccess');
            table.refreshData();
            this.setLoading(event, false);
          }
        },
        error: _err => {
          this.setLoading(event, false);
        }
      });
    }
  });
}

