sysOpenMaanageProductAction(event: EventInterface): void {
  const rowData = this.getRowData(event) as any;

  if (!rowData) {
    return;
  }

  this.setLoading(event, true);

  // 合并后的数据对象
  let mergedData = { ...rowData };

  // 内函数：合并对象数据到参数中
  const mergeObjectDataToParams = (objectData: Record<string, unknown>): void => {
    if (objectData) {
      // 将对象数据合并到新对象中，不修改原始 rowData
      mergedData = {
        ...rowData,
        // 这里的key不能改  ObjectData
        // 1模型中，使用这个字段判断替代设置的值
        // 点击替代申请列的按钮时，需要用到这个对象里面的值
        objectData: objectData,
        currentPage: 'product'
      };
    }
  };

  // 内函数：构建表格渲染参数
  const buildTableRenderParams = (): IRenderParameterNew<IUiModel> => {
    return {
      name: 'sysBOMTable',
      mParams: {
        dataSource: `/ItemManagement/IBomService/listBOM?templateName=BOM&guid=$END2#GUID$&className=$END2#CLASSNAME$&level=$expandLevel`,
        rootSource: `/ItemManagement/IBomService/listRoot?templateName=BOM&GUID$=${mergedData['GUID$']}&className=${mergedData['CLASSNAME$']}`,
        floatToolbar: 'sysInstanceBOMFloatToolbar',
        linkDataSource: { dParams: mergedData },
        toolbar: 'sysInstanceBOMToolbar'
      },
      dParams: { ...mergedData, currentPage: 'product' }
    };
  };

  // 内函数：生成产品标题
  const generateProductTitle = (data: Record<string, any>): Observable<string> => {
    const titleKey = 'productdesign.command.sysMaintenanceProductCommand';
    const botitleKey = data['BOTITLE$'] ?? data['END2#BOTITLE$'];
    const fullnameKey = data['FULLNAME$'] ?? data['END2#FULLNAME$'];

    const botitle = this.tranPipe.transform(botitleKey);
    const fullname = this.tranPipe.transform(fullnameKey);

    return this.dppTranslateService.get(titleKey).pipe(
      map(title => {
        return `【${botitle}】${fullname} (${title})`;
      })
    );
  };

  // 内函数：打开维护产品模态框
  const openMaintainProductModal = (title: string, tableDppRender: IRenderParameterNew<IUiModel>): void => {
    sendDataObj.sendNotify('singleDialog', () => { });

    const modalRef = this.as.openModal(
      {
        content: DppTableComponent as unknown as any,
        title: title,
        footer: [
          {
            label: 'common.button.confirm',
            type: 'primary',
            onClick: (data: DppTableComponent) => {
              // 调用猜你想逻辑代码 维护产品=》任务管理
              const obj = {
                data: mergedData,
                modal: { guess: 'TASK_MANAGEMENT', action: { process: 'TASK_MANAGEMENT' } },
                bs: () => modalRef
              };
              handelGuessSendNotify(obj, this.commonService);
              modalRef.close();
            }
          }
        ],
        closable: true,
        full: true
      },
      { isFatherSon: true, dppRender: tableDppRender }
    );
  };

  // 内函数：获取对象数据
  const getObjectData = (data: Record<string, any>): Observable<unknown> => {
    const guid = data['GUID$'];
    const className = data['CLASSNAME$'];
    const bomTemplate$ = this.productDesignService.getBOMTemplate({ guid, className }, 'BOM', 'Y');
    const object$ = this.boas.getObject(className, guid);
    return forkJoin({
      bomTemplate: bomTemplate$,
      objectData: object$
    }).pipe(
      map(({ bomTemplate, objectData }) => {
        // 如果有可用的BOM模板，BOM导入按钮才可用
        const hasBOMTemplate = Object.keys(bomTemplate.data!).length > 0;
        return {
          ...objectData.data,
          HASBOMTEMPLATE: hasBOMTemplate
        };
      })
    );

    // return this.boas.getObject(className, guid).pipe(
    //   map(response => {
    //     if (response && response.success) {
    //       return response.data;
    //     }
    //     return null;
    //   })
    // );
  };

  // 主要流程：先获取对象数据，然后进行后续操作
  getObjectData(rowData)
    .pipe(
      switchMap(objectData => {
        // 将获取到的对象数据合并到参数中
        mergeObjectDataToParams(objectData as Record<string, unknown>);

        // 构建表格渲染参数
        const tableDppRender = buildTableRenderParams();

        // 生成标题并返回 Observable，同时传递 tableDppRender
        return generateProductTitle(mergedData).pipe(map(title => ({ title, tableDppRender })));
      }),
      finalize(() => {
        this.setLoading(event, false);
      })
    )
    .subscribe({
      next: ({ title, tableDppRender }) => {
        openMaintainProductModal(title, tableDppRender);
      },
      error: error => {
        console.error('维护产品架构失败:', error);
        // 这里可以添加错误提示
      }
    });
}

