// 编辑节点
sysEditFolderAction(event: EventInterface): void {
  const contentCom = this.getContentCom<IBaseContentComponent>(event);
  const rowData = this.getRowData(event);
  const folderData = rowData?.['origin'];
  const params = {
    GUID: folderData['GUID'],
    name: 'ModifyFolderForm',
    mode: ModeTypeEnum.EDIT,
    model: {
      GUID: folderData['GUID'],
      NAME$: folderData['FOLDERNAME']
    }
  };
  const modal = this.as.openModal(
    {
      title: 'basic.common.command.sysModifyFolderCommand',
      width: '600px',
      height: '230px',
      content: DppFormComponent,
      footer: [
        {
          label: 'basic.common.button.reset',
          onClick: data => {
            data.reset();
          }
        },
        {
          label: 'common.button.confirm', // 按钮文本
          type: 'primary',
          onClick: data => {
            if (data.getFormData().name === '') {
              data.checkFormValidate();
              this.dppMessageService.error('basic.modalTip.nameIsRequired');
              return;
            }
            data.setLoading(true);
            let obs: Observable<DppResponse<IFoundaton>>;
            obs = this.commonSpaceService.saveFolder({
              GUID: data.getFormData().GUID,
              FOLDERNAME: data.getFormData().NAME$,
              DESCRIPTION: data.getFormData().DESCRIPTION
            });
            obs.subscribe({
              next: res => {
                if (res.success && res.data) {
                  this.dppMessageService.success('basic.modalTip.editSucceed');
                  if (contentCom?.type === 'menu') {
                    contentCom?.['getDataInit']();
                  }
                }
                data.setLoading(false);
              },
              error: err => {
                data.setLoading(false);
              }
            });
            modal?.close();
          }
        }
      ]
    },
    { dppRender: params }
  );
}

// 添加节点
sysNewFolderAction(event: EventInterface): void {
  const contentCom = this.getContentCom(event);
  const rowData = this.getRowData(event);
  const modal = this.as.openModal(
    {
      title: 'basic.common.command.sysNewFolder',
      width: '600px',
      height: 'auto',
      closable: true,
      content: DppFormComponent,
      bodyStyle: {
        maxHeight: '500px'
      },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: formCpn => {
            let isValid = formCpn.onSubmit();
            const formData = formCpn.getFormData();
            const params: Array<{ PARENTGUID: string; FOLDERNAME: string }> = [];
            formData.forEach((item: { FOLDERNAME: string }) => {
              params.push({
                PARENTGUID: rowData?.['key']!,
                FOLDERNAME: item.FOLDERNAME
              });
            });
            if (isValid) {
              formCpn.setLoading(true);
              this.commonSpaceService.batchSaveFolder(params).subscribe({
                next: res => {
                  if (res.success && res.data) {
                    if (res.data?.successCnt && res.data?.successCnt === res.data?.totalCnt) {
                      this.messageService.success('common.operation.newSuccess');
                    } else {
                      this.errorMessageService.showMessage(event, res);
                    }
                    res.data?.successCnt ? contentCom?.['getDataInit']() : '';
                  }
                  formCpn.setLoading(false);
                },
                error: err => {
                  formCpn.setLoading(false);
                }
              });
              modal.close();
            }
          }
        }
      ]
    },
    {
      dppRender: {
        name: FormBatchConfigModelEnum.BATCHNEWFOLDERFORM,
        mode: ModeTypeEnum.BATCHCREATE,
        isObject: false
      }
    }
  );
}

