/**
 * @description 移动文件夹 单个
 * @use 产品设计二级页面｜公共空间| 工艺管理二级页面
 * @param event
 */
sysPublicSpaceMoveAction(event: EventInterface): void {
  const page = this.getRootPageService(event);
  const table = this.getContentCom(event) as unknown as DppTableComponent;

  const data = this.getRowData(event) as Record<string, DppSafeAny>;
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;

  simpleMove();
  function simpleMove(): void {
    // 原文件夹ID
    let originFolderID = data[_this.MOVE_KEYS.folderIDKey];
    const okFn = (targetNode: NzTreeNodeOptions): Observable<unknown> => {
      return _this.commonSpaceService.moveto(
        data[_this.MOVE_KEYS.masterKey],
        data[_this.MOVE_KEYS.key],
        data[_this.MOVE_KEYS.classNameKey],
        data[_this.MOVE_KEYS.folderIDKey],
        targetNode.key,
        data[_this.MOVE_KEYS.dataTypeKey]
      );
    };
    openMoveDialog(okFn, originFolderID);
  }
  function openMoveDialog(okFn: any, GUID?: string): void {
    const modal = _this.as.openModal(
      {
        title: 'common.command.sysMoveFileCommand',
        width: '480px',
        bodyStyle: { height: '500px', padding: '10px', overflowY: 'hidden' },
        uiType: 'menuBaseTree',
        footer: [
          {
            label: 'common.button.confirm',
            type: 'primary',
            onClick(menu: MenuBaseTreeComponent) {
              const targetNode = menu.getSelectedData();
              if (GUID && GUID === targetNode.key) {
                _this.dppMessageService.warning('common.operation.unchanged');
                return;
              }
              if (!targetNode) {
                _this.dppMessageService.warning('basic.modalTip.failedMoveProduct');
                return;
              }
              const res$ = okFn(targetNode);
              this.loading = true;
              res$.subscribe(
                (res: DppResponse<IBatchData>) => {
                  if (res.success) {
                    if (res.data?.errorCnt) {
                      // _this.messageService.createTableMessage('warning', '失败原因', res['data']);
                      _this.errorMessageService.showMessage(event, res);
                    }
                    if (res.data!.successCnt && res.data!.totalCnt === res.data!.successCnt) {
                      _this.dppMessageService.success('basic.modalTip.successfullyMoveProduct');
                    }
                    // 执行刷新 ：单个移动和批量移动有成功的时执行
                    if (res['data']!.successCnt != 0) {
                      const pageService = _this.getRootPageService(event);
                      const menu = CommonEventUtil.getDesignLibraryMenuCom(pageService) as DppMenuComponent;
                      menu?.refresh();
                    }
                    if (page) {
                      page.refreshInstanceData({ isRefreshSelf: true });
                    }
                    modal.close();
                  }
                  this.loading = false;
                  _this.setLoading(event, false);
                },
                () => {
                  this.loading = false;
                  _this.setLoading(event, false);
                }
              );
            }
          }
        ]
      },
      {
        dppRender: assembParams({
          action: {
            params: {},
            toolbar: 'sysBaseMenuToolBar',
            url: DppUrlConfig.commonOperate.listLibraryFolder,
            childURL: DppUrlConfig.commonOperate.listLibraryFolder,
            GUID,
            triggerInstance: () => table
          }
        })
      }
    );
  }
}

