  const contentCom = this.getContentCom<IBaseComponent>(event);
  const rowData = this.getRowData(event);
  let modal: DppNzModalRef;

  const params = {
    name: 'ModifyFolderForm',
    data: {
      GUID$: rowData['GUID$'],
      DESCRIPTION: rowData['DESCRIPTION'],
      NAME$: rowData['NAME$']
    },
    mParams: {
      mode: ModeTypeEnum.EDIT,
      isObject: false
    }
  };

  const onOk = (formInstance: DppFormComponent): void => {
    const valid = formInstance.onSubmit();
    if (!valid) {
      this.dppMessageService.error('basic.modalTip.nameIsRequired');
      return;
    }
    const formData = formInstance.getFormData() as Record<string, string>;

    formInstance.setLoading(true);
    let save$ = this.commonSpaceService.saveFolder({
      GUID: formData['GUID$'],
      FOLDERNAME: formData['NAME$'],
      DESCRIPTION: formData['DESCRIPTION']
    });

    save$
      .pipe(
        finalize(() => {
          formInstance.setLoading(false);
        })
      )
      .subscribe({
        next: res => {
          if (res.success && res.data) {
            this.dppMessageService.success('basic.modalTip.editSucceed');
            const pageService = this.getRootPageService(event);
            const list = [
              MenuNameEnum.LIBRARYMENU,
              MenuNameEnum.ECIMPACTANALYSISMENU,
              MenuNameEnum.DETAILMENU,
              MenuNameEnum.TEMPLATEMANAGEMENU,
              MenuNameEnum.PROCESS
            ];
            let menu: DppMenuComponent;
            for (let i = 0; i < list.length; i++) {
              menu = pageService.getComFnMapByName(list[i]) as DppMenuComponent;
              if (menu) {
                menu.refresh();
                break;
              }
            }
            modal?.close();
          }
        }
      });
  };

  const openModal = (onOk: any, params: any): DppNzModalRef => {
    return this.as.openModal(
      {
        title: 'basic.common.command.sysModifyFolderCommand',
        width: '600px',
        height: '230px',
        content: DppFormComponent,
        footer: [
          {
            label: 'basic.common.button.reset',
            onClick: data => {
              data.reset();
            }
          },
          {
            label: 'common.button.confirm', // 按钮文本
            type: 'primary',
            onClick: form => {
              onOk.call(this, form);
            }
          }
        ]
      },
      { dppRender: params }
    );
  };

  modal = openModal(onOk, params);
}

