// 新增角色（可批量）
sysNewRoleAction(event: EventInterface): void {
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  const table = this.getContentCom(event) as unknown as DppTableComponent;

  const libguid = table.queryCondition?.params?.get('LIBRARYGUID');
  const formParams: IFormRender = {
    name: FormBatchConfigModelEnum.BATCHNEWROLEFORM,
    mParams: {
      mode: ModeTypeEnum.BATCHCREATE,
      isObject: false
    },

    data: { libguid }
  };

  const modal = this.as.openModal(
    {
      title: 'publicspace.modal.newRole',
      width: '750px',
      height: 'auto',
      closable: true,
      bodyStyle: {
        maxHeight: '500px'
      },
      openModalCloseDrawer: false,
      content: DppFormComponent,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick(formCpn: DppFormComponent) {
            const isValid = formCpn.onSubmit();
            const formData = formCpn.getFormData() as any;

            const params: Array<{ LIBRARYGUID: string; ROLENAME: string; DESCRIPTION: string }> = [];
            formData.forEach((item: { ROLENAME: string; DESCRIPTION: string }) => {
              params.push({
                LIBRARYGUID: libguid as string,
                ROLENAME: item.ROLENAME,
                DESCRIPTION: item.DESCRIPTION ?? ''
              });
            });
            if (isValid) {
              this.loading = true;
              formCpn.setLoading(true);
              _this.commonSpaceService.batchSaveRole(params).subscribe({
                next: res => {
                  if (res.success && res.data) {
                    this.loading = false;
                    formCpn.setLoading(false);
                    modal.close();
                    const { successCnt, totalCnt, details, errorCnt } = res.data;
                    if (successCnt === totalCnt) {
                      _this.dppMessageService.success('common.operation.operationSuccess');
                    } else {
                      _this.errorMessageService.showMessage(event, res);
                    }

                    const successAdd = details
                      .filter((item: any) => item.result === 'SUCCESS')
                      .map((item: any) => item.data);

                    if (successAdd.length > 0) {
                      table.applyTransaction({
                        add: successAdd
                      });
                    }
                  }
                },
                error: err => {
                  this.loading = false;
                  formCpn.setLoading(false);
                }
              });
            }
          }
        }
      ]
    },
    {
      dppRender: formParams
    }
  );
}

