// eslint-disable-next-line @typescript-eslint/no-explicit-any
openPermissionDialog(roleParams: any, libGuid: { LIBRARYGUID: string; ROLEGUID?: string }, rowData: any): void {
  this.commonSpaceService.getPermissionType({ LIBRARYGUID: libGuid.LIBRARYGUID }).subscribe({
    next: res => {
      if (res.success) {
        const permTableParams = {
          typeParams: res.data,
          title: roleParams ? '' : `: ${rowData.ROLENAME}`,
          // title: roleParams ? '' : '',
          width: roleParams ? '70%' : '40%',
          roleParams,
          permissions: [],
          allPermission: !!roleParams
        };
        this.openDialog.call(this, permTableParams, libGuid, rowData);
      }
    }
  });
}

openDialog(params: DppSafeAny, listGuid: DppSafeAny, rowData: DppSafeAny): void {
  let _title = 'publicspace.modal.configPermission';
  this.dppTranslateService.get(_title).subscribe(res => {
    _title = res;
  });
  this.commonSpaceService.getListRolePermissions(listGuid).subscribe(data => {
    params.permissions = data.data;

    const modal = this.as.openModal(
      {
        title: `${_title}${params.title}`,
        width: params.width,
        height: 'auto',
        closable: true,
        bodyStyle: {
          maxHeight: '600px'
        },
        closeOtherDrawer: false,
        openModalCloseDrawer: false,
        content: PermissionTableComponent,
        footer: [
          {
            label: 'common.button.cancel',
            type: 'default',
            onClick: () => {
              modal.close();
            }
          },
          {
            label: 'common.button.confirm',
            type: 'primary',
            onClick: (cpn: PermissionTableComponent) => {
              const PermissionParams: DppSafeAny = [];
              setTimeout(() => {
                if (cpn.finalselectedPermission && !cpn.dppRender?.dParams?.allPermission) {
                  cpn.finalselectedPermission.forEach(item => {
                    PermissionParams.push({
                      LIBRARYGUID: listGuid['LIBRARYGUID'],
                      ROLEGUID: listGuid['ROLEGUID'],
                      HASACL: item['isChecked'] ? 'Y' : 'N',
                      ACLTYPE: item.name,
                      EDITABLE: item['EDITABLE']
                    });
                  });
                } else {
                  cpn.finalselectedPermission.forEach(item => {
                    if (item['permissions']) {
                      item['permissions'].forEach((itex: { name: string; isChecked?: boolean; EDITABLE: string }) => {
                        PermissionParams.push({
                          LIBRARYGUID: item['libraryguid'],
                          ROLEGUID: item['roleguid'],
                          HASACL: itex.isChecked ? 'Y' : 'N',
                          ACLTYPE: itex.name,
                          EDITABLE: itex.EDITABLE
                        });
                      });
                    }
                  });
                }

                this.commonSpaceService.saveRolePermissions(PermissionParams).subscribe({
                  next: res => {
                    if (res.success) {
                      this.dppMessageService.success('publicspace.modal.permissionUpdateSuccess');
                    }
                  }
                });
              });
              modal.close();
            }
          }
        ]
      },
      {
        dppRender: params
      }
    );
  });
}

