// 粘贴团队 公共空间-团队-右上角
sysPasteTeamAction(event: EventInterface): void {
  const tableCom = this.getContentCom<DppTableComponent>(event);
  const pasteLibGuid = tableCom.queryCondition.params.get('LIBRARYGUID');
  const fromLibraryGuid = publiSaveData.getData('copyPasteTeam');
  if (!fromLibraryGuid) {
    this.dppMessageService.warning('productdesign.operation.noResourceCanPaste');
    return;
  }
  if (fromLibraryGuid === pasteLibGuid) {
    this.dppMessageService.warning('common.operation.pasteSelf');
    return;
  }
  this.commonSpaceService
    .pasteTeam({
      fromLibraryGuid: fromLibraryGuid,
      toLibraryGuid: pasteLibGuid as string
    })
    .subscribe({
      next: res => {
        if (res.success) {
          this.dppMessageService.success('common.operation.operationSuccess');
          tableCom.refreshData();
        }
      },
      error: res => {
        let errorMes = res?.error?.errorMessage;
        if (!errorMes) {
          errorMes = res?.message;
        }
        this.dppMessageService.error(errorMes);
      }
    });
}

