/**
 * 批量新建文件夹
 *
 * @usage
 * 1. 产品设计二级页面上方toolbar - 批量新建文件夹
 * 2. 公共空间二级页面上方toolbar - 批量新建文件夹
 */
sysBatchNewFolderAction(event: EventInterface): void {
  const rootPage = this.getRootPageService(event);
  const menuCom = CommonEventUtil.getDesignLibraryMenuCom(rootPage) as DppMenuComponent;
  const parentGuid = menuCom.getSelectedData()?.data?.key as string;

  const refreshFn = (res?: DppResponse<IBatchData>): void => {
    const data = res?.data;
    if (data?.errorCnt) this.errorMessageService.showMessage(event, res!);
    if (data?.successCnt && data?.successCnt === data?.totalCnt) {
      this.messageService.success('common.operation.newSuccess');
    }
    if (data?.successCnt) menuCom?.refresh();
  };

  this.openNewFolderModal(
    event,
    ModeTypeEnum.BATCHCREATE,
    formData => {
      const params = formData.map((item: { FOLDERNAME: string }) => ({
        PARENTGUID: parentGuid!,
        FOLDERNAME: item.FOLDERNAME
      }));
      return this.commonSpaceService.batchSaveFolder(params);
    },
    refreshFn
  );
}

/**
 * @description 单个新建文件夹操作
 *
 * @usage
 * 1. 在以下界面中用于“移动”或“新建文件夹”：
 *    - 产品设计二级页面：表格浮动 toolbar、表格操作栏
 *    - 公共空间二级页面：表格浮动 toolbar、表格操作栏
 *    - 实例界面：上方 toolbar
 * 2. 在工作台中用于位置选择后的新建文件夹操作：
 *    - 创建产品 / 设计变更 / 变更请求
 *    - 产品设计/公共空间二级页面新建料
 */
sysAddFolderAction(event: TagOpenEvent): void {
  const contentCom = this.getContentCom<IBaseComponent>(event) as MenuBaseTreeComponent;
  const parentGuid = contentCom['getSelectedData']()?.key;

  if (!parentGuid) {
    this.dppMessageService.warning('common.operation.selectLocationFirst');
    return;
  }

  const refreshFn = (res?: DppResponse<IBatchData>): void => {
    const data = res?.data;
    if (data?.successCnt == 1 && data?.successCnt === data?.totalCnt)
      (contentCom as MenuBaseTreeComponent).selectedNodes = null as unknown as NzTreeNodeOptions;
    (contentCom as MenuBaseTreeComponent).dppRender.mParams!.GUID = data!.details?.[0]?.data?.GUID;
    (contentCom as MenuBaseTreeComponent)?.refreshBaseTree();

    const triggerContent = (contentCom as MenuBaseTreeComponent).dppRender?.innerSend?.triggerInstance?.();
    if (triggerContent) {
      if (triggerContent.type === 'table') {
        const pageService = triggerContent.dppRender?.innerSend?.getPageThis?.() as IPageService;
        const menu = CommonEventUtil.getDesignLibraryMenuCom(pageService) as DppMenuComponent;
        menu?.refresh();
      } else if (triggerContent.type === 'card') {
        const table = triggerContent?.getTableThis?.() as DppTableComponent;
        const pageService = table?.dppRender?.innerSend?.getPageThis?.() as IPageService;
        const menu = CommonEventUtil.getDesignLibraryMenuCom(pageService) as DppMenuComponent;
        menu?.refresh();
      }
    } else {
      sendDataObj.sendNotify('menuInitRefresh', true);
    }
  };

  this.openNewFolderModal(
    event,
    ModeTypeEnum.EDIT,
    formData => {
      const object = {
        PARENTGUID: parentGuid,
        FOLDERNAME: formData.FOLDERNAME
      };
      return this.commonSpaceService.saveFolder(object);
    },
    refreshFn
  );
}

/**
 * @description 打开新建文件夹模态框（支持单个/批量）
 * @param event - 触发事件
 * @param mode - 模式：single | batch
 * @param saveFn - 保存方法（根据模式不同传入不同的服务调用）
 * @param refreshFn - 刷新回调
 */
private openNewFolderModal(
  event: EventInterface,
  mode: ModeTypeEnum,
  saveFn: (formData: any) => Observable<any>,
  refreshFn: (res: DppResponse<IBatchData>) => void
): void {
  const contentCom = this.getContentCom<IBaseComponent>(event) as MenuBaseTreeComponent;

  const modal: DppNzModalRef = this.as.openModal(
    {
      title: 'basic.common.command.sysNewFolder',
      width: '600px',
      height: 'auto',
      closable: true,
      content: DppFormComponent,
      bodyStyle: { maxHeight: '500px' },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => modal.close()
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: formCpn => {
            const isValid = formCpn.onSubmit();
            if (!isValid) return;

            const formData = formCpn.getFormData();
            formCpn.setLoading(true);

            saveFn(formData).subscribe({
              next: res => {
                if (res.success && res.data) {
                  refreshFn(res);
                }
                formCpn.setLoading(false);
                modal.close();
              },
              error: err => {
                formCpn.setLoading(false);
              }
            });
          }
        }
      ]
    },
    {
      dppRender: {
        name: FormBatchConfigModelEnum.BATCHNEWFOLDERFORM,
        mParams: {
          mode,
          isObject: false
        },
        innerSend: {
          triggerInstance: () => contentCom
        }
      }
    }
  );
}

