/**
 * 添加成员
 * @use 团队
 * @param event
 */
addMembersAction(event: TagOpenEvent): void {
  CommonEventUtil.addPersonAction(
    event,
    this.as,
    dataMess => {
      const { data, typeMap } = dataMess;
      if (data?.length > 0) {
        data.forEach((item: IBaseData) => {
          const memberType = item['MEMBERTYPE'];
          const id = item['MEMBERGUID'];
          const name = item['MEMBER$NAME'];
          const element = typeMap.get(memberType);
          element?.push({ guid: id, title: name, isSelected: true, type: memberType });
        });
      }
    },
    mess => {
      const { data, modal, tableRow, list, typeMap } = mess;
      if (!list.length) {
        this.dppMessageService.warning('common.operation.noDataSelected');
        return;
      }
      const LIBRARYGUID = tableRow?.['LIBRARYGUID'] as string;
      const ROLEGUID = tableRow?.['GUID'] as string;
      const objects: objetsInterface[] = list.map((item: { guid: any; type: any }) => {
        return {
          LIBRARYGUID: LIBRARYGUID,
          ROLEGUID: ROLEGUID,
          MEMBERGUID: item.guid,
          MEMBERTYPE: item.type
        };
      });
      const params: RoleMess = {
        roleGuid: ROLEGUID,
        libraryGuid: LIBRARYGUID,
        roles: objects
      };
      this.commonSpaceService.saveRoleMembers(params).subscribe(res => {
        if (res.success) {
          const libraryTable = event.beans.table.dppRender.innerSend?.triggerInstance?.();
          if (libraryTable) {
            libraryTable.refreshData();
          }
          event.updateRender({
            ...event.data,
            ...res.data
          });
          modal.close();
        }
      });
    }
  );
}

