repeatCheck$(data: Record<string, any>): Observable<boolean> {
  return this.publicService.repeatCheck(data).pipe(
    mergeMap(res => {
      if (res.success) {
        if (res.data && res.data.length > 0) {
          // 打开重复提示框并返回用户选择结果
          return this.openRepeatModel(res.data, data);
        } else {
          // 无重复数据直接返回 true
          return of(true);
        }
      } else {
        // 接口调用失败处理
        this.dppMessageService.error(res.errorMessage || 'common.operation.repeatError');
        return of(false);
      }
    }),
    catchError((err: string | TemplateRef<void>) => {
      // 错误处理
      this.dppMessageService.error(err);
      return of(false);
    })
  );
}

private openRepeatModel(dataList: Array<Record<string, any>>, data: Record<string, any>): Observable<boolean> {
  const result$ = new Subject<boolean>();

  // 弹窗配置
  const dppRender = {
    data: {
      fields: dataList[0]?.['REPEATFIELDS'], // 注意字段名大小写
      dataList: dataList,
      nowObjectData: data
    }
  };

  // 打开弹窗
  const modal = this.as.openModal(
    {
      title: 'process.operation.tips',
      uiType: 'repeatModal',
      footer: [
        {
          label: 'basic.common.button.cancel',
          type: 'default',
          onClick: () => {
            modal.close();
            result$.next(false); // 用户取消
            result$.complete();
          }
        },
        {
          label: 'basic.common.button.confirm',
          type: 'primary',
          onClick: () => {
            modal.close();
            result$.next(true); // 用户确认
            result$.complete();
          }
        }
      ],
      closeCallBack: () => {
        result$.next(false); // 用户取消
        result$.complete();
      }
    },
    { dppRender }
  );

  return result$.asObservable();
}

