cadConfigHandle(config: CadConfigHandleParams): {
  data: Record<string, unknown>;
  expression: string;
} {
  const { SYNDRAWINGID, SYNDRAWINGNAME } = config.configData;
  let formData = config.formData || {};
  let innerSend = {};
  if (config.formCom) {
    formData = config.formCom.getData?.() as Record<string, unknown>;
    innerSend = config.formCom.dppRender.innerSend || {};
  }

  let expression = '';
  if (SYNDRAWINGNAME === 'Y') {
    config.data['NAME$'] = formData?.['NAME$'];
    expression += `NAME$:required=false`;
  } else {
    config.data['NAME$'] = innerSend['modify_NAME$'] || '';
  }
  if (SYNDRAWINGID === 'Y') {
    config.data['ID$'] = formData?.['ID$'];
    expression += `;ID$:editable=false:required=false:placeholder=common.title.DrawIDAndItemAccord`;
  } else {
    config.data['ID$'] = innerSend['modify_ID$'] || '';
  }
  return { data: config.data, expression };
}

