/**
 * 创建产品 确认事件
 * @use 产品设计 | 场景入口|
 * @param event
 * @returns
 */
sysNewProductCompleteAction(event: EventInterface): void {
  const wizardCom = this.getContentCom<DppWizardComponent>(event);
  const modal = wizardCom.modalSelf?.() as DppNzModalRef;
  const tableCom = wizardCom?.triggerInstance?.() as unknown as DppTableComponent;
  // const formCom = wizardCom.getWizardHeadInstance<DppFormComponent>(0);

  // if (!formCom.onSubmit()) {
  //   return;
  // }
  // 验证必填处理
  const currentIndex = wizardCom.getWizardData().currentIndex;
  const stepForms = wizardCom.getComponentRefs();
  let firstForm: DppFormComponent | undefined, secondForm: DppFormComponent | undefined;

  Object.keys(stepForms).forEach((key: string, index: number) => {
    const formInstance = stepForms[key].instance as DppFormComponent;
    if (index === 0) {
      firstForm = formInstance;
    } else if (index === 1) {
      secondForm = formInstance;
    }
  });

  // 这里肯定有值，这里是为了过ts检查
  if (!firstForm) {
    return;
  }

  const isFirstFormValid = firstForm.onSubmit();
  const isSecondFormValid = secondForm ? secondForm.onSubmit() : true;

  if (!isFirstFormValid || !isSecondFormValid) {
    const errorKey =
      (currentIndex === 0 && !isFirstFormValid) || (currentIndex === 1 && !isSecondFormValid)
        ? 'productdesign.operation.requiredFieldsNotValue'
        : 'productdesign.operation.otherPageVerification';
    this.dppMessageService.warning(errorKey);
    return;
  }

  const formDta = firstForm.getFormData<IFoundaton>();
  const cadFromData = secondForm ? secondForm.getNotTranFormData<IFoundaton>() : null;

  // 处理分类 GUID
  if (formDta.CLASSIFICATION$) {
    formDta.CLASSIFICATIONGUID$ = formDta.CLASSIFICATION$;
  }

  this.setLoading(event, true);

  const createCADParams = (): Record<string, any> => {
    let result: Record<string, any> = {};
    let cadData = cadFromData as Record<string, any>;
    result = {
      ...cadData,
      CADTEMPLATE: cadData!['TEMPLATE'].value,
      CLASSNAME$: secondForm?.getNotTranFormData<any>()?.['CLASSTYPE']?.className,
      CLASSTYPE: cadData['CLASSTYPE']?.value,
      MODELCLASS: cadData['MODELCLASS']?.value,
      TEMPLATE: cadData['TEMPLATE']?.value
    };
    return result;
  };

  const createProdect$ = secondForm
    ? this.boas.saveObjectWithCad({
      ITEM: formDta,
      CAD: createCADParams()
    })
    : (this.productDesignService.createProduct(formDta) as Observable<DppResponse<IFoundaton>>);

