/**
 * 组合cad重复参数
 * @param cardFormData
 * @param cardFormOriginData
 * @returns
 */
private _comboRepeatCadParams(cardFormData: IFoundaton, cardFormOriginData: IFoundaton): Record<string, any> {
  const keys = [
    'COMMITFOLDER$',
    'COMMITFOLDER$NAME',
    'folderDataSoure',
    'withMainFile',
    'ISAUTOCHECKOUT$',
    'CLASSNAME$',
    'MODELCLASS$NAME',
    'MODELCLASS$TITLE',
    'MODELCLASS',
    'NAME$'
  ];
  const originKeys = [
    'CLASSNAME$TITLE',
    'MODELTYPE',
    'ISREVIEWED$',
    'BOGUID$',
    'HASNOTES$',
    'REVISIONID$',
    'ISEXPORTTOERP$',
    'CLASSGUID$',
    'TASKSTATUS',
    'HAS3D',
    'ISEDITABLE$',
    'ID$'
  ];

  let resParams = {};
  keys.map(item => {
    if (cardFormData) {
      resParams[item] = cardFormData[item];
    }
  });
  originKeys.map(item => {
    if (cardFormOriginData) {
      resParams[item] = cardFormOriginData[item];
    }
  });
  return resParams;
}

SearchAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const button: DppButtonComponent = this.getExeCom<DppButtonComponent>(event);
  const searchCondition = new QueryCondition(DppQueryConditionOperator.OR);

  const inputvalue: string = button.value;
  const nameKeys = [SystemClassFieldEnum.ID, SystemClassFieldEnum.NAME, SystemClassFieldEnum.ALTERID];

  if (!inputvalue) {
    table.refreshByCondition([]);
    return;
  }
  nameKeys.forEach(key => {
    searchCondition.addCondition(new QueryConditionInfo(key, [inputvalue], DppQueryConditionOperator.LIKE));
  });
  table.refreshByCondition(searchCondition);
}

