/**
 * 表格操作列下载图
 * @param {EventInterface} event
 * @memberof QueryInstanceEventService
 */
sysDownloadPicAction(event: any): void {
  const tableData = this.getRowData(event) as any;
  const guid = tableData['FILE$'][0].fileGuid;
  let fileName = tableData['FILE$'][0].fileName;
  const getFile$ = this.userWorkPlatformService.downloadAllFile;
  const param = `false/${guid}`;
  let isAll = false;
  if (tableData.OBJECTTYPE$ === '3DCad' && tableData.MODELCLASS$NAME === 'asm') {
    fileName = fileName.replace(/\.([^.]*)$/, '.zip');
    isAll = true;
  }
  getFile$.call(this.userWorkPlatformService, param, isAll).subscribe(res => {
    if (window.navigator && window.navigator['msSaveOrOpenBlob']) {
      window.navigator['msSaveOrOpenBlob'](res.data!, fileName);
    } else {
      const url = window.URL.createObjectURL(res.data!);
      const a = document.createElement('a');
      a.href = url;
      a.download = fileName;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(url);
    }
  });
}

/**
 * 表格操作列下载事件
 * @param {EventInterface} event
 * @memberof QueryInstanceEventService
 */
sysFileDownloadAction(event: EventInterface): void {
  this.setLoading(event, true);
  const tableData = this.getRowData(event);
  const instanceData = event.triggerRender?.innerSend?.instanceData! || event.triggerRender?.dParams;
  if (tableData['ISPRIMARY'] === 'Y') {
    const guid = instanceData!['GUID$'] as string;
    const classGuid = (instanceData!['CLASSGUID$'] as string) || (instanceData!['classGuid'] as string);
    const fileGuid = tableData!['GUID']! as string;
    const isPrimary = tableData!['ISPRIMARY'];
    this.queryInstanceService.downloadSingle(guid, classGuid!, fileGuid, isPrimary).subscribe({
      next: res => {
        if (res.success && res.data) {
          const url = window.URL.createObjectURL(res.data);
          const link = document.createElement('a');
          link.target = '_blank';
          link.download = `${instanceData['ID$'] || tableData['FILENAME']}.zip`;
          link.href = url;
          link.click();
          window.URL.revokeObjectURL(url);
          this.setLoading(event, false);
        }
      },
      error: () => {
        this.setLoading(event, false);
      }
    });
  } else {
    this.userWorkPlatformService.downloadFile(tableData['GUID']!, false).subscribe({
      next: res => {
        if (res.success && res.data) {
          const url = window.URL.createObjectURL(res.data);
          const link = document.createElement('a');
          link.target = '_blank';
          link.download = tableData['FILENAME']!;
          link.href = url;
          link.click();
          window.URL.revokeObjectURL(url);
          this.setLoading(event, false);
        }
      },
      error: () => {
        this.setLoading(event, false);
      }
    });
  }
}

