/**
 * 导出bom-bom页签更多操作里
 * @param event
 */
sysBOMExportAction(event: EventInterface): void {
  const data = this.getRowData(event);
  const table = this.getContentCom<DppTableComponent>(event);
  const dParams = table.modelManager.initParams;
  const fromProcess = table.dppRender.dParams!['fromProcess'] === 'true' ? true : undefined;

  // 这里兼容一下从根节点取guid className 因为维护产品结构没有从外部传入
  const rootNode = table.beans.rowModel.getRootNode().children?.[0];
  const rootData = rootNode?.origin;
  const guid = rootData?.['END2#GUID$'] || dParams?.['guid'];
  const className = rootData?.['END2#CLASSNAME$'] || dParams?.['className'];

  const modalParams = {
    name: 'sysExportBomForm',
    dParams: {
      BomTemplateName: 'BOM',
      className: className,
      guid: guid
    },
    mParams: {
      mode: ModeTypeEnum.EDIT,
      isObject: false
    },
    data: {
      // 防止请求getObject
      // form如果传递了className和guid,还没有传递data,那么就会自动请求getObject
      className: className,
      guid: guid,
      ID$: data['ID$'] || data['END2#ID$']
    }
  };
  const handleParams: (formData: Record<string, DppSafeAny>) => Record<string, DppSafeAny> = formData => {
    const COLLAPSED_DATA_TYPE = formData?.['COLLAPSED_DATA_TYPE$NODES']?.map((item: any) => ({
      BOGUID: item?.['origin']?.['BOGUID'],
      CLASSIFICATION: item?.['origin']?.['CLASSIFICATION']
    }));
    const params = {
      ITEM_GUID: data['END2#GUID$'], // 根物料GUID
      ITEM_CLASS_GUID: data['END2#CLASSGUID$'], // 根物料类名
      BOM_TEMPLATE_NAME: 'BOM', // BOM模板名
      BOM_REPORT_TEMPLATE_GUID: formData?.['BOM_TEMPLATE_NAME'], // BOM报表模板GUID
      EXPORT_FILE_TYPE: formData?.['EXPORT_FILE_TYPE'], // 导出文件类型
      BOM_REPORT_TYPE: formData?.['BOM_REPORT_TYPE'], // BOM报表类型(Tree/List)
      // IS_ALL_LEVEL: formData?.['IS_ALL_LEVEL'], // 是否导出所有层级
      COLLAPSED_DATA_TYPE,
      // 层级样式(1/2)
      LEVEL_STYLE: formData?.['LEVEL_STYLE'],
      // 包含替代料
      IS_CONTAIN_RS_DATA: formData?.['IS_CONTAIN_RS_DATA'] || 'N',
      SUMMARY_FIELD: formData?.['SUMMARY_FIELD'] // 汇总字段
    };
    if (formData?.['LEVEL'] === 'All') {
      params['IS_ALL_LEVEL'] = 'Y';
    } else {
      params['IS_ALL_LEVEL'] = 'N';
      params['LEVEL'] = Number(formData?.['LEVEL']);
    }
    return params;
  };
  const that = this;
  const modal = this.as.openModal(
    {
      title: 'common.command.sysBOMExportCommand',
      content: DppFormComponent,
      footer: [
        {
          label: 'basic.common.command.exportCommand',
          type: 'primary',
          onClick(form: DppFormComponent) {
            const isValid = form.onSubmit();
            if (!isValid) return;
            const formData = form.getFormData<Record<string, DppSafeAny>>();
            const params = handleParams(formData);
            this.loading = true;
            that.queryInstanceService.getExportBomMess(params).subscribe({
              next: res => {
                if (res.success && res.data) {
                  const fileGuid = res.data['FILE_GUID'];
                  if (!fileGuid) {
                    that.dppMess.success('productdesign.operation.createdReportQueueSuccess');
                    this.loading = false;
                    modal.close();
                    return;
                  }
                  let messageId = '';
                  that.dppMess.loading(
                    'basic.system.options.inOperation',
                    undefined,
                    messageRef => {
                      messageId = messageRef?.messageId ? messageRef?.messageId : '';
                    },
                    {
                      nzDuration: 0
                    }
                  );
                  that.userWorkPlatformService.downloadFile(fileGuid!, false).subscribe(res => {
                    if (res.success && res.data) {
                      that.dppMess.success('common.operation.operationSuccess');
                      that.message.remove(messageId);
                      const url = window.URL.createObjectURL(res.data);
                      const link = document.createElement('a');
                      link.target = '_blank';
                      const suffix = formData?.['EXPORT_FILE_TYPE'] === 'EXCEL' ? '.xls' : '.pdf';
                      console.log(formData);
                      const bomName = formData?.['BOM_TEMPLATE_NAME$TITLE'];
                      const id = formData?.['ID$'];
                      link.download = `${id}_${bomName}_${Date.now()}${suffix}`;
                      link.href = url;
                      link.click();
                      window.URL.revokeObjectURL(url);
                      this.loading = false;
                      modal.close();
                    }
                  });
                } else {
                  this.loading = false;
                  that.dppMess.success('common.operation.operationSuccess');
                }
              },
              error: () => {
                this.loading = false;
                modal.close();
              }
            });
          }
        },
        {
          label: 'common.button.close',
          onClick: () => {
            modal.close();
          }
        }
      ]
    },
    {
      dppRender: modalParams
    }
  );
}

