sysOpenTDDrawer(event: EventInterface, config?: OpenReplaceConfig): void {
  const data = this.getRowData(event);
  const table = this.getContentCom<DppTableComponent>(event);
  const page = this.getRootPageService(event);

  let instanceData: Record<string, DppSafeAny> = {};
  // 这里bom使用的是page,维护产品结构需要使用dParams里面的ObjectData
  if (page) {
    instanceData = page.getInstanceData();
  } else {
    instanceData = table.dppRender.dParams?.['objectData'] || {};
  }

  const title =
    config?.title || (data['ISQUDAI'] ? 'substitute.title.replaceRelationView' : 'substitute.title.widthRelationView');
  const content = this.getContentCom<DppTableComponent>(event);
  const property: Property = {
    uiType: UIModelTypeEnum.PAGE,
