    mask: false,
    isInteractive: true,
    width: '70vw',
    title: title,
    triggerInstance: () => content,
    wrapClassName: 'bom-replace-drawer'
  };
  const dppRender: IRenderParameterNew<IUiModel> = {
    name: config?.name || 'sysBomReplaceStandardViewPage',
    dParams: {
      bomGuid: data['GUID$'],
      bomKey: data['BOMKEY'],
      END1$GUID: data['END1#GUID$'],
      END1$CLASSNAME: data['END1$CLASSNAME'],
      END1$ID: data['END1#ID'],
      END1$NAME: data['END1#NAME'],
      END1$CLASS: data['END1$CLASS'],
      END2$GUID: data['END2#GUID$'],
      END2$CLASSNAME: data['END2#CLASSNAME$'],
      END2$ID$: data['END2#ID$'],
      END2$NAME$: data['END2#NAME$'],
      BOMKEY: data['BOMKEY'],
      ROWKEY: data['ROWKEY'],
      'END2#COMMITFOLDER$': data['END2#COMMITFOLDER$'],
      'END2#COMMITFOLDER$PATH': data['END2#COMMITFOLDER$PATH'],
      'END2#COMMITFOLDER$GUIDPATH': data['END2#COMMITFOLDER$GUIDPATH'],
      'END2#COMMITFOLDER$NAME': data['END2#COMMITFOLDER$NAME'],
      struct_className: data['ROWKEY']['CLASSNAME'],
      struct_guid: data['ROWKEY']['GUID'],
      'END2#UHASEFFECTIVEGLOBALRS': data['END2#UHASEFFECTIVEGLOBALRS'],
      RSFLAG: data['RSFLAG'],
      'END2#RSFLAG': data['END2#RSFLAG'],
      'END2#FULLNAME$': data['END2#FULLNAME$'],
      'END2#ID$': data['END2#ID$'],
      REPLACECONTROL: instanceData['REPLACECONTROL'],
      STATUS$: instanceData['STATUS$'],
      instanceStatus: instanceData['STATUS$']
