 */
sysBRSPartRowAction(event: CellSaveEvent): Observable<DppResponse<IBatchData>> {
  const data = event.data;
  const changedProps = event.editChancedRowData;

  // 获取当前日期
  const currentDate = new Date();
  currentDate.setHours(0, 0, 0, 0); // 设置时间为00:00:00

  if (!this.substituteUtil.dateIsValid({ changeData: changedProps, rowData: data, mess: this.dppMessageService })) {
    return of({ response: { success: false } } as DppSafeAny);
  }

  const params = this.substituteUtil.getBRSPartRowParam(data, changedProps);

  if (params['INVALID_DATE'] !== undefined && !params['INVALID_DATE']) {
    params['SET_INVALID_DATE_NULL'] = 'Y';
  }

  return this.substituteService.bRSSaveSub(params);
}

