/**
 * 替代查看-局部替代-日期批量编辑
 * @param event
 * @param dateType 'effective' 或 'expiration'
 * @returns
 */
private _sysSubItemBatchEditDateAction(event: EventInterface, dateType: 'effective' | 'expiration'): void {
  const bs = this.getExeCom(event) as DppButtonComponent;
  const action = bs.getUiModel().action as ButtonIUiModel;
  const table = this.getContentCom(event) as DppTableComponent;
  const selectedDatas = table.getCheckedNodeList();

  // 验证发布状态
  if (selectedDatas.some(item => item.origin['RSSTATUS$'] === 'N')) {
    this.dppMessageService.warning('substitute.prompt.releaseedNotHandle');
    return;
  }

  // 失效日期特殊处理：检查生效日期
  if (dateType === 'expiration') {
    if (selectedDatas.some(item => !item.origin['EFFECTIVEDATE'])) {
      this.dppMessageService.warning('substitute.prompt.setEffectiveDataFirst');
      return;
    }
  }

  // 准备表单参数
  const formParams: IFormRender = {
    name: action.name,
    mParams: {
      mode: action.mode,
      isObject: false,
      model: {}
    },
    data: {
      STATUS$: table.dppRender.dParams?.['STATUS$'],
      REPLACECONTROL: table.dppRender.dParams?.['REPLACECONTROL'],
      INVALIDDATE: ''
    }
  };

  const property = {
    title:
      dateType === 'effective'
        ? 'substitute.command.sysEditEffectiveDateCommand'
        : 'substitute.command.sysEditInvalidDateCommand',
    width: '600px',
    closable: true,
    closeOtherDrawer: false,
    openModalCloseDrawer: false,
    content: DppFormComponent
  };

  const that = this;
  const modal = this.substituteUtil.openModalAndDefaultCancel<DppFormComponent>({
    property,
    confirmBtn(formCpn) {
      const isValid = formCpn.onSubmit();

      if (isValid) {
        const formData = formCpn.getFormData<Record<string, DppSafeAny>>() || {};
        const changedProps = selectedDatas.map(item => ({
          ...item.origin,
          ...formData
        }));
        const params = that.substituteUtil.getBRSPartBatchRowParam(changedProps, that.datePipe, dateType);

        that.substituteService.bRSSetSubBatchDate(params).subscribe({
          next: res => {
            if (res.data && res.success) {
              if (res.data.successCnt === res.data.totalCnt) {
                that.dppMessageService.success('common.operation.operationSuccess');
                table.refreshData();
              } else {
                that.errorMessageService.showMessage(event, res);
              }
              table.refreshData();
              modal.close();
            }
          }
        });
      } else {
        that.dppMessageService.warning('substitute.prompt.setEffectiveDataFirst');
      }
    },
    dppRender: formParams
  });
}

