/**
 * 替代关系行编辑事件
 * @param event
 * @returns
 */
sysBRSSubRowAction(event: CellSaveEvent): Observable<DppResponse<IBatchData>> {
  const data = event.data;
  const changedProps = event.editChancedRowData;

  if (!Object.keys(changedProps).length) {
    return of({ response: { success: false } } as DppSafeAny);
  }

  const { key, classNameKey } = useKey();
  console.log(changedProps);

  let params = {
    SUBSTITUTE: {
      GUID: data[key],
      CLASSNAME: data[classNameKey]
    },
    COMPONENT_USAGE: Number(changedProps['COMPONENTUSAGE']) || undefined,
    // PRIORITY: Number(changedProps['RSNUMBER']) || undefined,
    RANGE: 'Partial',
    EFFECTIVE_DATE: changedProps['EFFECTIVEDATE'],
    INVALID_DATE: changedProps['INVALIDDATE']
  };

  if (params['INVALID_DATE'] !== undefined && !params['INVALID_DATE']) {
    params['SET_INVALID_DATE_NULL'] = 'Y';
  }

  if (changedProps['RSITEM']) {
    params['RS_ITEM'] = {
      // 替代件 选填
      GUID: changedProps['RSITEM'],
      CLASSNAME: data['RSITEM$CLASSNAME']
    };
  }
  return this.substituteService.bRSSubReplaceRowUpdate(params);
}

/**
 * 替代关系行编辑-新增类型
 * @param event
 * @returns
 */
sysBRSDRRowAddAction(event: RowSaveEvent): Observable<DppResponse<IBatchData>> {
  const rootPage = this.getRootPageService(event);
  const instanceData = rootPage.getInstanceData();
  const rowData = event.data;
  const addParams = this.substituteUtil.getBRSReplaceRowSaveParams(rowData, instanceData);
  const table = this.getContentCom<DppTableComponent>(event);
  const node = event.node;

  // 新增逻辑，修改的替代关系，如果生效日期早于当前日期，需要给后端传递参数
  if (addParams['EFFECTIVE_DATE'] && addParams['EFFECTIVE_DATE'] < new Date()) {
    addParams['EFFECTIVE_DATE_CHECK'] = false;
  }

  const isNotCom =
    !addParams['COMPONENT_ITEM'] || !addParams['COMPONENT_ITEM']['GUID'] || !addParams['COMPONENT_ITEM']['CLASSNAME'];
  const isNotRS = !addParams['RS_ITEM'] || !addParams['RS_ITEM']['GUID'] || !addParams['RS_ITEM']['CLASSNAME'];
  if (isNotRS && isNotCom) {
    this.dppMessageService.error('substitute.message.comAndSubIsNotEmpty');
    return of({ response: { success: false } } as DppSafeAny);
  }
  if (isNotRS && !isNotCom) {
    this.dppMessageService.error('substitute.message.subIsNotEmpty');
    return of({ response: { success: false } } as DppSafeAny);
  }
  if (isNotCom && !isNotRS) {
    this.dppMessageService.error('substitute.message.comIsNotEmpty');
    return of({ response: { success: false } } as DppSafeAny);
  }

  // 订阅异步请求
  return this.substituteService.bRSSubReplaceRowSave(addParams).pipe(
    tap(response => {
      setTimeout(() => {
        if (instanceData['SCOPE$NAME'] === 'Partial') {
          this.substituteUtil.addSubRefreshMain(rootPage, node);
        } else if (instanceData['SCOPE$NAME'] === 'Partial2') {
          this.substituteUtil.addSubRefreshCom(node);
          const mainTable = rootPage.getComFnMapByName<DppTableComponent>(SUB_TABLE_COMMAND.COM_MAIN_TABLE)!;
          this.substituteUtil.bRsComSetReplaceSelectRefreshMain({
            mainTable,
            subTable: table,
            selectNode: node,
            instanceData
          });
        } else {
          this.substituteUtil.addSubRefreshGlobal(node);
        }
      });
    })
  );
}

