 */
sysBRSAFDMRemoveCheckAction(
  event: EventInterface,
  data?: IBaseData,
  callBack?: (res: DppResponse<IBatchData<IBatchDataDetails>>) => void
): void {
  const rootPage = this.getRootPageService(event);
  const instanceData = rootPage.getInstanceData();
  const node = this.getNode(event) as RowNode;
  const params = this.substituteUtil.getbRSSubMainRelationDelParam(data || instanceData, node);
  const table = this.getContentCom<DppTableComponent>(event);
