/**
 * 替代关系-float-移除按钮(从主件)
 * @param event
 * @param data
 */
sysBRSAFDRPatchRemoveCheckAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const selectNodes = table.getCheckedNodes();
  const selectData = selectNodes.map(node => node.origin);

  const rootPage = this.getRootPageService(event);
  const instanceData = rootPage.getInstanceData();
  if (instanceData['STATUS$'] !== 'WIP') {
    this.dppMessageService.warning('substitute.message.thisStatusIsNot');
    return;
  }
  const addParams = this.substituteUtil.bRSPatchbuildApplyForDelParams(selectData);
  const mainTable = rootPage.getComFnMapByName<DppTableComponent>(SUB_TABLE_COMMAND.MAIN_TABLE);
  const selectedNode = mainTable?.getSelectedNodeList()?.[0];
  if (!selectedNode) {
    this.dppMessageService.warning('common.operation.noDataSelect');
    return;
  }
  this.setLoading(event, true);
  this.substituteService.bRSbatchDelApplyForSubItems(addParams).subscribe({
    next: res => {
      if (res.data && res.success) {
        if (res.data.successCnt === res.data.totalCnt) {
          this.dppMessageService.success('common.operation.operationSuccess');
          table.applyTransaction({
            remove: selectData
          });
          this.substituteUtil.delSubRefreshMain(event);
        } else {
          this.errorMessageService.showMessage(event, res);
        }
      }
      this.setLoading(event, false);
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

/**
 * 替代件加载完后联动主件
 * @param event
 */
sysBRSDRMComQueryAfterAction(event: EventInterface): void {
  const { exeTable, contentTable, instanceData } = this.substituteUtil.getBRSDRMCommonComponentsAndData(event);

  const mainTable = contentTable;
  const subTable = exeTable;
  if (!mainTable || !subTable || !instanceData) return;

  const selectNode = subTable.getAllNodes()[0];
  if (!selectNode) {
    console.warn('No nodes found in the sub table.');
    return;
  }

  this.substituteUtil.bRsComSetReplaceSelectRefreshMain({ selectNode, instanceData, subTable, mainTable });

  mainTable.afterQueryData.subscribe({
    next: res => {
      const subNodes = subTable.getAllNodes();
      subNodes.forEach(node => {
        node.origin['preType'] = 'modify';
      });

      subTable.applyTransaction({
        update: subNodes
      });
    },
    error: err => {
      console.error('Error in afterQueryData subscription:', err);
    }
  });
}

