  if (!selectNode) {
    this.dppMessageService.warning('common.operation.noDataSelect');
    return;
  }

  const rowData = selectNode?.origin || {};
  if (rowData['isNewRow']) {
    this.dppMessageService.warning('substitute.message.rowNotSave');
    return;
  }

