          if (res.data && res.success) {
            if (res.data.successCnt === res.data.totalCnt) {
              that.dppMessageService.success('common.operation.operationSuccess');
            } else {
              that.errorMessageService.showMessage(event, res);
            }
          }
          const selectedNode = subTable?.getSelectedNodeList()?.[0];
          selectedNode?.setData({ ...selectedNode?.origin, ...that.substituteUtil.hasLinkDataFlag('Y') });
          mainTable!.refreshData();
          this!.loading = false;
          modal!.close();
