/**
 * 请求接口并处理数据
 * @param action
 * @param data
 * @param tableCom
 */
fetchAndProcessOptions(config: BRSApplyForConfig): void {
  const { action, data, tableCom, optionName, event, fromType } = config;
  this.applyForInitDefault().subscribe({
    next: res => {
      if (res && res.data) {
        const options = res.data;
        let defaultData = {};
        const needOptions = options.filter(item => item.itemName === optionName);
        if (needOptions && needOptions.length) {
          const needKeys = ['SCOPE:value', 'SCOPE$NAME:itemName', 'SCOPE$TITLE:label', 'SCOPE$CODE:code'];
          needKeys.forEach(item => {
            defaultData[item.split(':')[0]] = needOptions[0][item.split(':')[1]];
          });
        }
        if (defaultData) {
          this.substituteUtil.bRSApplyForAction({
            ...config,
            action,
            data: {
              ...data,
              ...defaultData,
              CLASSNAME$: 'RSApplyForm'
            },
            tableCom,
            fromType
          });
        }
      }
      this.setLoading(event!, false);
    },
    error: () => {
      this.setLoading(event!, false);
    }
  });
}

applyForInitDefault(): Observable<DppResponse<ScopeOption[]>> {
  return this.substituteService.getScopeOptions({ codeName: 'Scope', type: 'code' });
}

