/**
 * 编辑替代物料组表格
 *  优先级｜用量｜生效｜失效
 *  用量： 编辑当前行，其他行不改变
 *  优先级｜生效｜失效： 同一优先级的所有行都改变
 * @author: lsp
 * @modify: 陈龙 2025-01-02 修改编辑后的表格刷新，优化编辑逻辑
 */
sysEditSubItemTableAction(event: CellSaveEvent): Observable<any> {
  if (this.isEmptyEdit(event.editChancedRowData)) {
    this.dppMessageService.warning('substitute.prompt.nothingEdited');
    return of({ success: false });
  }

  // 2. 获取基础数据
  const {
    data: rowData,
    column: { key: editedColumn }
  } = event;
  const table = event.beans.table;
  // 3. 构建更新属性
  const props = this.buildEditProps(event.editChancedRowData);

  // 4. 确定需要更新的行
  let rowsToUpdate = this.getRowsToUpdate(editedColumn, rowData, event);
  const rowsUpdateMap = new Map<string, any>();
  rowsToUpdate.forEach(item => {
    rowsUpdateMap.set(item['GUID$'], item);
  });

  // 5. 构建请求参数
  const params = this.buildRequestParams(rowData, rowsToUpdate, props);

  return this.substituteService.batchSaveSubItems(params).pipe(
    tap(res => {
      if (res.data && res.success) {
        const { successCnt, totalCnt, errorCnt, details } = res.data;
        if (totalCnt !== successCnt) {
          this.errorMessageService.showMessage(event, res);
        } else {
          this.dppMessageService.success('substitute.prompt.editSubItemGroupSuccess');
        }
        const successUpdatedData = details
          .filter((item: any) => item.result === 'SUCCESS')
          .map((item: any) => item.data);
        rowsToUpdate = successUpdatedData.map((item: any) => {
          const data = rowsUpdateMap.get(item['GUID$']);
          if (data) {
            return Object.assign(data, item);
          }
          return null;
        });

        if (successUpdatedData.length > 0) {
          table.applyTransaction({
            update: rowsToUpdate.filter(Boolean)
          });
        }

        // 如果修改的是优先级，则展开对应的节点
        if (editedColumn === 'PRIORITY') {
          event.node.parentNode!.isExpanded = true;
        }
      }
    }),
    map(res => {
      const { successCnt, totalCnt } = res.data;
      if (successCnt && successCnt === totalCnt) {
        return { success: res.success };
      } else {
        return { success: false };
      }
    })
  );
}

// 检查编辑数据是否为空
private isEmptyEdit(editData: object): boolean {
  return Object.values(editData).some(value => value === null || value === '' || value === undefined);
}

// 构建编辑属性
private buildEditProps(editData: object): Record<string, string> {
  const props: Record<string, string> = {};
  Object.entries(editData).forEach(([key, val]) => {
    props[key] = this.isDateField(key) ? this.formateDate(val) : val;
  });
  //优先级
  props['PRIORITY'] = (editData as any)['PRIORITY'];
  return props;
}

// 判断是否为日期字段
private isDateField(key: string): boolean {
  return ['INVALIDDATE', 'EFFECTIVEDATE'].includes(key);
}

// 获取需要更新的行数据
private getRowsToUpdate(editedColumn: string, rowData: any, event: CellSaveEvent): any[] {
  // 如果是编辑用量，只返回当前行
  if (editedColumn === 'QUANTITY') {
    return [rowData];
  }

  // 如果是编辑优先级或日期，返回同优先级的所有行
  if (this.isDateField(editedColumn) || editedColumn === 'PRIORITY') {
    const node = event.node;
    const groupData = node.parentNode!.childrenAfterGroup;
    return groupData.map(item => item.origin);
  }

  return [rowData]; // 默认只更新当前行
}

// 构建请求参数
private buildRequestParams(rowData: any, rowsToUpdate: any[], props: Record<string, string>): any {
  return {
    end1: {
      className: rowData['END1$CLASSNAME'],
      guid: rowData['END1#GUID$']
    },
    structures: rowsToUpdate.map(item => this.createEnd2Param(item, props))
  };
}

