/**
 * 替代物料表格移除
 * 1. 点的是替代主料的移除
 *   需要根据PRIORITY和ISKEYITEM来判断,并把该组的第二条数据自动设为替代主料
 * 2. 点的是替代物料组下的移除
 *   直接移除
 * @author: lsp
 * @modifier: 陈龙 2025-01-02 已经移除了主料辅料的概念，直接移除就可以 目前的expression没有传入node, 所以还需要设置属性标记为第一个
 *
 */
sysReplaceItemRemoveAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const targetNode = this.getNode(event) as RowNode;
  const rowData = targetNode.origin as SubItems;

  // 验证组行
  if (targetNode.group) {
    this.dppMessageService.error('substitute.prompt.groupNotHandle');
    return;
  }

  const params = this.buildRemoveParams(targetNode);
  const isKeyItem = rowData['ISKEYITEM'] === 'Y';
  const firstDataAfterRemoveInGroup = this.getGroupFirstNodeAfterRemoved(targetNode);

  this.substituteService
    .batchUnLinkSubItems(params)
    .pipe(
      tap(res => {
        if (!this.validateUnlinkResponse(res as UnlinkResponse)) {
          throw new Error('Invalid unlink response');
        }
      }),
      switchMap(unlinkRes => {
        // 如果是关键项且有后续节点，需要设置新的关键项
        if (isKeyItem && firstDataAfterRemoveInGroup) {
          const setFirstParams = this.buildSetFirstNodeAsKeyItemParams(firstDataAfterRemoveInGroup);
          return this.substituteService.batchSaveSubItems(setFirstParams).pipe(
            map(saveRes => ({
              unlinkRes,
              saveRes,
              needRefresh: true
            }))
          );
        }
        return of({
          unlinkRes,
          saveRes: null,
          needRefresh: false
        });
      }),
      catchError(error => {
        if (error.message === 'Invalid unlink response') {
          const errorMessage = 'substitute.prompt.removeSubItemFailed';
          this.dppMessageService.error(errorMessage);
        }
        return EMPTY;
      })
    )
    .subscribe({
      next: ({ unlinkRes, saveRes, needRefresh }) => {
        if (needRefresh) {
          // 验证设置新关键项的响应
          if (!saveRes || !this.validateSaveResponse(saveRes as SaveResponse)) {
            this.dppMessageService.error('substitute.prompt.setKeyItemFailed');
            return;
          }
          const updatedData = Object.assign(firstDataAfterRemoveInGroup!.origin, {
            ISKEYITEM: 'Y'
          });
          table.applyTransaction({
            remove: [targetNode.origin],
            update: [updatedData]
          });
        } else {
          table.deleteNode(targetNode);
        }

        // 显示成功消息
        this.dppMessageService.success('substitute.prompt.removeSubItemSuccess');
      }
    });
}

private buildRemoveParams(removeNode: RowNode): { [key: string]: object | string } {
  const data = removeNode.origin;
  return {
    end1: {
      className: data['END1$CLASSNAME'],
      guid: data['END1#GUID$']
    },
    structures: [
      {
        end2: {
          className: data['END2#CLASSNAME$'],
          guid: data['END2#GUID$']
        },
        objectGuid: {
          guid: data['GUID$'],
          className: data['CLASSNAME$']
        },
        modifyType: 'DEL'
      }
    ]
  };
}

private buildSetFirstNodeAsKeyItemParams(node: RowNode): { [key: string]: object | string } {
  const data = node.origin;
  return {
    end1: {
      className: data['END1$CLASSNAME'],
      guid: data['END1#GUID$']
    },
    structures: [
      {
        end2: {
          className: data['END2#CLASSNAME$']
        },
        objectGuid: {
          guid: data['GUID$'],
          className: data['CLASSNAME$']
        },
        props: {
          ISKEYITEM: 'Y'
        },
        modifyType: 'UPD'
      }
    ]
  };
}

private buildBatchSetFirstNodeAsKeyItemParams(nodes: RowNode[]): { [key: string]: object | string } {
  const params = {
    end1: {
      className: nodes[0].origin['END1$CLASSNAME'],
      guid: nodes[0].origin['END1#GUID$']
    },
    structures: nodes.map(node => {
      return {
        end2: {
          className: node.origin['END2#CLASSNAME$']
        },
        objectGuid: {
          guid: node.origin['GUID$'],
          className: node.origin['CLASSNAME$']
        },
        props: {
          ISKEYITEM: 'Y'
        },
        modifyType: 'UPD'
      };
    })
  };
  return params;
}

private getGroupFirstNodeAfterRemoved(nodeRemoved: RowNode): RowNode | null {
  const group = nodeRemoved.parentNode!;
  const children = group.childrenAfterSort;
  let firstNodeAfterRemoved: RowNode | null = null;
  if (children.length > 1) {
    firstNodeAfterRemoved = children[1];
  }
  return firstNodeAfterRemoved;
}

private validateUnlinkResponse(res: UnlinkResponse): boolean {
  return res.success && !!res.data?.totalCnt && res.data.totalCnt > 0;
}

private validateSaveResponse(res: SaveResponse): boolean {
  return (
    res.success &&
    res.data?.successCnt !== undefined &&
    res.data?.totalCnt !== undefined &&
    res.data.successCnt === res.data.totalCnt
  );
}

/**
 * 替代物料表格批量移除
 * 1. 获取所有选中的行数据，移除 DEL
 * 2. 过滤掉删除的数据，按组进行分类，每组第一条数据是替代主料
 * 3. 调用批量编辑的接口， 然后替代主料更新 UPD
 * @author: lsp
 * @modifier: 陈龙 2025-01-02 批量删除优化
 */
sysReplaceItemBatchRemoveAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const selectNodes = table.getCheckedNodes();

  // 验证选中数据
  if (this.validateSelectedNodes(selectNodes)) {
    return;
  }

  // 准备删除参数
  const { params, removeNodesMap } = this.prepareBatchRemoveParams(selectNodes, table);

  // 执行批量删除和更新操作
  this.substituteService
    .batchUnLinkSubItems(params)
    .pipe(
      // @ts-ignore
      tap((res: BatchRemoveResponse) => {
        if (!res.success || !res.data) {
          throw new Error('Failed to remove items');
        }
      }),
      switchMap(res => {
        const { successRemovedNodes, needSetKeyItemNodes, needSetKeyItemNodesMap } = this.processRemoveResponse(
          res,
          removeNodesMap
        );

        // 如果不需要设置新的关键项，直接返回当前结果
        if (needSetKeyItemNodes.length === 0) {
          return of({ removeRes: res, successRemovedNodes, needSetKeyItemNodesMap, updateRes: null });
        }

        // 需要设置新的关键项
        const updateParams = this.buildBatchSetFirstNodeAsKeyItemParams(needSetKeyItemNodes);
        return this.substituteService.batchSaveSubItems(updateParams).pipe(
          map(updateRes => ({
            removeRes: res,
            updateRes,
            successRemovedNodes,
            needSetKeyItemNodesMap
          }))
        );
      }),
      catchError(error => {
        this.dppMessageService.error('substitute.prompt.batchRemoveFailed');
        console.error('Batch remove failed:', error);
        return EMPTY;
      })
    )
    .subscribe({
      next: result => {
        const { removeRes, updateRes, successRemovedNodes, needSetKeyItemNodesMap } = result;

        // 处理删除响应
        this.handleBatchRemoveResult(removeRes, event);

        // 如果只有删除操作
        if (!updateRes) {
          table.applyTransaction({
            remove: successRemovedNodes.map(node => node.origin)
          });
          return;
        }

        // 处理更新响应
        if (updateRes.success && updateRes.data) {
          const successUpdatedNodes = this.processUpdateResponse(
            updateRes as BatchRemoveResponse,
            needSetKeyItemNodesMap
          );

          // 更新表格
          table.applyTransaction({
            remove: successRemovedNodes.map(node => node.origin),
            update: successUpdatedNodes.map(node =>
              Object.assign(node.origin, {
                ISKEYITEM: 'Y'
              })
