private processRemoveResponse(
  res: BatchRemoveResponse,
  removeNodesMap: Map<string, RowNode>
): {
  successRemovedNodes: RowNode[];
  needSetKeyItemNodes: RowNode[];
  needSetKeyItemNodesMap: Map<string, RowNode>;
} {
  const successRemovedData = res.data.details.filter(item => item.result === 'SUCCESS').map(item => item.data);

  const successRemovedNodes = successRemovedData
    .map(item => removeNodesMap.get(item['GUID$']))
    .filter(Boolean) as RowNode[];

  const { needSetKeyItemNodes, needSetKeyItemNodesMap } = this.findNodesToSetAsKeyItem(successRemovedNodes);

  return { successRemovedNodes, needSetKeyItemNodes, needSetKeyItemNodesMap };
}

private findNodesToSetAsKeyItem(successRemovedNodes: RowNode[]): {
  needSetKeyItemNodes: RowNode[];
  needSetKeyItemNodesMap: Map<string, RowNode>;
} {
  const levelMap = new Map<number, RowNode[]>();
  const needSetKeyItemNodes: RowNode[] = [];
  const needSetKeyItemNodesMap = new Map<string, RowNode>();

  // 按层级分组
  successRemovedNodes.forEach(node => {
    const level = node.origin['PRIORITY'];
    if (!levelMap.has(level)) {
      levelMap.set(level, []);
    }
    levelMap.get(level)!.push(node);
  });

  // 处理每个层级
  levelMap.forEach((nodes, level) => {
    const isKeyItemExist = nodes.some(node => node.origin['ISKEYITEM'] === 'Y');
    if (isKeyItemExist) {
      const remainNodes = nodes[0].parentNode!.childrenAfterSort.filter(node => !nodes.includes(node));
      if (remainNodes.length > 0) {
        needSetKeyItemNodes.push(remainNodes[0]);
        needSetKeyItemNodesMap.set(remainNodes[0].origin['GUID$'], remainNodes[0]);
      }
    }
  });

  return { needSetKeyItemNodes, needSetKeyItemNodesMap };
}

private handleBatchRemoveResult(res: BatchRemoveResponse, event: EventInterface): void {
  const { successCnt, totalCnt } = res.data;
  if (successCnt === totalCnt) {
    this.dppMessageService.success('substitute.prompt.removeSubItemSuccess');
  } else {
    this.errorMessageService.showMessage(event, res as any);
  }
}

