  const eferenceSubItemCheckedNodes = eferenceSubItem?.getCheckedNodes() || [];
  if (allCheckedNodes.length > 0) {
    return allCheckedNodes.map(node => node.origin);
  } else if (eferenceSubItemCheckedNodes.length > 0) {
    return eferenceSubItemCheckedNodes.map(node => node.origin);
  }
  return [];
}

private buildAddParams(instanceData: IFoundaton, selectedRows: any[], targetNode: RowNode): any {
  const rowData = targetNode.origin;
  const priority = Number(rowData['PRIORITY']!);
  const expirationDate = this.formateDate(rowData['INVALIDDATE']);
  const effectiveDate = this.formateDate(rowData['EFFECTIVEDATE']);
  return {
    end1: {
      className: instanceData['CLASSNAME$'],
      guid: instanceData['GUID$']
    },
    structures: selectedRows.map(item => ({
      end2: {
        className: item['CLASSNAME$'],
        guid: item['GUID$'],
        classGuid: item['CLASSGUID$']
      },
      props: {
        IsKeyItem: 'N',
        Priority: priority,
        EFFECTIVEDATE: effectiveDate,
        INVALIDDATE: expirationDate
      },
      modifyType: 'ADD'
    }))
  };
}

private buildNewParams(instanceData: IFoundaton, selectedRows: any[], table: DppTableComponent): any {
  let currentMaxPriority = 0;
  const rootNode = table.beans.rowModel.getRootNode();
  const firstLevelNodes = rootNode.childrenAfterGroup;
  firstLevelNodes.forEach(node => {
    const priority = Number(node.groupData!['PRIORITY']);
    if (priority > currentMaxPriority) {
      currentMaxPriority = priority;
    }
  });
  currentMaxPriority++;
  let structures: any[] = [];
  for (let i = 0; i < selectedRows.length; i++) {
    const item = selectedRows[i];
    const effectiveDate = this.formateDate(item['EFFECTIVEDATE']);
    const expirationDate = this.formateDate(item['EXPIRATIONDATE']);
    structures.push({
      end2: {
        className: item['CLASSNAME$'],
        guid: item['GUID$'],
        classGuid: item['CLASSGUID$']
      },
      props: {
        IsKeyItem: 'Y',
        Priority: currentMaxPriority + i,
        EFFECTIVEDATE: effectiveDate,
        INVALIDDATE: expirationDate
      },
      modifyType: 'ADD'
    });
  }
  return {
    end1: {
      className: instanceData['CLASSNAME$'],
      guid: instanceData['GUID$']
    },
    structures: structures
  };
}

