    'CR#REPLACEDMATERIALS$FULLNAME': rowData['END2#FULLNAME$'],
    'CR#REPLACEDMATERIALS$CLASSNAME': rowData['END2#CLASSNAME$'],
    'CR#REPLACEDMATERIALS$CLASSGUID': rowData['END2#CLASSGUID$']
  };
  CommonEventUtil.buildModal<DppFormComponent>({
    event,
    message: this.dppMessageService,
    cpmParams: { dppRender: render },
    footers: [
      {
        label: i18n_ECM.CANCEL,
        onClick: (button, formCpm, modal) => {
          CommonEventUtil.buildConfirmConfig(this.as, this.translation, modal);
        }
      },
      {
        label: i18n_ECM.EXECUTE,
        type: 'primary',
        onClick: (button, formCpm, modal) => {
          if (!formCpm.onSubmit()) {
            return;
          }
          let params = { ...formCpm.getFormData<Record<string, unknown>>() };
          // params['CR#REPLACERATE'] = `${params['CR#REPLACERATEM']}:${params['CR#REPLACERATEN']}`;
          // delete params['CR#REPLACERATEM'];
          // delete params['CR#REPLACERATEN'];
          params = {
            structureGuid: rowData['ROWKEY']['GUID'], //结构信息
            structureClassName: rowData['ROWKEY']['CLASSNAME'],
            replaceGuid: params['CR#TARGETITEM'], //取代信息
            replaceClassName: params['CR#TARGETITEM$CLASSNAME'],
            replaceMasterGuid: params['CR#TARGETITEM$MASTERFK$'],
            replaceMode: params['CR#REPLACEPOLICY$NAME'] === 'NaturalReplace' ? 'nature' : 'force', //取代方式
            replaceRate: params['CR#REPLACERATEN'], //取代比率
            effectiveDate: params['CR#EFFECTIVEDATE'], //日期
            invalidDate: params['CR#EXPIRATIONDATE'],
            base: params['CR#BASE'], //底数
            remark: params['CR#REMARK'], //备注
            bomTemplateName: "BOM"
          }
          button.loading = true;
          this.setLoading(event, true);
          this.substituteService
            .replaceSetting(params)
            // .pipe(catchError(i => of({ data: { NAME$: 'TEST111' } })))
            .subscribe({
              next: res => {
                if (res.data) {
                  const node = this.getNode(event) as RowNode;
                  // 当前行的下表
                  const replaceIndex = node.parentNode!.childrenAfterSort!.findIndex(item => item.id === node.id);
                  // / 被替换节点的上一个
                  const previousRow = node.parentNode!.childrenAfterSort![replaceIndex - 1];
                  const isFirst = replaceIndex === 0;
                  this.bomTableRefreshService
                    .refresh(BomOperationTypeEnum.REPLACE_ITEM, {
                      table: tableCpm,
                      details: [{ result: 'SUCCESS', data: { CHILD: res.data['child'], PARENT: res.data['parent'], AFFECTED: [{}] } }],
                      parentNode: node.parentNode!,
                      nearRow: previousRow,
                      isFirst: isFirst
                    })
                    .subscribe();
                  this.dppMessageService.success('common.operation.operationSuccess');
                }
                button.loading = false;
                this.setLoading(event, false);
                modal.close();
              },
              error: err => {
                button.loading = false;
                this.setLoading(event, false);
              }
            });
        }
      }
    ]
  });
}

