/**
 * @description 批量删除交付物
 *  @use tb项目任务对象-交付项和交付物详情-悬停操作栏
 */
sysTBTaskDeliverablesBatchDeleteAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const triggerInstance = table.dppRender.innerSend?.triggerInstance?.() as DppTableComponent;
  const projectData = triggerInstance?.dppRender?.data as IFoundaton;
  const data = table.getCheckedNodeList();
  const dppRenderData = { ...table.dppRender.dParams, ...table.dppRender.innerSend?.instanceData } as IFoundaton;
  // 交付物
  let object: Array<{
    projectID?: string;
    taskID?: string;
    GUID: string;
    TASK?: string;
    TASK$CLASS?: string;
    PROJECT?: string;
    PROJECT$CLASS?: string;
  }> = [];
  // 交付项
  let params: Array<{
    projectID?: string;
    taskID?: string;
    GUID: string;
    TASK?: string;
    TASK$CLASS?: string;
    PROJECT?: string;
    PROJECT$CLASS?: string;
  }> = [];
  data.forEach(item => {
    if (item.origin['ISROOT'] != 'Y') {
      object.push({
        GUID: item.origin['GUID'],
        taskID: dppRenderData?.['taskID']?.toString()!,
        projectID: projectData?.['projectID']!
      });
    } else {
      params.push({
        GUID: item.origin['GUID'],
        taskID: dppRenderData?.['taskID']?.toString()!,
        projectID: projectData?.['projectID']!
      });
    }
  });
  if (object?.length) {
    this.setLoading(event, true);
    this.tbProjectManageService.batchDeleteDeliverable(object).subscribe(res => {
      if (res.success) {
        if (res.data?.successCnt && res.data?.successCnt == res.data?.totalCnt) {
          this.dppMessageService.success('basic.modalTip.deleteSucceed');
        }
        if (res.data?.errorCnt) {
          this.errorMessageService.showMessage(event, res);
        }
        if (res.data?.successCnt) table.refreshData();
      }
      this.setLoading(event, false);
    });
  } else {
    if (params?.length) {
      this.setLoading(event, true);
      this.tbProjectManageService.batchDeleteDeliveryItem(params).subscribe(res => {
        if (res.success) {
          if (res.data?.successCnt && res.data?.successCnt == res.data?.totalCnt) {
            this.dppMessageService.success('basic.modalTip.deleteSucceed');
          }
          if (res.data?.errorCnt) {
            this.errorMessageService.showMessage(event, res);
          }
          if (res.data?.successCnt) table.refreshData();
        }
        this.setLoading(event, false);
      });
    }
  }
}

