// 相邻位置新建确认按钮
sysTableNewBrotherNodeCompteAction(event: EventInterface): void {
  const newItemEvent = this.getContentCom<DppWizardComponent>(event).dppRender.mParams[
    'newItemEvent'
  ] as EventInterface;
  const { table, node } = this._useKey(newItemEvent);
  const newObject$ = this.publicEvent.sysNewItemCompleteEcoAction(event, {
    openObject: false,
    refreshTable: false
  });

  const { fromProcess, createTask } = this.getCreateContext(newItemEvent);

  let checkout = false;
  let checkoutResult: CheckoutResult<any>;

  newObject$
    .pipe(
      switchMap(data => {
        return of(data).pipe(
          concatMap(data =>
            iif(
              () => checkout,
              // @ts-ignore
              of({ context: data, shouldRefresh: false, checkoutData: undefined }),
              this._handleCheckOut(node.parentNode!.origin, fromProcess, data)
            )
          ),
          tap(checkoutRes => {
            checkout = true;
            checkoutResult = checkoutRes as CheckoutResult<any>;
          }),
          concatMap(({ context }) => this._handleSequenceInsertCheck(context, [context], node)),
          concatMap(({ list, context }) => this._addRelationNext(node, list, context, fromProcess, createTask)),
          map(({ addResult, context }) => _handleResult(addResult, context)),
          catchError(err => _handleError(err, () => {}, checkoutResult))
        );
      })
    )
    .subscribe();

  // @ts-ignore
  let _that = this;
  function _handleResult(res: any, context: any): void {
    if (res.success) {
      const { successCnt, totalCnt, errorCnt, details } = res.data;
      if (successCnt === totalCnt) {
        _that.message.success('common.operation.newNeighborSuccess');
      } else if (errorCnt === totalCnt) {
        _that.showBatchMessage(event, res);
      } else {
        _that.showBatchMessage(event, res);
      }
      _that.bomTableRefreshService
        .refresh(BomOperationTypeEnum.ADD_CHILD, {
          table,
          details: res.data.details,
          nearRow: node,
          parentNode: node.parentNode!
        })
        .subscribe();
      _that.getRootPageService(event)?.refreshInstanceData({
        preventGuessSuggestionsRefresh: true
      });
    }
  }
  function _handleError(err: any, closeLoading: () => void, checkoutResult: CheckoutResult<any>): Observable<void> {
    if (err.type === 'valid' || err.type === 'checkout') {
      _that.message.error(err.message);
    } else {
      // 可能是后续的报错，判断是否需要刷新检出状态
      if (checkoutResult?.shouldRefresh) {
        // 调用表格刷新
        _that.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            details: [
              {
                result: 'SUCCESS',
                data: {
                  PARENT: { ...checkoutResult.checkoutData!, GUID$: checkoutResult.checkoutData!['END2#GUID$'] }
                }
              }
            ]
          })
          .subscribe();
      }
    }
    closeLoading();
    console.error(err);
    return EMPTY;
  }
}

