/**
 * @description 相邻位置添加
 * @jiexi 打开选择对象弹窗，1选择对象后，2【检出父级-查询bom模版信息】，3判断是否需要刷新顺序号插入，4添加关系
 * @param event
 */
sysTableAddBrotherNodesAction(event: EventInterface): void {
  const { table, node, btnModel } = this._useKey(event);

  const { fromProcess, createTask } = this.getCreateContext(event);

  const selectNode$ = this._openSelectObjectDialog(btnModel, node.parentNode!, event, this.message);
  let dialog: ModalSelect;
  let checkout = false;
  let checkoutResult: CheckoutResult<ModalSelect>;

  selectNode$
    .pipe(
      tap(data => {
        dialog = data;
      }),

      switchMap(dialogData => {
        return of(dialogData).pipe(
          map(dialogData => _validateDialogData(dialogData)),
          concatMap(dialogData => {
            return iif(
              () => checkout,
              // @ts-ignore
              of({ context: dialogData, shouldRefresh: false, checkoutData: undefined }),
              this._handleCheckOut(node.parentNode!.origin, fromProcess, dialogData)
            );
          }),
          tap(checkoutRes => {
            checkout = true;
            checkoutResult = checkoutRes as CheckoutResult<ModalSelect>;
          }),
          concatMap(({ context }) =>
            this._handleSequenceInsertCheck(
              checkoutResult,
              context.selectNodes.map(node => node.origin),
              node
            )
          ),
          concatMap(({ context, list }) => this._addRelationNext(node, list, context, fromProcess, createTask)),
          map(({ addResult, context }) => _handleResult(addResult, context)),
          catchError(err => _handleError(err, dialog.closeLoading, checkoutResult))
        );
      })
    )
    .subscribe();

  // @ts-ignore
  const _that = this;
  function _validateDialogData<T extends ModalSelect>(dialogData: T): T {
    const list = dialogData.selectNodes;
    if (!list || list.length === 0) {
      throw {
        type: 'valid',
        message: 'common.operation.noDataSelected'
      };
    }
    return dialogData;
  }
  function _handleResult(res: any, checkoutResult: any): Observable<never> {
    checkoutResult.context.closeLoading();

    if (res.success) {
      const { successCnt, totalCnt, errorCnt, details } = res.data;
      if (successCnt === totalCnt) {
        _that.message.success('common.operation.addNeighborSuccess');
        checkoutResult.context.close();
      } else if (errorCnt === totalCnt) {
        _that.showBatchMessage(event, res);
      } else {
        _that.showBatchMessage(event, res);
      }
      _that.bomTableRefreshService
        .refresh(BomOperationTypeEnum.ADD_CHILD, {
          table,
          details: res.data.details,
          nearRow: node,
          parentNode: node.parentNode!
        })
        .subscribe();
      _that.getRootPageService(event)?.refreshInstanceData({
        preventGuessSuggestionsRefresh: true
      });
    }
    return EMPTY;
  }

  function _handleError(
    err: any,
    closeLoading: () => void,
    checkoutResult: CheckoutResult<ModalSelect>
  ): Observable<void> {
    if ((err.type === 'valid' || err.type === 'checkout') && err.message) {
      _that.message.error(err.message);
    } else {
      // 可能是后续的报错，判断是否需要刷新检出状态
      if (checkoutResult?.shouldRefresh) {
        _that.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            details: [
              {
                result: 'SUCCESS',
                data: {
                  PARENT: { ...checkoutResult.checkoutData!, GUID$: checkoutResult.checkoutData!['END2#GUID$'] }
                }
              }
            ]
          })
          .subscribe();
      }
    }
    closeLoading();
    console.error(err);
    return EMPTY;
  }
}

/**
 * @description 相邻位置粘贴
 * @jiexi
 * @param event
 */
sysBOMTableAddBrotherNodesAction(event: EventInterface): void {
  const { table, node } = this._useKey(event);

  const { fromProcess, createTask } = this.getCreateContext(event);

  const copyNode = this.authService.getClipBoardSet(clipBoardTypeEnum.OBJECT_TYPE);
  if (!copyNode || copyNode.size === 0) {
    this.message.warning('common.operation.clipboardEmpty');
    return;
  }

  this.setLoading(event, true);

  let checkoutResult: CheckoutResult<any>;

  const selectNode$ = of([...copyNode] as unknown as any[]);
  selectNode$
    .pipe(
      switchMap(data => {
        return of(data).pipe(
          map(data => _validateDialogData(data)),
          concatMap(data => this._handleCheckOut(node.parentNode!.origin, fromProcess, data)),
          tap(checkoutRes => {
            checkoutResult = checkoutRes as CheckoutResult<any>;
          }),
          concatMap(({ context }) => this._handleSequenceInsertCheck(context, context, node)),
          concatMap(({ list }) => this._copyRelationNext(node, list, fromProcess, createTask)),
          map(({ addResult, context }) => _handleResult(addResult, checkoutResult)),
          catchError(err => _handleError(err, checkoutResult))
        );
      }),
      finalize(() => {
        this.setLoading(event, false);
      })
    )
    .subscribe();
  // @ts-ignore
  const _that = this;
  function _validateDialogData<T extends any[]>(data: T): T {
    if (!data || data.length === 0) {
      throw {
        type: 'valid',
        message: 'common.operation.noDataSelected'
      };
    }
    return data;
  }
  function _handleResult(res: any, context: any): void {
    _that.setLoading(event, false);
    if (res.success) {
      const { successCnt, totalCnt, errorCnt, details } = res.data;
      if (successCnt === totalCnt) {
        _that.message.success('common.operation.operationSuccess');
      } else if (errorCnt === totalCnt) {
        _that.showBatchMessage(event, res);
      } else {
        _that.showBatchMessage(event, res);
      }

      // 如果是剪切，清空表格中剪切的横线
      const isCut = localStorage.getItem('isCut') || 'false';
      if (isCut === 'true') {
        const copyNodes = Array.from(_that.authService.getClipBoardSet(clipBoardTypeEnum.OBJECT_TYPE));
        copyNodes.forEach(item => {
          let parentId = item['PARENTGUID'];
          let childId = item['OLDRELATION'];
          _that.bomTableRefreshService
            .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
              table,
              details: [
                {
                  result: 'SUCCESS',
                  data: {
                    PARENT: { GUID$: parentId },
                    CHILD: { GUID$: childId, cutStatus: '', isRefresh: false }
                  }
                }
              ]
            })
            .subscribe();
        });
      }
      // 清空应用中复制或者剪切的内容
      localStorage.removeItem(clipBoardTypeEnum.OBJECT_TYPE);

      _that.bomTableRefreshService
        .refresh(BomOperationTypeEnum.ADD_CHILD, {
          table,
          details: res.data.details,
          nearRow: node,
          parentNode: node.parentNode!
        })
        .subscribe();
      _that.getRootPageService(event)?.refreshInstanceData({
        preventGuessSuggestionsRefresh: true
      });
    }
  }
  function _handleError(err: any, checkoutResult: CheckoutResult<any> | undefined): Observable<void> {
    _that.setLoading(event, false);
    if (err.type === 'valid' || err.type === 'checkout') {
      _that.message.error(err.message);
    } else {
      // 可能是后续的报错，判断是否需要刷新检出状态
      if (checkoutResult?.shouldRefresh) {
        _that.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            details: [
              {
                result: 'SUCCESS',
                data: {
                  PARENT: { ...checkoutResult.checkoutData!, GUID$: checkoutResult.checkoutData!['END2#GUID$'] }
                }
              }
            ]
          })
          .subscribe();
      }
    }
    console.error(err);
    return EMPTY;
  }
}

