        message: 'common.operation.noDataSelected'
      };
    }
    let firstSelectData = list[0].origin;

    if (node.origin['END2#GUID$'] == firstSelectData['GUID$']) {
      throw {
        type: 'valid',
        message: 'common.operation.unmodifiedData'
      };
    }
    return dialogData;
  }
  function _handleResult(res: any, context: ModalSelect): void {
    if (res.success) {
      const { successCnt, totalCnt, errorCnt, details } = res.data;
      if (successCnt === totalCnt) {
        _that.message.success('common.operation.switchItemSuccess');
        context.closeLoading();
        context.close();
      } else if (errorCnt === totalCnt) {
        _that.showBatchMessage(event, res);
      } else {
        _that.showBatchMessage(event, res);
        context.closeLoading();
        context.close();
      }
      const replaceIndex = node.parentNode!.childrenAfterSort!.findIndex(item => item.id === node.id);
      const previousRow = node.parentNode!.childrenAfterSort![replaceIndex - 1];
      const isFirst = replaceIndex === 0;
      _that.bomTableRefreshService
        .refresh(BomOperationTypeEnum.REPLACE_ITEM, {
          table,
          details: res.data.details,
          parentNode: node.parentNode!,
          nearRow: previousRow,
          isFirst: isFirst
        })
        .subscribe();
      _that.getRootPageService(event)?.refreshInstanceData({
        preventGuessSuggestionsRefresh: true
      });
    }
  }
  function _handleError(
    err: any,
    closeLoading: () => void,
    checkoutResult: CheckoutResult<ModalSelect>
  ): Observable<void> {
    if (err.type === 'valid' || err.type === 'checkout') {
      _that.message.error(err.message);
    } else {
      // 可能是后续的报错，判断是否需要刷新检出状态
      if (checkoutResult?.shouldRefresh) {
        // 调用表格刷新
        _that.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            details: [
              {
                result: 'SUCCESS',
                data: {
                  PARENT: { ...checkoutResult.checkoutData!, GUID$: checkoutResult.checkoutData!['END2#GUID$'] }
                }
              }
            ]
          })
          .subscribe();
      }
    }
    closeLoading();
    console.error(err);
    return EMPTY;
  }
}

/**
 * 粘贴为子阶
 * @param event
 * @returns
 */
sysBOMTableAddChildNodeAction(event: EventInterface): void {
  const { node, table } = this._useKey(event);
  const { fromProcess, createTask } = this.getCreateContext(event);

  const copyNode = this.authService.getClipBoardSet(clipBoardTypeEnum.OBJECT_TYPE);

  if (!copyNode || copyNode.size === 0) {
    this.message.warning('common.operation.clipboardEmpty');
    return;
  }
  this.setLoading(event, true);

  let checkoutResult: CheckoutResult<any>;

  const selectNode$ = of([...copyNode] as unknown as any[]);
  selectNode$
    .pipe(
      concatMap(data => {
        return of(data).pipe(
          concatMap(data => this._handleCheckOut(node.origin, fromProcess, data)),
          tap(checkoutRes => {
            checkoutResult = checkoutRes as CheckoutResult<any>;
          }),
          concatMap(({ checkoutData, context }) => this._cutAndAddRelation(node, context, fromProcess, createTask)),
          map(({ addResult, context }) => _handleResult(addResult, checkoutResult)),
          catchError(err => _handleError(err, checkoutResult)),
          finalize(() => {
            this.setLoading(event, false);
          })
        );
      })
    )
    .subscribe();

  // @ts-ignore
  const _that = this;
  function _handleResult(res: any, context: any): void {
    if (res.success) {
      const { successCnt, totalCnt, errorCnt, details } = res.data;
      if (successCnt === totalCnt) {
        _that.message.success('common.operation.operationSuccess');
      } else if (errorCnt === totalCnt) {
        _that.showBatchMessage(event, res);
      } else {
        _that.showBatchMessage(event, res);
      }

      // 如果是剪切，清空表格中剪切的横线
      const isCut = localStorage.getItem('isCut') || 'false';
      if (isCut === 'true') {
        const copyNodes = Array.from(_that.authService.getClipBoardSet(clipBoardTypeEnum.OBJECT_TYPE));
        copyNodes.forEach(item => {
          let parentId = item['PARENTGUID'];
          let childId = item['OLDRELATION'];
          _that.bomTableRefreshService
            .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
              table,
              details: [
                {
                  result: 'SUCCESS',
                  data: {
                    PARENT: { GUID$: parentId },
                    CHILD: { GUID$: childId, cutStatus: '', isRefresh: false }
                  }
                }
              ]
            })
            .subscribe();
        });
      }
      // 清空应用中复制或者剪切的内容
      localStorage.removeItem(clipBoardTypeEnum.OBJECT_TYPE);

      _that.bomTableRefreshService
        .refresh(BomOperationTypeEnum.ADD_CHILD, {
          table,
          details: res.data.details,
          nearRow: undefined,
          parentNode: node
        })
        .subscribe();
      _that.getRootPageService(event)?.refreshInstanceData({
        preventGuessSuggestionsRefresh: true
      });
    }
  }
  function _handleError(err: any, checkoutResult: CheckoutResult<any> | undefined): Observable<void> {
    if (err.type === 'valid' || err.type === 'checkout') {
      _that.message.error(err.message);
    } else {
      // 可能是后续的报错，判断是否需要刷新检出状态
      if (checkoutResult?.shouldRefresh) {
        // 调用表格刷新
        _that.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            details: [
              {
                result: 'SUCCESS',
                data: {
                  PARENT: { ...checkoutResult.checkoutData!, GUID$: checkoutResult.checkoutData!['END2#GUID$'] }
                }
              }
            ]
          })
          .subscribe();
      }
    }
    return EMPTY;
  }
}

/**
 * @description 添加子级
 * @use bom
 * @param event
 */
sysTableAddChildNodeAction(event: EventInterface): void {
  const { node, table, btnModel, templateName } = this._useKey(event);

  const { fromProcess, createTask } = this.getCreateContext(event);

  const selectNode$ = this._openSelectObjectDialog(btnModel, node, event, this.message);
  let dialog: ModalSelect;
  // 如果第一次添加检出成功，后续报错，再次点击则不需要检出
  let checkout = false;
  let checkoutResult: CheckoutResult<ModalSelect>;
  selectNode$
    .pipe(
      tap(data => {
        dialog = data;
      }),
      // 套一层，防止出错导致不能再次点击
      concatMap(dialogData => {
        return of(dialogData).pipe(
          // 数据有效性验证
          map(dialogData => _validateDialogData(dialogData)),
          // 检出父级
          concatMap(dialogData => {
            return iif(
              () => checkout,
              // @ts-ignore
              of({ context: dialogData, shouldRefresh: false, checkoutData: undefined }),
              this._handleCheckOut(node.origin, fromProcess, dialogData)
            );
          }),
          tap(checkoutRes => {
            checkout = true;
            checkoutResult = checkoutRes as CheckoutResult<ModalSelect>;
          }),
          // 添加关联关系
          concatMap(checkoutResult => this._addChildRelation(node, checkoutResult, fromProcess, createTask)),
          // 消息提示及刷新处理
          map(({ addResult, context }) => _handleResult(addResult, context)),
          catchError(err => _handleError(err, dialog.closeLoading, checkoutResult)),
          finalize(() => {
            dialog.closeLoading();
          })
        );
      })
    )
    .subscribe();

  // @ts-ignore
  const _that = this;
  function _validateDialogData<T extends ModalSelect>(dialogData: T): T {
    const list = dialogData.selectNodes;
    if (!list || list.length === 0) {
      throw {
        type: 'valid',
        message: 'common.operation.noDataSelected'
      };
    }
    return dialogData;
  }
  function _handleResult(res: any, checkoutResult: any): void {
    if (res.success) {
      const { successCnt, totalCnt, errorCnt, details } = res.data;
      if (successCnt === totalCnt) {
        _that.message.success('common.operation.addChildSuccess');

        checkoutResult.context.closeLoading();
        checkoutResult.context.close();
      } else if (errorCnt === totalCnt) {
        _that.showBatchMessage(event, res);
      } else {
        _that.showBatchMessage(event, res);

        checkoutResult.context.closeLoading();
      }
      _that.bomTableRefreshService
        .refresh(BomOperationTypeEnum.ADD_CHILD, {
          table,
          details: res.data.details,
          nearRow: undefined,
          parentNode: node
        })
        .subscribe();
      _that.getRootPageService(event)?.refreshInstanceData({
        preventGuessSuggestionsRefresh: true
      });
    }
  }

  function _handleError(
    err: any,
    closeLoading: () => void,
    checkoutResult: CheckoutResult<ModalSelect>
  ): Observable<void> {
    closeLoading();
    if (err.type === 'valid' || err.type === 'checkout') {
      _that.message.error(err.message);
    } else {
      // 可能是后续的报错，判断是否需要刷新检出状态
      if (checkoutResult?.shouldRefresh) {
        // 调用表格刷新
        _that.bomTableRefreshService
          .refresh(BomOperationTypeEnum.UPDATE_PARENT_PROPERTIES, {
            table,
            details: [
              {
                result: 'SUCCESS',
                data: {
                  PARENT: { ...checkoutResult.checkoutData!, GUID$: checkoutResult.checkoutData!['END2#GUID$'] }
                }
              }
            ]
          })
          .subscribe();
      }
    }

    console.error(err);
    return EMPTY;
  }
}

// 批量移除
sysBOMBatchRemoveEnd2Action(event: EventInterface): void {
  const instanceData = this.getRootPageService(event)?.getInstanceData();
  if ((instanceData as any)?.['STATUS'] == 'RLS') {
    this.message.warning('common.operation.rlsObjectNotOperation');
    return;
  }

  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const fromProcess = table.dppRender.dParams!['fromProcess'] === 'true' ? true : undefined;
  const templateName = table.queryCondition.params.get('templateName') as string;
  const selectNodes = table.getCheckedNodes();

  // 根节点不能进行移除操作
  const isRootY = selectNodes.some(item => item.origin['ISROOT'] === 'Y');
  if (isRootY) {
    this.message.warning('common.message.warning.notRemoveRootNode');
    return;
  }
  // 只有同阶才能进行移除操作
  const isSameLevel =
    selectNodes.length > 0 && selectNodes.every(item => item['uiLevel'] === selectNodes[0]['uiLevel']);

  if (!isSameLevel) {
    this.message.warning('common.operation.selectSameGrade');
    return;
  }

  if (selectNodes.length === 0) {
    this.message.warning('common.operation.noDataSelect');
    return;
  }

  const filterSelectNodes = selectNodes.filter(item => item.origin['ROWKEY']);
  if (!filterSelectNodes.length) {
    this.message.warning('common.message.warning.notAllowRootNode');
    return;
  }

  this.setLoading(event, true);
  const removeParams = createParams();

  this.relation
    .removeBom(removeParams as any)
    .pipe(finalize(() => this.setLoading(event, false)))
    .subscribe({
      next: res => {
        const { successCnt, totalCnt, errorCnt, details } = res?.data as any;

        if (res.success && successCnt === totalCnt) {
          if (filterSelectNodes.length < selectNodes.length) {
            this.message.success('common.message.success.filterRootNode');
          } else {
            this.message.success('common.operation.removeSucceed');
          }
          this.bomTableRefreshService
            .refresh(BomOperationTypeEnum.REMOVE_RELATION, {
              table,
              details: details
            })
            .subscribe();

          this.getRootPageService(event)?.refreshInstanceData({
            preventGuessSuggestionsRefresh: true
          });
        } else {
          this.showBatchMessage(event, res as any);
          if (totalCnt === errorCnt) return;
        }
      }
    });

  function createParams(): Record<string, NzSafeAny> {
    const { key, classNameKey, treeKey, treeClassNameKey } = useKey();
    return {
      fromProcess,
      structure: filterSelectNodes.map(item => {
        return {
          objectGuid: {
            guid: item.origin[key],
            className: item.origin[classNameKey]
          }
        };
      })
    };
  }
}

