public getRoute(node: RowNode): string[] {
  const path: string[] = [];
  let current: RowNode | null = node;
  while (current) {
    path.unshift(current.id!);
    current = current.parentNode;
  }
  return path;
}

private _addChildRelation(
  node: RowNode,
  checkoutResult: NzSafeAny,
  fromProcess: boolean,
  createTask: boolean
): Observable<NzSafeAny> {
  const selectData = checkoutResult.context.selectNodes;
  const params = {
    fromProcess,
    end1: {
      guid: node.origin['END2#GUID$'],
      className: node.origin['END2#CLASSNAME$']
    },
    isCreateTask: createTask,
    structure: selectData.map((item: any) => {
      return {
        end2: {
          guid: item.origin['GUID$'],
          className: item.origin['CLASSNAME$']
        },
        props: {}
      };
    })
  };
  return this.relation.addBomChild(params).pipe(
    map(addResult => {
      return {
        context: checkoutResult,
        addResult: addResult
      };
    })
  );
}

