/**
 * @description 得到能插入的数量
 * @param node 当前节点
 * @returns {number} -10插入任意数量 0不能插入
 */
private _calcInsertNum(node: RowNode): number {
  const parentNode = node.parentNode!;
  const children = parentNode.children;
  const nextNode = children[children.indexOf(node) + 1];
  if (!nextNode) {
    return -10;
  }
  const nodeSeq = parseInt(node.origin['DATASEQ'], 10);
  const nextNodeSeq = parseInt(nextNode.origin['DATASEQ'], 10);
  return Math.floor(nextNodeSeq - nodeSeq) - 1;
}

/**
 * @description 检出node时需要刷新表格的回调
 * @param node 需要刷新的节点
 *
 * @param table
 */
private _checkOutTableCallback(node: RowNode, table: DppTableComponent): void {
  const dppUser: DppSafeAny = this.authService.getUser() || {};
  const userID = dppUser.guid || '';
  const userName = dppUser.userName || '';

  const viewValue = node.origin['VIEW#ISCHECKOUT$'];
  const state = viewValue ? node.origin['VIEW#STATUS$'] : 'WIP';

  let refreshData = {
    'VIEW#ISCHECKOUT$': 'Y',
    'VIEW#CHECKOUTUSER$': userID,
    'VIEW#CHECKOUTUSER$NAME': userName,
    VIEWEDITTYPE$: 'CHECKIN',
    'VIEW#STATUS$': state,
    ISEDIT$: true
  };
  table.refreshNode(node, refreshData);
}

private showBatchMessage(event: EventInterface, res: any): void {
  res = deepCopy(res);
  let processData = (item: any): Record<string, any> | undefined => {
    let data = item.data;
    if (typeof data === 'object' && data !== null) {
      return {
        result: item.result,
        message: item.message,
        data: {
          ...(data.CHILD || {})
        }
      };
    } else {
      return undefined;
    }
  };
  const result = res.data.details.map((item: any) => processData(item)).filter((item: any) => item !== undefined);
  res.data.details = result;
  this.errMessageService.showMessage(event, res);
}

// 获取新增操作的相关参数
private getCreateContext(event: EventInterface): { fromProcess: boolean; createTask: boolean } {
  const table = this.getContentCom(event) as DppTableComponent;
  const dParams = table.dppRender.dParams || {};
