/**
 * @description 打开是否刷新顺序号插入的弹窗
 * @param insertNum 插入的数量
 * @param outNum 超出的数量
 * @returns {Observable<boolean>} true 刷新 false 不刷新
 * @private
 */
private _openSeqDialog(insertNum: number, outNum: number): Array<Observable<boolean>> {
  const confirmText = 'common.operation.confirm.treeInsert.sequenceRunOutConfirm';
  const okText = 'common.command.sysRefreshSequenceAndInsert';
  const cancelText = 'common.command.sysNoRefreshSequenceAndInsert';
  const dialogTitleText = 'common.operation.confirm.treeInsert.outOfRangeContent';

  const translateText$ = this.translate.get([confirmText, okText, cancelText]);
  const refreshInsert$ = new Subject<boolean>();
  const noIconToClose$ = new Subject<boolean>();
  let autoClose = false;

  translateText$.subscribe(res => {
    const cText = res[confirmText];
    const oText = res[okText];
    const caText = res[cancelText];
    let confirmModal: DppNzModalRef | undefined = new ModalClass(this.dialog).confirm(
      cText,
      {
        title: this.translate.instant(dialogTitleText, {
          num1: insertNum,
          num2: outNum
        }),
        dppFooter: [
          {
            label: caText,
            onClick: () => {
              refreshInsert$.next(false);
              noIconToClose$.next(true);
              autoClose = true;
              confirmModal?.close();
            }
          },
          {
            label: oText,
            type: 'primary',
            onClick: () => {
              refreshInsert$.next(true);
              noIconToClose$.next(true);
              autoClose = true;
              confirmModal?.close();
            }
          }
        ]
      },
      true
    );
    confirmModal.afterClose.subscribe(() => {
      if (!autoClose) {
        refreshInsert$.next(false);
        noIconToClose$.next(false);
        confirmModal?.close();
      }
    });
  });
  return [refreshInsert$.asObservable(), noIconToClose$.asObservable()];
}

private _cutAndAddRelation(
  node: RowNode,
  children: any[],
  fromProcess: boolean,
  createTask: boolean
): Observable<DppSafeAny> {
  const data = node.origin;
  const { treeKey, treeClassNameKey } = useKey();
  let isCopy = !localStorage.getItem('isCut');
  const params = {
    fromProcess,
    end1: {
      guid: data[treeKey],
      className: data[treeClassNameKey]
    },
    isCopy,
    isCreateTask: createTask,
    isLast: true,
    structure: children.map(item => {
      return {
        // 对象
        end2: {
          guid: item.GUID,
          className: item.CLASSNAME
        },
        //结构
        objectGuid: {
          guid: item.OLDRELATION,
          className: item.OLDRELATION$CLASSNAME
        },
        props: {}
      };
    })
  };
  return this.relation.cutAndCopy(params).pipe(
    map(res => {
      return {
        context: null,
        addResult: res
      };
    })
  );
}

