          COMMITFOLDER$NAME: rootData['COMMITFOLDER$NAME'] || data['END2#COMMITFOLDER$NAME'],
          COMMITFOLDER$PATH: rootData['COMMITFOLDER$PATH'] || data['END2#COMMITFOLDER$PATH'],
          COMMITFOLDER$GUIDPATH: rootData['COMMITFOLDER$GUIDPATH'] || data['END2#COMMITFOLDER$GUIDPATH'],
          className: data['END2$CLASSNAME'],
          guid: data[treeKey],
          templateNames: templateName,
          ENABLED: enabled
        }
      };
      this.setLoading(event, true);

      const modal: DppNzModalRef = this.dialog.openModal(
        {
          title: bs.getUiModel().label,
          width: action.width,
          bodyStyle: { height: action.height! },
          closable: true,
          // bodyStyle: { height: '40vh' },
          // content: DppWizardComponent,
          uiType: UIModelTypeEnum.WIZARD,
          footer: 'noFooter',
          isInteractive: false,
          modalSelf: () => modal,
          triggerInstance: () => table
        },
        { dppRender: render }
      );
      modal.afterClose.subscribe(() => {
        this.setLoading(event, false);
      });
    }
  });
}

/**
 * @description 替换关联关系
 * @param node 被替换的节点
 * @param selectNode 选中的节点
 * @param isBOM
 * @param isCreateTask
 * @param templateName
 */
private _replaceRelation(
  node: RowNode,
  context: ModalSelect,
  fromProcess: boolean,
  createTask: boolean
): Observable<NzSafeAny> {
  const { key, classNameKey, treeKey, treeClassNameKey } = useKey();
  const selectData = context.selectNodes[0].origin;

  let params = {
    fromProcess,
    end2: {
      guid: selectData[key],
      className: selectData[classNameKey]
    },
    isCreateTask: createTask,
    structure: {
      objectGuid: {
        guid: node.origin[key],
        className: node.origin[classNameKey]
      }
    }
  };
  return this.relation.replaceBom(params).pipe(
    map(res => {
      return {
        context: context,
        addResult: res
      };
    })
  );
}

/**
 * @description 相邻位置粘贴关联关系(bom)
 * @param node 当前节点
 * @param list  添加的数据
 * @param isBOM
 * @param isCreateTask
 * @param templateName
 * @param refresh 是否刷新
 * @param canInsertNum 可插入的数量
 * @param templateInfo
 */
private _copyRelationNext(
  node: RowNode,
  list: DppSafeAny[],
  fromProcess: boolean,
  createTask: boolean
): Observable<DppSafeAny> {
  const data = node.parentNode!.origin;
  const { treeKey, treeClassNameKey, key, classNameKey } = useKey();
  let isCopy = !localStorage.getItem('isCut');
  const params = {
    fromProcess,
    end1: {
      guid: data[treeKey],
      className: data[treeClassNameKey]
    },
    isCopy,
    isCreateTask: createTask,
    isLast: node.parentNode!.children[node.parentNode!.children.length - 1] === node,
    nearby: {
      guid: node.origin[key],
      className: node.origin[classNameKey]
    },
    structure: list.map(item => {
      return {
        // 对象
        end2: {
          guid: item.GUID,
          className: item.CLASSNAME
        },
        //结构
        objectGuid: {
          guid: item.OLDRELATION,
          className: item.OLDRELATION$CLASSNAME
        },
        props: {}
      };
    })
  };
  return this.relation.cutAndCopy(params).pipe(
    map(res => {
      return {
        context: null,
        addResult: res
      };
    })
  );
}

private _useKey(event: EventInterface): TableEventParams {
  const table = this.getContentCom(event) as DppTableComponent;
  const node = this.getNode(event) as RowNode;
  const data = node.origin;
  const templateName = table.modelManager.rootInfo?.params['templateName'] as string;
  const btnModel = this.getExeModel(event);
  const action = btnModel['action'];
  const isBOM = action['isBOM'] === 'Y';
  const isCreateTask = action['isCreateTask'] === 'Y';
  const parentNode = node.parentNode!;
  return {
    table,
    node,
    data,
    templateName,
    btnModel,
    action,
    isBOM,
    isCreateTask,
    parentNode
  };
}

private isRootNode(node: RowNode): boolean {
  return node.level === 0;
}

private isAboveOrBelowPosition(position: DropTypeEnum): boolean {
  return position === DropType.Above || position === DropType.Below;
}

private getNodePermissions(node: RowNode): NodePermissions {
  return node.origin['PERMISSIONS$'];
}

private hasNoPermission(node: RowNode, permissionKey: keyof NodePermissions): boolean {
  const permissions = this.getNodePermissions(node);
  return permissions?.[permissionKey] === 'N';
}

private isChildPosition(position: DropTypeEnum): boolean {
  return position === DropType.Child;
}

/**
 * 根据放置位置获取需要检查的权限键
 */
private getPermissionKeyByPosition(position: DropTypeEnum): keyof NodePermissions | null {
  if (this.isAboveOrBelowPosition(position)) {
    return 'ADDNEIGHBOR$';
  } else if (this.isChildPosition(position)) {
    return 'ADDCHILD$';
  }
  return null;
}

public sysValidBomDragAction(params: RowDragValidateParams): DragValidationResult {
  const { dragNode } = params;

  if (this.isRootNode(dragNode)) {
    return { canDrag: false, reason: VALIDATION_MESSAGES.ROOT_NODE_CANNOT_DRAG };
  }

  if (this.hasNoPermission(dragNode, 'DRAG$')) {
    return { canDrag: false, reason: VALIDATION_MESSAGES.PERMISSION_DENIED };
  }

  return { canDrag: true };
}

// bom drop 验证
public sysValidBomDropAction(params: RowDropValidateParams): DropValidationResult {
  const { dragNode, dropNode, position } = params;

  if (this.isRootNode(dropNode) && this.isAboveOrBelowPosition(position)) {
    return { canDrop: false, reason: VALIDATION_MESSAGES.CANNOT_DROP_AT_ROOT_SIBLING };
  }

  const permissionKey = this.getPermissionKeyByPosition(position);
  if (permissionKey && this.hasNoPermission(dropNode, permissionKey)) {
    return { canDrop: false, reason: VALIDATION_MESSAGES.PERMISSION_DENIED };
  }

  return { canDrop: true };
}

// 设计变更（下一页）
sysECMNextPageAction(event: EventInterface): void {
  const wizardCom = this.getContentCom<DppWizardComponent>(event);
  const wizardData = wizardCom.getWizardData();
  if (wizardData.currentIndex === 0) {
    const formCom = wizardCom.getWizardHeadInstance<DppFormComponent>(0);
    if (formCom.getNotTranFormData<IBaseData>()[SystemClassFieldEnum.GUID]) {
      // 判断是否已经加载过后面的组件了
      if (Object.keys(wizardCom.getComponentRefs()).length > 1) {
        wizardCom.next();
        return;
      }
      WizardEventUtil.wizardNextHandleOfForm(formCom, wizardCom);
    } else {
      this.setLoading(event, true);
      if (formCom.onSubmit()) {
        // 创建ecr
        const formData = formCom.getFormData<IBaseData>();
        if (formData['WFTEMPLATEGUID']) {
          formData['autoCreateProcess'] = 'Y';
        }
        this.ecm.createMasterObject(formData).subscribe(
          res => {
            if (res.success) {
              //回调给导向组件中的form组件
              formCom.callback({
                action: EventCallbacksActionName.UPDATE,
                params: res.data
              });
              WizardEventUtil.wizardNextHandleOfForm(formCom, wizardCom);
            } else {
              this.message.warning(`${res.errorCode}:${res.errorMsg}`);
            }
            this.setLoading(event, false);
          },
          error => this.setLoading(event, false)
        );
      } else {
        this.message.warning('basic.common.notice.verificationFailed');
        this.setLoading(event, false);
      }
    }
  } else {
    wizardCom.next();
  }
}

