private async deleteDetailObject(event: EventInterface): Promise<void> {
  const wizardCom = this.getContentCom<DppWizardComponent>(event);
  const comRefS = wizardCom.getComponentRefs();
  if (Object.keys(comRefS).length < 2) {
    return;
  }
  const formCom = wizardCom.getWizardHeadInstance<DppFormComponent>(0);
  const tableCom = wizardCom.getWizardHeadInstance<DppTableComponent>(1);
  const tableDatas = tableCom.getCheckedNodes().map(i => i.origin) as IFoundaton[];

  if (!isEmpty(tableDatas)) {
    const formData = formCom.getNotTranFormData<IFoundaton>();
    await EcmEventUtil.deleteDetailObject(event, formData, tableDatas, this.ecm, this.message, tableCom);
  }
}

private async batchDeleteFiles(event: EventInterface): Promise<void> {
  const wizardCom = this.getContentCom<DppWizardComponent>(event);
  const comRefS = wizardCom.getComponentRefs();
  if (Object.keys(comRefS).length < 3) {
    return;
  }
  const tableCom_ = wizardCom.getWizardHeadInstance<DppTableComponent>(2);
  const tableDatas_ = tableCom_.getCheckedNodeList().map(i => i.origin) as IBaseData[];
  if (!isEmpty(tableDatas_)) {
    const files = new Array<{
      fileGuid: string;
      fileName: string;
    }>();
    const mainFile = { fileGuid: '', fileName: '' };
    tableDatas_.forEach(item => {
      if (item['ISPRIMARY'] === 'Y') {
        mainFile.fileGuid = item['GUID']!;
        mainFile.fileName = item['FILENAME'];
      } else {
        files.push({
          fileName: item['FILENAME'],
          fileGuid: item['GUID']!
        });
      }
    });
    // 保证主文件为最后一个
    files.push(mainFile);
    await this.boas
      .deleteFiles(files)
      .toPromise()
      .then(
        res => {
          if (res!.success && res!.data) {
            if (res!.data.totalCnt === res!.data.successCnt) {
              this.message.success('common.operation.deleteSuccess');
            } else {
              this.message.createTableMessage('success', 'basic.common.button.delete', res!.data);
            }
            // tableCom_.callback(CommonEventUtil.buildCallBack(res!.data, undefined, EventCallbacksActionName.UPDATE));
            tableCom_.refreshData();
          } else {
            this.message.warning(`${res!.errorCode}:${res!.errorMsg}`);
          }
          this.setLoading(event, false);
        },
        err => {
          this.setLoading(event, false);
        }
      );
  }
}

