  model[SystemClassFieldEnum.CLASSNAME] = formData[SystemClassFieldEnum.CLASSNAME];
  model[SystemClassFieldEnum.UPDATETIME] = formData[SystemClassFieldEnum.UPDATETIME];

  model[Form_Constant.INPUT_FILES_KEY] = tableCom.getCheckedNodeList().map(i => i.origin);
  const params: IFormRender = {
    name: action.name,
    mParams: {
      mode: action.mode,
      isObject: action.isObject!
    },
    data: model
    //false
  };
  const modal = CommonEventUtil.buildDefaultModal<DppFormComponent>(
