          res => {
            if (res.success && res.success) {
              if (res!.data!.totalCnt === res!.data!.successCnt) {
                this.message.success('common.operation.operationSuccess');
                this.contentComCallback(
                  event,
                  CommonEventUtil.buildCallBack(undefined, undefined, EventCallbacksActionName.REFRESH)
                );
              } else {
                this.message.error(res.data?.details[0].message!);
              }
              modal.close();
            } else {
              this.message.warning(`${res.errorCode}:${res.errorMsg}`);
            }
            this.setLoading(event, false);
          },
          error => {
            okButtonThis.loading = false;
            this.setLoading(event, false);
          }
        );
      } else {
        // this.message.warning('common.operation.noDataSelect');
        okButtonThis.loading = false;
        // this.setLoading(event, false);
      }
    },
    this.message,
    { key: currentPerformer ? currentPerformer : '' },
    false
  );
}

