/**
 * 工艺分工
 * @param event
 */
processTaskDistribution(event: CardEventInterface): void {
  // eslint-disable-next-line @typescript-eslint/no-this-alias
  const _this = this;
  this.processManagementService.getProcessDesignLibrary().subscribe({
    next: res => {
      if (res.success) {
        const params: IRenderParameterNew<IUiModel> = {
          name: FormConfigModelEnum.PROCESSTASKDISTRIBUTION,
          mParams: {
            mode: ModeTypeEnum.EDIT,
            expression: 'PRODUCTITEMOBJECT:required=true',
            isObject: false
          },
          dParams: {
            // className: cardData?.['CLASSNAME$'],
            // guid: cardData?.['GUID$']
          },
          data: {
            // libraryGuid: res?.data['GUID'],
          }
        };
        if (res.data) {
          params.data!['libraryGuid'] = res?.data['GUID'];
          generateFieldMapping({
            mappingType: 'folder',
            fieldKey: 'COMMITFOLDER$',
            sourceData: res?.data,
            onValueUpdate: (key, value) => {
              params.data![key] = value;
            },
            isMapToObject: false
          });
        }

        const modal = this.as.openModal(
          {
            title: 'workbench.command.sysProcessDistributionCommand',
            width: '480px',
            centered: true,
            bodyStyle: { height: '380px' },
            content: DppFormComponent,
            footer: [
              {
                label: 'common.button.cancel',
                type: 'default',
                onClick: (): void => {
                  modal.close();
                }
              },
              {
                label: 'common.button.confirm',
                type: 'primary',
                onClick(data: DppFormComponent) {
                  // 内容组件
                  const isValid = data.onSubmit();
                  const formData = data.getFormData() as DppSafeAny;

                  if (isValid) {
                    data.setLoading(true);
                    this.loading = true;
                    const object = {
                      ISAUTOCHECKOUT$: true,
                      props: {
                        ID$: '',
                        NAME$: formData['NAME$'],
                        ProductItemObject: formData['PRODUCTITEMOBJECT'],
                        ProductItemObject$CLASS: formData['PRODUCTITEMOBJECT$CLASS'],
                        ProcessApproval: formData['DIVIDEWORKAPPROVAL'],
                        Remark: formData['REMARK']
                      }
                    };
                    generateFieldMapping({
                      mappingType: 'folder',
                      fieldKey: 'COMMITFOLDER$',
                      sourceData: formData,
                      onValueUpdate: (key, value) => {
                        object.props![key] = value;
                      }
                    });
                    // 表单验证通过
                    // 发送saveObject请求
                    _this.processManagementService.createProcessAssign(object).subscribe({
                      next: res => {
                        if (res.success) {
                          data.setLoading(false);
                          this.loading = false;
                          // 关闭模态框
                          _this.dppMessageService.success('common.operation.newSuccess');
                          const property = {
                            uiType: 'instance',
                            routePath: '/instance'
                          };
                          const params = {
                            dppRender: {
                              className: res.data['CLASSNAME$'],
                              guid: res.data['GUID$']
                            }
                          };
                          _this.as.openBlank(property, params);
                        }
                      },
                      error: err => {
                        data.setLoading(false);
                        this.loading = false;
                      }
                    });
                    modal.close();
                  }
                }
              }
            ]
          },
          { dppRender: params }
        );
      }
    }
  });
}

