/**
 * 产品料号搜索事件
 * @param event
 */
sysProcessTaskDistributionSearchAction(event: EventInterface): void {
  const keys = ['ID$', 'NAME$'];
  const button: DppButtonComponent = this.getExeCom<DppButtonComponent>(event);
  const table = this.getContentCom(event) as DppTableComponent;
  const inputvalue: string = button.value;
  if (!inputvalue) {
    table.refreshByCondition([]);
    return;
  }
  const searchCondition = new QueryCondition(DppQueryConditionOperator.OR);
  keys.forEach(itey => {
    searchCondition.addCondition(new QueryConditionInfo(itey, [inputvalue], DppQueryConditionOperator.LIKE));
  });
  table.refreshByCondition(searchCondition);
}

