/**
 * 派工
 * @param event
 */
sysSendWorkAction(event: EventInterface): void {
  this.setLoading(event, true);
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const instanceData = table.dppRender.innerSend?.instanceData!;
  const rowData = this.getRowData(event);
  const objects = {
    assign: {
      GUID$: instanceData['GUID$']?.toString()!,
      CLASSNAME$: instanceData['CLASSNAME$']?.toString()!
    },
    items: [
      {
        GUID$: rowData['GUID$'],
        CLASSGUID$: rowData['CLASSGUID$']
      }
    ]
  };

  this.processManagementService.assignTaskForDesignItem(objects).subscribe({
    next: res => {
      if (res.success && res.data) {
        const data = res?.data;
        if (data?.errorCnt) {
          this.dppMessageService.error(res.data.details[0]?.message);
        }
        if (data?.successCnt && data?.successCnt === data?.totalCnt) {
          table.refreshData();
          this.dppMessageService.success('common.operation.newSuccess');
        }
        this.setLoading(event, false);
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

