  this.setLoading(event, true);
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const instanceData = table.dppRender.innerSend?.instanceData!;
  const rowData = this.getRowData(event);
  let contents = this.translation.transform('process.title.confirmrevocation');
  const titles = this.translation.transform('basic.common.Notice.Alert');
  const modal = this.as.openModal({
    title: titles,
    full: 'false',
    linkType: 'modal',
    isInteractive: false,
    content: `${contents}</b>`,
    footer: [
      {
        label: 'common.button.cancel',
        type: 'default',
        onClick: data => {
          this.setLoading(event, false);
          modal.close();
        }
      },
      {
        label: 'common.button.confirm',
        type: 'primary',
        onClick: data => {
          const objects = {
            assign: {
              GUID$: instanceData['GUID$']?.toString()!,
              CLASSNAME$: instanceData['CLASSNAME$']?.toString()!
