 * @param event
 */
sysBatchSendWorkAction(event: EventInterface): void {
  this.setLoading(event, true);
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const instanceData = table.dppRender.innerSend?.instanceData!;
  const checkedNodesDatas = table.getCheckedNodes();
  const items: Array<{ GUID$: string; CLASSGUID$: string }> = [];
  checkedNodesDatas?.forEach(item => {
    if (item['origin']) {
