// 对象key 转化成 大写
handelParamsToUpperCase(param: { category?: string; isreaded?: string; searchKey?: string }): void {
  Object.keys(param).forEach(key => {
    const upperCaseKey = key?.toUpperCase();
    if (upperCaseKey !== key) {
      param[upperCaseKey] = param[key];
      delete param[key];
    }
  });
}

