/**
 * @description 通知消息排序
 * @use 通知
 * @param event
 */
sortAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;

  const orderKey = 'CREATETIME';
  const column = table.columnManager.getColumn(orderKey);
  if (!column) {
    return;
  }
  const currentOrder = column!.orderStatus;
  const states = [SortState.normal, SortState.asc, SortState.desc];
  const currentIndex = states.indexOf(currentOrder);
  const nextIndex = (currentIndex + 1) % states.length;
  const nextOrder = states[nextIndex];
  column.orderStatus = nextOrder;

  table.refreshByOrder({ name: orderKey, orderby: nextOrder });
}

