/**
 * 打开CAD操作事件
 * @param event
 */
openDesignAction(event: EventInterface): void {
  const page = this.getRootPageService(event);
  const data: IFoundaton = page.getInstanceData();
  if (!data?.FILENAME$) {
    this.dppMessageService.error('common.operation.noModelFilesExist');
    return;
  }
  const tokenValue = this.authUserService.getUser()?.access_token;
  const currentLanguage = this.authUserService.getLanguage();
  const apiUrl = `${this.configService.getConfig().apiUrl}/restful/service`;
  const param = {
    token: tokenValue,
    local: currentLanguage,
    downloadUrl: apiUrl + DppUrlConfig.drawManagement.downloadModelFiles4Open,
    objectInfo: { guid: data['GUID$'], classGuid: data['CLASSGUID$'], token: tokenValue, fileName: data?.FILENAME$ }
  };
  const jsonString = encodeSpecialChars(JSON.stringify(param)); // 将对象转换为JSON字符串
  const url = `digiwinplmopen://${jsonString}`;
  const link = document.createElement('a');
  // link.target = '_blank';
  link.download = 'tableData';
  link.href = url;
  link.click();
  window.URL.revokeObjectURL(url);

  function encodeSpecialChars(str: string): string {
    const replacements: Record<string, string> = {
      '+': '%2B',
      '/': '%2F',
      '=': '%3D',
      '&': '%26',
      '#': '%23',
      '%': '%25',
      '?': '%3F'
    };

    return str.replace(/[+/=]/g, match => replacements[match]);
  }
}

