/**
 * 分派任务管理-导出全部
 */
sysAssignTaskExportAllAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const params = table.queryCondition.getRawValue() as unknown as IQueryInfoParameter;
  const user = this.authUserService.getUser()?.userName;
  this.setLoading(event, true);
  this.workbenchService.exportAllSendTask(params).subscribe({
    next: res => {
      if (res.success) {
        this.setLoading(event, false);
        this.dppMessageService.success('common.operation.operationSuccess');
        const now = new Date();
        const year = now.getFullYear();
        const month = String(now.getMonth() + 1).padStart(2, '0');
        const day = String(now.getDate()).padStart(2, '0');
        const dateStr = `${year}${month}${day}`;
        const timestamp = String(Date.now()).slice(0, 9);

        const downloadUrl = window.URL.createObjectURL(res.data!);
        const link = document.createElement('a');
        link.href = downloadUrl;
        link.download = `${user}-${dateStr}${timestamp}.xlsx`;
        link.click();
        window.URL.revokeObjectURL(downloadUrl);
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

/**
 * 提交
 * @use 流程-上方toolbar
 * @param event
 */
sysApproveSubmitAction(event: EventInterface): void {
  this.setLoading(event, true);
  const page = this.getRootPageService(event);
  const table = page.getComFnMapByName<DppTableComponent>('sysApproveObjectTableCommand');
  const dppRender = this.getContentCom<IBaseContentComponent>(event)['dppRender'];
  const procRtGuid = dppRender.dParams?.['guid'] as string;
  this.workFlowService
    .checkAttachmentsAndPerformer(procRtGuid)
    .pipe(
      switchMap(res => {
        if (res.success) {
          return this.workFlowService.verifyValidAttach(procRtGuid);
        } else {
          return of(null);
        }
      }),
      catchError(err => {
        this.setLoading(event, false);
        throw of(null);
      })
    )
    .subscribe(res => {
      if (!res) {
        this.setLoading(event, false);
        return;
      }
      if (res.data && (res.data as object[]).length) {
        const modal: DppNzModalRef = this.as.openModal(
          {
            content: DppTableComponent,
            width: '800px',
            height: '500px',
            footer: [
              {
                label: 'common.button.cancel',
                type: 'default',
                onClick: () => {
                  modal.close();
                }
              },
              {
                label: 'common.button.confirm',
                type: 'primary',
                onClick: () => {
                  modal.close();
                  this.sysApproveSubmitValidAction(event);
                }
              }
            ]
          },
          {
            dppRender: {
              name: 'sysApproveErrorTable',
              data: res.data,
              toolbar: 'sysApproveErrorToolbar'
            }
          }
        );
        modal.afterClose.subscribe(() => {
          this.setLoading(event, false);
        });
      } else {
        this.sysApproveSubmitValidAction(event);
      }
    });
}

