  if (tableComponent) {
    tableData = this.getData(event, tableComponent) as Array<{ APPROVALSTATUS: string; DEADLINE: Date }>;
  }
  // APPROVALSTATUS='in progress'
  let current;
  let previous;
  let isContinue = true;
