  sysNewTemplateAction(event: EventInterface): void {
    const templateSelectedBtn = this.getButton(event, 'sysSelectTemplateCommand') as DppButtonComponent;

    const button = this.getExeCom<DppButtonComponent>(event);
    const table = this.getContentCom<DppTableComponent>(event);
