                  next: res => {
                    modal.close();
                    this.loading = false;
                    if (res.success) {
                      if (res.data && res.data.successCnt !== res.data.totalCnt) {
                        that.dppMessageService.createTableMessage('warning', bs.getUiModel().label, res.data);
                      }
                      that.contentComCallback(event, {
