                      });
                    } else {
                      that.dppMessageService.warning(`${res.errorCode}:${res.errorMsg}`);
                    }
                  },
                  error: () => {
                    modal.close();
                    this.loading = false;
                  }
                });
              }
            }
          }
        ],
        onOk: (res: DppGlobalSearchComponent) => {
          const attaches: Array<{ GUID$: string; CLASSGUID$: string; CLASSNAME$: string }> = [];

          const selectedData = res.table.getCheckedNodes();
          if (selectedData.length > 0) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            selectedData.forEach((item: any) => {
              attaches.push({
                GUID$: item.origin.GUID$,
                CLASSGUID$: item.origin.CLASSGUID$,
                CLASSNAME$: item.origin.CLASSNAME$
              });
            });
            if (!attaches.length) return;
            const params = {
              procRtGuid: processGuid,
              attaches: attaches
            };
            this.setLoading(event, true);
            this.workFlowService.updateProcAttach(params).subscribe({
              next: res => {
                this.setLoading(event, false);
                if (res.success) {
                  if (res.data && res.data.successCnt !== res.data.totalCnt) {
                    this.dppMessageService.createTableMessage('warning', bs.getUiModel().label, res.data);
                  }
                  this.contentComCallback(event, {
                    operate: EventCallbacksActionName.REFRESH
                  });
                } else {
                  this.dppMessageService.warning(`${res.errorCode}:${res.errorMsg}`);
                }
              },
              error: () => {
