  // 粘贴
  sysWorkflowPasteAction(event: EventInterface): void {
    const table = this.getContentCom<IBaseContentComponent>(event) as unknown as DppTableComponent;
    const tableData = table.getTreeNodes();
    const params = {
      procRtGuid: table.dppRender.data!['GUID'],
      attaches: []
    };
    const copySet = this.authService.getClipBoardSet(clipBoardTypeEnum.OBJECT_TYPE);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const repeatData = Array.from(copySet).filter((item: any) =>
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      tableData.some((element: any) => item.GUID === element['GUID$'])
    );
    const filterData = Array.from(copySet).filter(
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (item: any) => !tableData.some((element: any) => item.GUID === element['GUID$'])
    );
    if (repeatData.length > 0 && filterData.length === 0) {
      this.dppMessageService.warning('common.operation.addDataDuplicate');
      return;
    }
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    filterData.forEach((item: any) => {
      if (item.GUID && item.CLASSGUID && item.CLASSNAME) {
        const attache = {
          GUID$: item.GUID,
          CLASSGUID$: item.CLASSGUID,
          CLASSNAME$: item.CLASSNAME
        };
        params.attaches.push(attache as never);
      }
    });
    if (params.attaches.length === 0) {
      this.dppMessageService.warning('common.operation.noDataCanPaste');
      return;
    }
    this.setLoading(event, true);
    this.workFlowService.addAttachments(params).subscribe({
      next: res => {
        if (res.success) {
          this.setLoading(event, false);
          const ExceptionData = res.data as IBatchData;
          if (ExceptionData && ExceptionData.successCnt !== ExceptionData.totalCnt) {
            this.dppMessageService.createTableMessage('success', 'common.operation.newSuccess', ExceptionData);
            return;
          }
          this.contentComCallback(event, {
            operate: EventCallbacksActionName.REFRESH
          });
          if (repeatData.length > 0 && filterData.length > 0) {
            this.dppMessageService.success('common.operation.addSuccessAndDeduplicated');
          } else {
            this.dppMessageService.success('common.operation.operationSuccess');
          }
        } else {
          this.setLoading(event, false);
          this.dppMessageService.error('basic.modalTip.operationfailed');
        }
        // event.contentComFn()['queryData']();
      },
      error: err => {
        this.setLoading(event, false);
      }
    });
  }

