  /**
   * 下载图纸具体实现
   * @use 流程详情-表格上方toolbar
   * @use 图纸审批-批量下载图纸
   * @param params
   */
  downloadAllDrawing(params: { procRtGuid: string }, setBtnLoading: (loading: boolean) => void): void {
    setBtnLoading(true);
    this.workFlowService.downloadAllDraw(params).subscribe({
      next: res => {
        const blob = new Blob([res.data as Blob], {
          type: 'application/zip'
        });
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.target = '_blank';
        link.download = 'drawings.zip'!;
        link.href = url;
        link.click();
        window.URL.revokeObjectURL(url);
        setBtnLoading(false);
      },
      error: err => {
        setBtnLoading(false);
      }
    });
  }

