  // 图纸审批 表格加载后设置首次行选中
  drawApproveHasInit = false;
  sysDrawApprovePreviewTableAfetrAction(event: EventInterface): void {
    if (this.drawApproveHasInit) {
      return;
    }
    const rootPage = this.getRootPageService(event);
    const fileBottom = rootPage.getChildPage<DppPageComponent>('sysDrawApproveBottomPageCommand');
    const fileBottomEye = rootPage.getChildPage<DppPageComponent>('sysLightWeightDrawingApprovalBottomPageCommand');
    const fileBottomPage = fileBottom || fileBottomEye;

    if (!fileBottomPage) {
      this.setLoading(event, false, { isOpenOther: true });
      return;
    }

    const preTable = fileBottomPage.getPageThis().getChildPage<DppTableComponent>('sysDrawApproveTableCommand');
    const preEyeTable = fileBottomPage
      .getPageThis()
      .getChildPage<DppTableComponent>('sysLightWeightDrawingApprovalTableCommand');
    const previewTable = preTable || preEyeTable;

    const fileCon = fileBottomPage.getPageThis().getChildPage<ViewerComponent>('sysDrawApproveFilePreviewCommand');
    const fileEyeCon = fileBottomPage
      .getPageThis()
      .getChildPage<ViewerComponent>('sysDrawApproveFileEyePreviewCommand');
    const file = fileCon || fileEyeCon;
    const kkfile = file['kkfile'];
    const editorForm = kkfile?.['form'];
    const nextData = previewTable?.getTreeNodes()?.[0];

    if (nextData.origin['VIEW_FILE_TYPE'] === 'KK_FILE') {
      previewTable.setNodeSelected(0);
      this.handelDrawApprovePreview(
        file,
        nextData?.origin as IFoundaton,
        nextData?.origin['VIEW_FILE_GUID'],
        undefined,
        undefined,
        nextData
      );

      this.workFlowService.getAnnotationComment(nextData?.origin['REVIEW_GUID'][0]).subscribe({
        next: res => {
          if (res.success && res.data) {
            editorForm?.callback({
              params: res.data,
              action: EventCallbacksActionName.UPDATE
            });
          }
        }
      });
      this.setLoading(event, false, { isOpenOther: true });
    } else if (
      nextData.origin['VIEW_FILE_TYPE'] === 'NEW_DI_2D' ||
      nextData.origin['VIEW_FILE_TYPE'] === 'NEW_DI_3D' ||
      nextData.origin['VIEW_FILE_TYPE'] === 'ZI_QI_AN'
    ) {
      previewTable.setNodeSelected(0);
      this.workFlowService.getAnnotationComment(nextData?.origin['REVIEW_GUID'][0]).subscribe({
        next: res => {
          if (res.success && res.data) {
            this.handelDrawApprovePreview(
              file,
              nextData?.origin as IFoundaton,
              nextData?.origin['VIEW_FILE_GUID'],
              res.data
            );
            // bs.setLoading(false);
            setTimeout(() => {
              this.setLoading(event, false, { isOpenOther: true });
            }, 500);
          }
        }
      });
    }
  }

  private handelDrawApprovePreview(
    file: ViewerComponent,
    tableData: IFoundaton,
    fileGuid: string,
    tags?: IAnnotationComment,
    callback?: () => void,
    rowNode?: RowNode
  ): void {
    if (!file) {
      let errorMessage = 'workflow.operation.noFileCanPreview';
      this.dppTranslateService.get(errorMessage).subscribe(res => {
        errorMessage = res;
      });
      this.message.error(errorMessage);
      return;
    }
    file.dppRender.dParams!.className = tableData['CLASSNAME$'];
    file.dppRender.dParams!.guid = tableData['GUID$'];
    file.dppRender.dParams!['fileGuid'] = fileGuid;
    file.dppRender.dParams!['fileTags'] = tags;
    file.browse({
      dParams: {
        className: tableData['CLASSNAME$'],
        guid: tableData['GUID$'],
        is2DDrawApprove: true,
        dataSource: `${DppUrlConfig.WorkFlow.getAnnotationComment}?REVIEW_GUID=${tableData['REVIEW_GUID'][0]}`,
        fileGuid: fileGuid,
        fileTags: tags,
        actRtGuid: file.dppRender.dParams!['actRtGuid'],
        ziqianHideBtn: file.dppRender.dParams?.['ziqianHideBtn'],
        autoOpenStruct: true,
        hidebtnCfg: file.dppRender.dParams?.['hidebtnCfg']
      }
    });
    // 设置图纸已阅
    if (tableData['IS_READ'] === 'N' || !tableData['IS_READ']) {
      this.workFlowService.markAsRead(tableData?.['REVIEW_GUID']).subscribe({
        next: res => {
          if (res.data && res.success) {
            callback?.();
            rowNode?.setDataValue('IS_READ', 'Y');
            // this.dppMessageService.success('common.operation.operationSuccess');
          }
        }
      });
    }
  }

