    }
    this.handlePreviewAndMarkReadTargetNode(context);
  }

  private showNoPreviewMessage(): void {
    let errorMessage = 'workflow.operation.noFileCanPreview';
    this.dppTranslateService.get(errorMessage).subscribe(res => {
      errorMessage = res;
    });
    this.message.error(errorMessage);
