  private handlePreviewAndMarkReadTargetNode(context: PreviewContext): void {
    const { viewComp, targetNode } = context;
    const data = targetNode.origin;
    // 更新预览并处理逻辑
    this.previewDrawApproveRow(context)
      .pipe(
        tap(previewSuccess => {
          if (!previewSuccess) {
            throw new Error('Preview failed'); // 抛出错误以便处理
          }
        }),
        filter(previewSuccess => previewSuccess), // 确保只有预览成功才继续
        tap(() => {
          const isRead = data['IS_READ'] === 'N' || !data['IS_READ'];
          if (!isRead) {
            throw new Error('Already read'); // 如果已经是已读状态，则终止流
          }
        }),
        switchMap(() => this.workFlowService.markAsRead(data['REVIEW_GUID'][0])), // 标记为已读
        tap(res => {
          targetNode.setData({
            ...data,
            ...res.data[0]
          });
        }),
        catchError(err => {
          // 在这里处理错误并提示
          if (err.message === 'Preview failed') {
            // 替换为你的提示方法
          } else if (err.message === 'Already read') {
            // 替换为你的提示方法
          } else {
            // 记录其他未知错误
          }
          return EMPTY; // 返回空流终止后续操作
        }),
        finalize(() => {
          // 无论成功或失败都执行的逻辑
          context.setBtnLoading?.(false);
        })
      )
      .subscribe();
  }

  /**
   * 获取预览上下文
   * @description 根据不同的触发方式获取预览相关的上下文信息
   * @param event - 事件对象
   * @param triggerType - 触发类型：
   *                   - rowClick: 表格行点击（默认）
   *                   - up: 上一个按钮
   *                   - down: 下一个按钮
   * @returns {PreviewContext} 预览上下文对象，包含：
   *          - viewComp: 预览组件
   *          - source: 来源（sp: 审批页面 | eye: 预览页面）
   *          - setBtnLoading: 设置按钮加载状态的函数
   *          - lastNode: 上一个选中的节点
   *          - targetNode: 当前目标节点
   *          - event: 事件对象
   *          - table: 表格组件
   */
  private getPreviewContext(event: EventInterface, triggerType: TriggerType = 'rowClick'): PreviewContext | undefined {
    // 根据触发类型获取页面服务
    const pageService = triggerType === 'rowClick' ? this.getRootPageService(event) : this.getRootPageService(event);

    // 获取预览组件和来源信息
    const sp_iframe = pageService.getComFnMapByName('sysDrawApproveFilePreviewCommand') as ViewerComponent;
    const eye_iframe = pageService.getComFnMapByName('sysDrawApproveFileEyePreviewCommand') as ViewerComponent;
    const source: PreviewSource = sp_iframe ? 'sp' : eye_iframe ? 'eye' : null;
    const viewComp = source === 'sp' ? sp_iframe : eye_iframe;

    if (!source) {
      return;
    }

    // 初始化表格和节点变量
    let table: DppTableComponent;
    let lastNode: RowNode;
    let targetNode: RowNode;

    if (triggerType === 'rowClick') {
      // 行点击：从事件中获取节点信息
      targetNode = this.getNode(event) as RowNode;
      table = targetNode.beans.table;
      lastNode = table.getSelectedNodeList()[0];
    } else {
      // 上一个/下一个按钮：获取对应表格和节点
      const tableName = source === 'sp' ? 'sysDrawApproveTableCommand' : 'sysLightWeightDrawingApprovalTableCommand';
      table = pageService.getChildPage<DppTableComponent>(tableName);

      lastNode = table.getSelectedNodeList()[0];
      if (!lastNode) {
        targetNode = table.getAllNodes()[0];
      } else {
        // 获取所有节点并计算目标索引
        const nodes = lastNode.parentNode!.childrenAfterFilter;
        const lastIndex = nodes.indexOf(lastNode);
        // 使用取模运算实现循环
        const targetIndex = (lastIndex + (triggerType === 'up' ? -1 : 1) + nodes.length) % nodes.length;
        targetNode = nodes[targetIndex];
      }
    }

    // 设置加载状态函数
    const setBtnLoading =
      triggerType === 'rowClick'
        ? undefined
        : (loading: boolean) => {
          if (loading) {
            this.setLoading(event, loading, { isDisabledOther: true });
          } else {
            this.setLoading(event, loading, { isOpenOther: true });
          }
        };

    return {
      viewComp,
      source,
      setBtnLoading,
      lastNode,
      targetNode,
      event,
      table
    };
  }

  /**
   * 初始化图纸审批状态
   * @private
   */
  private initDrawApproveStatus(): void {
    if (!this.drawApproveHasInit) {
      this.drawApproveHasInit = true;
    }
  }
  /**
   * @description 预览行
   * @param event
   * @returns Observable<boolean>
   */
  private previewDrawApproveRow(context: PreviewContext): Observable<boolean> {
    const { viewComp, targetNode } = context;

    const data = targetNode.origin;

    const fileType = data['VIEW_FILE_TYPE'];

    const isKK_FILE = fileType === 'KK_FILE';
    const isNEW_DI_2D = fileType === 'NEW_DI_2D';
    const isNEW_DI_3D = fileType === 'NEW_DI_3D';
    const isZI_QI_AN = fileType === 'ZI_QI_AN';

    return of(fileType).pipe(
      switchMap(fileType => {
        if (isKK_FILE) {
          return this.handleKKFilePreview(viewComp, targetNode);
        } else if (isNEW_DI_2D || isNEW_DI_3D || isZI_QI_AN) {
          return this.handleDrawingPreview(viewComp, targetNode);
        } else {
          return of(false);
        }
      })
    );
  }

  /**
   * @description 处理KK_FILE类型的预览
   * @param file
   * @param data
   * @returns Observable<boolean>
   */
  private handleKKFilePreview(viewComp: ViewerComponent, node: RowNode): Observable<boolean> {
    const kkFile = viewComp.kkfile;
    const editorForm = kkFile?.form;
    return this.commonPreviewDrawApprove(viewComp, node, editorForm);
  }

  /**
   * @description 处理NEW_DI_2D、NEW_DI_3D、ZI_QI_AN类型的预览
   * @param file
   * @param data
   * @returns Observable<boolean>
   */
  private handleDrawingPreview(viewComp: ViewerComponent, node: RowNode): Observable<boolean> {
    const data = node.origin;

    return this.workFlowService.getAnnotationComment(data['REVIEW_GUID'][0]).pipe(
      tap(res => {
        if (!res.success || !res.data) {
          throw new Error('获取注释信息失败');
        }
      }),
      switchMap(res => this.commonPreviewDrawApprove(viewComp, node, undefined, res.data)),
      catchError(err => {
        // 处理错误并返回一个失败的流
        console.error('预览失败:', err.message || err);
        return of(false);
      })
    );
  }
  private commonPreviewDrawApprove(
    viewComp: ViewerComponent,
    node: RowNode,
    editFrom: DppFormComponent | undefined,
    tags?: IAnnotationComment
  ): Observable<boolean> {
    const data = node.origin;
    const dParams = viewComp.dppRender.dParams!;
    Object.assign(dParams, {
      className: data['CLASSNAME$'],
      guid: data['GUID$'],
      fileGuid: data['VIEW_FILE_GUID'],
      fileTags: data['FILE_TAGS']
    });

    viewComp.browse({
      dParams: {
        className: data['CLASSNAME$'],
        guid: data['GUID$'],
        is2DDrawApprove: true,
        dataSource: `${DppUrlConfig.WorkFlow.getAnnotationComment}?REVIEW_GUID=${data['REVIEW_GUID'][0]}`,
        fileGuid: data['VIEW_FILE_GUID'],
        fileTags: tags,
        actRtGuid: dParams['actRtGuid'],
        ziqianHideBtn: dParams?.['ziqianHideBtn'],
        autoOpenStruct: true,
        hidebtnCfg: dParams?.['hidebtnCfg']
      }
    });
    if (editFrom) {
      this.workFlowService.getAnnotationComment(data['REVIEW_GUID'][0]).subscribe({
        next: res => {
          if (res.success && res.data) {
            editFrom?.callback({
              params: res.data,
              action: EventCallbacksActionName.UPDATE
            });
          }
        }
      });
    }

    // 目前组件没有预览成功还是失败的回调，这里暂时默认认为成功
    return of(true);
  }

