    const rootPage = this.getRootPageService(event);
    const pageData = (rootPage.getPageData() || dppRender.innerSend?.['pageData']) as IBaseData;
    const actRtGuid = pageData['ACTIVITYRUNTIMELIST'][0]['GUID'];
    const procRtGuid = dppRender.dParams?.['guid'] as string;
    const table = this.getContentCom<DppTableComponent>(event);
    const totalColumns = table.beans.columnManage.totalColumns;
    const exportFields = [];
    for (const column of totalColumns) {
      if (column.key === 'OPERATION$' || column.key === 'leftControl') continue;
      const value = this.translate.transform(column.label!);
      exportFields.push([column.key, value]);
    }
    const object = {
      procRtGuid,
      actRtGuid,
      exportFields
    };
    this.workFlowService.exportAllAttachments(object).subscribe(res => {
      this.downloadBlob(res.data!, `results.csv`);
    });
  }

  downloadBlob(data: Blob, fileName: string): void {
    const downloadUrl = window.URL.createObjectURL(data);
    const link = document.createElement('a');
    link.href = downloadUrl;
    link.download = fileName;
    link.click();
    window.URL.revokeObjectURL(downloadUrl);
  }
  configBomCellEditorSelector(params: CellEditorSelectorParams): CellEditorSelectorResult | undefined {
    const { node, data } = params;
    // 是否开启位号检查
    const shouldUseCell = data['DESIGNATORCHECK'] === 'Y';
    if (shouldUseCell) {
      return {
        component: 'bomCell'
      };
    }
    return undefined;
  }
  configBomCellValueSetter(params: ValueSetterParams): boolean {
    // 因为有三个编辑器，1number  2 editLargeText  3 bom-Cell
    const newValue = params.newValue;
    const key = params.column.key;

    if (typeof newValue === 'object') {
      params.data['QUANTITY'] = newValue['QUANTITY'];
      params.data['DESIGNATORS'] = newValue['DESIGNATORS'];
    } else {
      params.data[key] = newValue;
    }

    return true;
  }

  sysApproveOpenGeneralDrawerAction(event: EventInterface): void {
    this.publicEventService.sysOpenGeneralDrawerAction(event as HasModelEventInterface, {
      extraDParams: { fromProcess: 'true' }
    });
  }
}

// 创建下拉菜单容器的函数
createDropdownContainer(top: number, left: number): HTMLDivElement {
  const dropdownContainer = document.createElement('div');
  dropdownContainer.style.top = `${top}px`;
  dropdownContainer.style.left = `${left}px`;
  dropdownContainer.classList.add('custom-dropdown');
  return dropdownContainer;
}

// 创建下拉菜单选项的函数
createDropdownOption(dropdownContainer: HTMLElement, text: string): HTMLDivElement {
  const optionElement = document.createElement('div');
  optionElement.classList.add('dropdown-option');
  optionElement.textContent = text;

  // 将选项添加到下拉菜单容器中
  dropdownContainer.appendChild(optionElement);
  return optionElement;
}

/**
 * 拒绝
 * @use 流程-上方toolbar
 * @param event
 */
sysWorkflowRejectAction(event: EventInterface): void {
  const modal = this.getTriggerModal(event) as DppNzModalRef;
  const dppRender = this.getContentCom<IBaseContentComponent>(event)['dppRender'];
  const pageData = dppRender.innerSend?.['pageData'] as IBaseData;
  const trigger = this.getTrigger(event);

  const rootPage = this.getRootPageService(event);
  let rejectTitle = 'workflow.title.rejectWf';
  let rejectContent = 'workflow.operation.rejectProcessConfirmation';
  this.dppTranslateService.get(rejectTitle).subscribe(res => {
    rejectTitle = res;
  });
  this.dppTranslateService.get(rejectContent).subscribe(res => {
    rejectContent = res;
  });
  const OkText = this.translate.transform('basic.system.boolean.Y');
  const cancelText = this.translate.transform('basic.system.boolean.N');
  this.modal.confirm({
    nzTitle: rejectTitle,
    nzContent: rejectContent,
    nzOkText: OkText,
    nzCancelText: cancelText,
    nzOnOk: () =>
      new Promise((resolve, reject) => {
        // 获取目标按钮和容器元素
        setTimeout(Math.random() > 0.5 ? resolve : reject, 0);
        const buttonEvent = event.event as Event;
        const buttonElement = buttonEvent.target as HTMLElement;

        const top = buttonElement.getBoundingClientRect().top + 30;
        const left = buttonElement.getBoundingClientRect().left - 20;
        (event.event as Event).preventDefault();
        (event.event as Event).stopPropagation();
        const data = this.getData(event);
        const suggestionCom = this.findPageChildren<WorkflowSuggestionComponent>(
          event,
          'sysApproveSuggestionCommand'
        );
        const comments = suggestionCom.suggestionTextarea;
        const procRtGuid = pageData?.['ACTIVITYRUNTIMELIST'][0]['PROCRTGUID'];
        const actRtGuid = pageData?.['ACTIVITYRUNTIMELIST'][0]['GUID'];
        const params = { procRtGuid, actRtGuid, comments };
        // this.setLoading(event, true);
        rootPage.setLoading('sysApprovePage', true);
        const form = suggestionCom.form;
        const files = form.getFormData()!['DWFILES'];
        const formData = new FormData();
        if (files?.length > 0) {
          files.forEach((file: any) => {
            delete file.url;
            const clonedFile = new File([file], file.uid, {
              type: file.type
            });
            formData.append('files', clonedFile, file.name);
          });
        } else {
          formData.append('files', '');
        }
        // this.workFlowService.executeProcess(procRtGuid, actRtGuid, comments)
        const token = JSON.parse(localStorage.getItem('dppUser')!).access_token;
        const httpOptions = {
          headers: new HttpHeaders({
            token: token,
            Authorization: `Bearer ${token}`
          })
        };
        const url = this.configService.getConfig().apiUrl;
        const base = this.configService.getConfig().uri_base;
        this.workFlowService.listActivityCanReject(actRtGuid).subscribe({
          next: res => {
            if (res.data!.length === 1) {
              const rejectToActRtGuid = res.data![0].GUID;
              const object = {
                procRtGuid,
                actRtGuid,
                comments,
                rejectToActRtGuid
              };
              formData.append('object', JSON.stringify(object));
              // this.workFlowService.refuseProcess(procRtGuid, actRtGuid, comments, rejectToActRtGuid)
              this.http
                .post(`${url}${base}/Workflow/IWorkflowService/refuseProcess`, formData, httpOptions)
                .subscribe({
                  next: refuse => {
                    rootPage.setLoading('sysApprovePage', false);
                    this.dppMessageService.success('workflow.operation.rejectWfSuccess');
                    // this.workflowTool.refreshApproveAndForm(event, res.data as IFoundaton);
                    rootPage.refreshPageData();
                    // this.setLoading(event, false);
                    this.closeAction({ router: this.router, closeNow: true });
                  },
                  error: () => {
                    rootPage.setLoading('sysApprovePage', false);
                  }
                });
            } else {
              // 获取按钮下方的下拉菜单容器
              const dropdownContainer = this.createDropdownContainer(top, left);
              document.addEventListener('click', function (event) {
                if (!dropdownContainer.contains(event['target'] as Node)) {
                  dropdownContainer.style.display = 'none';
                }
              });
              // 将下拉菜单容器添加到按钮下方
              const body = document.querySelector('body');
              body!.appendChild(dropdownContainer);
              // eslint-disable-next-line @typescript-eslint/no-this-alias
              const that = this;
              // 添加选项
              res.data?.forEach(procRt => {
                const title = this.translation.transform(procRt.TITLE);
                const HTMLOptionElement = this.createDropdownOption(dropdownContainer, title);
                // 添加点击事件监听器
                HTMLOptionElement.addEventListener('click', () => {
                  const object = {
                    procRtGuid: params.procRtGuid,
                    actRtGuid: params.actRtGuid,
                    comments,
                    rejectToActRtGuid: procRt.GUID
                  };
                  formData.append('object', JSON.stringify(object));
                  // this.workFlowService.refuseProcess(procRtGuid, actRtGuid, comments, rejectToActRtGuid)
                  that.http
                    .post(`${url}${base}/Workflow/IWorkflowService/refuseProcess`, formData, httpOptions)
                    // that.workFlowService
                    //   .refuseProcess(params.procRtGuid, params.actRtGuid, comments, procRt.GUID)
                    .subscribe({
                      next: () => {
                        rootPage.setLoading('sysApprovePage', false);
                        this.dppMessageService.success('workflow.operation.rejectWfSuccess');
                        // this.workflowTool.refreshApproveAndForm(event, res.data as IFoundaton);
                        rootPage.refreshPageData();
                        // this.setLoading(event, false);
                        this.closeAction({ router: this.router, closeNow: true });
                      },
                      error: () => {
                        rootPage.setLoading('sysApprovePage', false);
                      }
                    });
                  dropdownContainer.style.display = 'none';
                });
              });
            }
          },
          error: () => {
            rootPage.setLoading('sysApprovePage', false);
          }
        });
      }).catch(() => console.log('Oops errors!'))
  });
}

