/**
 * 添加审批人
 * @use 流程详情-表格中tag
 * @param event
 */
addApproverAction(event: TagOpenEvent): void {
  const rowData = event.data;
  const queryParams = {
    wfTemplateGuid: rowData['PROCRTGUID'],
    activityName: rowData['ACTRTNAME'],
    DISABLEDRIGPARENT: true,
    DISABLEDGROUPSPARENT: true
  };
  CommonEventUtil.addPersonAction(
    event,
    this.as,
    (dataMess): DppSafeAny[] => {
      const { data, typeMap } = dataMess;

      if (data?.length > 0) {
        data.forEach((item: IBaseData) => {
          const memberType = item['PERFTYPE'];
          const id = item['PERFGUID'];
          const name = item['PERFNAME'];
          const element = typeMap.get(memberType) as any;
          element.push({ guid: id, title: name, isSelected: true, type: memberType });
        });
      }
      return data;
    },
    (mess): void => {
      const { data, modal, list, typeMap, tableRow } = mess;
      const procRtGuid = tableRow?.['PROCRTGUID'] as string;
      const actrtGuid = tableRow?.['GUID'] as string;
      const performerList: performer[] = list.map(item => {
        return {
          perfGuid: item.guid as string,
          perfType: item.type as string
        };
      });
      if (!list.length) {
        this.dppMessageService.warning('common.operation.noDataSelected');
        return;
      }

      const params: ApproverRoleMess = { procRtGuid, actrtGuid, performerList };
      this.workFlowService.addPerformer(params as addApproverParams).subscribe(res => {
        let props = res.data as any;
        const newData = { ...event.data, ...props };
        event.updateRender(newData);
        modal.close();
      });
    },
    queryParams
  );
}

