// 添加审批对象
sysWorkflowAddAction(event: EventInterface): void {
  const bs = this.getExeCom(event) as DppButtonComponent;
  const action = bs.getUiModel().action!;
  const processGuid = this.getRowData(event)['GUID']!;
  const that = this;
  const modal: DppNzModalRef = this.as.openModal(
    {
      title: 'basic.common.command.sysCommonAddCommand',
      width: '80%',
      height: '700px',
      linkType: 'modal',
      uiType: 'search',
      bodyStyle: {
        maxHeight: '700px',
        borderRadius: '5px',
        overflowY: 'auto',
        padding: '10px'
      },
      modalSelf: () => modal,
      triggerInstance: () => this.getContentCom(event),
      reFreshCallBack: () => {
        modal?.close();
      },
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: () => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: function (res: DppGlobalSearchComponent) {
            const attaches: Array<{ GUID$: string; CLASSGUID$: string; CLASSNAME$: string }> = [];
            const selectedData = res.table.getCheckedNodes();
            if (!selectedData.length) {
              that.dppMessageService.warning('common.operation.noDataSelected');
              return;
            }
            if (selectedData.length > 0) {
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
              selectedData.forEach((item: any) => {
                attaches.push({
                  GUID$: item.origin.GUID$,
                  CLASSGUID$: item.origin.CLASSGUID$,
                  CLASSNAME$: item.origin.CLASSNAME$
                });
              });
              if (!attaches.length) return;
              const params = {
                procRtGuid: processGuid,
                attaches: attaches
              };
              this.loading = true;
              that.workFlowService.updateProcAttach(params).subscribe({
                next: res => {
                  modal.close();
                  this.loading = false;
                  if (res.success) {
                    if (res.data && res.data.successCnt !== res.data.totalCnt) {
                      that.dppMessageService.createTableMessage('warning', bs.getUiModel().label, res.data);
                    }
                    that.contentComCallback(event, {
                      operate: EventCallbacksActionName.REFRESH
                    });
                  } else {
                    that.dppMessageService.warning(`${res.errorCode}:${res.errorMsg}`);
                  }
                },
                error: () => {
                  modal.close();
                  this.loading = false;
                }
              });
            }
          }
        }
      ],
      onOk: (res: DppGlobalSearchComponent) => {
        const attaches: Array<{ GUID$: string; CLASSGUID$: string; CLASSNAME$: string }> = [];

        const selectedData = res.table.getCheckedNodes();
        if (selectedData.length > 0) {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          selectedData.forEach((item: any) => {
            attaches.push({
              GUID$: item.origin.GUID$,
              CLASSGUID$: item.origin.CLASSGUID$,
              CLASSNAME$: item.origin.CLASSNAME$
            });
          });
          if (!attaches.length) return;
          const params = {
            procRtGuid: processGuid,
            attaches: attaches
          };
          this.setLoading(event, true);
          this.workFlowService.updateProcAttach(params).subscribe({
            next: res => {
              this.setLoading(event, false);
              if (res.success) {
                if (res.data && res.data.successCnt !== res.data.totalCnt) {
                  this.dppMessageService.createTableMessage('warning', bs.getUiModel().label, res.data);
                }
                this.contentComCallback(event, {
                  operate: EventCallbacksActionName.REFRESH
                });
              } else {
                this.dppMessageService.warning(`${res.errorCode}:${res.errorMsg}`);
              }
            },
            error: () => {
              this.setLoading(event, false);
            }
          });
        }
      }
    },
    {
      dppRender: {
        ...action,
        dataSource: `${action.dataSource}?procRtGuid=${processGuid}`,
        menuDataSource: `${action['menuDataSource']}?procRtGuid=${processGuid}`,
        name: 'ItemManageSearchTable'
      }
    }
  );
}

