private handelDrawApprovePreview(
  file: ViewerComponent,
  tableData: IFoundaton,
  fileGuid: string,
  tags?: IAnnotationComment,
  callback?: () => void,
  rowNode?: RowNode
): void {
  if (!file) {
    let errorMessage = 'workflow.operation.noFileCanPreview';
    this.dppTranslateService.get(errorMessage).subscribe(res => {
      errorMessage = res;
    });
    this.message.error(errorMessage);
    return;
  }
  file.dppRender.dParams!.className = tableData['CLASSNAME$'];
  file.dppRender.dParams!.guid = tableData['GUID$'];
  file.dppRender.dParams!['fileGuid'] = fileGuid;
  file.dppRender.dParams!['fileTags'] = tags;
  file.browse({
    dParams: {
      className: tableData['CLASSNAME$'],
      guid: tableData['GUID$'],
      is2DDrawApprove: true,
      dataSource: `${DppUrlConfig.WorkFlow.getAnnotationComment}?REVIEW_GUID=${tableData['REVIEW_GUID'][0]}`,
      fileGuid: fileGuid,
      fileTags: tags,
      actRtGuid: file.dppRender.dParams!['actRtGuid'],
      ziqianHideBtn: file.dppRender.dParams?.['ziqianHideBtn'],
      autoOpenStruct: true,
      hidebtnCfg: file.dppRender.dParams?.['hidebtnCfg']
    }
  });
  // 设置图纸已阅
  if (tableData['IS_READ'] === 'N' || !tableData['IS_READ']) {
    this.workFlowService.markAsRead(tableData?.['REVIEW_GUID']).subscribe({
      next: res => {
        if (res.data && res.success) {
          callback?.();
          rowNode?.setDataValue('IS_READ', 'Y');
          // this.dppMessageService.success('common.operation.operationSuccess');
        }
      }
    });
  }
}

/**
