// 撤销
sysApproveCancelAction(event: EventInterface): void {
  const trigger = this.getTrigger<DppTableComponent>(event);
  const modal = this.getTriggerModal(event) as DppNzModalRef;
  let cancelTitle = 'workflow.title.cancelWf';
  let cancelContent = 'workflow.operation.cancelProcessConfirmation';
  this.dppTranslateService.get(cancelTitle).subscribe(res => {
    cancelTitle = res;
  });
  this.dppTranslateService.get(cancelContent).subscribe(res => {
    cancelContent = res;
  });
  const OkText = this.translate.transform('basic.system.boolean.Y');
  const cancelText = this.translate.transform('basic.system.boolean.N');
  this.modal.confirm({
    nzTitle: cancelTitle,
    nzContent: cancelContent,
    nzOkText: OkText,
    nzCancelText: cancelText,
    nzOnOk: () => {
      const data = this.getData(event);
      const dppRender = this.getContentCom<IBaseContentComponent>(event)['dppRender'];
      const procRtGuid = dppRender.dParams?.guid as string;
      let actRtGuid;
      if (data['ACTIVITYRUNTIMELIST']) {
        actRtGuid = data['ACTIVITYRUNTIMELIST'][0]['GUID'];
      }
      this.workFlowService.repealProcess(procRtGuid, actRtGuid).subscribe(res => {
        this.dppMessageService.success('workflow.operation.cancelWfSuccess');

        this.workflowTool.refreshApproveAndForm(event, res.data as IFoundaton);
        this.closeAction({ router: this.router, closeNow: true });
      });
    }
  });
}

// 检入
sysApproveCheckInAction(event: EventInterface): void {
  const contentComponent: IBaseContentComponent = this.getContentCom<IBaseContentComponent>(event);
  const rowData: IFoundaton = this.getRowData(event);
  this.boas
    .checkObject(
      rowData.CLASSNAME$!,
      rowData.GUID$!,
      new Date(rowData.UPDATETIME$ as string).getTime().toString(),
      CheckActiveEnum.CHECKIN
    )
    .subscribe({
      next: res => {
        if (res.success) {
          // this.message.success('检入成功！');

          this.dppMessageService.success('basic.modalTip.checkInSucceed');
          // 检出相关的清空
          this.checkOutObjeceHandle(res.data as IFoundaton);
          const operateJudge =
            contentComponent.dppRender?.name === ModeNameEnum.SYSWORKBENCHMYTASKTABLE
              ? EventCallbacksActionName.REFRESH
              : EventCallbacksActionName.UPDATE;
          this.contentComCallback(event, {
            operate: operateJudge,
            action: operateJudge,
            guidList: [rowData.GUID$ as string],
            params: res.data
          });
          this.setLoading(event, false);
        } else {
          this.dppMessageService.error(`${res.errorCode}:${res.errorMsg}`);
          this.setLoading(event, false);
        }
      },
      error: res => {
        // this.errorShow(bs, res);
        // this.outgoingCallback(bs, {});
        this.setLoading(event, false);
      }
    });
}

