sysWorkflowOpenGeneralBlankAction(event: HasModelEventInterface): void {
  const rootPageService = this.getRootPageService(event);
  let fromProcess = false;
  if (rootPageService) {
    const status = rootPageService.getPageData()['STATUS'];
    const hasFromProcessStatus = ['RUNNING', 'ONHOLD'];
    fromProcess = hasFromProcessStatus.includes(status);
  }
  this.publicEventService.sysOpenGeneralBlankAction(event, {
    transformRoutePath: routePath => (fromProcess ? `${routePath}&fromProcess=true` : routePath)
  });
}

sysWorkflowExportAction(event: EventInterface): void {
  const dppRender = this.getContentCom<IBaseContentComponent>(event)['dppRender'];
  const rootPage = this.getRootPageService(event);
  const pageData = (rootPage.getPageData() || dppRender.innerSend?.['pageData']) as IBaseData;
  const actRtGuid = pageData['ACTIVITYRUNTIMELIST'][0]['GUID'];
  const procRtGuid = dppRender.dParams?.['guid'] as string;
  const table = this.getContentCom<DppTableComponent>(event);
  const totalColumns = table.beans.columnManage.totalColumns;
  const exportFields = [];
  for (const column of totalColumns) {
    if (column.key === 'OPERATION$' || column.key === 'leftControl') continue;
    const value = this.translate.transform(column.label!);
    exportFields.push([column.key, value]);
  }
  const object = {
    procRtGuid,
    actRtGuid,
    exportFields
  };
  this.workFlowService.exportAllAttachments(object).subscribe(res => {
    this.downloadBlob(res.data!, `results.csv`);
  });
}

downloadBlob(data: Blob, fileName: string): void {
  const downloadUrl = window.URL.createObjectURL(data);
  const link = document.createElement('a');
  link.href = downloadUrl;
  link.download = fileName;
  link.click();
  window.URL.revokeObjectURL(downloadUrl);
}

configBomCellEditorSelector(params: CellEditorSelectorParams): CellEditorSelectorResult | undefined {
  const { node, data } = params;
  // 是否开启位号检查
  const shouldUseCell = data['DESIGNATORCHECK'] === 'Y';
  if (shouldUseCell) {
    return {
      component: 'bomCell'
    };
  }
  return undefined;
}

configBomCellValueSetter(params: ValueSetterParams): boolean {
  // 因为有三个编辑器，1number  2 editLargeText  3 bom-Cell
  const newValue = params.newValue;
  const key = params.column.key;

  if (typeof newValue === 'object') {
    params.data['QUANTITY'] = newValue['QUANTITY'];
    params.data['DESIGNATORS'] = newValue['DESIGNATORS'];
  } else {
    params.data[key] = newValue;
  }

  return true;
}

